void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The simplest strategy is to reverse the permutation.
    // The sums of adjacent elements will be the same, just in reverse order.
    // Sorting them will yield the same fingerprint.
    // We need to ensure the reversed permutation is different from the original.
    // If p is a palindrome (p_i = p_{n-1-i}), then reversing it yields p itself.
    // However, a permutation of length n cannot be a palindrome for n > 1.
    // A permutation contains distinct integers from 1 to n.
    // If p is a palindrome, then p_1 = p_n, p_2 = p_{n-1}, etc.
    // But p_1 and p_n must be distinct if n > 1, unless n=1.
    // For n=1, p=[1], p_rev=[1]. But problem states n >= 2.
    // So p_1 must be different from p_n.
    // Thus, p cannot be a palindrome.
    // Therefore, reversing p will always yield a different permutation p'.

    // Example: n=2, p=[1,2]. p_rev=[2,1]. Different.
    // Example: n=6, p=[2,1,6,5,4,3]. p_rev=[3,4,5,6,1,2]. Different.
    // Example: n=5, p=[2,4,3,1,5]. p_rev=[5,1,3,4,2]. Different.

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation is a valid and simple solution.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

