#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int current_a1 = a[0];
    int days_left = d;

    for (int i = 1; i < n; ++i) {
        int pile_idx = i; // 0-indexed pile index
        int haybales_in_pile = a[pile_idx];
        int cost_per_haybale = pile_idx; // days to move to pile 0

        if (cost_per_haybale == 0) { // Should not happen for i > 0
            continue;
        }

        // Calculate how many haybales we can move from this pile
        // based on available days.
        int max_haybales_movable_by_days = days_left / cost_per_haybale;

        // We can move at most 'haybales_in_pile' from this pile.
        int haybales_to_move = std::min(haybales_in_pile, max_haybales_movable_by_days);

        current_a1 += haybales_to_move;
        days_left -= haybales_to_move * cost_per_haybale;

        if (days_left <= 0) {
            break; // No more days left
        }
    }

    std::cout << current_a1 << std::endl;
}

