void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
    } else {
        // For n >= 2, we can construct a number.
        // The strategy is to use '2' as the first digit,
        // and '3' for all subsequent digits, except for the last digit.
        // The last digit will be '9'.
        // This forms the number 233...39.
        // Let's check the divisibility conditions for 233...39:
        // 1. Divisibility by 2: The number ends in 9, which is odd, so it's not divisible by 2.
        // 2. Divisibility by 3: The sum of digits is 2 + (n-2)*3 + 9.
        //    Sum = 2 + 3n - 6 + 9 = 3n + 5.
        //    For the number to be divisible by 3, 3n + 5 must be divisible by 3.
        //    This means 5 must be divisible by 3, which is false.
        //    So, the number is not divisible by 3.
        // 3. Divisibility by 9: For the number to be divisible by 9, the sum of digits (3n + 5) must be divisible by 9.
        //    This is generally not true. For example, if n=2, sum=11. If n=3, sum=14. If n=4, sum=17.
        //    The only case where 3n+5 is divisible by 9 is if 3n+5 = 9k for some integer k.
        //    This implies 3n = 9k - 5.
        //    Since 9k is divisible by 3, for 3n to be divisible by 3, 5 must be divisible by 3, which is false.
        //    Therefore, 3n+5 is never divisible by 3, and thus never divisible by 9.
        //
        // So, the number 233...39 is not divisible by 2, 3, or 9.
        // Since these are the only digits present in the number, it satisfies all conditions.

        std::cout << '2';
        for (int i = 0; i < n - 2; ++i) {
            std::cout << '3';
        }
        std::cout << '9' << "\n";
    }
}

