#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    // Iterate from right to left
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // If a[i] == b[i], no operation is needed for this element.
            // However, we need to update has_one/has_minus_one for elements to its left.
            if (a[i] == 1) {
                has_one = true; // This '1' is still available for elements to its left
            } else if (a[i] == -1) {
                has_minus_one = true; // This '-1' is still available for elements to its left
            }
            continue;
        }

        // If a[i] != b[i], we need to change a[i].
        // The only way to change a[i] is by adding a[k] for some k < i.
        // This means a[i] must be able to reach b[i] using available +1s and -1s from its left.

        if (b[i] > a[i]) { // Need to increase a[i]
            if (!has_one) { // If no '1' is available to the left, we cannot increase a[i].
                std::cout << "NO\n";
                return;
            }
        } else { // b[i] < a[i], need to decrease a[i]
            if (!has_minus_one) { // If no '-1' is available to the left, we cannot decrease a[i].
                std::cout << "NO\n";
                return;
            }
        }

        // If we reach here, it means we can potentially change a[i] to b[i].
        // The crucial part is that a[i] itself is not a source for operations on elements to its left.
        // So, we must update has_one/has_minus_one based on the *original* a[i] for elements to its left.
        if (a[i] == 1) {
            has_one = true; // This '1' is still available for elements to its left
        } else if (a[i] == -1) {
            has_minus_one = true; // This '-1' is still available for elements to its left
        }
    }

    std::cout << "YES\n";
}

