void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<std::vector<int>> a(n, std::vector<int>(m));
    std::vector<bool> row_used(n, false);
    std::vector<bool> col_used(m, false);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            std::cin >> a[i][j];
            if (a[i][j] == 1) {
                row_used[i] = true;
                col_used[j] = true;
            }
        }
    }

    int free_rows = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_used[i]) {
            free_rows++;
        }
    }

    int free_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_used[j]) {
            free_cols++;
        }
    }

    int moves_possible = std::min(free_rows, free_cols);

    if (moves_possible % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

