#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    // For elements a_i < T/2, assign color 0.
    // For elements a_i > T/2, assign color 1.
    // This ensures that if a_i + a_j = T and a_i != a_j, then one is < T/2 and one is > T/2,
    // so they will be assigned different colors, contributing 0 to misfortune.
    // The only problematic case is when a_i = T/2.

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T / 2.0) { // Using 2.0 for floating point comparison
            p[i] = 0;
        } else if (a[i] > T / 2.0) {
            p[i] = 1;
        }
    }

    // Handle elements where a_i = T/2.
    // If T is odd, T/2 is not an integer, so no a_i can be exactly T/2.
    // If T is even, then T/2 is an integer.
    // For all elements equal to T/2, we can alternate their colors.
    // This minimizes pairs of (T/2, T/2) within the same array.
    // For example, if we have k elements equal to T/2, we can assign
    // ceil(k/2) to one color and floor(k/2) to the other.
    // This results in floor(k/2) * ceil(k/2) pairs if they were all in one array,
    // but by splitting, we get floor(k/2) * (floor(k/2)-1)/2 + ceil(k/2) * (ceil(k/2)-1)/2.
    // The optimal strategy is to alternate colors: 0, 1, 0, 1, ...
    // This ensures that if there are k elements equal to T/2,
    // floor(k/2) elements get color 0 and ceil(k/2) elements get color 1 (or vice versa).
    // The number of pairs within one array will be 0 if k <= 1.
    // If k=2, one 0, one 1, 0 pairs.
    // If k=3, two 0s, one 1 (or one 0, two 1s), 0 pairs.
    // If k=4, two 0s, two 1s, 1 pair in 0s, 1 pair in 1s. Total 2.
    // This is not quite right. The goal is to minimize pairs.
    // If we have $k$ elements equal to $T/2$, and we assign $k_0$ to color 0 and $k_1$ to color 1,
    // then $k_0 + k_1 = k$. The number of pairs is $k_0(k_0-1)/2 + k_1(k_1-1)/2$.
    // This is minimized when $k_0$ and $k_1$ are as close as possible, i.e., $k_0 = \lfloor k/2 \rfloor$ and $k_1 = \lceil k/2 \rceil$.
    // The alternating assignment (0, 1, 0, 1, ...) achieves this.

    int current_color_for_half_T = 0;
    if (T % 2 == 0) {
        for (int i = 0; i < n; ++i) {
            if (a[i] == T / 2) {
                p[i] = current_color_for_half_T;
                current_color_for_half_T = 1 - current_color_for_half_T; // Alternate 0 and 1
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

