int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic is based on the observation that if p[i] is not n,
        // then p[i] = max_{j!=i} min(p[i], p[j]) = max_{j!=i, p[j]>p[i]} p[i] = p[i].
        // If p[i] is n, then max_{j!=i} min(p[i], p[j]) = max_{j!=i} p[j] = n-1.
        // So, if max_val_in_row is n-1, p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 0) { // Edge case, though problem states n >= 1
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    // Initialize min_suffix with a value larger than any possible price (10^6)
    int min_suffix = 1000001; 

    // Iterate from right to left
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > min_suffix) {
            bad_prices_count++;
        }
        // Update min_suffix to be the minimum of current min_suffix and a[i]
        min_suffix = std::min(min_suffix, a[i]);
    }

    std::cout << bad_prices_count << "\n";
}

