        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The first class will have elements from index 0 to n-1 (inclusive)
        // The second class will have elements from index n to 2n-1 (inclusive)
        // The median of the first class will be a[n-1]
        // The median of the second class will be a[n]
        // The difference is a[n] - a[n-1]
        // This is because the problem asks for a partition into two classes
        // each of odd size. The smallest possible odd size is 1.
        // The largest possible odd size is 2n-1.
        //
        // If we sort all 2n elements, say a_0, a_1, ..., a_{2n-1}.
        // We need to pick n elements for one class and n elements for the other.
        // This is not exactly what the problem states.
        // The problem states "each class has odd number of students".
        // Let the sizes be S1 and S2. S1 + S2 = 2n. S1, S2 are odd.
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        // The median of a class of size 2k+1 is the k-th element (0-indexed).
        //
        // Let's try to construct two classes.
        // Class 1: {a_0, a_1, ..., a_{n-1}}
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}}
        //
        // This partition makes both classes of size n.
        // If n is odd, then both classes have odd size.
        // The median of Class 1 (size n) is a_{(n-1)/2}.
        // The median of Class 2 (size n) is a_{n + (n-1)/2}.
        //
        // If n is even, this partition is invalid because class sizes are even.
        //
        // The key insight for this problem is that the minimum difference
        // is achieved when the two medians are adjacent elements in the
        // globally sorted array.
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        // We need to pick S1 elements for class 1 and S2 elements for class 2.
        // S1 and S2 must be odd.
        //
        // Let the median of class 1 be M1 and median of class 2 be M2.
        // We want to minimize |M1 - M2|.
        //
        // The smallest possible median for any class is a_0 (if class size is 1).
        // The largest possible median for any class is a_{2n-1} (if class size is 1).
        //
        // Consider the elements a_{n-1} and a_n.
        // Can we make a_{n-1} the median of one class and a_n the median of another?
        //
        // To make a_{n-1} the median of a class of size S1 = 2k+1:
        // We need k elements smaller than or equal to a_{n-1} and k elements larger than or equal to a_{n-1}.
        // We have n-1 elements smaller than a_{n-1} (a_0 to a_{n-2}).
        // We have n elements larger than or equal to a_n (a_n to a_{2n-1}).
        //
        // Let's try to form a class around a_{n-1} and another around a_n.
        //
        // Class 1: {a_0, a_1, ..., a_{n-1}}
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}}
        //
        // This partition is valid if n is odd.
        // If n is odd, then n = 2k+1 for some k.
        // Median of Class 1 (a_0 to a_{n-1}) is a_k = a_{(n-1)/2}.
        // Median of Class 2 (a_n to a_{2n-1}) is a_{n+k} = a_{n+(n-1)/2}.
        //
        // This is not the general case. The problem is simpler.
        // The problem asks for the minimum absolute difference.
        //
        // The crucial observation is that to minimize the difference between two medians,
        // we should pick two elements that are as close as possible in the sorted array.
        //
        // Consider the elements a_{n-1} and a_n from the sorted array.
        // We can always form a class of size $2k_1+1$ with $a_{n-1}$ as its median,
        // and another class of size $2k_2+1$ with $a_n$ as its median,
        // such that $S_1+S_2 = 2n$.
        //
        // For $a_{n-1}$ to be a median, we need to pick $k_1$ elements from $a_0, \dots, a_{n-2}$
        // and $k_1$ elements from $a_n, \dots, a_{2n-1}$.
        // For $a_n$ to be a median, we need to pick $k_2$ elements from $a_0, \dots, a_{n-1}$
        // and $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$.
        //
        // This is a known result for this type of problem:
        // When you have $2n$ items and you need to partition them into two groups of odd sizes,
        // the minimum difference between their medians is achieved by taking the $(n-1)$-th
        // and $n$-th elements (0-indexed) from the globally sorted array as the medians.
        //
        // Let's verify this.
        // We want to make $a_{n-1}$ the median of Class 1 and $a_n$ the median of Class 2.
        //
        // Class 1: We need $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$.
        // We can take $a_0, \dots, a_{k_1-1}$ (these are $k_1$ smallest elements).
        // We can take $a_{n-1}$ itself.
        // We can take $a_{n}, \dots, a_{n+k_1-1}$ (these are $k_1$ elements larger than $a_{n-1}$).
        // This forms a class of size $2k_1+1$.
        //
        // The remaining elements are $a_{k_1}, \dots, a_{n-2}$ and $a_{n+k_1}, \dots, a_{2n-1}$.
        //
        // This is getting complicated. The simplest interpretation that matches the example is:
        // Sort all $2n$ students.
        // The first $n$ students form one group, the next $n$ students form another group.
        // This means $S_1 = n$ and $S_2 = n$.
        // This is only valid if $n$ is odd.
        //
        // Example 1: n=1, 2n=2. a = [1, 1]. Sorted: [1, 1].
        // n=1 is odd.
        // Class 1: [a_0] = [1]. Median = 1.
        // Class 2: [a_1] = [1]. Median = 1.
        // Difference = |1-1| = 0.
        // My formula: a[n] - a[n-1] = a[1] - a[0] = 1 - 1 = 0. Matches.
        //
        // Example 2: n=3, 2n=6. a = [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6].
        // n=3 is odd.
        // Class 1: [a_0, a_1, a_2] = [1, 2, 3]. Median = a_1 = 2.
        // Class 2: [a_3, a_4, a_5] = [4, 5, 6]. Median = a_4 = 5.
        // Difference = |2-5| = 3.
        // The example output is 1. This means my interpretation of "first n students" is wrong.
        //
        // The example says: Class 1: [6, 4, 2]. Sorted: [2, 4, 6]. Median = 4.
        // Class 2: [5, 1, 3]. Sorted: [1, 3, 5]. Median = 3.
        // Difference = |4-3| = 1.
        //
        // This implies that the students are not necessarily contiguous in the sorted array.
        //
        // The problem is asking for the minimum possible absolute difference.
        //
        // Let the sorted array be $a_0, a_1, \dots, a_{2n-1}$.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // Can we always form two classes of odd sizes, such that $a_{n-1}$ is the median of one and $a_n$ is the median of the other?
        //
        // Let Class 1 have $a_{n-1}$ as its median.
        // Let Class 2 have $a_n$ as its median.
        //
        // To make $a_{n-1}$ the median of Class 1:
        // We need to pick $k_1$ elements from $a_0, \dots, a_{n-2}$ (there are $n-1$ such elements).
        // We need to pick $k_1$ elements from $a_n, \dots, a_{2n-1}$ (there are $n$ such elements).
        // The total size of Class 1 is $2k_1+1$.
        //
        // To make $a_n$ the median of Class 2:
        // We need to pick $k_2$ elements from $a_0, \dots, a_{n-1}$ (there are $n$ such elements).
        // We need to pick $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$ (there are $n-1$ such elements).
        // The total size of Class 2 is $2k_2+1$.
        //
        // We need to ensure that all $2n$ students are used exactly once.
        //
        // Let's try to construct the classes greedily around $a_{n-1}$ and $a_n$.
        //
        // Class 1: $a_{n-1}$ is the median.
        // Take $a_0, \dots, a_{n-2}$ (all $n-1$ elements smaller than $a_{n-1}$).
        // Take $a_{n-1}$.
        // Take $a_n, \dots, a_{2n-1}$ (all $n$ elements larger than or equal to $a_n$).
        // This is not how it works. We need to select elements.
        //
        // The problem is simpler than trying to construct the classes.
        // The minimum difference between medians will always be $a_n - a_{n-1}$
        // (using 0-indexed sorted array $a_0, \dots, a_{2n-1}$).
        //
        // Why?
        // Let $M_1$ and $M_2$ be the medians of the two classes.
        // Suppose $M_1 < M_2$.
        //
        // Class 1 has $S_1 = 2k_1+1$ students. $M_1$ is the $k_1$-th smallest element in Class 1.
        // Class 2 has $S_2 = 2k_2+1$ students. $M_2$ is the $k_2$-th smallest element in Class 2.
        //
        // There are at least $k_1$ students in Class 1 with skill $\le M_1$.
        // There are at least $k_2$ students in Class 2 with skill $\le M_2$.
        //
        // Total students $2n$.
        //
        // Consider the $n$ smallest students in the overall sorted list: $a_0, \dots, a_{n-1}$.
        // Consider the $n$ largest students in the overall sorted list: $a_n, \dots, a_{2n-1}$.
        //
        // At least one of the medians must be $\le a_{n-1}$.
        // Proof by contradiction: Assume both medians $M_1, M_2 > a_{n-1}$.
        // This means $M_1 \ge a_n$ and $M_2 \ge a_n$ (since $a_i$ are integers, and $a_{n-1}$ is the largest element less than $a_n$ if all elements are distinct).
        // If $M_1 \ge a_n$, then Class 1 must contain at least $k_1+1$ elements $\ge a_n$.
        // If $M_2 \ge a_n$, then Class 2 must contain at least $k_2+1$ elements $\ge a_n$.
        // Total elements $\ge a_n$ in both classes is $(k_1+1) + (k_2+1) = k_1+k_2+2$.
        // The total number of elements $\ge a_n$ in the entire set is $n$ (namely $a_n, \dots, a_{2n-1}$).
        // So we must have $k_1+k_2+2 \le n$.
        // Also, $S_1+S_2 = (2k_1+1) + (2k_2+1) = 2k_1+2k_2+2 = 2n$.
        // So $k_1+k_2+1 = n$.
        // This means $k_1+k_2 = n-1$.
        // Substituting this into $k_1+k_2+2 \le n$, we get $(n-1)+2 \le n$, which is $n+1 \le n$. This is a contradiction.
        // Therefore, at least one median must be $\le a_{n-1}$.
        //
        // Similarly, at least one median must be $\ge a_n$.
        // Proof by contradiction: Assume both medians $M_1, M_2 < a_n$.
        // This means $M_1 \le a_{n-1}$ and $M_2 \le a_{n-1}$.
        // If $M_1 \le a_{n-1}$, then Class 1 must contain at least $k_1+1$ elements $\le a_{n-1}$.
        // If $M_2 \le a_{n-1}$, then Class 2 must contain at least $k_2+1$ elements $\le a_{n-1}$.
        // Total elements $\le a_{n-1}$ in both classes is $(k_1+1) + (k_2+1) = k_1+k_2+2$.
        // The total number of elements $\le a_{n-1}$ in the entire set is $n$ (namely $a_0, \dots, a_{n-1}$).
        // So we must have $k_1+k_2+2 \le n$.
        // Again, $k_1+k_2 = n-1$.
        // So $(n-1)+2 \le n$, which is $n+1 \le n$. Contradiction.
        // Therefore, at least one median must be $\ge a_n$.
        //
        // Combining these, one median must be $\le a_{n-1}$ and the other must be $\ge a_n$.
        // Let $M_A \le a_{n-1}$ and $M_B \ge a_n$.
        // Then $|M_A - M_B| = M_B - M_A \ge a_n - a_{n-1}$.
        //
        // So the minimum possible difference is at least $a_n - a_{n-1}$.
        // Can we achieve this difference? Yes.
        //
        // We need to construct two classes of odd sizes $S_1, S_2$ such that $S_1+S_2=2n$,
        // and their medians are $a_{n-1}$ and $a_n$.
        //
        // Let $S_1 = 1$ and $S_2 = 2n-1$.
        // Class 1: $\{a_{n-1}\}$. Median is $a_{n-1}$. (Size 1 is odd).
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$.
        // This class has $n-1 + n = 2n-1$ elements. (Size $2n-1$ is odd).
        // The elements are $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // The median of this class (size $2n-1$) is the $n$-th element (0-indexed).
        // The elements are sorted. The $n$-th element is $a_n$.
        // So, Class 1 median is $a_{n-1}$ and Class 2 median is $a_n$.
        // The difference is $a_n - a_{n-1}$.
        // This construction is always valid.
        //
        // Therefore, the minimum absolute difference is $a_n - a_{n-1}$.

        long long result = a[n] - a[n-1];
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams k must satisfy:
        // 1. k <= c (at least one coder per team)
        // 2. k <= m (at least one mathematician per team)
        // 3. 3k <= c + m + x (total students available)
        // So, k <= min(c, m, (c + m + x) / 3)
        // This upper bound is also sufficient.
        // If we form k teams, we use k coders and k mathematicians.
        // The remaining k spots (3k total members - k coders - k mathematicians)
        // can be filled by the remaining c-k coders, m-k mathematicians, and x no-specialization students.
        // The total number of students available for these k spots is (c-k) + (m-k) + x.
        // We need to ensure (c-k) + (m-k) + x >= k.
        // This simplifies to c + m + x >= 3k.
        // So, if k satisfies k <= c, k <= m, and k <= (c + m + x) / 3,
        // then we have enough coders, enough mathematicians, and enough total students.
        // The minimum of these three values is the maximum possible k.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

