    int left = 1;
    int right = k + 1; // The largest number we will use in the alternating sequence to generate k distinct differences.
                       // The differences will be (k+1)-1, (k+1)-2, ..., 1.
                       // So, k+1 is the upper bound for the first k+1 numbers.

    for (int i = 0; i < k + 1; ++i) {
