#include <iostream>
#include <string>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0) {
            // Only add ')' if it can be matched with an existing '(' in the result
            // and we still need closing brackets.
            // The condition `result.length() - (k/2 - open_needed) > 0`
            // checks if the number of '(' in `result` is greater than the number of ')'
            // already added to `result`.
            // `result.length()` is the current length of `result`.
            // `k/2 - open_needed` is the number of '(' already added to `result`.
            // `result.length() - (k/2 - open_needed)` is the number of ')' already added to `result`.
            // So, we need `(k/2 - open_needed) > (result.length() - (k/2 - open_needed))`
            // which simplifies to `2 * (k/2 - open_needed) > result.length()`.
            // Or, more simply, the number of open brackets in `result` must be greater than the number of close brackets.
            // The number of open brackets in `result` is `k/2 - open_needed`.
            // The number of close brackets in `result` is `result.length() - (k/2 - open_needed)`.
            if ((k / 2 - open_needed) > (result.length() - (k / 2 - open_needed))) {
                result += ')';
                close_needed--;
            }
        }
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long k_max = n / m;

        // Precompute the sum of last digits for one cycle (10 multiples of m)
        // The last digits of k*m repeat every 10 values of k.
        // E.g., last digits of m, 2m, ..., 10m are the same as 11m, 12m, ..., 20m.
        // This is because (k*m)%10 depends on (k%10) and (m%10).
        // So, (k*m)%10 = ((k%10)*(m%10))%10.
        // When k goes from 1 to 10, k%10 goes from 1 to 0 (for k=10).
        // When k goes from 11 to 20, k%10 also goes from 1 to 0.
        std::vector<long long> cycle_last_digits_sum(10);
        for (int i = 1; i <= 10; ++i) {
            cycle_last_digits_sum[i - 1] = (static_cast<long long>(i) * m) % 10;
        }
        long long sum_one_cycle = 0;
        for (long long digit : cycle_last_digits_sum) {
            sum_one_cycle += digit;
        }

        // Calculate how many full cycles of 10 multiples are there
        long long num_full_cycles = k_max / 10;
        long long total_sum = num_full_cycles * sum_one_cycle;

        // Add the sum of remaining multiples
        long long remaining_multiples = k_max % 10;
        for (int i = 0; i < remaining_multiples; ++i) {
            total_sum += cycle_last_digits_sum[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // Update current_min_idx and current_max_idx to include the element 'm'
        // This ensures that the range [current_min_idx, current_max_idx]
        // covers all elements from 1 to m.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // For 'm' to be beautiful, the subarray p[current_min_idx ... current_max_idx]
        // must be a permutation of 1, ..., m.
        // This means its length must be exactly 'm'.
        // The length of the subarray is (current_max_idx - current_min_idx + 1).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

