int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
            continue;
        }

        // For a and b to be real, discriminant d^2 - 4d must be non-negative.
        // d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d >= 0, this implies d - 4 >= 0, so d >= 4.
        // If d < 4 (and d > 0), there are no real solutions.
        if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            // The problem statement implies d is an integer, but calculations are real.
            // Due to floating point precision, discriminant might be slightly negative
            // even if mathematically it should be zero or positive.
            // For example, if d=4, d*d - 4*d should be 0.
            // But if d=4.0, d*d - 4.0*d could be -1e-15.
            // We should ensure discriminant is non-negative for sqrt.
            // However, the condition d < 4.0 already handles the case where it's
            // significantly negative. For d >= 4.0, it should be non-negative.
            // If d is exactly 4, discriminant is 0.
            // If d is slightly more than 4, discriminant is positive.
            // So, no need to clamp discriminant to 0.0.

            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // We need a and b to be non-negative.
            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d^2 - 4d).
            // Since d >= 4, d^2 >= 4d, so d^2 - 4d >= 0.
