        // If A+B is odd, and A+D == 0, then A=0, D=0. So all toys are in B or C.
        // If all toys are in B or C, then the product will always be in (-1,0).
        // So, if A+D > 0, ans1 = "Ya".
        if (A > 0 || D > 0) {
            ans1 = "Ya";
        }

        // Can it be in Box 2 (-1, 0)?
        // To get (-1, 0), we need to be able to make a product P such that -1 < P < 0.
        // This is possible if we have at least one toy in Box 2 or Box 3.
        // If B+C > 0, we can make a product in (-1,0).
        // If B+C == 0, then all toys are in A or D.
        // If A+B is odd, and B+C == 0, then B=0, C=0. So all toys are in A or D.
        // If A+B is odd, then A must be odd.
        // If A is odd, and all toys are in A or D.
