        // If B+C == 0, then A must be odd. If A > 0, we can make a product in (-1,0) by picking values like -0.5, 2.
        // If A == 0 and B+C == 0, then D must be > 0. But A+B is odd, so A must be odd. This case is impossible.
        // So, if A+B is odd, and total_toys > 0, we can always make a product in (-1,0).
        ans2 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

