#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_ops
    // prefix_min_ops[i] stores the minimum value a[i] must have
    // to satisfy a[0] < a[1] < ... < a[i]
    // Specifically, a[i] must be at least i.
    // So, a[i] - i must be non-negative.
    // If a[i] < i, it's impossible to make a[i] >= i.
    // We can achieve a[i] = i by decreasing a[i] by a[i]-i.
    // The actual value of a[i] after operations must be at least i.
    // So, a[i] (original) must be at least i.
    // If a[i] < i for any i, then it's impossible to form the strictly increasing prefix up to a[i].
    // This is because a[0] >= 0, a[1] >= 1, ..., a[i] >= i.
    // So, we need a[i] >= i for all i in the increasing part.
    // The first element a[0] must be at least 0.
    // The second element a[1] must be at least 1.
    // The i-th element a[i] must be at least i.
    // So, for the prefix a_0, ..., a_k, we need a_i >= i for all 0 <= i <= k.
    // This means a_i - i >= 0.
    // The maximum possible k for the increasing part is the largest k such that a_i >= i for all 0 <= i <= k.

    int max_k_prefix = -1; // Stores the largest index i such that a[0]...a[i] can be made strictly increasing
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            break;
        }
        max_k_prefix = i;
    }

    // Calculate suffix_min_ops
    // suffix_min_ops[i] stores the minimum value a[i] must have
    // to satisfy a[i] > a[i+1] > ... > a[n-1]
    // Specifically, a[i] must be at least n-1-i.
    // So, a[i] - (n-1-i) must be non-negative.
    // If a[i] < n-1-i, it's impossible to make a[i] >= n-1-i.
    // We can achieve a[i] = n-1-i by decreasing a[i] by a[i]-(n-1-i).
    // The actual value of a[i] after operations must be at least n-1-i.
    // So, a[i] (original) must be at least n-1-i.
    // If a[i] < n-1-i for any i, then it's impossible to form the strictly decreasing suffix from a[i].
    // This is because a[n-1] >= 0, a[n-2] >= 1, ..., a[i] >= n-1-i.
    // So, we need a[i] >= n-1-i for all i in the decreasing part.
    // The minimum possible k for the decreasing part is the smallest k such that a[k]...a[n-1] can be made strictly decreasing.

    int min_k_suffix = n; // Stores the smallest index i such that a[i]...a[n-1] can be made strictly decreasing
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            break;
        }
        min_k_suffix = i;
    }

    // A sharpened array requires a peak at index k.
    // The prefix a[0]...a[k] must be strictly increasing.
    // The suffix a[k]...a[n-1] must be strictly decreasing.
    // This means k must be a valid index for both conditions.
    // So, we need to find if there exists a k such that:
    // 1. a[0]...a[k] can be made strictly increasing (i.e., k <= max_k_prefix)
    // 2. a[k]...a[n-1] can be made strictly decreasing (i.e., k >= min_k_suffix)
    // If such a k exists, then max_k_prefix >= min_k_suffix.
    // If max_k_prefix >= min_k_suffix, then any k in [min_k_suffix, max_k_prefix] can be the peak.
    // For example, if k = min_k_suffix, then a[0]...a[min_k_suffix] can be made increasing,
    // and a[min_k_suffix]...a[n-1] can be made decreasing.
    // The condition for a peak at index k is that a[k] must be at least k AND a[k] must be at least n-1-k.
    // This is implicitly handled by max_k_prefix and min_k_suffix.
    // If max_k_prefix >= min_k_suffix, then there is at least one index k that satisfies both conditions.
    // For example, k = min_k_suffix.
    // For this k, a[min_k_suffix] >= min_k_suffix (from prefix condition)
    // and a[min_k_suffix] >= n-1-min_k_suffix (from suffix condition).
    // So, a[min_k_suffix] can be set to max(min_k_suffix, n-1-min_k_suffix) and still satisfy both.
    // The existence of such a k is sufficient.

    if (max_k_prefix >= min_k_suffix) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

