void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `idx_non_inc` such that the suffix `a[idx_non_inc...n-1]` is non-increasing.
    // This means `a[idx_non_inc] >= a[idx_non_inc+1] >= ... >= a[n-1]`.
    // We start from `n-1` and move left as long as the non-increasing property holds.
    int idx_non_inc = n - 1;
    while (idx_non_inc > 0 && a[idx_non_inc - 1] >= a[idx_non_inc]) {
        idx_non_inc--;
    }

    // At this point, `a[idx_non_inc...n-1]` is non-increasing.
    // If `idx_non_inc > 0`, then `a[idx_non_inc-1] < a[idx_non_inc]`.
    // This `idx_non_inc` marks the potential "peak" or the start of the non-increasing part of the mountain.

    // Now, find the rightmost index `idx_non_dec` such that the subarray `a[idx_non_dec...idx_non_inc]` is non-decreasing.
    // This means `a[idx_non_dec] <= a[idx_non_dec+1] <= ... <= a[idx_non_inc]`.
    // We start from `idx_non_inc` and move left as long as the non-decreasing property holds.
    int idx_non_dec = idx_non_inc;
    while (idx_non_dec > 0 && a[idx_non_dec - 1] <= a[idx_non_dec]) {
        idx_non_dec--;
    }

    // The subarray `a[idx_non_dec...n-1]` now forms a "mountain" shape:
    // `a[idx_non_dec] <= ... <= a[idx_non_inc]` (non-decreasing part)
    // `a[idx_non_inc] >= ... >= a[n-1]` (non-increasing part)
    // This subarray `a[idx_non_dec...n-1]` is a "good" array.
    // The elements `a[0...idx_non_dec-1]` are the prefix that needs to be removed.
    // The length of this prefix is `idx_non_dec`.
    std::cout << idx_non_dec << std::endl;
}

