    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for elements to be placed (larger elements)
    for (int i = 0; i < n; ++i) { // Pointer for original positions (smaller elements)
        // We are trying to find an element a[j] such that a[j] > a[i]
        // and a[j] has not been used yet.
        // Since both arrays are sorted, if a[j] > a[i], then any a[k] with k > j
        // will also be >= a[j], and thus potentially > a[i].
        // We want to use the smallest possible a[j] that is greater than a[i]
        // to save larger elements for later, potentially larger a[i]'s.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] > a[i]
            count++;
            j++; // Move to the next element in the 'larger' pool
        } else {
            // No more elements in 'larger' pool are greater than a[i]
            // Since a is sorted, no subsequent a[k] (k > i) will find a match either.
            break;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
