struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b.begin(), b.end());

    // Create a map to store the counts of each B value
    // This is effectively a frequency map for B values
    std::map<long long, int> b_counts;
    for (long long val : b) {
        b_counts[val]++;
    }

    // Create a vector of pairs (B_value, count) sorted by B_value
    std::vector<std::pair<long long, int>> sorted_b_counts;
    for (auto const& [val, count] : b_counts) {
        sorted_b_counts.push_back({val, count});
    }

    // The final rearranged array A'
    std::vector<long long> a_prime(m);

    // Pointers for a_elements (sorted A) and sorted_b_counts
    int a_ptr = m - 1; // Start from largest A
    int b_type_ptr = sorted_b_counts.size() - 1; // Start from largest B type

    // Fill a_prime from right to left (largest A values first)
    while (a_ptr >= 0) {
        long long current_b_val = sorted_b_counts[b_type_ptr].first;
        int count_for_current_b = sorted_b_counts[b_type_ptr].second;

        // Assign 'count_for_current_b' largest remaining A values
        // to the positions corresponding to 'current_b_val'
        for (int i = 0; i < count_for_current_b; ++i) {
            a_prime[a_elements[a_ptr].original_index] = a_elements[a_ptr].value;
            a_ptr--;
        }
        b_type_ptr--;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

