#include <numeric>
#include <algorithm>

// Function to check if a prefix a[0...len-1] is a permutation of length len
bool is_prefix_permutation(int len, const std::vector<int>& a, const std::vector<int>& prefix_max_val, const std::vector<int>& prefix_counts) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (prefix_max_val[len - 1] != len) return false; // Max element must be len
    // Check if all counts are 1 up to len. This is implicitly handled by prefix_max_val and prefix_counts.
    // If prefix_max_val[len-1] == len, it means all elements from 1 to len are present at least once.
    // If prefix_counts[len-1] == len, it means there are no duplicates and no missing elements.
    // So, we just need to check prefix_max_val[len-1] == len and prefix_counts[len-1] == len.
    // The prefix_counts[len-1] == len check is actually redundant if prefix_max_val[len-1] == len
    // and we know that all elements are <= len.
    // Let's re-evaluate.
    // prefix_max_val[len-1] == len means the maximum value in a[0...len-1] is len.
    // prefix_counts[len-1] == len means there are 'len' distinct values in a[0...len-1].
    // If max value is len, and there are len distinct values, and all values are positive,
    // then these distinct values must be 1, 2, ..., len.
    // So, these two conditions together are sufficient.
    return prefix_max_val[len - 1] == len && prefix_counts[len - 1] == len;
}

// Function to check if a suffix a[start_idx...n-1] is a permutation of length len
bool is_suffix_permutation(int start_idx, int len, const std::vector<int>& a, const std::vector<int>& suffix_max_val, const std::vector<int>& suffix_counts) {
    if (len == 0) return false; // Permutation length must be non-zero
    int n = a.size();
    if (suffix_max_val[start_idx] != len) return false; // Max element must be len
    // Similar logic as prefix:
    // suffix_max_val[start_idx] == len means max value in a[start_idx...n-1] is len.
    // suffix_counts[start_idx] == len means there are 'len' distinct values in a[start_idx...n-1].
    // Together, these imply it's a permutation of length len.
    return suffix_max_val[start_idx] == len && suffix_counts[start_idx] == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix maximums and distinct counts
    std::vector<int> prefix_max_val(n);
    std::vector<int> prefix_counts(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max value can be n, so size n+1
    int current_max = 0;
    int distinct_count = 0;
    for (int i = 0; i < n; ++i) {
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            distinct_count++;
        }
        current_max = std::max(current_max, a[i]);
        prefix_max_val[i] = current_max;
        prefix_counts[i] = distinct_count;
    }

    // Precompute suffix maximums and distinct counts
    std::vector<int> suffix_max_val(n);
    std::vector<int> suffix_counts(n);
    std::vector<bool> seen_suffix(n + 1, false); // Max value can be n, so size n+1
    current_max = 0;
    distinct_count = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (!seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            distinct_count++;
        }
        current_max = std::max(current_max, a[i]);
        suffix_max_val[i] = current_max;
        suffix_counts[i] = distinct_count;
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 is the length of the first permutation p1.
    // l2 = n - l1 is the length of the second permutation p2.
    // Both l1 and l2 must be non-zero, so l1 ranges from 1 to n-1.
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if a[0...l1-1] is a permutation of length l1
        bool p1_is_perm = is_prefix_permutation(l1, a, prefix_max_val, prefix_counts);

        // Check if a[l1...n-1] is a permutation of length l2
        bool p2_is_perm = is_suffix_permutation(l1, l2, a, suffix_max_val, suffix_counts);

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

