}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need S' = 2 * X'
    // Let S' = current_sum + b1 + b2 + ...
    // Let X' = current_xor_sum ^ b1 ^ b2 ^ ...

    // Case 1: Array is already good.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
        return;
    }

    // Case 2: Append two elements.
    // We want to find b1, b2 such that:
    // current_sum + b1 + b2 = 2 * (current_xor_sum ^ b1 ^ b2)
    // Let b1 = current_xor_sum.
    // Then current_xor_sum ^ b1 = current_xor_sum ^ current_xor_sum = 0.
    // The equation becomes:
    // current_sum + current_xor_sum + b2 = 2 * (0 ^ b2)
    // current_sum + current_xor_sum + b2 = 2 * b2
    // current_sum + current_xor_sum = b2
    // So, b2 = current_sum + current_xor_sum.

    // Let's verify this.
    // Appended elements: b1 = current_xor_sum, b2 = current_sum + current_xor_sum.
    // New sum S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    // S' = 2 * current_sum + 2 * current_xor_sum.
    // New XOR sum X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    // X' = 0 ^ (current_sum + current_xor_sum)
    // X' = current_sum + current_xor_sum.
    // We need S' = 2 * X'.
    // (2 * current_sum + 2 * current_xor_sum) = 2 * (current_sum + current_xor_sum).
    // This is true.

    // The problem states we can append AT MOST 3 elements.
    // This strategy appends 2 elements.
    // The values can be large, up to 10^9 for initial elements.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
    // b2 = current_sum + current_xor_sum can be up to 10^14 + 10^9, which is within 10^18.
    // So this solution is valid.

    std::cout << 2 << "\n";
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
}

