#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long current_a_count = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it can be combined with any 'a's to its left.
            // These 'a's are represented by current_a_count.
            // Each 'a' to its left will eventually "jump over" this 'b'.
            // When an 'a' jumps over a 'b', it effectively becomes 'ba' and adds 1 to total_steps.
            // The 'a' then becomes 'a' again, but it's now to the right of the 'b'.
            // The 'b' effectively doubles the number of 'a's that can jump over subsequent 'b's.
            // So, current_a_count doubles.
            current_a_count = (current_a_count * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it will eventually jump over all 'b's to its right.
            // The number of 'b's it needs to jump over is current_a_count.
            // Each jump costs 1 step.
            total_steps = (total_steps + current_a_count) % MOD;
            // After jumping over all 'b's to its right, this 'a' itself becomes available
            // to be jumped over by 'b's to its left (which we haven't processed yet).
            // So, we increment current_a_count.
            current_a_count = (current_a_count + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

