void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w_cand(n, '1'); // Initialize w_cand with all '1's

    // Step 1: Determine necessary '0's in w_cand based on s_i = '0'
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s_i is '0', then w_{i-x} (if exists) must be '0'
            if (i - x >= 0) {
                w_cand[i - x] = '0';
            }
            // And w_{i+x} (if exists) must be '0'
            if (i + x < n) {
                w_cand[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if w_cand can produce s
    // Construct s_check based on w_cand and x
    std::string s_check(n, '0');
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        // Check w_{i-x}
        if (i - x >= 0 && w_cand[i - x] == '1') {
            is_one = true;
        }
        // Check w_{i+x}
        if (i + x < n && w_cand[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_check[i] = '1';
        }
    }

    // Compare s_check with the given s
    if (s_check == s) {
        std::cout << w_cand << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

