#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left side
    // Let 'i' be the number of items taken from the left (0 <= i <= n)
    // Then 'n-i' items are taken from the right side
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        // These are w[0]...w[i-1]
        current_energy += (prefix_sum[i] - prefix_sum[0]) * l;

        // Energy for items taken from the right
        // These are w[n-(n-i)]...w[n-1]
        // Which means w[i]...w[n-1] if i items are taken from left
        // No, this is wrong. If i items are taken from left, then n-i items are taken from right.
        // The items taken from right are w[n-1], w[n-2], ..., w[n-(n-i)]
        // The sum of these weights is (prefix_sum[n] - prefix_sum[n-(n-i)])
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalties
        int num_left = i;
        int num_right = n - i;

        if (num_left > num_right) {
            // More items taken from left. The last item must have been from left.
            // The difference is num_left - num_right.
            // If num_left = num_right + 1, no penalty.
            // If num_left = num_right + 2, one extra left item, penalty Ql.
            // If num_left = num_right + k, k-1 extra left items, penalty (k-1)*Ql.
            current_energy += (long long)(num_left - num_right - 1) * Ql;
        } else if (num_right > num_left) {
            // More items taken from right. The last item must have been from right.
            // The difference is num_right - num_left.
            // If num_right = num_left + 1, no penalty.
            // If num_right = num_left + 2, one extra right item, penalty Qr.
            // If num_right = num_left + k, k-1 extra right items, penalty (k-1)*Qr.
            current_energy += (long long)(num_right - num_left - 1) * Qr;
        }
        // If num_left == num_right, no penalty.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

