// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // If x is divisible by q, then x must have at least a_i factors of f_i for all i.
        // We want to remove just enough factors from p to make it not divisible by q,
        // while keeping the resulting number as large as possible.
        // This means for each prime factor f_i of q, we try to remove all occurrences of f_i from p
        // until p is no longer divisible by q.
        // The candidate x values will be p / f_i^k for some k, where f_i is a prime factor of q.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 1;

        for (long long factor : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by 'factor' until it's no longer divisible by q.
            // This means current_p / factor^k such that (current_p / factor^k) % q != 0.
            // We want to find the largest such current_p / factor^k.
            // This is equivalent to finding the smallest k such that (p / factor^k) % q != 0.
            // And then taking p / factor^k.
            // To maximize p / factor^k, we need to minimize k.
            // The smallest k is such that p / factor^k is not divisible by q.
            // This means we divide p by factor until the condition (p / factor^k) % q != 0 is met.
            // But we need to be careful. If we divide p by factor, it might still be divisible by q.
            // We need to divide p by factor until the exponent of 'factor' in p is less than
            // the exponent of 'factor' in q.
            // Or more simply, we divide p by 'factor' until (p / factor^k) % q != 0.
            // We want to find the largest divisor of p that is not divisible by q.
            // Let's iterate through all prime factors of q.
            // For each prime factor `f` of `q`:
            //   Calculate `p_temp = p`.
            //   While `p_temp` is divisible by `q`:
            //     `p_temp /= f`.
            //   `max_x = std::max(max_x, p_temp)`.

            long long temp_p = p;
            while (temp_p % q == 0) {
                temp_p /= factor;
            }
            max_x = std::max(max_x, temp_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;

    while (n > 0) {
        // Chanek's turn
        if (n == 1) {
            chanek_coins += 1;
            n -= 1;
        } else if (n == 2) {
            chanek_coins += 1; // Take 1, opponent takes 1. Chanek gets 1.
            n -= 1;
        } else if (n == 3) {
            chanek_coins += 1; // Take 1, opponent takes 1, Chanek takes 1. Chanek gets 2.
            n -= 1;
        } else if (n % 2 == 1) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            // Option 1: Take 1 coin
            // Chanek gets 1. Remaining N-1. Opponent's turn.
            // Opponent will face N-1 (odd). Opponent takes 1. Remaining N-2. Chanek's turn.
            // Chanek will face N-2 (even).
            // If N-2 is 0, Chanek gets 0.
            // If N-2 is 2, Chanek takes 1.
            // If N-2 is 4, Chanek takes 2.
            // If N-2 is 6, Chanek takes 3.
            // This path seems to lead to Chanek getting 1 + (N-2)/2 coins from the remaining N-2.
            // Total for Chanek: 1 + (N-2)/2.
            // Total for Opponent: 1.

            // Option 2: Take N/2 coins
            // Chanek gets N/2. Remaining N/2. Opponent's turn.
            // Opponent will face N/2.
            // If N/2 is odd, opponent takes 1. Remaining N/2-1. Chanek's turn.
            // If N/2 is even, opponent takes N/4. Remaining N/4. Chanek's turn.

            // Let's analyze the opponent's optimal play after Chanek takes N/2.
            // If N/2 is odd, opponent takes 1. Chanek gets N/2. Opponent gets 1.
            // If N/2 is even, opponent takes N/4. Chanek gets N/2. Opponent gets N/4.

            // The strategy is to take N/2 if it leads to a better outcome for Chanek.
            // When N is even, Chanek has two choices:
            // 1. Take 1: Chanek gets 1. N becomes N-1. Opponent's turn.
            //    Opponent faces N-1 (odd). Opponent takes 1. N becomes N-2. Chanek's turn.
            //    Chanek gets 1. Opponent gets 1.
            // 2. Take N/2: Chanek gets N/2. N becomes N/2. Opponent's turn.
            //    Opponent faces N/2.
            //    If N/2 is odd: Opponent takes 1. N becomes N/2-1. Chanek's turn.
            //    Chanek gets N/2. Opponent gets 1.
            //    If N/2 is even: Opponent takes N/4. N becomes N/4. Chanek's turn.
            //    Chanek gets N/2. Opponent gets N/4.

            // The key insight is that if N is even, and N/2 is odd, Chanek should take N/2.
            // Because then Chanek gets N/2, and opponent gets only 1.
            // If Chanek takes 1, Chanek gets 1, opponent gets 1.
            // N/2 vs 1. N/2 is better for Chanek if N/2 > 1, i.e., N > 2.
            // If N=2, N/2=1. Take 1. Chanek gets 1.
