    // Modular inverse of 2 modulo 10^9+7 is (10^9+7 + 1) / 2 = 10^9+8 / 2 = 500000004.
    long long inv2 = 500000004;

    long long sum_r_term = (b - 1);
    if (sum_r_term < 0) sum_r_term = 0; // If b=1, then b-1=0, sum is 0.

    sum_r_term = (sum_r_term % MOD * (b % MOD)) % MOD;
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // This is sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a+1) / 2) + a
    long long sum_k_part1 = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_part1 = (sum_k_part1 * inv2) % MOD;
    sum_k_part1 = (sum_k_part1 * (b % MOD)) % MOD;

    long long sum_k_part2 = a % MOD;

    long long sum_k_term = (sum_k_part1 + sum_k_part2) % MOD;

    // Total sum = (sum_k_term * sum_r_term) % MOD
    long long total_sum = (sum_k_term * sum_r_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <map>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_path;
    char start_char = '\0';

    // Find a starting character for a path (degree 1 or 0)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c) && adj[c].size() <= 1) {
            start_char = c;
            break;
        }
    }
    // If all characters in adj have degree 2, it means they form a cycle.
    // This is impossible for a linear keyboard.
    // However, the problem constraints (at most 2 neighbors) already handle this.
    // If all chars in adj have degree 2, it means they form a single path or multiple paths/cycles.
    // If it's a single path, any end can be a start. If it's a cycle, it's impossible.
    // But we already checked for >2 neighbors.
    // If all chars in adj have degree 2, and it's a valid path, it means it's a path of length 26.
    // This is not necessarily true. It could be a path of length < 26 where all internal nodes have degree 2.
    // Example: "abcde". a,e degree 1. b,c,d degree 2.
    // If all chars in adj have degree 2, it means it's a cycle.
    // A cycle is impossible on a linear keyboard.
    // So, if start_char is still '\0', it means all characters in `adj` have degree 2.
    // This implies a cycle, which is impossible.
    // Example: "abacaba" -> a-b, a-c. a has degree 2. b,c have degree 1.
    // Example: "abcde" -> a-b, b-c, c-d, d-e. a,e degree 1. b,c,d degree 2.
    // Example: "abac" -> a-b, a-c. a degree 2. b,c degree 1.
    // The only case where start_char would be '\0' is if adj is empty (s.length() == 1)
    // or if all characters in adj have degree 2.
    // If s.length() == 1, adj is empty. start_char remains '\0'.
    // In this case, we can just print "abcdef...".
    // If all characters in adj have degree 2, it means they form a cycle.
    // A cycle is impossible on a linear keyboard.
    // So, if start_char is '\0' and adj is not empty, it's impossible.
    // Let's refine: if adj is empty, start_char remains '\0'.
    // If adj is not empty, but start_char is '\0', it means all nodes in adj have degree 2.
    // This implies a cycle, which is impossible.
    // So, if adj is not empty and start_char is '\0', it's "NO".

    if (adj.empty()) { // s has length 1
        layout_str += s[0];
        visited_in_path.insert(s[0]);
    } else {
        if (start_char == '\0') { // All characters in adj have degree 2, implies a cycle
            std::cout << "NO\n";
            return;
        }

        char current_char = start_char;
        while (current_char != '\0') {
            layout_str += current_char;
            visited_in_path.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (visited_in_path.find(neighbor) == visited_in_path.end()) {
                    next_char = neighbor;
                    break;
                }
            }
            current_char = next_char;
        }
    }

    // Add remaining characters not in the path
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_path.find(c) == visited_in_path.end()) {
            layout_str += c;
        }
    }

    // Check if all characters from 's' are present in the constructed path
    // This implicitly checks for disconnected components in the required adjacencies.
    // If there are multiple disconnected components, it's impossible.
    // Example: s = "ab", then s' = "cd". This would require a-b and c-d.
    // But a-b and c-d cannot be simultaneously satisfied on a single linear keyboard
    // unless they are part of the same path.
    // The current algorithm constructs one path. If there are other required adjacencies
    // not part of this path, they won't be satisfied.
    // This is implicitly handled by checking if all characters in `adj` are visited.
    // If `adj` contains characters not in `visited_in_path`, it means there's a disconnected component.
    // This would mean `start_char` would not be able to reach all required characters.
    // The `current_char != '\0'` loop ensures we follow one connected component.
    // If `adj` has multiple connected components, then `start_char` would only be able to start one.
    // The other components would not be visited.
    // So, we need to check if all characters that *must* be adjacent are part of the constructed path.
    // This is equivalent to checking if all characters in `adj` are in `visited_in_path`.
    // More precisely, if `adj` has multiple connected components, it's impossible.
    // The current path construction only builds one component.
    // If `adj` is not empty, and `start_char` was found, we built a path.
    // We need to ensure that this path covers all characters that have required adjacencies.
    // If `adj` has multiple connected components, then after building one path,
    // there would still be characters in `adj` that are not in `visited_in_path`.
    // Let's check this.
    for (const auto& pair : adj) {
        if (visited_in_path.find(pair.first) == visited_in_path.end()) {
            std::cout << "NO\n";
            return;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

