#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> next_char_pos(L, std::vector<int>(26, L));
    for (int i = L - 1; i >= 0; --i) {
        if (i + 1 < L) {
            next_char_pos[i] = next_char_pos[i + 1];
        }
        next_char_pos[i][s[i] - 'a'] = i;
    }

    double total_prob = 0.0;

    for (int k_true = 0; k_true < L; ++k_true) {
        char first_char_val = s[k_true];

        std::vector<int> possible_k_after_first_char;
        for (int k_cand = 0; k_cand < L; ++k_cand) {
            if (s[k_cand] == first_char_val) {
                possible_k_after_first_char.push_back(k_cand);
            }
        }

        if (possible_k_after_first_char.size() == 1) {
            total_prob += 1.0; // k is uniquely determined
            continue;
        }

        // Vasya needs to choose an optimal p
        // For a fixed k_true, and fixed first_char_val, Vasya wants to choose p
        // that maximizes the probability of winning among the remaining candidates.
        // This is equivalent to choosing p that maximizes the number of candidates
        // that are uniquely determined by t[p].

        int max_wins_for_this_k_true = 0;

        // Iterate over all possible p values
        for (int p = 1; p < L; ++p) { // p cannot be 0, as t[0] is already known
            char second_char_val = s[(k_true + p) % L];

            int wins_for_this_p = 0;

            // Group candidates by their t[p] value
            std::map<char, std::vector<int>> groups_by_second_char;
            for (int k_cand : possible_k_after_first_char) {
                groups_by_second_char[s[(k_cand + p) % L]].push_back(k_cand);
            }

            // Count how many candidates would be uniquely determined
            for (const auto& pair : groups_by_second_char) {
                if (pair.second.size() == 1) {
                    wins_for_this_p++;
                }
            }
            max_wins_for_this_k_true = std::max(max_wins_for_this_k_true, wins_for_this_p);
        }
        total_prob += (double)max_wins_for_this_k_true / possible_k_after_first_char.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_prob / L << std::endl;

    return 0;
}

