#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    // Calculate prefix sums for differences (1 for strawberry, -1 for blueberry)
    // For left part (indices 0 to n-1), prefix sums from left to right
    // For right part (indices n to 2n-1), prefix sums from right to left

    // Left part: a[0]...a[n-1]
    // diff_L[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // k jars removed from left means jars a[0]...a[k-1] are removed.
    // The remaining jars on the left are a[k]...a[n-1].
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Right part: a[n]...a[2n-1]
    // diff_R[k] = (count of 1s in a[2n-1]...a[2n-k]) - (count of 2s in a[2n-1]...a[2n-k])
    // k jars removed from right means jars a[2n-k]...a[2n-1] are removed.
    // The remaining jars on the right are a[n]...a[2n-k-1].
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars removed from the left
    // to achieve a certain difference in the remaining left segment.
    // key: difference, value: number of jars removed from left
    std::map<int, int> left_diff_to_removed_count;

    // Iterate through all possible numbers of jars removed from the left (0 to n)
    // Let k be the number of jars removed from the left.
    // The jars a[0]...a[k-1] are removed.
    // The remaining jars on the left are a[k]...a[n-1].
    // The difference for these remaining jars is diff_L[n] - diff_L[k].
    // The number of jars removed is k.
    for (int k = 0; k <= n; ++k) {
        int current_left_diff = diff_L[n] - diff_L[k];
        if (left_diff_to_removed_count.find(current_left_diff) == left_diff_to_removed_count.end()) {
            left_diff_to_removed_count[current_left_diff] = k;
        } else {
            left_diff_to_removed_count[current_left_diff] = std::min(left_diff_to_removed_count[current_left_diff], k);
        }
    }

    int min_total_removed = 2 * n; // Initialize with max possible removals

    // Iterate through all possible numbers of jars removed from the right (0 to n)
    // Let k be the number of jars removed from the right.
    // The jars a[2n-k]...a[2n-1] are removed.
    // The remaining jars on the right are a[n]...a[2n-k-1].
    // The difference for these remaining jars is diff_R[n] - diff_R[k].
    // Note: diff_R is calculated from right to left.
    // So, diff_R[k] is the difference of the k jars removed from the right.
    // The total difference of all jars on the right (a[n]...a[2n-1]) is diff_R[n].
    // The difference of the remaining jars on the right is diff_R[n] - diff_R[k].
    for (int k = 0; k <= n; ++k) {
        int current_right_diff = diff_R[n] - diff_R[k];
        // We need (remaining_left_s - remaining_left_b) + (remaining_right_s - remaining_right_b) = 0
        // So, remaining_left_diff + remaining_right_diff = 0
        // This means remaining_left_diff = -remaining_right_diff
        int target_left_diff = -current_right_diff;

        if (left_diff_to_removed_count.count(target_left_diff)) {
            int removed_from_left = left_diff_to_removed_count[target_left_diff];
            min_total_removed = std::min(min_total_removed, removed_from_left + k);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0-9), track how it transforms an input bit.
    // state[b][0] = final value of bit b if input bit b is 0
    // state[b][1] = final value of bit b if input bit b is 1
    // Initialize: if input bit b is 0, output bit b is 0. If input bit b is 1, output bit b is 1.
    // This means state[b][0] = 0 and state[b][1] = 1 for all b.
    std::vector<std::vector<int>> state(10, std::vector<int>(2));
    for (int b = 0; b < 10; ++b) {
        state[b][0] = 0; // If input bit b is 0, it remains 0 initially
        state[b][1] = 1; // If input bit b is 1, it remains 1 initially
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int b = 0; b < 10; ++b) {
            int x_bit = (x >> b) & 1; // b-th bit of constant x
            if (op_char == '&') {
                state[b][0] &= x_bit;
                state[b][1] &= x_bit;
            } else if (op_char == '|') {
                state[b][0] |= x_bit;
                state[b][1] |= x_bit;
            } else { // op_char == '^'
                state[b][0] ^= x_bit;
                state[b][1] ^= x_bit;
            }
        }
    }

    // Now, for each bit b, we have (state[b][0], state[b][1]).
    // This pair represents the function for bit b:
    // (0,0) -> always 0
    // (0,1) -> identity (input bit)
    // (1,0) -> flip (1 - input bit)
    // (1,1) -> always 1

    // We want to find A, B, C such that:
    // (X & A | B) ^ C is equivalent to the combined operations.
    // Let's determine A, B, C bit by bit.
    // For each bit b:
    // (X_b & A_b | B_b) ^ C_b must be state[b][X_b]

    int final_A = 1023; // Initialize A to all 1s (no effect on & initially)
    int final_B = 0;    // Initialize B to all 0s (no effect on | initially)
    int final_C = 0;    // Initialize C to all 0s (no effect on ^ initially)

    for (int b = 0; b < 10; ++b) {
        int s0 = state[b][0]; // Output bit if input bit is 0
        int s1 = state[b][1]; // Output bit if input bit is 1

        // Case 1: (s0, s1) = (0,0) -> always 0
        // We need (0 & A_b | B_b) ^ C_b = 0  => B_b ^ C_b = 0
        // We need (1 & A_b | B_b) ^ C_b = 0  => (A_b | B_b) ^ C_b = 0
        // From B_b ^ C_b = 0, we have B_b = C_b.
        // Substitute into second: (A_b | B_b) ^ B_b = 0.
        // This implies A_b | B_b = B_b. This is true if A_b = 0.
        // So, if (s0,s1) = (0,0), we need A_b=0, B_b=0, C_b=0.
        // This means final_A's b-th bit must be 0.
        if (s0 == 0 && s1 == 0) {
            final_A &= ~(1 << b); // Set A_b to 0
            // B_b and C_b remain 0 for this bit, which is their initial value.
        }
        // Case 2: (s0, s1) = (0,1) -> identity (input bit)
        // We need (0 & A_b | B_b) ^ C_b = 0  => B_b ^ C_b = 0
        // We need (1 & A_b | B_b) ^ C_b = 1  => (A_b | B_b) ^ C_b = 1
        // From B_b ^ C_b = 0, we have B_b = C_b.
        // Substitute into second: (A_b | B_b) ^ B_b = 1.
        // This implies A_b | B_b = 1 - B_b.
        // If B_b = 0, then A_b | 0 = 1, so A_b = 1.
        // If B_b = 1, then A_b | 1 = 0, which is impossible.
        // So, if (s0,s1) = (0,1), we need A_b=1, B_b=0, C_b=0.
        // This means final_A's b-th bit must be 1 (initial value).
        // B_b and C_b remain 0 for this bit.
        // This is the default state, so no change needed for final_A, final_B, final_C.
        // final_A's b-th bit is 1 by default.
        // final_B's b-th bit is 0 by default.
        // final_C's b-th bit is 0 by default.
        // So, no action needed for this case.

        // Case 3: (s0, s1) = (1,0) -> flip (1 - input bit)
        // We need (0 & A_b | B_b) ^ C_b = 1  => B_b ^ C_b = 1
        // We need (1 & A_b | B_b) ^ C_b = 0  => (A_b | B_b) ^ C_b = 0
        // From B_b ^ C_b = 1, we have B_b = 1 - C_b.
        // Substitute into second: (A_b | B_b) ^ (1 - B_b) = 0.
        // This implies A_b | B_b = 1 - (1 - B_b) = B_b.
        // This is true if A_b = 0.
        // So, if (s0,s1) = (1,0), we need A_b=0, B_b=1, C_b=0.
        // This means final_A's b-th bit must be 0.
        // final_B's b-th bit must be 1.
        // final_C's b-th bit must be 0.
        if (s0 == 1 && s1 == 0) {
            final_A &= ~(1 << b); // Set A_b to 0
            final_B |= (1 << b);  // Set B_b to 1
            // C_b remains 0 for this bit.
        }
        // Case 4: (s0, s1) = (1,1) -> always 1
        // We need (0 & A_b | B_b) ^ C_b = 1  => B_b ^ C_b = 1
        // We need (1 & A_b | B_b) ^ C_b = 1  => (A_b | B_b) ^ C_b = 1
        // From B_b ^ C_b = 1, we have B_b = 1 - C_b.
        // Substitute into second: (A_b | B_b) ^ (1 - B_b) = 1.
        // This implies A_b | B_b = 1 - (1 - B_b) = B_b.
        // This is true if A_b = 0.
        // So, if (s0,s1) = (1,1), we need A_b=0, B_b=1, C_b=1.
        // This means final_A's b-th bit must be 0.
        // final_B's b-th bit must be 1.
        // final_C's b-th bit must be 1.
        if (s0 == 1 && s1 == 1) {
            final_A &= ~(1 << b); // Set A_b to 0
            final_B |= (1 << b);  // Set B_b to 1
            final_C |= (1 << b);  // Set C_b to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_A != 1023) { // If A is not all 1s, we need an AND operation
        result_ops.push_back({'&', final_A});
    }
    if (final_B != 0) { // If B is not all 0s, we need an OR operation
        result_ops.push_back({'|', final_B});
    }
    if (final_C != 0) { // If C is not all 0s, we need an XOR operation
        result_ops.push_back({'^', final_C});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure n <= m for simpler logic, swap if necessary
        if (abs_n > abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: k is less than the minimum number of moves required
        // The minimum number of moves is max(abs_n, abs_m)
        if (k < abs_m) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k and abs_m have different parities
        // If k and abs_m have different parities, we must make an odd number of "wasted" moves.
        // A wasted move is one that doesn't contribute to increasing max(abs_n, abs_m)
        // or one that moves away from the target and then back.
        // For example, (x,y) -> (x+1,y) -> (x,y) takes 2 moves and changes parity of x by 0.
        // (x,y) -> (x+1,y) -> (x+1,y+1) takes 2 moves.
        // (x,y) -> (x+1,y) -> (x+2,y) takes 2 moves.
        //
        // Consider the parity of (k - abs_m).
        // If (k - abs_m) is odd, it means we need to make an odd number of "net" moves that don't
        // contribute to reaching abs_m.
        // Each move changes the parity of x or y or both.
        // A diagonal move changes both x and y parity.
        // A straight move changes one coordinate's parity.
        //
