        prefix_zeros[i + 1] = prefix_zeros[i] + (s[i] == '0');
    }

    // Iterate through all possible right endpoints 'r'
    for (int r = 0; r < n; ++r) {
        // Case 1: Substrings starting with '1'
        // Iterate through possible lengths 'len' for substrings s[l...r]
        // where s[l] == '1'.
        // The maximum possible value for f(s[l...r]) is 2^18 - 1, which is ~2.6e5.
        // Since n <= 2e5, the maximum length we need to check is around 18-20.
        // Let's say MAX_LEN_CHECK = 20 for safety.
        // If len > MAX_LEN_CHECK, then 2^len is much larger than len.
        // For len = 19, 2^19 = 524288. Max n = 2e5.
        // So if len >= 19, f(s[l...r]) will be much larger than len, unless it has many leading zeros.
        // But we are considering s[l] == '1' here.
        // So if s[l] == '1', then f(s[l...r]) >= 2^(len-1).
        // We need 2^(len-1) <= len. This only holds for very small len.
        // For len=1, 2^0=1. For len=2, 2^1=2. For len=3, 2^2=4 > 3.
        // So for s[l] == '1', we only need to check len=1 and len=2.
        // For len=1: s[r...r] = "1". f("1") = 1. Length = 1. Good.
        // For len=2: s[r-1...r] = "10". f("10") = 2. Length = 2. Good.
        //            s[r-1...r] = "11". f("11") = 3. Length = 2. Not good.
        // So for s[l] == '1', we only need to check a small window.
        // Let's check up to a length that makes f(s[l...r]) potentially equal to len.
        // Max value of len is N. Max value of f(s[l...r]) is 2^N.
        // We need len = f(s[l...r]).
        // If s[l] == '1', then f(s[l...r]) >= 2^(len-1).
        // We need 2^(len-1) <= len. This is only true for len=1 (1=1) and len=2 (2=2).
        // For len=3, 2^2=4 > 3. For len=4, 2^3=8 > 4.
        // So for substrings starting with '1', we only need to check len=1 and len=2.
        // This is incorrect. The value f(s[l...r]) can be small if the substring is short.
        // Example: s = "1011".
        // r=0, s[0]='1'. l=0. s[0...0]="1". len=1, f("1")=1. Good.
        // r=1, s[1]='0'.
        // r=2, s[2]='1'. l=2. s[2...2]="1". len=1, f("1")=1. Good.
        // r=3, s[3]='1'. l=3. s[3...3]="1". len=1, f("1")=1. Good.
        // r=1, s[1]='0'.
        // r=2, s[2]='1'.
        // r=3, s[3]='1'.
        // s[0...1]="10". len=2, f("10")=2. Good.
        // s[2...3]="11". len=2, f("11")=3. Not good.
        // s[0...2]="101". len=3, f("101")=5. Not good.
        // s[1...3]="011". len=3, f("011")=3. Good.

        // The maximum length of a substring we need to consider is limited.
        // If len = r - l + 1, and val = f(s[l...r]).
        // We need len = val.
        // If s[l] == '1', then val >= 2^(len-1).
        // If len >= 20, then 2^(len-1) >= 2^19 = 524288.
        // But len <= N <= 2e5. So if len >= 20, 2^(len-1) > N >= len.
        // Thus, if s[l] == '1', we only need to check len up to ~19.
        // Let's use a constant `MAX_BITS_TO_CHECK` for this.
        // A safe upper bound for `MAX_BITS_TO_CHECK` is around 20.
        // If `len` is 19, `2^(len-1)` is `2^18 = 262144`.
        // If `len` is 18, `2^(len-1)` is `2^17 = 131072`.
        // The maximum possible length of `s` is `2 * 10^5`.
        // So if `s[l] == '1'`, we need `2^(len-1) <= len`. This is only true for `len=1, 2`.
        // This reasoning is flawed. `f(s[l...r])` is the value, not `2^(len-1)`.
        // `f(s[l...r])` can be `len`.
        // The maximum value of `len` is `N`.
        // If `s[l] == '1'`, then `f(s[l...r])` is at least `2^(len-1)`.
        // We need `len = f(s[l...r])`.
        // So `len >= 2^(len-1)`. This is only true for `len=1` and `len=2`.
        // For `len=1`, `1 >= 2^0 = 1`. `s[l...l] = "1"`. `f("1")=1`. Good.
        // For `len=2`, `2 >= 2^1 = 2`. `s[l...l+1] = "10"`. `f("10")=2`. Good.
        // `s[l...l+1] = "11"`. `f("11")=3`. `len=2`. Not good.
        // For `len=3`, `3 < 2^2 = 4`. So `len < 2^(len-1)`.
        // This means if `s[l] == '1'` and `len >= 3`, then `f(s[l...r]) >= 2^(len-1) > len`.
        // So `len = f(s[l...r])` is impossible if `s[l] == '1'` and `len >= 3`.
        // This simplifies things greatly for substrings starting with '1'.
        // We only need to check `len=1` and `len=2` for `s[l]=='1'`.

        // Let's re-evaluate.
        // The condition is `r - l + 1 = f(s_l \dots s_r)`.
        // Let `len = r - l + 1`.
        // The maximum possible value of `len` is `N`.
        // The maximum possible value of `f(s_l \dots s_r)` is `2^len - 1`.
        // If `s_l = '1'`, then `f(s_l \dots s_r) \ge 2^{len-1}`.
        // We need `len = f(s_l \dots s_r)`.
        // So we must have `len \ge 2^{len-1}`.
        // This inequality holds only for `len=1` (1 >= 2^0=1) and `len=2` (2 >= 2^1=2).
        // For `len=3`, `3 < 2^2=4`. For `len \ge 3`, `len < 2^{len-1}`.
        // So, if `s_l = '1'`, we only need to check `len=1` and `len=2`.
        // If `len=1`: `l=r`. `s[r] == '1'`. `f("1")=1`. `len=1`. Match.
        // If `len=2`: `l=r-1`. `s[r-1] == '1'`. `s[r-1...r]`.
        //   If `s[r-1...r] == "10"`, `f("10")=2`. `len=2`. Match.
        //   If `s[r-1...r] == "11"`, `f("11")=3`. `len=2`. No match.

        // So for `s[l] == '1'`, we only need to check `l=r` and `l=r-1`.
        if (s[r] == '1') { // len = 1
            good_substrings_count++; // s[r...r] = "1", f("1")=1, len=1. Always good.
        }
        if (r > 0 && s[r-1] == '1') { // len = 2
            if (s[r] == '0') { // s[r-1...r] = "10", f("10")=2, len=2. Always good.
                good_substrings_count++;
            }
        }

        // Case 2: Substrings starting with '0'
        // If `s[l] == '0'`, then `f(s[l...r])` is the value of `s[k...r]` where `s[k]` is the first '1'.
        // Or 0 if all are '0's.
        // Let `k` be the index of the first '1' in `s[l...r]`.
        // If `s[l...r]` consists only of '0's, then `f(s[l...r]) = 0`.
        // We need `len = 0`. But `len = r - l + 1 \ge 1`. So this is impossible.
        // Thus, a good substring must contain at least one '1'.
        // Let `k` be the index of the first '1' in `s[l...r]`.
        // Then `f(s[l...r]) = f(s[k...r])`.
        // The length of `s[k...r]` is `r - k + 1`.
        // The number of leading zeros is `k - l`.
        // We need `r - l + 1 = f(s[k...r])`.
        // Let `val = f(s[k...r])`.
        // We need `r - l + 1 = val`.
        // This means `l = r + 1 - val`.
        // Also, `s[l...k-1]` must be all '0's, and `s[k]` must be '1'.
        // The number of leading zeros is `k - l`.
        // We need `k - l = k - (r + 1 - val) = k - r - 1 + val`.
        // This must be equal to `prefix_zeros[k] - prefix_zeros[l]`.
        // And `s[k]` must be '1'.

        // Iterate `k` from `r` down to `0`. `k` is the index of the first '1' in `s[l...r]`.
        // This means `s[k] == '1'` and `s[k+1...r]` are part of the binary number.
        // `s[l...k-1]` are leading zeros.
        long long current_val = 0;
        long long power_of_2 = 1;
        const int MAX_BITS_FOR_VAL = 19; // Max len is N=2e5. 2^18 = 262144. 2^17 = 131072.
                                         // If val > N, it cannot be equal to len.
                                         // So we only care about val up to N.
                                         // 2^18 is enough to cover N.
                                         // So we need at most 18 bits for val.
                                         // If current_val exceeds N, we can stop.
                                         // The maximum length of a substring is N.
                                         // If current_val > N, it cannot be equal to len.
                                         // So we can stop when current_val > N.
                                         // This means we need to check at most ~18-19 bits.
                                         // Let's say we check up to 20 bits to be safe.

        for (int k = r; k >= 0 && (r - k + 1) <= MAX_BITS_FOR_VAL; --k) {
            if (s[k] == '1') {
                current_val += power_of_2;
            }
            power_of_2 *= 2;

            if (current_val > n) { // Optimization: if value exceeds max possible length, break.
                break;
            }

            // Now `current_val` is `f(s[k...r])`.
            // We need to find `l` such that `s[l...k-1]` are all '0's, `s[k] == '1'`,
            // and `r - l + 1 == current_val`.
            // From `r - l + 1 == current_val`, we get `l = r + 1 - current_val`.

            // Check if this `l` is valid:
            // 1. `l >= 0` (within string bounds)
            // 2. `l <= k` (the first '1' is at or after `l`)
            // 3. `s[l...k-1]` must be all '0's. This means `prefix_zeros[k] - prefix_zeros[l]` must be `k - l`.

            int l = r + 1 - (int)current_val;

            if (l >= 0 && l <= k) { // `l <= k` implies `s[k]` is the first '1' or `l=k`
                if (s[k] == '1') { // Ensure s[k] is indeed '1'
                    // Check if s[l...k-1] are all '0's
                    // This is true if the count of zeros in s[l...k-1] is exactly (k-l)
                    if (prefix_zeros[k] - prefix_zeros[l] == (k - l)) {
                        good_substrings_count++;
                    }
                }
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] unused, a[1] set per query, a[2]...a[n] from input
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> dp_y(n + 1, -1); // dp_y[k] stores y value if starting at x=k, y=0
    std::vector<int> dp_x(n + 1, -1);     // dp_x[k] stores next x value if starting at x=k, y=0
    std::vector<bool> visited(n + 1, false); // For cycle detection

    for (int k = 2; k <= n; ++k) { // Precompute for a[k] where k >= 2
        if (dp_y[k] != -1) continue; // Already computed

        std::vector<int> path;
        int current_x = k;
        long long current_y_offset = 0; // y offset from the start of this subproblem

        while (current_x >= 1 && current_x <= n && !visited[current_x] && dp_y[current_x] == -1) {
            visited[current_x] = true;
            path.push_back(current_x);

            long long val_ax = a[current_x];

            // Step 2: x = x + a_x, y = y + a_x
            int next_x_step2 = current_x + val_ax;
            long long next_y_offset_step2 = current_y_offset + val_ax;

            // Step 3: y = y + a_x, x = x - a_x
            current_x = next_x_step2 - val_ax; // This is the x for the next iteration
            current_y_offset = next_y_offset_step2 + val_ax; // This is the y for the next iteration
        }

        if (current_x < 1 || current_x > n) { // Terminated out of bounds
            for (int node : path) {
                dp_y[node] = current_y_offset;
                dp_x[node] = current_x;
            }
        } else if (visited[current_x] && dp_y[current_x] == -1) { // Cycle detected
            for (int node : path) {
                dp_y[node] = -1;
                dp_x[node] = -1;
            }
        } else { // Reached an already computed state
            for (int node : path) {
                if (dp_y[current_x] == -1) { // If the state we reached is part of a cycle
                    dp_y[node] = -1;
                    dp_x[node] = -1;
                } else {
                    dp_y[node] = current_y_offset + dp_y[current_x];
                    dp_x[node] = dp_x[current_x];
                }
            }
        }
        for (int node : path) {
            visited[node] = false; // Reset visited for next path
        }
    }

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for this run

        int current_x = 1;
        long long total_y = 0;

        // First pair of steps (from x=1)
        long long val_a1 = a[1];

        // Step 2: x = x + a_x, y = y + a_x
        int next_x_step2 = current_x + val_a1;
        total_y += val_a1;

        // Step 3: y = y + a_x, x = x - a_x
        current_x = next_x_step2 - val_a1;
        total_y += val_a1;

        if (current_x < 1 || current_x > n) {
            std::cout << total_y << "\n";
        } else {
            if (dp_y[current_x] == -1) {
                std::cout << -1 << "\n";
            } else {
                std::cout << total_y + dp_y[current_x] << "\n";
            }
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    long long ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_a++;
        }
    }

    long long ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    // Calculate the maximum number of ones we can achieve in string 'a'
    // by appending its parity.
    // If ones_a is odd, we can append '1', increasing ones_a by 1.
    // If ones_a is even, we can append '0', ones_a remains the same.
    // So, if ones_a is odd, we can effectively get ones_a + 1 ones.
    // If ones_a is even, we can only get ones_a ones.
    // This means the maximum number of ones we can achieve is ones_a if ones_a is even,
    // and ones_a + 1 if ones_a is odd.
    // This can be compactly written as ones_a + (ones_a % 2).
    long long max_ones_a_possible = ones_a + (ones_a % 2);

    if (max_ones_a_possible >= ones_b) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a[i] to a very large value, effectively positive infinity.
    // This is because a_0[i] <= M_k - sum(d_j) for all relevant k.
    // We want to find the largest possible a_0[i] that satisfies all constraints.
    // So, a_0[i] <= min(M_k - sum(d_j)).
    // Initialize with a large value, then take min.
    std::vector<long long> initial_a(n, std::numeric_limits<long long>::max());

    // Calculate prefix sums of d values for each index.
    // This is not the final prefix sum, but rather the sum of d's
    // that would be applied to an element if it were at index `i`
    // and all type 1 operations up to the current one were applied.
    // This is used to determine the `sum_d_j` part for type 2 operations.
    std::vector<long long> current_d_prefix_sum(n + 1, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // For type 1 operation (l, r, d), update current_d_prefix_sum.
            // This is a difference array approach to track the sum of d's.
            current_d_prefix_sum[ops[i].l] += ops[i].val;
            current_d_prefix_sum[ops[i].r + 1] -= ops[i].val;
        } else { // Type 2 operation (l, r, M)
            // For each j in [l, r], we have a_0[j] + sum_d_j <= M.
            // sum_d_j is the sum of d values applied to index j up to this point.
            // We need to calculate sum_d_j for each j in [l, r].
            // This can be done by iterating through current_d_prefix_sum.
            long long current_d_val = 0;
            for (int j = 0; j < n; ++j) {
                current_d_val += current_d_prefix_sum[j];
                if (j >= ops[i].l && j <= ops[i].r) {
                    initial_a[j] = std::min(initial_a[j], ops[i].val - current_d_val);
                }
            }
        }
    }

    // If initial_a[j] is still max_long_long, it means it was never constrained by a type 2 query.
    // We can set it to 0, as it satisfies |a_i| <= 10^9.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == std::numeric_limits<long long>::max()) {
            initial_a[i] = 0;
        }
    }

    // Verify the solution
    std::vector<long long> a = initial_a;
    std::vector<long long> current_diff_array(n + 1, 0); // For current_a values

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            current_diff_array[ops[i].l] += ops[i].val;
            current_diff_array[ops[i].r + 1] -= ops[i].val;
        } else { // Type 2 operation (l, r, M)
            long long max_val = std::numeric_limits<long long>::min();
            long long current_d_sum = 0;
            for (int j = 0; j < n; ++j) {
                current_d_sum += current_diff_array[j];
                if (j >= ops[i].l && j <= ops[i].r) {
                    max_val = std::max(max_val, initial_a[j] + current_d_sum);
                }
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i goes to the doctor

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0; // Accumulates d_j from children leaving due to chain reaction

        // Apply effects from child i crying in the office
        // And then process chain reactions
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_effect from previous children leaving
            children[j].p -= total_d_effect;

            // Apply v_effect from child i
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect = std::max(0LL, current_v_effect - 1);
            }

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (b_1=a_1, b_n=a_n, no middle elements)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_zero_run(n); // left_zero_run[i] = length of consecutive zeros ending at i
    std::vector<int> right_zero_run(n); // right_zero_run[i] = length of consecutive zeros starting at i
    std::vector<int> left_one_run(n); // left_one_run[i] = length of consecutive ones ending at i
    std::vector<int> right_one_run(n); // right_one_run[i] = length of consecutive ones starting at i

    // Calculate left runs
    left_zero_run[0] = (a[0] == 0);
    left_one_run[0] = (a[0] == 1);
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_run[i] = left_zero_run[i - 1] + 1;
            left_one_run[i] = 0;
        } else {
            left_one_run[i] = left_one_run[i - 1] + 1;
            left_zero_run[i] = 0;
        }
    }

    // Calculate right runs
    right_zero_run[n - 1] = (a[n - 1] == 0);
    right_one_run[n - 1] = (a[n - 1] == 1);
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_run[i] = right_zero_run[i + 1] + 1;
            right_one_run[i] = 0;
        } else {
            right_one_run[i] = right_one_run[i + 1] + 1;
