#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s[0...i-1] and s[i...n-1].
    // We can reassemble as s[i...n-1] + s[0...i-1].
    // This new string must be a palindrome and not equal to s.
    for (int i = 1; i < n; ++i) { // i is the cut point, s[0...i-1] and s[i...n-1]
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i);
        std::string s_prime = p2 + p1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // A string of length N can be cut into 3 pieces.
    // If all characters in s are the same, e.g., "aaaa", then any reordering
    // of pieces will result in "aaaa". In this case, it's impossible.
    // We can check this by counting unique characters.
    // If there's only one unique character, it's impossible.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Consider cutting s into s[0...0], s[1...n-2], s[n-1...n-1].
    // This is s[0], s.substr(1, n-2), s[n-1].
    // Since s is a palindrome, s[0] == s[n-1].
    // If n is odd, n-2 is odd. If n is even, n-2 is even.
    // The middle part s.substr(1, n-2) is also a palindrome.
    // If s is not all same characters, then s.substr(1, n-2) is either empty (n=2),
    // or has length 1 (n=3), or has length >= 2.
    // If n=1, s="a", all_same_char is true, handled above.
    // If n=2, s="aa", all_same_char is true, handled above.
    // If n=3, s="aba", s[0]='a', s[1]='b', s[2]='a'.
    // Pieces: "a", "b", "a". Reorder to "a", "a", "b" -> "aab" (not palindrome).
    // Reorder to "b", "a", "a" -> "baa" (not palindrome).
    // This specific strategy of cutting into s[0], s[1...n-2], s[n-1] and reordering
    // to s[0], s[n-1], s[1...n-2] (which is s[0], s[0], s.substr(1,n-2))
    // forms s[0] + s[0] + s.substr(1,n-2). This is not necessarily a palindrome.
    //
    // A simpler argument for k=2:
    // If s is not all same characters, then there exists at least one character s[i] != s[0].
    // Since s is a palindrome, s[i] == s[n-1-i].
    // Consider the string s' formed by taking s and removing its first character,
    // then appending it to the end. This is equivalent to a single cut.
    // If this doesn't work, it means s.substr(1) + s[0] is either s or not a palindrome.
    //
    // The problem statement guarantees that if k=1 doesn't work, and not all characters are the same,
    // then k=2 is the answer. This is a known property for palindromes.
    // If a palindrome `s` is not composed of all identical characters, and no single cut
    // and reordering yields a new palindrome, then two cuts will always suffice.
    // For example, cut `s` into `s[0]`, `s[1...n-2]`, `s[n-1]`.
    // Since `s` is a palindrome, `s[0] == s[n-1]`.
    // The middle part `s[1...n-2]` is also a palindrome.
    // If `s` is not all same characters, then `s[0]` must be different from some character in `s[1...n-2]`.
    // Or `s[1...n-2]` is empty or length 1.
    //
    // Example: "nolon" (n=5)
    // s[0]='n', s[1]='o', s[2]='l', s[3]='o', s[4]='n'
    // Pieces: "n", "olo", "n"
    // Reorder to "n", "n", "olo" -> "nnolo" (not palindrome)
    // Reorder to "olo", "n", "n" -> "olonn" (not palindrome)
    //
    // The example "nolon" -> 2 cuts, "no|l|on" -> "on|l|no"
    // Pieces: "no", "l", "on"
    // Reorder: "on", "l", "no" -> "onlno" (palindrome)
    // This is a specific set of 3 pieces.
    //
    // The logic for k=2 being always possible if not all chars are same and k=1 fails:
    // If s is not all same characters, then there exists some `i` such that `s[i] != s[0]`.
    // Consider the string `s'` formed by `s[1...n-1] + s[0]`.
    // If `s'` is not `s` and is a palindrome, `k=1` is the answer.
    // If `s'` is `s`, then `s[1...n-1]` must be `s[0...n-2]`. This means `s[0] = s[1] = ... = s[n-1]`,
    // which contradicts "not all same characters". So `s'` cannot be `s` if not all chars are same.
    // Thus, if `k=1` fails, it must be that `s[1...n-1] + s[0]` is not a palindrome.
    //
    // The problem statement implies that if k=1 doesn't work, and it's not "Impossible", then k=2 is the answer.
    // The "Impossible" case is when all characters are the same.
    // So, if we reach this point, it means `k=1` failed, and `s` is not composed of all identical characters.
    // Therefore, `k=2` must be the answer.
    std::cout << 2 << std::endl;

    return 0;
}

