#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The reverse of a permutation has the same fingerprint.
        // If p is [p_1, p_2, ..., p_n], its adjacent sums are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
        // The reverse p' is [p_n, p_{n-1}, ..., p_1].
        // Its adjacent sums are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
        // This is the same multiset of sums, just in reverse order.
        // Therefore, F(p) = F(p').
        // Since n >= 2, p and p' are different unless p is a palindrome (e.g., [1,2,1] which is not a permutation, or [1,2,3,2,1] not a permutation).
        // For a permutation, p_i are distinct. So p_1 != p_n unless n=1 (which is not allowed, n>=2).
        // If p_1 != p_n, then p != p_rev.
        // The only case where p == p_rev is if n=1, but n>=2.
        // So reversing the permutation always gives a different permutation with the same fingerprint.

        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

