    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = k + 1; // Initialize with a value larger than any possible a_i
        int min_idx = -1;

        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_operations = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself
            }
            // Number of times min_val can be added to a[i] without exceeding k
            // (k - a[i]) is the remaining capacity in pile a[i]
            // (k - a[i]) / min_val gives how many times min_val can fit into that capacity
            total_operations += (k - a[i]) / min_val;
        }
        std::cout << total_operations << "\n";
    }
    return 0;
}

