#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    bool first_half_T_assigned_to_c = false; // For T/2 elements, if T is even

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (2 * a[i] < T) {
            // Elements strictly less than T/2
            // These can only form a sum T with elements strictly greater than T/2.
            // We can put all of them in one array (e.g., white) and their complements in the other.
            // For simplicity, let's put them all in white (0).
            p[i] = 0;
        } else if (2 * a[i] > T) {
            // Elements strictly greater than T/2
            // These can only form a sum T with elements strictly less than T/2.
            // We can put all of them in one array (e.g., black) and their complements in the other.
            // For simplicity, let's put them all in black (1).
            p[i] = 1;
        } else { // 2 * a[i] == T, i.e., a[i] == T/2
            // These elements are problematic. Any two of them sum to T.
            // To minimize pairs, we should distribute them as evenly as possible.
            // We can alternate their colors.
            if (!first_half_T_assigned_to_c) {
                p[i] = 0; // Assign to white (c)
                first_half_T_assigned_to_c = true;
            } else {
                p[i] = 1; // Assign to black (d)
                first_half_T_assigned_to_c = false;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

