#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for faster input/output.
    // This unties cin/cout from stdio and disables synchronization.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a vector to store prices.
        // For N up to 150,000, a vector is efficient.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        if (n == 0) { // Edge case: if n is 0, no prices, no bad prices.
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix with the last price.
        // The last price can never be bad because there are no later days.
        int min_suffix = a[n - 1];

        // Iterate from the second-to-last day backwards to the first day.
        // This allows us to maintain the minimum price encountered so far
        // in the suffix of the array.
        for (int i = n - 2; i >= 0; --i) {
            // If the current price a[i] is greater than the minimum price
            // found in the suffix a[i+1...n-1], then a[i] is a bad price.
            if (a[i] > min_suffix) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix, it means a[i]
                // is less than or equal to min_suffix.
                // This a[i] now becomes the new minimum for the suffix a[i...n-1].
                min_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0; // Indicate successful execution
}

