#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_dist = 0;
        int current_dist = 0;

        // The frog starts at 0.
        // The first 'R' character is at index 0 (cell 1).
        // The last 'R' character is at index n-1 (cell n).
        // The target is cell n+1.

        // We need to consider the distance from the previous 'R' cell
        // (or cell 0) to the current 'R' cell, or to cell n+1.

        // The first jump is from cell 0.
        // The distance from cell 0 to the first 'R' cell (say, cell i)
        // is i. If there are no 'R' cells, the distance to n+1 is n+1.

        // Let's track the last 'R' cell encountered.
        // Initialize last_R_pos to 0, representing the starting point.
        int last_R_pos = 0; 

        for (int i = 0; i < n; ++i) {
            // s[i] corresponds to cell i+1
            if (s[i] == 'R') {
                // The frog can jump from last_R_pos to cell i+1.
                // The required jump distance for this segment is (i+1) - last_R_pos.
                max_dist = std::max(max_dist, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to the current 'R' cell
            }
        }

        // After iterating through the string, last_R_pos holds the position
        // of the last 'R' cell encountered, or 0 if no 'R' cells were found.
        // The frog still needs to jump from last_R_pos to n+1.
        max_dist = std::max(max_dist, (n + 1) - last_R_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

