        // The maximum number of teams is limited by three factors:
        // 1. The total number of students divided by 3 (since each team needs 3 members).
        // 2. The number of coders (each team needs at least 1 coder).
        // 3. The number of mathematicians (each team needs at least 1 mathematician).
        // So, the number of teams 'k' must satisfy:
        // k <= (c + m + x) / 3
        // k <= c
        // k <= m
        // Combining these, k <= min(c, m, (c + m + x) / 3).
        // Let's call this upper bound 'max_possible_teams'.

        long long max_possible_teams = std::min({c, m, (c + m + x) / 3});

        std::cout << max_possible_teams << "\n";
    }
    return 0;
}

