int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the top part (a smaller triangle) up to the i-th cut
        // should be i times the area of a single piece.
        // Total area of the carrot is h/2.
        // Area of one piece is (h/2) / n = h / (2n).
        // Area of the top part up to the i-th cut should be i * (h / (2n)).
        // Let x_i be the height of this smaller triangle.
        // By similar triangles, if the base of the full triangle is B and height is H,
        // then for a smaller triangle with height x and base b, b/x = B/H.
        // Here, B=1, H=h. So b/x = 1/h => b = x/h.
        // Area of smaller triangle = (1/2) * b * x = (1/2) * (x/h) * x = x^2 / (2h).
        // So, x_i^2 / (2h) = i * (h / (2n)).
        // x_i^2 = i * h^2 / n.
        // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n).
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between the smallest available and largest available numbers
    // from the range [1, k+1].
    // For example, if k=2, range is [1,3].
    // p_1 = 1, p_2 = 3, p_3 = 2.
    // Differences: |1-3|=2, |3-2|=1. Distinct: {1,2}.
    // If k=3, range is [1,4].
    // p_1 = 1, p_2 = 4, p_3 = 2, p_4 = 3.
    // Differences: |1-4|=3, |4-2|=2, |2-3|=1. Distinct: {1,2,3}.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left (smallest available)
            p[i] = left;
            left++;
        } else { // Odd index, take from right (largest available)
            p[i] = right;
            right--;
        }
    }

    // For the remaining n - (k+1) elements, just append them in increasing order.
    // This will only introduce a difference of 1, which is already present (if k >= 1).
    // The numbers used so far are 1, 2, ..., k+1 in some order.
    // The next available number is k+2.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This will be k+2, k+3, ..., n
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i+1]
    // This marks the end of the non-increasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is a non-increasing suffix.
    // If i is 0, the whole array is non-increasing.

    // Find the rightmost index `j` such that a[j] > a[j+1]
    // This marks the end of the non-decreasing suffix
    int j = i; // Start search from `i`
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now, a[j...n-1] is a "good" array.
    // The prefix to erase is a[0...j-1], which has length j.

    std::cout << j << std::endl;
}

