#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long k_max = n / m;

        // Precompute the sum of last digits for one cycle (10 multiples of m)
        // The last digits are (m % 10), (2*m % 10), ..., (10*m % 10)
        // which are equivalent to ((1*m_last_digit)%10), ((2*m_last_digit)%10), ..., ((10*m_last_digit)%10)
        // where m_last_digit = m % 10.
        // Let's just compute them directly.
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full cycles of 10 multiples
        long long num_full_cycles = k_max / 10;
        long long total_sum = num_full_cycles * cycle_sum;

        // Remaining multiples after full cycles
        long long remaining_multiples = k_max % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');

    // For m=1, the subsegment is just [1]. Its length is 1, min is 1, max is 1.
    // This is always possible by taking l=r=pos[1].
    ans[0] = '1';

    // Initialize min_idx and max_idx for the current range [1, ..., k]
    // For k=1, the range is just [1]. Its index is pos[1].
    int min_idx = pos[1];
    int max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Update min_idx and max_idx to include the position of 'm'
        // The current range of indices [min_idx, max_idx] covers numbers [1, ..., m-1].
        // To cover numbers [1, ..., m], we need to extend this range to include pos[m].
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // A number 'm' is beautiful if the subsegment p[min_idx ... max_idx]
        // contains exactly numbers 1 to m.
        // This means its length must be 'm'.
        // The length of p[min_idx ... max_idx] is (max_idx - min_idx + 1).
        if ((max_idx - min_idx + 1) == m) {
            ans[m - 1] = '1';
        } else {
            ans[m - 1] = '0';
        }
    }

    std::cout << ans << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

