            std::cout << (D == 1 ? "Ya" : "Tidak") << "\n";
            continue;
        }

        // General case: A+B+C+D > 1
        std::cout << (can_be_box1(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box2(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box3(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box4(A, B, C, D) ? "Ya" : "Tidak") << "\n";
    }
    return 0;
}

