// Function to convert an integer to its parity pattern string
// The pattern is always 18 characters long, padded with '0's from the left.
// '0' for even digits, '1' for odd digits.
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern_str += '0';
            } else { // Odd digit
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long
    // This effectively means padding with '0's from the left for the original number
    // when considering digits from right to left.
    while (pattern_str.length() < 18) {
        pattern_str += '0';
    }
    return pattern_str;
}

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // A map to store counts of each 18-digit parity pattern.
    // The key is the 18-character string representing the parity pattern.
    // The value is the count of numbers in the multiset that generate this pattern.
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern 's' with '0's from the left to make it 18 characters long.
            // This is equivalent to padding with '0's from the right when building the key for the map.
            std::string query_pattern = s;
            while (query_pattern.length() < 18) {
                query_pattern = '0' + query_pattern;
            }

            // The map stores patterns where the 0th index corresponds to the rightmost digit's parity.
            // So, we need to reverse the query_pattern to match the stored format.
            std::reverse(query_pattern.begin(), query_pattern.end());

            // Retrieve the count for the matching pattern.
            // If the pattern is not in the map, its count is 0.
            std::cout << pattern_counts[query_pattern] << "\n";
        }
    }

    return 0;
}

