#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let 'i' be the number of items taken from the left (0 <= i <= n)
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += (prefix_sum[i] - prefix_sum[0]) * l;

        // Energy for items taken from the right
        // The sum of weights for items taken from the right is total_sum - sum_of_left_items
        // which is (prefix_sum[n] - prefix_sum[i])
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for consecutive actions
        if (i > j) { // More items from left than right
            // The last item taken must have been from the left to have an excess of left items
            // The number of excess left items is i - j - 1 (if i > j, then i-j >= 1)
            // This means there were i-j-1 times we took left item consecutively after another left item
            // Example: L L R L L L R L L. i=7, j=2. i-j=5.
            // The sequence of actions could be L R L R L L L L L.
            // The number of times we took an item from the left when the previous was also left is (i - j - 1)
            // This applies if i > j.
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            // The last item taken must have been from the right to have an excess of right items
            // The number of excess right items is j - i - 1
            current_energy += (j - i - 1) * Qr;
        }
        // If i == j, no extra penalty from this rule.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

