                // C: N=6 (even). Takes 3. N=3. Chanek: 3.
                // O: N=3 (odd). Takes 1. N=2. Opponent: 1.
                // C: N=2 (even). Takes 1. N=1. Chanek: 3+1=4.
                // O: N=1 (odd). Takes 1. N=0. Opponent: 1+1=2.
                // Result: Chanek 4. Matches example.

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long solve() {
    long long p, q;
    std::cin >> p >> q;

    if (p % q != 0) {
        return p;
    }

    long long ans = 1;
    long long temp_q = q;

    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            long long current_prime_factor = i;

            // Calculate the exponent of current_prime_factor in q
            long long q_prime_exp = 0;
            while (temp_q % current_prime_factor == 0) {
                q_prime_exp++;
                temp_q /= current_prime_factor;
            }

            // Calculate the exponent of current_prime_factor in p
            long long p_prime_exp = 0;
            long long temp_p = p;
            while (temp_p > 0 && temp_p % current_prime_factor == 0) { // temp_p > 0 check for safety, though p >= 1
                p_prime_exp++;
                temp_p /= current_prime_factor;
            }

            // If p has enough factors of current_prime_factor to be divisible by q's factors
            if (p_prime_exp >= q_prime_exp) {
                long long factor_to_remove = 1;
                for(int k = 0; k < q_prime_exp - 1; ++k) {
                    factor_to_remove *= current_prime_factor;
                }
                // This is equivalent to p / (current_prime_factor^(q_prime_exp - 1))
                // Or more simply, p / (q / current_prime_factor) if q_prime_exp is 1
                // Or p / (current_prime_factor^q_prime_exp / current_prime_factor)
                // The goal is to remove just enough factors of current_prime_factor from p
                // so that the resulting number is not divisible by q.
                // The largest such number is p / current_prime_factor.
                // But we need to remove current_prime_factor^(q_prime_exp - 1) from p
                // to make it not divisible by q.
                // No, this is wrong. We need to remove current_prime_factor from p
                // until its exponent is less than q_prime_exp.
                // The largest such number is p / current_prime_factor.
                // No, it's p / (current_prime_factor ^ (p_prime_exp - (q_prime_exp - 1)))
                // This is p / (current_prime_factor ^ (p_prime_exp - q_prime_exp + 1))
                // This is p / (current_prime_factor ^ (p_prime_exp - q_prime_exp)) / current_prime_factor
                // This is (p / (current_prime_factor ^ p_prime_exp)) * (current_prime_factor ^ (q_prime_exp - 1))
                // No, it's p / (current_prime_factor ^ (p_prime_exp - (q_prime_exp - 1)))
                // The largest divisor of p that is not divisible by q, considering only this prime factor.
                // If p = A * f^P_exp and q = B * f^Q_exp, where A, B are not divisible by f.
                // We need x = C * f^X_exp such that X_exp < Q_exp.
                // To maximize x, we want X_exp to be Q_exp - 1.
                // So we want to remove f^(P_exp - (Q_exp - 1)) from p.
                // This is p / (f^(P_exp - Q_exp + 1)).
                long long current_x = p;
                for (int k = 0; k < p_prime_exp - q_prime_exp + 1; ++k) {
                    current_x /= current_prime_factor;
                }
                ans = std::max(ans, current_x);
            }
        }
    }

    if (temp_q > 1) { // temp_q is now a prime factor itself
        long long current_prime_factor = temp_q;
        long long q_prime_exp = 1; // exponent of this prime factor in q is 1

        long long p_prime_exp = 0;
        long long temp_p = p;
        while (temp_p > 0 && temp_p % current_prime_factor == 0) {
            p_prime_exp++;
            temp_p /= current_prime_factor;
        }

        if (p_prime_exp >= q_prime_exp) {
            long long current_x = p;
            for (int k = 0; k < p_prime_exp - q_prime_exp + 1; ++k) {
                current_x /= current_prime_factor;
            }
            ans = std::max(ans, current_x);
        }
    }

    return ans;
}

