int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // If f1 is 0, robot cannot move left. So, X must be >= x.
            // This means the target X must be to the right or at the current x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // If f3 is 0, robot cannot move right. So, X must be <= x.
            // This means the target X must be to the left or at the current x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // If f4 is 0, robot cannot move down. So, Y must be >= y.
            // This means the target Y must be above or at the current y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // If f2 is 0, robot cannot move up. So, Y must be <= y.
            // This means the target Y must be below or at the current y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

