int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    long long sum_r;
    if (b == 1) { // If b=1, then b-1=0, sum is 0.
        sum_r = 0;
    } else {
        sum_r = (b - 1);
        sum_r = (sum_r * b) % MOD;
        // Multiply by modular inverse of 2
        // Modular inverse of 2 modulo 10^9+7 is (10^9+8)/2 = 500000004
        sum_r = (sum_r * 500000004) % MOD;
    }

    // Calculate sum_kb_plus_1 = sum_{k=1 to a} (k * b + 1)
    // This is (sum_{k=1 to a} k*b) + (sum_{k=1 to a} 1)
    // = b * (sum_{k=1 to a} k) + a
    // = b * (a * (a+1) / 2) + a
    long long sum_k = (a % MOD);
    sum_k = (sum_k * ((a + 1) % MOD)) % MOD;
    // Multiply by modular inverse of 2
    sum_k = (sum_k * 500000004) % MOD;

    long long sum_kb_plus_1 = (b % MOD);
    sum_kb_plus_1 = (sum_kb_plus_1 * sum_k) % MOD;
    sum_kb_plus_1 = (sum_kb_plus_1 + (a % MOD)) % MOD;

    // Total sum = sum_r * sum_kb_plus_1
    long long total_sum = (sum_r * sum_kb_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<bool> in_password(26, false);

    for (size_t i = 0; i < s.length(); ++i) {
        in_password[s[i] - 'a'] = true;
        if (i > 0) {
            adj[s[i] - 'a'].insert(s[i - 1]);
            adj[s[i - 1] - 'a'].insert(s[i]);
        }
    }

    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    // Find starting points for paths (characters with only one required neighbor)
    // Or if all characters in password have 2 neighbors, pick any unvisited one.
    // Or if password has only one unique char, pick that one.

    char current_char = 0;
    bool found_start = false;
    for (int i = 0; i < 26; ++i) {
        if (in_password[i] && adj[i].size() <= 1) { // <=1 covers single char password and path ends
            current_char = (char)('a' + i);
            found_start = true;
            break;
        }
    }

    // If all characters in password have 2 neighbors (e.g., 'abacaba' -> a-b, a-c, b-a, c-a, but a has 2 distinct neighbors b,c)
    // This means it's a cycle, which is not allowed on a linear keyboard.
    // However, the problem statement guarantees no adjacent equal characters.
    // The adj.size() check already handles this. If a char has 2 distinct neighbors, it's fine.
    // If all chars in password have 2 neighbors, it means they form a cycle.
    // Example: abcda -> a-b, b-c, c-d, d-a. All have 2 neighbors.
    // This is a cycle, which is impossible on a linear keyboard.
    // The only case where all in_password chars have 2 neighbors and it's valid is if the password itself is a single character.
    // But then adj.size() would be 0.
    // So if found_start is false, it means all in_password chars have 2 neighbors.
    // This implies a cycle among the in_password chars, which is impossible.
    // Except for the case where the password has only one unique character.
    // If s.length() == 1, then in_password[s[0]-'a'] is true, adj[s[0]-'a'].size() is 0.
    // So current_char will be s[0].
    // If s.length() > 1 and found_start is false, it's a cycle.

    if (!found_start && s.length() > 0) { // If password is not empty and no path start found
        // This means all characters in the password have exactly two distinct neighbors.
        // This forms a cycle, which is impossible on a linear keyboard.
        // Example: "abcda" -> a-b, b-c, c-d, d-a. All have 2 neighbors.
        // This is a cycle.
        std::cout << "NO\n";
        return;
    }

    if (s.length() == 0) { // Empty password, any layout is fine.
        std::cout << "YES\n";
        std::cout << "abcdefghijklmnopqrstuvwxyz\n";
        return;
    }

    // Build the layout for characters in the password
    while (current_char != 0 && !visited[current_char - 'a']) {
        layout += current_char;
        visited[current_char - 'a'] = true;

        char next_char = 0;
        for (char neighbor : adj[current_char - 'a']) {
            if (!visited[neighbor - 'a']) {
                next_char = neighbor;
                break;
            }
        }
        current_char = next_char;
    }

    // Check if all characters from the password are included in the layout
    for (int i = 0; i < 26; ++i) {
        if (in_password[i] && !visited[i]) {
            // This means there's a disconnected component of password characters,
            // or a cycle that wasn't caught by adj.size() > 2 (e.g., a-b, c-d, but password is "ac").
            // The logic for finding start char should have covered this.
            // If a character is in_password but not visited, it means it's part of a separate path/cycle
            // that wasn't connected to the one we started building.
            // This is impossible for a single linear keyboard.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining characters not in the password
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

