int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> next_char_pos(n, std::vector<int>(26, n));
    for (int i = n - 1; i >= 0; --i) {
        if (i < n - 1) {
            next_char_pos[i] = next_char_pos[i + 1];
        }
        next_char_pos[i][s[i] - 'a'] = i;
    }

    std::vector<std::vector<int>> prev_char_pos(n, std::vector<int>(26, -1));
    for (int i = 0; i < n; ++i) {
        if (i > 0) {
            prev_char_pos[i] = prev_char_pos[i - 1];
        }
        prev_char_pos[i][s[i] - 'a'] = i;
    }

    std::vector<std::vector<int>> count_pairs(26, std::vector<int>(26, 0));
    std::vector<int> count_first_char(26, 0);

    for (int k = 0; k < n; ++k) {
        count_first_char[s[k] - 'a']++;
        for (int p = 1; p < n; ++p) {
            count_pairs[s[k] - 'a'][s[(k + p) % n] - 'a']++;
        }
    }

    double total_win_prob = 0.0;

    for (int first_char_val = 0; first_char_val < 26; ++first_char_val) {
        if (count_first_char[first_char_val] == 0) {
            continue;
        }

        double max_win_prob_for_char = 0.0;

        for (int p = 1; p < n; ++p) {
            int current_p_win_count = 0;
            for (int second_char_val = 0; second_char_val < 26; ++second_char_val) {
                int count = 0;
                for (int k = 0; k < n; ++k) {
                    if (s[k] - 'a' == first_char_val && s[(k + p) % n] - 'a' == second_char_val) {
                        count++;
                    }
                }
                if (count == 1) {
                    current_p_win_count++;
                }
            }
            max_win_prob_for_char = std::max(max_win_prob_for_char, (double)current_p_win_count / count_first_char[first_char_val]);
        }
        total_win_prob += max_win_prob_for_char * count_first_char[first_char_val];
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));

    // If n is a perfect square, k*k = n.
    // We want to construct a permutation where LIS = k and LDS = k.
    // This can be done by dividing the numbers 1 to n into k blocks of size k.
    // For example, for n=9, k=3:
    // Block 1: 1 2 3
    // Block 2: 4 5 6
    // Block 3: 7 8 9
    // Permutation: [3 2 1, 6 5 4, 9 8 7]
    // LIS: [1, 4, 7] (length 3)
    // LDS: [3, 2, 1] (length 3)
    // Sum = 6.
    // This construction gives LIS = k and LDS = k.

    // If n is not a perfect square, k*k < n.
    // We can still use blocks.
    // Let k = floor(sqrt(n)).
    // We want LIS and LDS to be close to sqrt(n).
    // A construction that achieves LIS = ceil(n/k) and LDS = k is as follows:
    // Divide numbers 1 to n into blocks of size k.
    // The last block might be smaller.
    // For each block, reverse the order of elements.
    // Example: n=4, k=2
    // Blocks: [1,2], [3,4]
    // Permutation: [2,1,4,3]
    // LIS: [2,4] or [1,3] (length 2)
    // LDS: [2,1] or [4,3] (length 2)
    // Sum = 4.
    // Here, ceil(n/k) = ceil(4/2) = 2. LIS = 2, LDS = 2.

    // Example: n=5, k=2
    // Blocks: [1,2], [3,4], [5]
    // Permutation: [2,1,4,3,5]
    // LIS: [2,4,5] or [1,3,5] (length 3)
    // LDS: [2,1] or [4,3] (length 2)
    // Sum = 5.
    // Here, ceil(n/k) = ceil(5/2) = 3. LIS = 3, LDS = 2.

    // The general construction:
    // Iterate from i = 0 to n-1.
    // The number at index i in the permutation will be part of block (i / k).
    // The numbers in block j (0-indexed) are from (j*k + 1) to min((j+1)*k, n).
    // To reverse the block, for an element at index i, its value is
    // (j*k + k) - (i % k).
    // Or more simply, for each block starting at `start_val`, print `start_val + k - 1`, `start_val + k - 2`, ..., `start_val`.
    // But we need to handle the last block which might be smaller.

    // Let's refine the block construction.
    // We want to print numbers in groups of `k`.
    // For each group, print them in decreasing order.
    // The groups are `1..k`, `k+1..2k`, etc.
    // The last group will be `(num_blocks-1)*k + 1 .. n`.

    int current_val = n;
    while (current_val > 0) {
        int start_of_block = std::max(1, current_val - k + 1);
        for (int i = current_val; i >= start_of_block; --i) {
            std::cout << i << " ";
        }
        current_val = start_of_block - 1;
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n <= abs_m for simpler logic
        if (abs_n > abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: k < abs_m (minimum moves required is abs_m)
        if (k < abs_m) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k >= abs_m
        // The maximum number of diagonal moves is abs_n.
        // After abs_n diagonal moves, we are at (abs_n, abs_n) or similar.
        // We still need to cover abs_m - abs_n distance in y-coordinate.
        // This requires abs_m - abs_n straight moves.
        // Total moves so far: abs_n (diagonal) + (abs_m - abs_n) (straight) = abs_m moves.
        // Remaining moves: k - abs_m.

        long long remaining_moves = k - abs_m;
        long long result;

        // If abs_n and abs_m have different parity, we need an odd number of straight moves
        // to adjust the parity of the coordinates.
        // If abs_n and abs_m have the same parity, we need an even number of straight moves.
        // The parity of (abs_m - abs_n) determines the parity of the required straight moves.
        // If (abs_m - abs_n) is odd, we need an odd number of straight moves.
        // If (abs_m - abs_n) is even, we need an even number of straight moves.

        // The parity of k must match the parity of abs_m.
        // If k and abs_m have different parities, it's impossible to reach (abs_m, abs_m)
        // or (abs_m, abs_n) in k moves.
        // This is because each move changes the sum of coordinates (x+y) by an odd amount
        // (if diagonal) or an odd amount (if straight).
        // More simply, each move changes the parity of x+y.
        // (0,0) has sum 0 (even).
        // (N,M) has sum N+M.
        // After K moves, the parity of the sum of coordinates will be K % 2.
        // So, (N+M) % 2 must be equal to K % 2.
        // This is equivalent to (abs_n + abs_m) % 2 == K % 2.
        // Or, (abs_n + abs_m - K) % 2 == 0.

        // Let's check the parity condition:
        if ((abs_n + abs_m) % 2 != k % 2) {
            // If parities don't match, we must use one extra straight move to flip parity.
            // This means we use k-1 moves to reach a point with correct parity,
            // and then one more move to reach the target.
            // This effectively means we lose one diagonal move.
            // The total moves are k.
            // If k is odd and (abs_n+abs_m) is even, or vice versa,
            // we need to make an odd number of "wasted" moves.
