    // diff_L[k] = (count of 1s) - (count of 2s) among jars 1 to k
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // diff_R[k] = (count of 1s) - (count of 2s) among jars 2n-k+1 to 2n
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store indices for diff_L values
    // map_L[diff_value] = minimum k such that diff_L[k] = diff_value
    std::map<int, int> map_L;
    for (int k = 0; k <= n; ++k) {
        if (map_L.find(diff_L[k]) == map_L.end()) {
            map_L[diff_L[k]] = k;
        }
    }

    int min_removed = 2 * n; // Initialize with max possible removals

    // Iterate through all possible removals from the right side
    // k_R is the number of jars removed from the right (0 to n)
    for (int k_R = 0; k_R <= n; ++k_R) {
        // Current difference from jars removed from right: diff_R[k_R]
        // Total difference from all jars: initial_s1 - initial_s2
        // Difference from remaining jars: (initial_s1 - initial_s2) - diff_R[k_R]
        // We need this remaining difference to be 0.
        // So, we need to remove k_L jars from the left such that
        // diff_L[k_L] = (initial_s1 - initial_s2) - diff_R[k_R]
        int target_diff_L = (initial_s1 - initial_s2) - diff_R[k_R];

        if (map_L.count(target_diff_L)) {
            int k_L = map_L[target_diff_L];
            min_removed = std::min(min_removed, k_L + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

