        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long count = 0;

    // Iterate through all possible starting positions l
    for (int l = 0; l < n; ++l) {
        // Case 1: Substrings starting with '1'
        // These substrings can have length up to ~18-20 because f(t) grows exponentially.
        // If f(t) > n, it's impossible for length to be f(t).
        // Max length of s is 2e5. 2^18 = 262144. So max relevant L is around 18.
        // Let's check up to L=20 to be safe, as f(t) can be up to 2^L-1.
        // If L=18, f(t) can be up to 262143.
        // If L=19, f(t) can be up to 524287.
        // If L=20, f(t) can be up to 1048575.
        // The length of the substring itself is at most N.
        // So we only need to check L such that L <= N.
        // And also, f(t) <= N.
        // Since f(t) = L, we need L <= N.
        // The maximum value of L we need to check is around 18-20.
        // Let's use a constant MAX_L_CHECK for this.
        // A value of 20 is sufficient because 2^20 > 2e5.
        // If L > 20, then f(t) >= 2^20 > 2e5 >= N.
        // So L = f(t) would imply L > N, which is impossible.
        // Thus, we only need to check substrings of length up to ~20.

        long long current_val = 0;
        const int MAX_L_CHECK = 20; // Max length to check for '1' starting substrings

        for (int r = l; r < std::min(n, l + MAX_L_CHECK); ++r) {
            current_val = (current_val << 1) | (s[r] - '0');
            int len = r - l + 1;
            if (current_val == len) {
                count++;
            }
        }

        // Case 2: Substrings starting with '0'
        // These substrings have leading zeros.
        // f(0...01...) = value of 1...
        // f(0...0) = 0
        // The condition is r - l + 1 = f(s_l ... s_r).
        // If s_l = '0', then f(s_l ... s_r) is the value of the binary string
        // ignoring leading zeros.
        // Example: s = 0001000
        // l=0, s[0]='0'.
        //   r=0, s[0]='0'. len=1. f('0')=0. 1 != 0.
        //   r=1, s[0..1]='00'. len=2. f('00')=0. 2 != 0.
        //   r=2, s[0..2]='000'. len=3. f('000')=0. 3 != 0.
        //   r=3, s[0..3]='0001'. len=4. f('0001')=1. 4 != 1.
        //   r=4, s[0..4]='00010'. len=5. f('00010')=2. 5 != 2.
        //   r=5, s[0..5]='000100'. len=6. f('000100')=4. 6 != 4.
        //   r=6, s[0..6]='0001000'. len=7. f('0001000')=8. 7 != 8.

        // For substrings starting with '0', we need to find the first '1'.
        // If there's no '1', the value is 0.
        // If there is a '1', the value is determined by the suffix starting from the first '1'.
        // Let's find the first '1' after index l.
        // If s[l] == '0':
        //   We are looking for substrings s[l...r] such that r-l+1 = f(s[l...r]).
        //   If all characters from s[l] to s[r] are '0', then f(s[l...r]) = 0.
        //   So we need r-l+1 = 0, which is impossible since length >= 1.
        //   Thus, a substring of all '0's is never good.
        //   This means if s[l] == '0', the substring must contain at least one '1'.
        //   Let k be the index of the first '1' in s[l...r].
        //   Then f(s[l...r]) = f(s[k...r]).
        //   The condition becomes r-l+1 = f(s[k...r]).
        //   Let L_prime = r-k+1 be the length of s[k...r].
        //   Let num_zeros = k-l be the number of leading zeros.
        //   Then r-l+1 = L_prime + num_zeros.
        //   So we need L_prime + num_zeros = f(s[k...r]).
        //   We know f(s[k...r]) >= L_prime (since s[k]='1', so f(s[k...r]) >= 2^(L_prime-1)).
        //   The condition L_prime + num_zeros = f(s[k...r]) implies:
        //   f(s[k...r]) - L_prime = num_zeros.
        //   Since num_zeros >= 0, we need f(s[k...r]) - L_prime >= 0.
        //   Also, num_zeros = k-l.
        //   So we need f(s[k...r]) - L_prime = k-l.
        //   The maximum value of f(s[k...r]) - L_prime is bounded.
        //   If L_prime is large, f(s[k...r]) - L_prime grows very fast.
        //   For example, if L_prime = 18, f(s[k...r]) can be up to 2^18-1.
        //   f(s[k...r]) - L_prime can be up to 2^18-1 - 18.
        //   This value can be up to N (2e5).
        //   So we can iterate k from l to n-1. If s[k] == '1', then we consider it as the start of the '1'-part.
        //   Then iterate r from k to min(n-1, k + MAX_L_CHECK).
        //   Calculate val = f(s[k...r]) and L_prime = r-k+1.
        //   If val - L_prime >= 0 and val - L_prime <= k-l (number of leading zeros), then it's a good substring.
        //   The number of leading zeros is k-l.
        //   So we need to check if val - L_prime is a valid number of leading zeros.
        //   Specifically, we need 0 <= val - L_prime <= k-l.
        //   This means we need to count how many '0's are there before s[k].
        //   Let's precompute prefix sums of '0's.
    }

    // Optimized approach for '0' starting substrings:
    // Iterate through all possible ending positions r.
    // For each r, we are looking for l such that s[l...r] is good.
    // If s[r] == '0', it can be part of a good substring.
    // If s[r] == '1', it can be part of a good substring.
    // The previous loop already covered substrings starting with '1' and having length up to MAX_L_CHECK.
    // This means it covered all good substrings where the first '1' is at index l.
    // What about substrings starting with '0'?
    // s_l ... s_k-1 s_k ... s_r where s_l...s_k-1 are all '0's and s_k = '1'.
    // Length = r-l+1. Value = f(s_k...s_r).
    // Condition: r-l+1 = f(s_k...s_r).
    // Let val_suffix = f(s_k...s_r).
    // Let len_suffix = r-k+1.
    // Let num_leading_zeros = k-l.
    // We need len_suffix + num_leading_zeros = val_suffix.
    // So, num_leading_zeros = val_suffix - len_suffix.
    // We need to find l such that k-l = val_suffix - len_suffix.
    // This means l = k - (val_suffix - len_suffix).
    // For a fixed k and r (where s[k]='1'), we calculate val_suffix and len_suffix.
    // Then we calculate required_l = k - (val_suffix - len_suffix).
    // If required_l >= 0 and required_l < k and s[required_l...k-1] are all '0's, then it's a good substring.
    // The condition s[required_l...k-1] are all '0's is equivalent to:
    // required_l is greater than or equal to the index of the last '1' before k.
    // Or, more simply, k - required_l <= number of consecutive zeros ending at k-1.

    // Let's refine the approach for '0' starting substrings.
    // Iterate k from 0 to n-1. If s[k] == '1':
    //   This '1' is the first '1' in some potential good substring s[l...r].
    //   Iterate r from k to min(n-1, k + MAX_L_CHECK).
    //     Calculate val_suffix = f(s[k...r]) and len_suffix = r-k+1.
    //     If val_suffix < len_suffix, then val_suffix - len_suffix is negative.
    //       This means num_leading_zeros would be negative, which is impossible. Break.
    //     If val_suffix - len_suffix > n, then required_l would be too small (negative). Break.
    //     num_leading_zeros = val_suffix - len_suffix.
    //     required_l = k - num_leading_zeros.
    //     If required_l >= 0 and required_l < k:
    //       We need to check if s[required_l...k-1] are all '0's.
    //       This is true if k - required_l <= (number of consecutive '0's ending at k-1).
    //       Let's precompute `zeros_before[i]` = number of consecutive '0's ending at i-1.
    //       `zeros_before[i]` is 0 if s[i-1] == '1'.
    //       `zeros_before[i]` is `zeros_before[i-1] + 1` if s[i-1] == '0'.
    //       This is equivalent to `zeros_before[k]` being the count of consecutive zeros ending at `k-1`.
    //       So, if `num_leading_zeros <= zeros_before[k]`, then it's a good substring.
    //       count++;

    // Precompute `zeros_before` array. `zeros_before[i]` stores the count of consecutive '0's
    // immediately preceding index `i`.
    // For example, s = "001001"
    // i:             0 1 2 3 4 5
    // s[i]:          0 0 1 0 0 1
    // zeros_before[i]:
    // i=0: 0 (no char before)
    // i=1: 1 (s[0] is '0')
    // i=2: 2 (s[0], s[1] are '0')
    // i=3: 0 (s[2] is '1')
    // i=4: 1 (s[3] is '0')
    // i=5: 2 (s[3], s[4] are '0')
    std::vector<int> zeros_before(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            zeros_before[i + 1] = zeros_before[i] + 1;
        } else {
            zeros_before[i + 1] = 0;
        }
    }

    for (int k = 0; k < n; ++k) {
        if (s[k] == '1') {
            long long val_suffix = 0;
            // Iterate r from k to min(n-1, k + MAX_L_CHECK).
            // The MAX_L_CHECK here is for the length of the '1'-part (s[k...r]).
            // If len_suffix > MAX_L_CHECK, then val_suffix - len_suffix will be very large.
            // If val_suffix - len_suffix > n, then required_l will be negative.
            // So we can cap r at k + MAX_L_CHECK.
            for (int r = k; r < std::min(n, k + MAX_L_CHECK + 1); ++r) { // +1 to include MAX_L_CHECK length
                val_suffix = (val_suffix << 1) | (s[r] - '0');
                int len_suffix = r - k + 1;

                // If val_suffix becomes too large, further iterations for r will also yield large values.
                // The difference val_suffix - len_suffix will also grow.
                // If val_suffix - len_suffix > n, then required_l will be negative.
                // We can break early if val_suffix - len_suffix exceeds n.
                // This is an optimization.
                if (val_suffix - len_suffix > n) {
                    break;
                }

                long long num_leading_zeros = val_suffix - len_suffix;

                if (num_leading_zeros >= 0) {
                    // Check if there are enough leading zeros before k.
                    // The number of leading zeros required is `num_leading_zeros`.
                    // The available leading zeros before k is `zeros_before[k]`.
                    if (num_leading_zeros <= zeros_before[k]) {
                        count++;
                    }
                }
            }
        }
    }

    std::cout << count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: length of consecutive 0s ending at i
    if (a[0] == 0) L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 0;
        }
    }

    // Calculate R[i]: length of consecutive 0s starting at i
    if (a[n - 1] == 0) R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            int left_zeros = (i > 0) ? L[i - 1] : 0;
            int right_zeros = (i < n - 1) ? R[i + 1] : 0;

            if (left_zeros == 0 && right_zeros == 0) {
                // 1 surrounded by 1s, or at boundary
                // This 1 will never change to 0
            } else if (left_zeros == 0) { // 1...0
                max_k = std::max(max_k, (right_zeros + 1) / 2);
            } else if (right_zeros == 0) { // 0...1
                max_k = std::max(max_k, (left_zeros + 1) / 2);
            } else { // 0...1...0
                max_k = std::max(max_k, std::min(left_zeros, right_zeros));
            }
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> b = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 1) {
            int left_zeros = (i > 0) ? L[i - 1] : 0;
            int right_zeros = (i < n - 1) ? R[i + 1] : 0;

            if (left_zeros == 0 && right_zeros == 0) {
                // 1 surrounded by 1s, or at boundary
                // Stays 1
            } else if (left_zeros == 0) { // 1...0
                if (right_zeros < 2 * max_k) {
                    b[i] = 0;
                }
            } else if (right_zeros == 0) { // 0...1
                if (left_zeros < 2 * max_k) {
                    b[i] = 0;
                }
            } else { // 0...1...0
                if (left_zeros < max_k || right_zeros < max_k) {
                    b[i] = 0;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits are 1
    int current_or_mask = 0;    // All bits are 0
    int current_xor_mask = 0;   // All bits are 0

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_and_mask &= val;
            current_or_mask &= val;
            current_xor_mask &= val;
        } else if (op_char == '|') {
            current_and_mask |= val;
            current_or_mask |= val;
            current_xor_mask |= val;
        } else if (op_char == '^') {
            current_and_mask ^= val;
            current_or_mask ^= val;
            current_xor_mask ^= val;
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // Determine the final operations based on the masks
    // The goal is to transform an initial value 'x' into
    // (x & current_and_mask) | current_or_mask ^ current_xor_mask

    // We need to find A, B, C such that for any bit x_j:
    // (x_j & A_j) | B_j ^ C_j = (x_j & current_and_mask_j) | current_or_mask_j ^ current_xor_mask_j

    // Let's find the equivalent A, B, C for the simplified form:
    // (x & A) | B ^ C

    // A: For bits that become 0 regardless of x, A_j must be 0.
    //    For bits that become 1 regardless of x, A_j can be 0 or 1.
    //    For bits that follow x, A_j must be 1.
    //    A_j = 1 if (0 -> 0 and 1 -> 1)
    //    A_j = 0 if (0 -> 0 and 1 -> 0) or (0 -> 1 and 1 -> 1) or (0 -> 1 and 1 -> 0)

    // Let's determine the final state for input 0 and input 1023 (all bits 1).
    // For input 0:
    // (0 & current_and_mask) | current_or_mask ^ current_xor_mask
    // = 0 | current_or_mask ^ current_xor_mask
    // = current_or_mask ^ current_xor_mask
    int val_for_0 = current_or_mask ^ current_xor_mask;

    // For input 1023 (all bits 1):
    // (1023 & current_and_mask) | current_or_mask ^ current_xor_mask
    // = current_and_mask | current_or_mask ^ current_xor_mask
    int val_for_1023 = current_and_mask | current_or_mask ^ current_xor_mask;

    // Now we need to find A, B, C such that:
    // (0 & A) | B ^ C = val_for_0
    // (1023 & A) | B ^ C = val_for_1023

    // From the first equation: B ^ C = val_for_0
    // Substitute into the second: (1023 & A) | val_for_0 = val_for_1023

    // Let's find A, B, C bit by bit.
    // For each bit j (0 to 9):
    // Let x_j be the j-th bit of input x.
    // Let a_j, b_j, c_j be the j-th bits of A, B, C.
    // The final j-th bit is (x_j & a_j) | b_j ^ c_j.

    // Let f_j(0) be the j-th bit of val_for_0.
    // Let f_j(1) be the j-th bit of val_for_1023.

    // We have:
    // (0 & a_j) | b_j ^ c_j = f_j(0)  =>  b_j ^ c_j = f_j(0)
    // (1 & a_j) | b_j ^ c_j = f_j(1)  =>  a_j | (b_j ^ c_j) = f_j(1)

    // So, a_j | f_j(0) = f_j(1).
    // This implies:
    // If f_j(0) = 0: a_j | 0 = f_j(1) => a_j = f_j(1).
    // If f_j(0) = 1: a_j | 1 = f_j(1) => f_j(1) must be 1. If f_j(1) is 0, this is impossible.
    //                                    If f_j(1) is 1, a_j can be 0 or 1. We choose a_j=0 to minimize operations.

    // Let's construct A, B, C.
    int A_final = 0;
    int B_final = 0;
    int C_final = 0;

    for (int j = 0; j < 10; ++j) {
        int f0_j = (val_for_0 >> j) & 1;
        int f1_j = (val_for_1023 >> j) & 1;

        int a_j, b_j, c_j;

        if (f0_j == 0) { // b_j ^ c_j = 0 => b_j = c_j
            a_j = f1_j;  // a_j | 0 = f1_j => a_j = f1_j
            b_j = 0;     // Choose b_j = 0, then c_j = 0
            c_j = 0;
        } else { // f0_j = 1 => b_j ^ c_j = 1 => b_j != c_j
            // a_j | 1 = f1_j. This implies f1_j must be 1.
            // If f1_j is 0, it's an error in logic, but it won't happen because
            // (x & current_and_mask) | current_or_mask ^ current_xor_mask
            // For x=0, it's current_or_mask ^ current_xor_mask
            // For x=1023, it's current_and_mask | current_or_mask ^ current_xor_mask
            // The j-th bit of current_and_mask | current_or_mask ^ current_xor_mask
            // is always >= j-th bit of current_or_mask ^ current_xor_mask
            // because a_j | 1 = 1.
            // So f1_j will always be 1 if f0_j is 1.
            a_j = 0; // Choose a_j = 0 to simplify.
            b_j = 1; // Choose b_j = 1, then c_j = 0
            c_j = 0;
        }

        A_final |= (a_j << j);
        B_final |= (b_j << j);
        C_final |= (c_j << j);
    }

    // The operations are: (x & A_final) | B_final ^ C_final
    // This can be simplified to:
    // (x & A_final) | (B_final ^ C_final)
    // Let B_prime = B_final ^ C_final.
    // So, (x & A_final) | B_prime.
    // This is equivalent to:
    // x & A_final
    // | B_prime

    // Let's re-evaluate A_final, B_final, C_final based on the derived logic.
    // We want to find A, B, C such that for each bit j:
    // (x_j & A_j) | B_j ^ C_j = (x_j & current_and_mask_j) | current_or_mask_j ^ current_xor_mask_j

    // Let's define the target function for each bit:
    // f_j(x_j) = (x_j & current_and_mask_j) | current_or_mask_j ^ current_xor_mask_j
    // f_j(0) = current_or_mask_j ^ current_xor_mask_j
    // f_j(1) = current_and_mask_j | current_or_mask_j ^ current_xor_mask_j

    // We need to find A_j, B_j, C_j such that:
    // (0 & A_j) | B_j ^ C_j = f_j(0)  => B_j ^ C_j = f_j(0)
    // (1 & A_j) | B_j ^ C_j = f_j(1)  => A_j | (B_j ^ C_j) = f_j(1)

    // So, A_j | f_j(0) = f_j(1).
    // This means A_j must be 1 if f_j(0) = 0 and f_j(1) = 1.
    // Otherwise, A_j can be 0.
    // A_j = f_j(1) & (~f_j(0))  (This is wrong, A_j is 1 if f_j(0)=0 and f_j(1)=1)
    // A_j = (f_j(1) == 1 && f_j(0) == 0) ? 1 : 0;
    // This is equivalent to A_j = f_j(1) & (~f_j(0)) if we consider f_j(0) and f_j(1) as bits.
    // A_j = f_j(1) AND (NOT f_j(0))

    // Let's reconstruct A, B, C.
    int final_A = 0; // This will be the constant for '&'
    int final_B = 0; // This will be the constant for '|'
    int final_C = 0; // This will be the constant for '^'

    for (int j = 0; j < 10; ++j) {
        int bit_f0 = (val_for_0 >> j) & 1;
        int bit_f1 = (val_for_1023 >> j) & 1;

        // Determine A_j
        int a_j = 0;
        if (bit_f0 == 0 && bit_f1 == 1) {
            a_j = 1;
        }
        final_A |= (a_j << j);

        // Determine B_j and C_j such that B_j ^ C_j = bit_f0
        // We can choose B_j = bit_f0 and C_j = 0.
        final_B |= (bit_f0 << j);
        // C_j remains 0.
    }

    // The sequence of operations is:
    // x & final_A
    // | final_B
    // ^ final_C (which is 0, so this operation is effectively skipped)

    // So we have at most two operations:
    // 1. & final_A
    // 2. | final_B

    // If final_A is 1023 (all bits 1), then '& 1023' is identity.
    // If final_B is 0 (all bits 0), then '| 0' is identity.

    // Let's check if we can simplify further.
    // The target function for each bit is:
    // f_j(x_j) = (x_j & a_j) | b_j
    // where a_j is the j-th bit of final_A, b_j is the j-th bit of final_B.

    // Case 1: f_j(0) = 0, f_j(1) = 0
    //   (0 & a_j) | b_j = 0 => b_j = 0
    //   (1 & a_j) | b_j = 0 => a_j | 0 = 0 => a_j = 0
    //   So, a_j = 0, b_j = 0. This means (x_j & 0) | 0 = 0.

    // Case 2: f_j(0) = 0, f_j(1) = 1
    //   (0 & a_j) | b_j = 0 => b_j = 0
    //   (1 & a_j) | b_j = 1 => a_j | 0 = 1 => a_j = 1
    //   So, a_j = 1, b_j = 0. This means (x_j & 1) | 0 = x_j.

    // Case 3: f_j(0) = 1, f_j(1) = 0
    //   (0 & a_j) | b_j = 1 => b_j = 1
    //   (1 & a_j) | b_j = 0 => a_j | 1 = 0. IMPOSSIBLE.
    // This means the target function cannot be represented as (x & A) | B.
    // This is where XOR comes in.

    // The general form is (x & A) | B ^ C.
    // Let's use the approach from the problem statement's note:
    // Any sequence of operations can be reduced to the form (x & A) | B ^ C.
    // This is because:
    // (x & A) | B ^ C & D = (x & A & D) | (B & D) ^ (C & D)
    // (x & A) | B ^ C | D = (x & A) | (B | D) ^ (C & ~D)
    // (x & A) | B ^ C ^ D = (x & A) | B ^ (C ^ D)

    // Let's track the state of two values:
    // `val0`: what 0 becomes after all operations.
    // `val1`: what 1023 becomes after all operations.
    // These are `val_for_0` and `val_for_1023` calculated above.

    // We need to find A, B, C such that:
    // (0 & A) | B ^ C = val_for_0
    // (1023 & A) | B ^ C = val_for_1023

    // From the first equation: B ^ C = val_for_0
    // From the second equation: A | (B ^ C) = val_for_1023
    // Substituting: A | val_for_0 = val_for_1023

    // Now we need to find A, B, C.
    // A: For each bit j, A_j | val_for_0_j = val_for_1023_j
    //    If val_for_0_j = 0: A_j = val_for_1023_j
    //    If val_for_0_j = 1: val_for_1023_j must be 1. A_j can be 0 or 1. We choose A_j = 0 to simplify.
    // So, A_j = val_for_1023_j & (~val_for_0_j)
    int A_val = val_for_1023 & (~val_for_0);

    // B and C: B ^ C = val_for_0.
    // We can choose B = val_for_0 and C = 0.
    int B_val = val_for_0;
    int C_val = 0;

    // So the operations are:
    // & A_val
    // | B_val
    // ^ C_val (which is 0, so this is skipped)

    // This gives at most 2 operations: & A_val, | B_val.
    // This is the standard reduction for (x & A) | B.
    // But the problem states (x & A) | B ^ C.
    // The form (x & A) | B ^ C is more general.
    // Let's re-evaluate the final operations.

    // The final state of each bit j can be one of four functions of x_j:
    // 1. f(x_j) = 0 (constant 0)
    // 2. f(x_j) = 1 (constant 1)
    // 3. f(x_j) = x_j (identity)
    // 4. f(x_j) = ~x_j (negation)

    // Let's determine which of these 4 functions each bit j follows.
    // f_j(0) = (val_for_0 >> j) & 1
    // f_j(1) = (val_for_1023 >> j) & 1

    // For each bit j:
    // If f_j(0) = 0, f_j(1) = 0: bit j is always 0.
    // If f_j(0) = 1, f_j(1) = 1: bit j is always 1.
    // If f_j(0) = 0, f_j(1) = 1: bit j is x_j.
    // If f_j(0) = 1, f_j(1) = 0: bit j is ~x_j.

    // We can construct three constants:
    // AND_CONST: has 0 for bits that are always 0, or ~x_j. Has 1 for bits that are always 1 or x_j.
    // OR_CONST: has 1 for bits that are always 1. Has 0 for bits that are always 0, x_j, or ~x_j.
    // XOR_CONST: has 1 for bits that are ~x_j or always 1 (if OR_CONST is 0). Has 0 for bits that are x_j or always 0.

    // Let's use the standard reduction to (x & A) | B ^ C.
    // A = 0; B = 0; C = 0;
    // For each bit j from 0 to 9:
    //   int bit_0_result = (val_for_0 >> j) & 1;
    //   int bit_1_result = (val_for_1023 >> j) & 1;

    //   If bit_0_result == 0 && bit_1_result == 0: // Bit is always 0
    //     A_j = 0, B_j = 0, C_j = 0
    //   If bit_0_result == 0 && bit_1_result == 1: // Bit is x_j
    //     A_j = 1, B_j = 0, C_j = 0
    //   If bit_0_result == 1 && bit_1_result == 0: // Bit is ~x_j
    //     A_j = 1, B_j = 0, C_j = 1
    //   If bit_0_result == 1 && bit_1_result == 1: // Bit is always 1
    //     A_j = 0, B_j = 1, C_j = 0

    // Let's build A, B, C based on this.
    int final_A_val = 0;
    int final_B_val = 0;
    int final_C_val = 0;

    for (int j = 0; j < 10; ++j) {
        int bit_0_res = (val_for_0 >> j) & 1;
        int bit_1_res = (val_for_1023 >> j) & 1;

        if (bit_0_res == 0 && bit_1_res == 0) { // Always 0
            // A_j=0, B_j=0, C_j=0
        } else if (bit_0_res == 0 && bit_1_res == 1) { // x_j
            final_A_val |= (1 << j); // A_j=1, B_j=0, C_j=0
        } else if (bit_0_res == 1 && bit_1_res == 0) { // ~x_j
            final_A_val |= (1 << j); // A_j=1, B_j=0, C_j=1
            final_C_val |= (1 << j);
        } else { // bit_0_res == 1 && bit_1_res == 1: // Always 1
            final_B_val |= (1 << j); // A_j=0, B_j=1, C_j=0
        }
    }

    // Now, add operations if their constants are non-trivial.
    // The order is important: AND, then OR, then XOR.
    if (final_A_val != 1023) { // If A is not all 1s, we need an AND operation
        result_ops.push_back({'&', final_A_val});
    }
    if (final_B_val != 0) { // If B is not all 0s, we need an OR operation
        result_ops.push_back({'|', final_B_val});
    }
    if (final_C_val != 0) { // If C is not all 0s, we need an XOR operation
        result_ops.push_back({'^', final_C_val});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // delta_sum[i] stores the sum of d values applied to index i by all type 1 operations.
    // This is used to calculate the final value of a[i] if initial a_0[i] was 0.
    std::vector<long long> delta_sum(n, 0);

    // initial_a[i] stores the value of a_0[i] that we are trying to find.
    // Initialize with a very small value to ensure max constraints are met.
    // The problem states |a_i| <= 10^9, so -10^9 is a valid initial value.
    std::vector<long long> initial_a(n, -1000000000LL); 

    // Process operations in reverse to determine initial_a values.
    // For type 2 operations (max constraint), we need to ensure that
    // initial_a[j] + delta_sum[j] <= m_i for all j in [l_i, r_i].
    // This means initial_a[j] <= m_i - delta_sum[j].
    // We take the minimum of these upper bounds for each initial_a[j].
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If it's a type 1 operation (add d), it means this d was applied
            // to elements in [l, r] *before* this point in time.
            // So, for future calculations (which are effectively earlier in time),
            // this d should be subtracted from the running delta_sum.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                delta_sum[j] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // If it's a type 2 operation (max query), it means max(a[j]) = m_i
            // for j in [l, r] at this point in time.
            // The current value of a[j] is initial_a[j] + delta_sum[j].
            // So, initial_a[j] + delta_sum[j] <= ops[i].val (m_i) for all j in [l, r].
            // This implies initial_a[j] <= ops[i].val - delta_sum[j].
            // We update initial_a[j] with the minimum of its current value and this new upper bound.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - delta_sum[j]);
            }
        }
    }

    // Check if the found initial_a satisfies all constraints by simulating operations.
    // current_a will store the array values as operations are applied.
    std::vector<long long> current_a = initial_a;

    // current_delta_prefix_sum[i] stores the sum of d values applied to index i
    // by type 1 operations up to the current point in the forward simulation.
    // This is used to efficiently calculate current_a[j] for type 2 checks.
    std::vector<long long> current_delta_prefix_sum(n + 1, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Apply the range add operation to the prefix sum array.
            current_delta_prefix_sum[ops[i].l] += ops[i].val;
            if (ops[i].r + 1 < n) {
                current_delta_prefix_sum[ops[i].r + 1] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            long long max_val = LLONG_MIN;
            long long current_delta_val = 0; // Actual delta for current index
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta_val += current_delta_prefix_sum[j];
                max_val = std::max(max_val, initial_a[j] + current_delta_val);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // If all checks pass, print YES and the initial array.
    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

