#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0 && open_needed < k / 2) { // Only add ')' if there's a matching '(' already added or available
            result += ')';
            close_needed--;
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <list>

struct Child {
    long long v, d, p;
    int original_idx;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::list<Child> children_in_line;
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_in_line.push_back({v_val, d_val, p_val, i + 1});
    }

    std::vector<int> cured_children_indices;

    while (!children_in_line.empty()) {
        Child current_doctor_child = children_in_line.front();
        children_in_line.pop_front();
        cured_children_indices.push_back(current_doctor_child.original_idx);

        long long v_cry_effect = current_doctor_child.v;
        long long d_cry_total_effect = 0;

        auto it = children_in_line.begin();
        while (it != children_in_line.end()) {
            // Apply d_cry_total_effect from previous children who left
            it->p -= d_cry_total_effect;

            // Apply v_cry_effect from the child currently at the doctor
            if (v_cry_effect > 0) {
                it->p -= v_cry_effect;
                v_cry_effect--;
            }

            if (it->p < 0) {
                d_cry_total_effect += it->d;
                it = children_in_line.erase(it); // Child leaves, iterator invalidated
            } else {
                ++it; // Move to the next child
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

