// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k = 1
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;

        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2
    // If k=1 didn't work, we need to check if k=2 is always possible,
    // or if there are cases where it's impossible.
    // The only case where k=2 might not work is if all characters in s are the same.
    // If s consists of all identical characters (e.g., "aaaa", "qqqq"),
    // then any permutation of its substrings will result in the same string "aaaa".
    // For example, "aa|aa" -> "aaaa", "a|a|a|a" -> "aaaa".
    // In this case, it's impossible to form a new string s' != s.

    // Check if all characters in s are the same
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 is always possible.
        // Example: s = "nolon"
        // Cut: "no" | "l" | "on"
        // Rearrange: "on" | "l" | "no" -> "onlno" (palindrome, != "nolon")
        // This strategy works for any palindrome that is not all same characters.
        // The middle character (if N is odd) or middle two characters (if N is even)
        // will be different from the ends, allowing a swap.
        // For example, take s[0...N/2-1] | s[N/2] | s[N/2+1...N-1] (for odd N)
        // or s[0...N/2-1] | s[N/2...N-1] (for even N)
        // If s is not all same characters, then s[0...N/2-1] is not all same characters.
        // Or s[0] != s[N/2] for odd N.
        // Consider s = "abacaba". N=7.
        // s1 = "aba", s2 = "c", s3 = "aba".
        // s' = s3 + s2 + s1 = "abacaba" (same)
        // But we can do s1 = s[0...N/2-1], s2 = s[N/2...N-1].
        // s = "nolon". N=5.
        // s1 = "no", s2 = "lon". s' = "lonno". Not palindrome.
        // s1 = "nol", s2 = "on". s' = "onnol". Not palindrome.
        // The problem statement guarantees that if k=1 doesn't work, k=2 is the answer
        // unless it's impossible. The only impossible case is when all characters are the same.
        std::cout << 2 << std::endl;
    }

    return 0;
}

