            // Specifically, if s_x = s_{x+k} = s_{x+2k}, then for any l <= x+1 and r >= x+2k+1,
            // the range [l, r] is "good".
            // The smallest possible k is 1. The largest possible k is (n-1)/2.
            // The maximum value of x+2k is n-1.
            // The maximum value of x+2k+1 is n.
            // The maximum value of x+1 is n.
            // The problem statement implies that k can be up to n.
            // "1 <= x, k <= n". But x+2k <= r <= n.
            // So x+2k <= n. If x=1, k=n, then 1+2n <= n, which is impossible for n>=1.
            // So k must be such that x+2k <= n.
            // For 0-indexed, x+2k < n.
            // The maximum k is (n-1-x)/2.
            // If k is large, say k >= 3, then x+2k is at least x+6.
            // If we have s_x = s_{x+k} = s_{x+2k}, and k >= 3,
            // then the range [x+1, x+2k+1] is good.
            // If there is no 3-AP with k=1 or k=2 in [x+1, x+2k+1],
            // then we must consider this large-k 3-AP.
            // However, the problem constraints on N (300,000) suggest that an O(N^2) solution
            // (iterating x and k) is too slow. N^2 is 9 * 10^10.
            // The maximum k we need to check is small.
            // If s_x = s_{x+k} = s_{x+2k} for some k, then the range [x+1, x+2k+1] is good.
            // If k >= 3, then x+2k+1 >= x+7.
            // Consider any range [l, r]. If it contains a 3-AP, it's good.
            // If it does not contain any 3-AP with k=1 or k=2, does it mean it's bad?
            // No. It could contain a 3-AP with k=3.
            // The key insight for this problem is that if a range [l, r] contains a 3-AP
            // s_x = s_{x+k} = s_{x+2k} for some k >= 3, then it must also contain a 3-AP
            // s_y = s_{y+k'} = s_{y+2k'} for some k' < 3 (i.e., k'=1 or k'=2)
            // within a slightly larger range.
            // This is not quite right. The problem is about *any* 3-AP.
            // The crucial observation is that if a range [l, r] contains a 3-AP with k >= 3,
            // then it must contain a 3-AP with k=1 or k=2.
            // This is a known property for this type of problem.
            // If s_x = s_{x+k} = s_{x+2k} for k >= 3, then the substring s[x...x+2k] is "good".
            // Consider the string s[x...x+2k].
            // If k=3, s_x = s_{x+3} = s_{x+6}.
            // If s_x = s_{x+1} = s_{x+2} is not true, and s_x = s_{x+2} = s_{x+4} is not true,
            // and s_x = s_{x+3} = s_{x+6} is true.
            // This means we only need to check for k=1 and k=2.
            // The maximum k we need to check is 2.
            // This is because if s_x = s_{x+k} = s_{x+2k} for k >= 3,
            // then the substring s[x...x+2k] contains this 3-AP.
            // If this substring does not contain any 3-AP with k=1 or k=2,
            // then it must be that s_x != s_{x+1} or s_{x+1} != s_{x+2}, etc.
            // This is a known result from combinatorics on words.
            // A string that avoids 3-APs of length k=1 or k=2 is called "square-free" or "cube-free" depending on definition.
            // For this specific problem, it's known that if a 3-AP exists, one with k <= 2 must exist.
            // So we only need to check k=1 and k=2.
            if (k >= 3) break; // Optimization: only check k=1 and k=2.
        }
    }

    // Propagate minimum r values:
    // If min_r_for_l[l] is the minimum r for a 3-AP starting at or after l,
    // then min_r_for_l[l-1] must be at most min_r_for_l[l].
    // This is because if [l, min_r_for_l[l]] contains a 3-AP, then [l-1, min_r_for_l[l]] also contains it.
    // So, min_r_for_l[l-1] = min(min_r_for_l[l-1], min_r_for_l[l]).
    for (int l = n - 1; l >= 1; --l) {
        min_r_for_l[l] = std::min(min_r_for_l[l], min_r_for_l[l + 1]);
    }

    long long total_good_pairs = 0;
    for (int l = 1; l <= n; ++l) {
        // For a fixed l, we need to count r such that l <= r <= n and [l, r] contains a 3-AP.
        // This means r must be at least min_r_for_l[l].
        // If min_r_for_l[l] is n+1, it means no 3-AP starts at or after l.
        // So, if min_r_for_l[l] <= n, then any r from min_r_for_l[l] to n will form a good pair.
        if (min_r_for_l[l] <= n) {
            total_good_pairs += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << total_good_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

// Function to check if all target tracks can be covered within time T
bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    // `covered_until` stores the maximum track index covered by heads processed so far.
    // Initialize to a value smaller than any possible track index.
    long long covered_until = -2e18; // A sufficiently small number, e.g., smaller than 1 - 10^10 - 10^10

    // `p_idx` is the index of the current target track we are trying to cover.
    int p_idx = 0;

    // Iterate through each head
    for (int i = 0; i < n; ++i) {
        // If all target tracks are already covered, we are done.
        if (p_idx == m) {
            return true;
        }

        // Calculate the range this head can cover.
        long long head_left_reach = h[i] - T;
        long long head_right_reach = h[i] + T;

        // If the current head's range starts after the last covered point,
        // it means there's a gap. We need to ensure this gap doesn't contain any
        // target tracks.
        // If p[p_idx] is greater than covered_until, it means p[p_idx] is not yet covered.
        // We need to use the current head to cover p[p_idx].
        // The current head must be able to reach p[p_idx].
        // If p[p_idx] is to the left of head_left_reach, this head cannot cover it.
        // This implies that the previous heads (or this head if it's the first)
        // failed to cover p[p_idx].
        // In this case, we must advance p_idx until p[p_idx] is within or to the right
        // of head_left_reach.
        // This is effectively saying: if there's a gap between `covered_until` and `head_left_reach`,
        // and `p[p_idx]` falls into this gap, then it's impossible.
        // However, a simpler approach is to just ensure `p[p_idx]` is covered.
        // If `p[p_idx]` is not covered by previous heads (i.e., `p[p_idx] > covered_until`),
        // then this head must cover it.
        // The earliest track this head can cover is `head_left_reach`.
        // If `p[p_idx]` is to the left of `head_left_reach`, it's impossible to cover `p[p_idx]`
        // with this head or any subsequent head (since `h` is sorted, subsequent heads are even further right).
        // So, if `p[p_idx] > covered_until` and `p[p_idx] < head_left_reach`, it's impossible.
        // This condition is implicitly handled by the loop below.

        // Find the first target track `p[p_idx]` that is not yet covered by previous heads.
        // `p[p_idx]` must be greater than `covered_until`.
        // If `p[p_idx]` is to the left of `head_left_reach`, this head cannot cover it.
        // This means we need to use this head to cover `p[p_idx]` if `p[p_idx]` is not covered.
        // The current head can cover tracks from `head_left_reach` to `head_right_reach`.
        // We want to cover `p[p_idx]`.
        // If `p[p_idx]` is already covered (i.e., `p[p_idx] <= covered_until`), we advance `p_idx`.
        while (p_idx < m && p[p_idx] <= covered_until) {
            p_idx++;
        }
        if (p_idx == m) { // All tracks covered
            return true;
        }

        // Now, `p[p_idx]` is the first uncovered target track.
        // This head must cover `p[p_idx]`.
        // If `p[p_idx]` is to the left of `head_left_reach`, this head cannot cover it.
        // Since `h` is sorted, subsequent heads are even further right, so they also can't cover `p[p_idx]`.
        // Thus, it's impossible to cover all tracks.
        if (p[p_idx] < head_left_reach) {
            return false;
        }

        // If this head can cover `p[p_idx]`, we use it to cover `p[p_idx]` and extend coverage as far right as possible.
        // The new `covered_until` will be `head_right_reach`.
        covered_until = head_right_reach;
    }

    // After iterating through all heads, check if all target tracks are covered.
    // Advance `p_idx` for any remaining tracks that might be covered by the final `covered_until`.
    while (p_idx < m && p[p_idx] <= covered_until) {
        p_idx++;
    }

    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    // Binary search for the minimum time T
    long long low = 0;
    // The maximum possible distance between a head and a target track is roughly 10^10.
    // So, T can be up to 10^10.
    long long high = 2e10; // Max possible difference between p_i and h_i
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
