        }

        // The problem statement guarantees that a solution exists.
        // Reversing the permutation always produces a different permutation
        // (unless n=1, but n >= 2) and results in the same set of adjacent sums.
        // Since the fingerprint is the sorted array of these sums,
        // reversing the permutation will always yield the same fingerprint.
        // For n=2, p=[1,2] -> p'=[2,1]. F(p)=[3], F(p')=[3].
        // For n > 2, a reversed permutation is always different from the original
        // unless the original permutation is a palindrome (e.g., [1,2,1] not a perm, [1,2,3,2,1] not a perm).
        // A permutation of distinct integers from 1 to n cannot be a palindrome
        // unless n=1 (not allowed) or n=0 (not allowed).
        // For example, if p = [p_1, p_2, ..., p_n] and p_rev = [p_n, ..., p_2, p_1]
        // are the same, then p_1 = p_n, p_2 = p_{n-1}, etc.
        // But p_1 and p_n must be distinct if n > 1.
        // So, reversing a permutation of distinct elements always yields a different permutation.

        std::reverse(p.begin(), p.end());

        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

