#include <limits>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    long long min_val = std::numeric_limits<long long>::max();
    int min_idx = -1;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < min_val) {
            min_val = a[i];
            min_idx = i;
        }
    }

    long long total_spells = 0;
    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue;
        }
        // For each other pile a[i], we can add min_val to it as many times as possible
        // without exceeding k.
        // The number of times is floor((k - a[i]) / min_val).
        // This is because a[i] + x * min_val <= k
        // x * min_val <= k - a[i]
        // x <= (k - a[i]) / min_val
        // Since x must be an integer, x = floor((k - a[i]) / min_val)
        total_spells += (k - a[i]) / min_val;
    }

    std::cout << total_spells << std::endl;
}

