    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // The number 2 followed by (n-1) occurrences of 3 works.
        // Example: n=2 -> 23
        //          n=3 -> 233
        //          n=4 -> 2333
        //
        // Let s = 233...3 (n-1 times 3).
        //
        // 1. s > 0: True.
        // 2. s consists of n digits: True, first digit 2, then n-1 digits 3.
        // 3. No digit in s equals 0: True, only digits are 2 and 3.
        // 4. s is not divisible by any of its digits:
        //    Digits are 2 and 3.
        //    Is s divisible by 2? No, because s ends in 3 (odd).
        //    Is s divisible by 3?
        //    The sum of digits is 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        //    For s to be divisible by 3, its sum of digits (3n - 1) must be divisible by 3.
        //    However, 3n is always divisible by 3, so 3n - 1 is never divisible by 3.
        //    Thus, s is not divisible by 3.
        //
        // Since s is not divisible by 2 and not divisible by 3, it satisfies all conditions.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

