    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        std::map<int, int> counts;
        for (int i = 0; i < n; ++i) {
            int s_val;
            std::cin >> s_val;
            if (s_val <= 2048) {
                counts[s_val]++;
            }
        }

        int current_sum = 0;
        for (auto const& [val, count] : counts) {
            // Add the total value contributed by this power of two
            // to the current_sum, but only up to 2048.
            // If we have 'count' copies of 'val', they contribute 'count * val'
            // to the total sum of numbers that can be combined.
            // We are interested in whether this sum can reach 2048.
            // The problem is not about sum, but about forming 2048.
            // Let's re-think.
            // We can simulate the combining process.
            // Start with the smallest powers of two.
            // If we have 'count' copies of 'val', we can form 'count / 2' copies of '2*val'.
            // The remaining 'count % 2' copies of 'val' are left over.
            // This is a greedy approach.
        }

        // A better approach: simulate the 2048 game logic.
        // We only care about numbers up to 2048.
        // Numbers larger than 2048 are useless.
        // We want to accumulate a sum of numbers that can be combined to form 2048.
        // If we have a 1, it contributes 1 to the potential sum.
        // If we have a 2, it contributes 2.
        // If we have a 4, it contributes 4.
        // ...
        // If we have a 1024, it contributes 1024.
        // The total sum of all numbers <= 2048 in the multiset
        // represents the maximum possible value we can form by combining them.
        // If this sum is >= 2048, then we can definitely form 2048.
        // Why? Because any combination operation (x, x -> 2x) preserves the sum.
        // If we have a multiset {1, 1, 2}, sum is 4. We can make {2, 2}, sum is 4. Then {4}, sum is 4.
        // If the initial sum of numbers <= 2048 is S, and S >= 2048,
        // we can always combine numbers until we have at most one of each power of two,
        // plus possibly some numbers greater than 2048.
        // If the sum is S, and S >= 2048, we can always form 2048.
        // Example: {1024, 512, 512, 4}. Sum = 1024 + 512 + 512 + 4 = 2052.
        // 512, 512 -> 1024. Multiset becomes {1024, 1024, 4}.
        // 1024, 1024 -> 2048. Multiset becomes {2048, 4}. Win.
        // This logic seems correct. The sum of all numbers less than or equal to 2048
        // is the total "value" we have available to combine.
        // If this total value is 2048 or more, we can always form 2048.
        // If it's less than 2048, we can never form 2048 because combining operations
        // preserve the sum of the elements.

        long long total_val_up_to_2048 = 0;
        for (auto const& [val, count] : counts) {
            total_val_up_to_2048 += (long long)val * count;
        }

        if (total_val_up_to_2048 >= 2048) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }
    return 0;
}

