#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it was already made equal.
            // The flags `has_pos_one` and `has_neg_one` reflect the state of elements
            // *before* index `i`.
            if (a[i] == 1) has_pos_one = true; // This element itself is a 1
            if (a[i] == -1) has_neg_one = true; // This element itself is a -1
            continue;
        }

        // If a[i] != b[i], we need to change a[i].
        // The change must come from elements a[k] where k < i.
        // The current a[i] is the original a[i] plus any modifications from a[k] (k < i).
        // However, the problem states "Add a_i to a_j". This means the *current* value of a_i
        // is added to a_j. But the problem example implies original values.
        // "Add a_i to a_j. In other words, j-th element of the array becomes equal to a_i + a_j."
        // This is ambiguous. Let's assume the standard interpretation in competitive programming:
        // `a_j` becomes `a_j + (original a_i)`. If it were `a_j + (current a_i)`, it would be much harder.
        // The example "transform [1, -1, 0] to [1, -1, -2]" by (2,3) twice.
        // Original a_2 = -1. a_3 = 0.
        // First op: a_3 = a_3 + a_2 = 0 + (-1) = -1. Array is [1, -1, -1].
        // Second op: a_3 = a_3 + a_2 = -1 + (-1) = -2. Array is [1, -1, -2].
        // This confirms that `a_i` refers to its *original* value.
        // So, the `has_pos_one` and `has_neg_one` flags should track if there was an original 1 or -1
        // at an index `k < i`.

        if (b[i] > a[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // b[i] < a[i], need to decrease a[i]
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // After processing a[i], update flags for elements to its left.
        // This element a[i] itself can be used to modify elements a[k] where k > i.
        // But we are iterating from right to left, so we are considering elements
        // that are *not* modified by a[i].
        // The flags `has_pos_one` and `has_neg_one` should reflect the presence of
        // original 1s and -1s in `a[0...i-1]`.
        // When we move from `i` to `i-1`, the element `a[i-1]` becomes the new `a[i]`.
        // So, we update the flags based on `a[i-1]` (the original value).
        if (a[i] == 1) has_pos_one = true;
        if (a[i] == -1) has_neg_one = true;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // With 2n students, if we sort them as a_0, a_1, ..., a_{2n-1},
        // the optimal strategy is to pick the median of the first class as a_{n-1}
        // and the median of the second class as a_n.
        // This is because if we pick a_i as the median of the first class,
        // it must have i elements smaller than or equal to it, and 2n-1-i elements
        // larger than or equal to it.
        // To form a class of size 2k+1 with median a_i, we need k elements <= a_i
        // and k elements >= a_i.
        // The smallest possible median for a class is a_0 (class [a_0]).
        // The largest possible median for a class is a_{2n-1} (class [a_{2n-1}]).
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        // The two medians will be some a_i and a_j.
        // To minimize |a_i - a_j|, we want i and j to be as close as possible.
        //
        // Let the first class have size $2k_1+1$ and median $M_1$.
        // Let the second class have size $2k_2+1$ and median $M_2$.
        // We know $k_1+k_2 = n-1$.
        //
        // The elements $a_0, \dots, a_{n-1}$ are the $n$ smallest elements.
        // The elements $a_n, \dots, a_{2n-1}$ are the $n$ largest elements.
        //
        // If we choose $M_1 = a_{n-1}$ and $M_2 = a_n$,
        // we can form a class $C_1$ with median $a_{n-1}$ and a class $C_2$ with median $a_n$.
        // For $C_1$ with median $a_{n-1}$:
        // We need $k_1$ elements $\le a_{n-1}$ and $k_1$ elements $\ge a_{n-1}$.
        // We can pick $a_{n-1}$ itself.
        // We can pick $k_1$ elements from $a_0, \dots, a_{n-2}$ (there are $n-1$ such elements).
        // We can pick $k_1$ elements from $a_n, \dots, a_{2n-1}$ (there are $n$ such elements).
        //
        // For $C_2$ with median $a_n$:
        // We need $k_2$ elements $\le a_n$ and $k_2$ elements $\ge a_n$.
        // We can pick $a_n$ itself.
        // We can pick $k_2$ elements from $a_0, \dots, a_{n-1}$ (there are $n$ such elements).
        // We can pick $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$ (there are $n-1$ such elements).
        //
        // The total number of elements available for $C_1$ (excluding $a_{n-1}$) is $2n-1$.
        // The total number of elements available for $C_2$ (excluding $a_n$) is $2n-1$.
        //
        // We need to show that it's always possible to construct such classes.
        // Let $M_1 = a_{n-1}$ and $M_2 = a_n$.
        // We need to partition the remaining $2n-2$ students into two sets,
        // one for $C_1$ (size $2k_1$) and one for $C_2$ (size $2k_2$).
        // The elements $a_0, \dots, a_{n-2}$ are all $\le a_{n-1}$. There are $n-1$ such elements.
        // The elements $a_{n+1}, \dots, a_{2n-1}$ are all $\ge a_n$. There are $n-1$ such elements.
        // The elements $a_0, \dots, a_{n-2}$ can serve as smaller elements for $C_1$ or $C_2$.
        // The elements $a_{n+1}, \dots, a_{2n-1}$ can serve as larger elements for $C_1$ or $C_2$.
        //
        // Consider the elements $a_0, \dots, a_{n-2}$ (call this set $S_L$, size $n-1$)
        // and $a_{n+1}, \dots, a_{2n-1}$ (call this set $S_R$, size $n-1$).
        //
        // We need to pick $k_1$ elements from $S_L \cup S_R$ that are $\le a_{n-1}$ for $C_1$.
        // We need to pick $k_1$ elements from $S_L \cup S_R$ that are $\ge a_{n-1}$ for $C_1$.
        // We need to pick $k_2$ elements from $S_L \cup S_R$ that are $\le a_n$ for $C_2$.
        // We need to pick $k_2$ elements from $S_L \cup S_R$ that are $\ge a_n$ for $C_2$.
        //
        // The simplest partition is to make $C_1$ of size $1$ and $C_2$ of size $2n-1$.
        // If $k_1=0$, $C_1 = \{a_{n-1}\}$. Median is $a_{n-1}$.
        // Then $k_2 = n-1$. $C_2$ needs $n-1$ elements $\le a_n$ and $n-1$ elements $\ge a_n$.
        // We have $a_0, \dots, a_{n-2}$ ($n-1$ elements) which are all $\le a_n$.
        // We have $a_{n+1}, \dots, a_{2n-1}$ ($n-1$ elements) which are all $\ge a_n$.
        // So we can form $C_2 = \{a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This class has size $(n-1)+1+(n-1) = 2n-1$. Its median is $a_n$.
        //
        // This construction is always possible.
        // The minimum difference is $a_n - a_{n-1}$.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a vector to store prices.
        // For N up to 150000, a vector is efficient.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        if (n <= 1) {
            // If there's only one day or no days, no price can be "bad"
            // because there are no later days.
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix with the last price.
        // This variable will store the minimum price encountered
        // in the suffix of the array processed so far (from right to left).
        int min_suffix = a[n - 1];

        // Iterate from the second to last element backwards to the first element.
        // For each a[i], we compare it with the minimum price found *after* it.
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix) {
                // If the current price a[i] is greater than the minimum price
                // found in the suffix a[i+1...n-1], then a[i] is a bad price.
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix, it means a[i] is
                // either equal to or less than min_suffix.
                // In this case, a[i] itself becomes the new minimum for the
                // suffix starting from a[i].
                min_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n, it means p[i] must be n.
        // Otherwise, p[i] could be max_val_in_row or n.
        // Since we need to find *any* valid permutation,
        // we can try to assign p[i] = max_val_in_row if it's not n,
        // and p[i] = n if max_val_in_row is n.
        // This logic is simplified: if max_val_in_row is less than n,
        // then p[i] could be max_val_in_row + 1.
        // If max_val_in_row is n, then p[i] must be n.
        // The problem guarantees a solution exists.
        // The maximum possible value for any p[i] is n.
        // If max_val_in_row is already n-1, then p[i] could be n.
        // If max_val_in_row is less than n-1, then p[i] could be max_val_in_row + 1.
        // The only case where p[i] must be n is if max_val_in_row is n-1 AND all other p[j] are <= n-1.
        // A simpler approach: if max_val_in_row is less than n, then p[i] could be max_val_in_row + 1.
        // If max_val_in_row is n, then p[i] must be n.
        // However, max_val_in_row can never be n, because a[i][j] = min(p[i], p[j]) and p[j] is at most n.
        // So max_val_in_row is at most n-1.
        // If max_val_in_row is n-1, then p[i] could be n.
        // If max_val_in_row is less than n-1, then p[i] could be max_val_in_row + 1.
        // The only way to distinguish is if there's a unique 'n' in the permutation.
        // If there is a 'n' in the permutation, say p[k] = n, then for all j != k, a[k][j] = min(n, p[j]) = p[j].
        // So max_{j != k} a[k][j] would be max_{j != k} p[j] = n-1.
        // If p[i] is not n, then p[i] <= n-1. Then max_{j != i} a[i][j] could be p[i] or some p[j].
        // The crucial observation is that if p[i] is not n, then p[i] must be equal to max_{j != i} a[i][j]
        // if there is some p[j] > p[i].
        // If p[i] is the largest value, i.e., p[i] = n, then max_{j != i} a[i][j] = max_{j != i} p[j] = n-1.
        // For all other p[k] != n, max_{j != k} a[k][j] will be p[k] if p[k] is not the maximum among all p[j] for j != k.
        // If p[k] is not n, then p[k] is one of 1, ..., n-1.
        // If p[k] is not n, then there must be some p[j] = n.
        // Then a[k][j] = min(p[k], n) = p[k].
        // So max_{l != k} a[k][l] will be at least p[k].
        // If p[k] is not n, then p[k] = max_{l != k} a[k][l].
        // If p[k] = n, then max_{l != k} a[k][l] = n-1.
        // So, if max_val_in_row == n-1, then p[i] could be n. Otherwise p[i] = max_val_in_row.
        // To ensure we get a permutation, we assign n to the one that has max_val_in_row = n-1.
        // If multiple rows have max_val_in_row = n-1, we can pick any one.
        // If no row has max_val_in_row = n-1, this implies n is not used, which contradicts the problem.
        // So there must be at least one such row.
        // If there are multiple such rows, it means multiple p[i] could be n.
        // This is only possible if n=1, but n >= 2.
        // So exactly one p[i] will be n.
        // The logic is: if max_val_in_row is n-1, then p[i] = n.
        // Otherwise, p[i] = max_val_in_row.
        // This works because if p[i] is not n, then p[i] is one of 1, ..., n-1.
        // There must be some p[j] = n. Then a[i][j] = min(p[i], n) = p[i].
        // So max_{k != i} a[i][k] will be at least p[i].
        // In fact, max_{k != i} a[i][k] will be exactly p[i] if p[i] is not n.
        // If p[i] = n, then max_{k != i} a[i][k] = max_{k != i} p[k] = n-1.
        // So, if max_val_in_row == n-1, then p[i] = n.
        // Otherwise, p[i] = max_val_in_row.
        // This is the correct logic.

        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The number of coders available (each team needs at least one coder).
        // 2. The number of mathematicians available (each team needs at least one mathematician).
        // 3. The total number of students available (each team needs exactly three students).
        // So, the number of teams 'k' must satisfy:
        // k <= c
        // k <= m
        // 3 * k <= c + m + x  =>  k <= (c + m + x) / 3
        //
        // Therefore, k <= min(c, m, (c + m + x) / 3).
        // Let's call this upper bound 'max_possible_teams'.
        // We need to check if this 'max_possible_teams' is always achievable.
        //
        // If we form 'k' teams, we use 'k' coders and 'k' mathematicians as a minimum.
        // The remaining students are (c - k) coders, (m - k) mathematicians, and x no-specialization students.
        // The total number of remaining students is (c - k) + (m - k) + x.
        // Each team needs 3 members. We've already accounted for 1 coder and 1 mathematician for each team.
        // So, each team still needs 1 more member.
        // These 'k' additional members must come from the remaining students.
        // Thus, the total number of remaining students must be at least 'k'.
        // (c - k) + (m - k) + x >= k
        // c + m + x - 2k >= k
        // c + m + x >= 3k
        // k <= (c + m + x) / 3
        //
        // This condition is already included in our 'min' calculation.
        // So, the maximum number of teams is indeed min(c, m, (c + m + x) / 3).

        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

