int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces should have an area of (h/2) / n = h / (2n).

    // Consider a cut at distance x from the apex.
    // By similar triangles, if the original triangle has height H and base B,
    // a smaller triangle formed by a cut at distance x from the apex has height x.
    // Its base b_x will be (x/H) * B.
    // In our case, H=h, B=1. So, b_x = (x/h) * 1 = x/h.
    // The area of this smaller triangle is (1/2) * b_x * x = (1/2) * (x/h) * x = x^2 / (2h).

    // We want the i-th cut (at distance x_i from the apex) to define a triangle
    // whose area is i times the area of one piece.
    // Area_triangle_up_to_x_i = i * (h / (2n))
    // x_i^2 / (2h) = i * h / (2n)
    // x_i^2 = i * h^2 / n
    // x_i = sqrt(i * h^2 / n)
    // x_i = h * sqrt(i / n)

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << std::fixed << std::setprecision(12) << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

