int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    // Generate k distinct differences: |1-(k+1)|, |(k+1)-2|, |2-k|, ...
    // This sequence will be: 1, k+1, 2, k, 3, k-1, ...
    // The differences will be: k, k-1, k-2, ..., 1.
    // This generates k distinct differences: k, k-1, ..., 1.
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, take from left (small numbers)
            p[i] = left;
            left++;
        } else { // Odd index, take from right (large numbers)
            p[i] = right;
            right--;
        }
    }

    // Fill the remaining n - (k + 1) elements in increasing order
    // This ensures the differences are 1, which are already covered by the
    // k distinct differences (since k >= 1, difference 1 is always included).
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This will be left, which is i+1
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

