void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This is the end of the "right non-decreasing part".
    int right_non_decreasing_end = n - 1;
    while (right_non_decreasing_end > 0 && a[right_non_decreasing_end - 1] <= a[right_non_decreasing_end]) {
        right_non_decreasing_end--;
    }

    // Find the rightmost index `j` such that a[j...right_non_decreasing_end-1] is non-increasing.
    // This is the end of the "middle non-increasing part".
    // If right_non_decreasing_end is 0, it means the whole array is non-decreasing, so j can be 0.
    int middle_non_increasing_end = right_non_decreasing_end;
    while (middle_non_increasing_end > 0 && a[middle_non_increasing_end - 1] >= a[middle_non_increasing_end]) {
        middle_non_increasing_end--;
    }

    std::cout << middle_non_increasing_end << std::endl;
}

