        if (k == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // The last digits of (i * m) % 10 for i = 1, 2, ... form a cycle.
        // The cycle length is at most 10.
        // We can precompute the sum of last digits for one full cycle (i=1 to 10).

        std::vector<int> cycle_digits(10);
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_digits[i - 1] = (static_cast<long long>(i) * m) % 10;
            cycle_sum += cycle_digits[i - 1];
        }

        // Calculate how many full cycles are there
        long long num_full_cycles = k / 10;
        long long remaining_elements = k % 10;

        long long total_sum = num_full_cycles * cycle_sum;

        // Add the sum of last digits for the remaining elements
        for (int i = 0; i < remaining_elements; ++i) {
            total_sum += cycle_digits[i];
        }

        std::cout << total_sum << "\n";
    }
