                // This is the maximum distance the frog *must* be able to jump to cover the 'L's in between.
                max_dist = std::max(max_dist, i - last_R_pos);
                last_R_pos = i;
            }
        }

        // After iterating through the string, we need to consider the jump from the last 'R' (or 0 if no 'R's)
        // to the target cell n+1.
        // The distance is (n + 1 - last_R_pos).
        max_dist = std::max(max_dist, n + 1 - last_R_pos);

        std::cout << max_dist << "\n";
