#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_ok: prefix_ok[i] is true if a[0...i] can form a strictly increasing sequence
    // starting from 0, 1, 2, ...
    // Specifically, a[j] must be at least j for j in [0, i].
    std::vector<bool> prefix_ok(n);
    prefix_ok[0] = (a[0] >= 0); // a[0] must be at least 0
    for (int i = 1; i < n; ++i) {
        prefix_ok[i] = (a[i] >= i) && prefix_ok[i-1];
    }

    // Calculate suffix_ok: suffix_ok[i] is true if a[i...n-1] can form a strictly decreasing sequence
    // ending at ..., 2, 1, 0.
    // Specifically, a[j] must be at least (n-1-j) for j in [i, n-1].
    std::vector<bool> suffix_ok(n);
    suffix_ok[n-1] = (a[n-1] >= 0); // a[n-1] must be at least 0
    for (int i = n - 2; i >= 0; --i) {
        suffix_ok[i] = (a[i] >= (n - 1 - i)) && suffix_ok[i+1];
    }

    // Check if there exists a peak k (0-indexed) such that:
    // 1. a[0...k] can be made strictly increasing (0, 1, ..., k)
    // 2. a[k...n-1] can be made strictly decreasing (k, k-1, ..., 0)
    // The value at a[k] must be at least k (from prefix) AND at least (n-1-k) (from suffix).
    // The minimum value a[k] can take is max(k, n-1-k).
    // So, we need a[k] >= k AND a[k] >= (n-1-k).
    // This is equivalent to checking if prefix_ok[k] and suffix_ok[k] are both true.
    // If prefix_ok[k] is true, it means a[j] >= j for all j <= k.
    // If suffix_ok[k] is true, it means a[j] >= (n-1-j) for all j >= k.
    // If both are true for a given k, then a[k] >= k and a[k] >= (n-1-k).
    // We can then set a[j] = j for j < k, a[j] = (n-1-j) for j > k, and a[k] = max(k, n-1-k).
    // This forms a valid sharpened array.

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        if (prefix_ok[k] && suffix_ok[k]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

