int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // First, ensure the median element itself is s.
    // This is a mandatory cost.
    operations += std::abs(a[median_idx] - s);

    // Elements to the left of the median must be <= s.
    // If any a[i] < s for i < median_idx, it's fine.
    // If any a[i] > s for i < median_idx, we must decrease it to s.
    // The cost is a[i] - s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of the median must be >= s.
    // If any a[i] > s for i > median_idx, it's fine.
    // If any a[i] < s for i > median_idx, we must increase it to s.
    // The cost is s - a[i].
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

