#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the subsegment is just [1]. This is always possible.
    // l = r = pos[1]. min_val = 1, max_val = 1, length = 1.
    // So 1 is always beautiful.
    result[0] = '1';

    // For m > 1, we need to find if there exists a subsegment [l, r]
    // such that it contains exactly 1, 2, ..., m.
    // This means:
    // 1. min(p[l...r]) == 1
    // 2. max(p[l...r]) == m
    // 3. r - l + 1 == m (length of subsegment is m)

    // We can iterate m from 2 to n.
    // For each m, we need to check if the condition holds.
    // The key observation is that for a subsegment to contain 1, ..., m,
    // it must contain pos[1], pos[2], ..., pos[m].
    // Let min_idx be the minimum index among pos[1], ..., pos[m].
    // Let max_idx be the maximum index among pos[1], ..., pos[m].
    // For the subsegment to contain all numbers from 1 to m, it must span
    // at least from min_idx to max_idx.
    // So, the candidate subsegment is [min_idx, max_idx].
    // If this subsegment contains exactly 1, ..., m, then:
    // 1. Its length must be m. (max_idx - min_idx + 1 == m)
    // 2. The maximum value in p[min_idx...max_idx] must be m.
    //    (The minimum value is guaranteed to be 1 because we include pos[1])

    // We can maintain min_idx and max_idx as we iterate m from 1 to n.
    // For m=1, min_idx = pos[1], max_idx = pos[1].
    // For m=k, we update min_idx = min(current_min_idx, pos[k]),
    // and max_idx = max(current_max_idx, pos[k]).
    // Then we check if max_idx - min_idx + 1 == k.
    // If this condition holds, then k is beautiful.

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int k = 2; k <= n; ++k) {
        current_min_idx = std::min(current_min_idx, pos[k]);
        current_max_idx = std::max(current_max_idx, pos[k]);

        // If the length of the segment [current_min_idx, current_max_idx]
        // is exactly k, then this segment contains all numbers from 1 to k
        // (because we've included pos[1]...pos[k]) and no other numbers
        // (because its length is exactly k).
        // The maximum value in this segment must be k, and minimum 1.
        // This is implicitly true if the length condition holds.
        // Example: if length is k, and it contains 1..k, then max must be k.
        // If it contained some value > k, say X, then it would need to contain
        // 1..k and X, which means it would need at least k+1 distinct values.
        // But its length is k, so it only has k distinct values.
        // Thus, if length is k, and it contains 1..k, it must be exactly 1..k.
        if (current_max_idx - current_min_idx + 1 == k) {
            result[k - 1] = '1';
        }
    }

    std::cout << result << "\n";
}

