    int j = 0; // Pointer for elements to be placed (larger elements)
    for (int i = 0; i < n; ++i) { // Pointer for original positions (smaller elements)
        // We are trying to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, if a[j] > a[i], then any a[k] with k > j will also be > a[i]
        // We want to use the smallest possible a[j] that satisfies a[j] > a[i]
        // to save larger elements for later, potentially larger a[i] values.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] > a[i]
            count++;
            j++; // Move to the next element to be placed
        } else {
            // No more elements in 'a' are greater than a[i]
            // Any remaining a[i] cannot be matched with a larger element.
            break; 
        }
    }

    std::cout << count << std::endl;

    return 0;
}

