int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
            continue;
        }

        // For a and b to be real, the discriminant d^2 - 4d must be non-negative.
        // d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d >= 0, this implies d - 4 >= 0, so d >= 4.
        // If d = 0, d(d-4) = 0, which is >= 0. This case is handled above.
        // So, for d > 0, we need d >= 4.
        if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            // Solutions for 'a' are (d + sqrt_discriminant) / 2 and (d - sqrt_discriminant) / 2
            // Let's pick a = (d + sqrt_discriminant) / 2
            double a = (d + sqrt_discriminant) / 2.0;
            // Then b = d - a
            double b = d - a;

            // Both a and b must be non-negative.
            // Since d >= 4, d is positive.
            // sqrt_discriminant is real and non-negative.
            // So a = (d + sqrt_discriminant) / 2.0 will always be non-negative.
            // For b = (d - sqrt_discriminant) / 2.0 to be non-negative, we need d - sqrt_discriminant >= 0.
            // This means d >= sqrt_discriminant.
            // Squaring both sides (both are non-negative): d^2 >= discriminant
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true since d >= 4.
            // So both a and b will always be non-negative when d >= 4.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

