#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<int> counts(n + 1, 0);
    int max_val_a = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        counts[a[i]]++;
        if (a[i] > max_val_a) {
            max_val_a = a[i];
        }
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<int> current_counts(n + 1, 0);
    int current_max_prefix = 0;
    bool possible_prefix = true;

    for (int l1 = 1; l1 <= n; ++l1) {
        int val = a[l1 - 1];
        current_counts[val]++;
        if (current_counts[val] > 1) {
            possible_prefix = false;
        }
        if (val > current_max_prefix) {
            current_max_prefix = val;
        }

        if (possible_prefix && current_max_prefix == l1) {
            is_prefix_perm[l1] = true;
        } else {
            is_prefix_perm[l1] = false;
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::fill(current_counts.begin(), current_counts.end(), 0);
    int current_max_suffix = 0;
    bool possible_suffix = true;

    for (int l2 = 1; l2 <= n; ++l2) {
        int val = a[n - l2];
        current_counts[val]++;
        if (current_counts[val] > 1) {
            possible_suffix = false;
        }
        if (val > current_max_suffix) {
            current_max_suffix = val;
        }

        if (possible_suffix && current_max_suffix == l2) {
            is_suffix_perm[l2] = true;
        } else {
            is_suffix_perm[l2] = false;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, l2 must be at least 1
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

