int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % mod;
        } else { // s[i] == 'a'
            // This 'a' needs to move past all 'b's to its right.
            // Each 'b' to its right requires one operation.
            // When 'ab' -> 'bba', the 'a' moves past one 'b', and a new 'b' is created.
            // So, if there are 'k' 'b's to the right, this 'a' will cause 'k' operations.
            // After these 'k' operations, this 'a' will be to the right of all original 'b's.
            // However, each of these 'k' operations also creates a new 'b'.
            // These new 'b's will be to the left of the current 'a'.
            // So, the number of 'b's that the *next* 'a' (to the left) will encounter
            // will be the current b_count * 2.
            total_steps = (total_steps + b_count) % mod;
            b_count = (b_count * 2) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // Condition: current_sum = 2 * current_xor_sum
    // If already good, append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // We need to append at most 3 elements.
    // Let's try to append 2 elements.
    // Let the two elements be x and y.
    // New sum: S' = current_sum + x + y
    // New XOR sum: X' = current_xor_sum ^ x ^ y
    // We want S' = 2 * X'
    // current_sum + x + y = 2 * (current_xor_sum ^ x ^ y)

    // A common strategy for these problems is to make the XOR sum equal to some value,
    // and then adjust the sum.
    // Let's try to make the new XOR sum equal to current_xor_sum.
    // This means we need to append elements whose XOR sum is 0.
    // For example, append x and x.
    // If we append x and x, then new XOR sum is current_xor_sum ^ x ^ x = current_xor_sum.
    // New sum is current_sum + x + x = current_sum + 2x.
    // We want current_sum + 2x = 2 * current_xor_sum.
    // 2x = 2 * current_xor_sum - current_sum.
    // x = current_xor_sum - current_sum / 2.
    // This requires current_sum to be even, and current_xor_sum - current_sum / 2 to be non-negative.

    // Let's try a different approach that always works with 2 elements.
    // We want to find b1, b2 such that:
    // (current_sum + b1 + b2) = 2 * (current_xor_sum ^ b1 ^ b2)
    // Let b1 = current_xor_sum.
    // Then the new XOR sum becomes current_xor_sum ^ current_xor_sum ^ b2 = b2.
    // The new sum becomes current_sum + current_xor_sum + b2.
    // So we need: current_sum + current_xor_sum + b2 = 2 * b2
    // current_sum + current_xor_sum = b2
    // So, b2 = current_sum + current_xor_sum.
    //
    // Let's check this:
    // Appended elements: b1 = current_xor_sum, b2 = current_sum + current_xor_sum.
    // New sum: S' = current_sum + b1 + b2
    //             = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    //             = 2 * current_sum + 2 * current_xor_sum
    // New XOR sum: X' = current_xor_sum ^ b1 ^ b2
    //                = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    //                = 0 ^ (current_sum + current_xor_sum)
    //                = current_sum + current_xor_sum
    //
    // Is S' = 2 * X'?
    // 2 * current_sum + 2 * current_xor_sum = 2 * (current_sum + current_xor_sum)
    // Yes, this holds!
    //
    // The elements b1 and b2 are non-negative because current_sum and current_xor_sum are non-negative.
    // The values can be large, up to 10^9 for initial elements, so current_sum can be 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 (approx 10^9).
    // b1 = current_xor_sum is fine.
    // b2 = current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long (10^18 max).
    //
    // This strategy always works and uses exactly 2 elements.
    // The problem statement says "at most 3 elements", and "you don't have to minimize".
    // So, this 2-element solution is perfectly fine.

    long long b1 = current_xor_sum;
    long long b2 = current_sum + current_xor_sum;

    std::cout << 2 << std::endl;
    std::cout << b1 << " " << b2 << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

