// Function to check if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 1) {
        return A == 1;
    }

    // Case 1: Final toy is negative. This requires an odd number of negative toys.
    // The number of negative toys is A + B.
    // If A+B is even, the final toy is positive.
    // If A+B is odd, the final toy is negative.
    if ((A + B) % 2 == 0) { // Final toy must be positive
        return false;
    }

    // Case 2: Final toy has magnitude >= 1.
    // This requires that at some point, we have a toy with magnitude >= 1.
    // If A+D == 0, all initial toys have magnitude < 1.
    // If B+C == 0, all initial toys have magnitude >= 1.
    // If A+D == 0 and B+C > 0:
    //   All initial toys have magnitude < 1.
    //   Multiplying two numbers with magnitude < 1 results in a number with magnitude < 1.
    //   So, if A+D == 0, the final toy will always have magnitude < 1.
    //   Thus, it cannot be in Box 1 (or Box 4).
    if (A + D == 0) {
        return false;
    }

    // If A+D > 0, there's at least one toy with magnitude >= 1.
    // We need to ensure we can *keep* the magnitude >= 1.
    // If we have any toys in Box 2 or Box 3 (B+C > 0), we can potentially reduce magnitude.
    // If B+C == 0, then all toys are in Box 1 or Box 4. All have magnitude >= 1.
    // Multiplying two numbers with magnitude >= 1 results in a number with magnitude >= 1.
    // So if B+C == 0, the final toy will always have magnitude >= 1.
    // In this case, if A+B is odd, it can be in Box 1.
    if (B + C == 0) {
        return true; // (A+B) % 2 == 1 already checked
    }

    // General case: A+D > 0 and B+C > 0.
    // We have toys with magnitude >= 1 and toys with magnitude < 1.
    // We need to be able to end up with a magnitude >= 1.
    // This is always possible if A+D > 0.
    // We can always multiply all B and C toys together first. This results in a toy with magnitude < 1.
    // Let's call this toy X. Its magnitude is < 1.
    // Then we have A+D toys with magnitude >= 1, and one toy X with magnitude < 1.
    // If A+D >= 1, we can pick one toy from A or D, say Y.
    // Multiply Y with X. The result Y*X will have magnitude < |Y|.
    // If |Y| >= 1, then |Y*X| can be < 1 or >= 1 depending on specific values.
    // However, we can always choose to multiply toys from A and D together first.
    // As long as we have at least one toy in A or D, we can ensure the final magnitude is >= 1.
    // For example, if we have one toy in Box 4 (value 2) and one in Box 3 (value 0.5).
    // If we multiply them, we get 1. This is in Box 4.
    // If we have one toy in Box 4 (value 2) and one in Box 2 (value -0.5).
    // If we multiply them, we get -1. This is in Box 1.
    // The only way to guarantee magnitude < 1 is if all initial toys have magnitude < 1 (A+D=0).
    // Since A+D > 0, we can always construct a scenario where the final magnitude is >= 1.
    // For example, pick all toys from B and C. Multiply them together. The result is a toy X with |X| < 1.
    // Now we have A+D toys with magnitude >= 1, and one toy X with magnitude < 1.
    // If A+D >= 1, we can multiply all A+D toys together. The result is a toy Y with |Y| >= 1.
    // Now we have Y and X. Multiply them. Y*X. This could be < 1 or >= 1.
    // This logic is tricky. Let's simplify.
    // The only way to *force* the final magnitude to be < 1 is if all initial toys have magnitude < 1 (A+D=0).
    // If A+D > 0, it is *possible* to end up with a magnitude >= 1.
    // For example, if A=1, B=1, C=1, D=1.
    // A: -2, B: -0.5, C: 0.5, D: 2
    // (-0.5 * 0.5) = -0.25 (Box 2)
    // (-2 * 2) = -4 (Box 1)
    // (-4 * -0.25) = 1 (Box 4)
    // This example shows that even with B and C toys, we can end up with magnitude >= 1.
    // The only way to guarantee magnitude < 1 is if A+D=0.
    // Since we already checked A+D=0, and it returned false, here A+D > 0.
    // So it is possible to end up with magnitude >= 1.
    // Combined with (A+B)%2 == 1, it means Box 1 is possible.
    return true;
}

// Function to check if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 1) {
        return B == 1;
    }

    // Case 1: Final toy is negative. This requires an odd number of negative toys.
    if ((A + B) % 2 == 0) { // Final toy must be positive
        return false;
    }

    // Case 2: Final toy has magnitude < 1.
    // This requires that we can make the final magnitude < 1.
    // If A+D == 0, all initial toys have magnitude < 1.
    // Multiplying numbers with magnitude < 1 always results in magnitude < 1.
    // So if A+D == 0, the final toy will always have magnitude < 1.
    // In this case, if A+B is odd, it can be in Box 2.
    if (A + D == 0) {
        return true; // (A+B) % 2 == 1 already checked
    }

    // General case: A+D > 0. We have at least one toy with magnitude >= 1.
    // We need to be able to end up with a magnitude < 1.
    // This is possible if we have at least one toy in Box 2 or Box 3 (B+C > 0).
    // If B+C == 0, then all toys are in Box 1 or Box 4. All have magnitude >= 1.
    // Multiplying two numbers with magnitude >= 1 results in a number with magnitude >= 1.
    // So if B+C == 0, the final toy will always have magnitude >= 1.
    // Thus, it cannot be in Box 2 (or Box 3).
    if (B + C == 0) {
        return false;
    }

    // If A+D > 0 and B+C > 0:
    // We have toys with magnitude >= 1 and toys with magnitude < 1.
    // We can always make the final magnitude < 1.
    // Strategy: Multiply all toys from Box 1 and Box 4 together. This results in a toy Y with |Y| >= 1.
    // Multiply all toys from Box 2 and Box 3 together. This results in a toy X with |X| < 1.
    // Now we have two toys, Y and X. Multiply them: Y*X.
    // Since |Y| >= 1 and |X| < 1, we can choose specific values such that |Y*X| < 1.
    // For example, if Y is 2 and X is 0.1, Y*X = 0.2.
    // If Y is 2 and X is 0.6, Y*X = 1.2.
    // But we can always pick values such that |Y*X| < 1.
    // For example, if we have a toy in Box 4 (value 2) and a toy in Box 3 (value 0.1).
    // We can multiply them to get 0.2 (Box 3).
    // The problem states "you do not know their fun values". This means we can pick values.
    // So if A+D > 0 and B+C > 0, it is always possible to end up with magnitude < 1.
    // Combined with (A+B)%2 == 1, it means Box 2 is possible.
    return true;
}

