    // We need to ensure we can *keep* the magnitude >= 1.
    // If B+C == 0, then all toys are in Box 1 or Box 4. All have magnitude >= 1.
    // Multiplying two numbers with magnitude >= 1 results in a number with magnitude >= 1.
    // So if B+C == 0, the final toy will always have magnitude >= 1.
    // In this case, if A+B is even, it can be in Box 4.
    if (B + C == 0) {
        return true; // (A+B) % 2 == 0 already checked
    }

    // If A+D > 0 and B+C > 0:
    // We have toys with magnitude >= 1 and toys with magnitude < 1.
    // We can always make the final magnitude >= 1. (Same logic as for Box 1)
    // Combined with (A+B)%2 == 0, it means Box 4 is possible.
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::cout << (can_be_box1(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box2(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box3(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box4(A, B, C, D) ? "Ya" : "Tidak") << "\n";
    }
    return 0;
}

#include <iostream>
