#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // k_L is the number of items taken from the left (0 to n)
    for (int k_L = 0; k_L <= n; ++k_L) {
        int k_R = n - k_L; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += (prefix_sum[k_L] - prefix_sum[0]) * l;

        // Energy for items taken from the right
        current_energy += (prefix_sum[n] - prefix_sum[n - k_R]) * r;

        // Add extra energy for consecutive picks
        if (k_L > k_R) {
            // More items from left. The last item taken could be from left.
            // If k_L = k_R + 1, then the last item taken from left is not consecutive.
            // If k_L > k_R + 1, then there are (k_L - (k_R + 1)) extra left items
            // that must have been taken consecutively after another left item.
            current_energy += (k_L - k_R - 1) * Ql;
        } else if (k_R > k_L) {
            // More items from right. The last item taken could be from right.
            // If k_R = k_L + 1, then the last item taken from right is not consecutive.
            // If k_R > k_L + 1, then there are (k_R - (k_L + 1)) extra right items
            // that must have been taken consecutively after another right item.
            current_energy += (k_R - k_L - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

