    // Step 1: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    // Construct a candidate s_prime from w
    std::string s_prime(n, '0');
    for (int i = 0; i < n; ++i) {
        // s_prime[i] is '1' if w[i-x] is '1' or w[i+x] is '1'
        bool found_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            found_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            found_one = true;
        }
        if (found_one) {
            s_prime[i] = '1';
        }
    }

