// Function to convert a number to its parity pattern string
// The pattern is always 18 characters long, padded with '0's on the left.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's on the right to make it 18 characters long
    // This corresponds to padding with '0's on the left for the number itself
    // because we built the string from right to left.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // A map to store counts of each parity pattern string
    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            counts[pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's on the left to make it 18 characters long
            // This corresponds to padding with '0's on the right for the string representation
            // because the pattern is given from left to right (most significant to least significant).
            // However, our get_parity_pattern function builds the string from right to left
            // (least significant to most significant).
            // So, if the input pattern is "010", it means 0 (MSB), 1, 0 (LSB).
            // Our stored patterns are LSB first.
            // Example: 241 -> 100...0 (LSB first)
            // Query "010" -> LSB is 0, middle is 1, MSB is 0.
            // So we need to reverse the query pattern and then pad.
            std::reverse(s.begin(), s.end());
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

