#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) {
        std::vector<int> colors(n);
        int last1 = -1; // Last digit placed in color 1
        int last2 = -1; // Last digit placed in color 2
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                // Must be color 1
                if (d[i] < last1) {
                    possible_p = false;
                    break;
                }
                colors[i] = 1;
                last1 = d[i];
            } else if (d[i] > p) {
                // Must be color 2
                if (d[i] < last2) {
                    possible_p = false;
                    break;
                }
                colors[i] = 2;
                last2 = d[i];
            } else { // d[i] == p
                // Can be color 1 or 2. Try to put in color 2 if possible.
                // This ensures that digits equal to p are pushed to color 2
                // as much as possible, which helps satisfy last1 <= first2.
                if (d[i] >= last2) {
                    colors[i] = 2;
                    last2 = d[i];
                } else if (d[i] >= last1) {
                    colors[i] = 1;
                    last1 = d[i];
                } else {
                    possible_p = false;
                    break;
                }
            }
        }

        if (possible_p) {
            // Final check: last digit of S1 <= first digit of S2
            // This is implicitly handled by the greedy choice for d[i] == p
            // and the fact that last1 and last2 track the maximums.
            // If last1 > first2, it means some d[i]=p was forced into color 1
            // but it was greater than some d[j]=p that was forced into color 2.
            // This logic is already covered by the last1/last2 checks.

            // Construct the output string
            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

