// Function to find prime factors of a number
// Returns a vector of unique prime factors
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x such that p % x == 0 and x % q != 0.
        // This means x must be p / (some factor of q that makes x not divisible by q).
        // Or, more generally, x must be p / k for some k, such that (p/k) % q != 0.
        // We want to maximize p/k, which means minimizing k.
        // The smallest k that makes (p/k) % q != 0 is what we are looking for.
        //
        // Let q = f1^a1 * f2^a2 * ... * fm^am be the prime factorization of q.
        // If x is divisible by q, then x must have at least f1^a1, f2^a2, etc.
        // To make x not divisible by q, we must remove at least one prime factor f_j
        // from x such that its power in x becomes less than a_j.
        //
        // We are looking for the largest divisor of p, say x_max.
        // x_max = p / (some factor of p that is also a factor of q, say k_j)
        // such that x_max is not divisible by q.
        //
        // Consider prime factors of q.
        // For each prime factor f_j of q:
        //   Find the largest power of f_j that divides p. Let it be f_j^b_j.
        //   Find the largest power of f_j that divides q. Let it be f_j^a_j.
        //   Since p is divisible by q, we know b_j >= a_j for all j.
        //   If we divide p by f_j, the new number p/f_j will have f_j^(b_j-1) as its power of f_j.
        //   If b_j-1 < a_j, then p/f_j is not divisible by q.
        //   We want to find the largest such p/f_j^k.
        //   The largest x will be p / (f_j^k) where f_j^k is the smallest factor of p
        //   such that p / (f_j^k) is not divisible by q.
        //   This means we need to divide p by f_j until the power of f_j in p becomes less than a_j.
        //   The smallest factor to divide p by is f_j^(b_j - a_j + 1).
        //   So, for each prime factor f_j of q, we can form a candidate x_j = p / (f_j^(b_j - a_j + 1)).
        //   The maximum of these candidates will be our answer.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long f : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by f until it's no longer divisible by q
            // This means we need to reduce the power of f in current_p
            // until it's less than the power of f in q.
            //
            // Let's find the power of f in q.
            long long temp_q = q;
            long long power_f_in_q = 0;
            while (temp_q > 0 && temp_q % f == 0) {
                power_f_in_q++;
                temp_q /= f;
            }

            // Now, divide p by f until the power of f in p is less than power_f_in_q.
            // We want to find the largest x, so we divide p by the smallest possible factor.
            // The smallest factor to divide p by is f^(power_f_in_p - power_f_in_q + 1).
            //
            // A simpler way: keep dividing current_p by f as long as current_p is divisible by q.
            // Once current_p is not divisible by q, it's a candidate for x.
            // This is because if current_p is divisible by q, it means the power of f in current_p
            // is still >= power_f_in_q. We need to reduce it further.
            while (current_p % q == 0) {
                current_p /= f;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

