int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 1 means can move left (x-1), so x can be smaller. If f1=0, x cannot be smaller than current x.
            if (f1 == 0) { // Cannot move left, so target X must be >= current x
                min_x = std::max(min_x, x);
            }
            // f3 = 1 means can move right (x+1), so x can be larger. If f3=0, x cannot be larger than current x.
            if (f3 == 0) { // Cannot move right, so target X must be <= current x
                max_x = std::min(max_x, x);
            }
            // f4 = 1 means can move down (y-1), so y can be smaller. If f4=0, y cannot be smaller than current y.
            if (f4 == 0) { // Cannot move down, so target Y must be >= current y
                min_y = std::max(min_y, y);
            }
            // f2 = 1 means can move up (y+1), so y can be larger. If f2=0, y cannot be larger than current y.
            if (f2 == 0) { // Cannot move up, so target Y must be <= current y
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>

long long sum_arithmetic_series(long long n) {
    if (n <= 0) return 0;
    long long MOD = 1000000007;
    long long n_mod = n % MOD;
    long long n_plus_1_mod = (n + 1) % MOD;
    long long term1 = n_mod;
    long long term2 = n_plus_1_mod;

    // One of n or n+1 must be even, so n*(n+1) is always divisible by 2.
    // We need to compute (n * (n+1) / 2) % MOD.
    // This is equivalent to (n % MOD * (n+1) % MOD * inv(2) % MOD) % MOD.
    // inv(2) modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004.
    long long inv2 = 500000004;

    long long sum = (term1 * term2) % MOD;
    sum = (sum * inv2) % MOD;
    return sum;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // If b = 1, then mod(x, b) is always 0, so no nice integers.
    // The sum of r from 1 to b-1 would be sum from 1 to 0, which is 0.
    // So the total sum is 0.
    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Calculate sum_r = sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    long long sum_r = sum_arithmetic_series(b - 1);

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // This is sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a+1) / 2) + a
    long long sum_k_b_part = sum_arithmetic_series(a);
    sum_k_b_part = (sum_k_b_part * (b % MOD)) % MOD;

    long long sum_ones_part = a % MOD;

    long long sum_k_b_plus_1 = (sum_k_b_part + sum_ones_part) % MOD;

    // Total sum = (sum_k_b_plus_1 * sum_r) % MOD
    long long total_sum = (sum_k_b_plus_1 * sum_r) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <map>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;

    // Find a starting character for a chain
    char start_char = '\0';
    for (char c : used_in_s) {
        if (adj[c].size() <= 1) { // A character with 0 or 1 neighbor can be an endpoint
            start_char = c;
            break;
        }
    }

    // If all characters in s have 2 neighbors, it means they form a cycle.
    // This is impossible for a linear keyboard.
    // Exception: if s has only 1 character, it has 0 neighbors.
    // If s has 2 characters, say "ab", 'a' has 'b', 'b' has 'a'. Both have 1 neighbor.
    // If s has 3 characters, say "abc", 'a' has 'b', 'b' has 'a','c', 'c' has 'b'. 'a' and 'c' have 1 neighbor.
    // If s has 4 characters, say "abcd", 'a' has 'b', 'b' has 'a','c', 'c' has 'b','d', 'd' has 'c'. 'a' and 'd' have 1 neighbor.
    // So, if start_char is still '\0' and used_in_s is not empty, it means all characters in used_in_s have 2 neighbors.
    // This forms a cycle, which is impossible.
    if (start_char == '\0' && !used_in_s.empty()) {
        std::cout << "NO\n";
        return;
    }

    // If s is empty, or only contains one character, start_char will be that character or '\0'.
    // If s is "a", start_char = 'a'.
    // If s is "ab", start_char = 'a' (or 'b').
    // If s is "aba", start_char = 'b'.
    // If s is "abacaba", start_char = 'c' (or 'b').
    // If s is "codedoca", start_char = 'e' (or 'a').
    // If s is "abcda", 'a' has 'b','d', 'b' has 'a','c', 'c' has 'b','d', 'd' has 'a','c'. All have 2 neighbors. This is a cycle.
    // The check `start_char == '\0' && !used_in_s.empty()` correctly identifies cycles.

    if (start_char != '\0') {
        char current = start_char;
        char prev = '\0'; // To keep track of the previous character in the layout chain

        while (current != '\0' && visited_in_layout.find(current) == visited_in_layout.end()) {
            layout_str += current;
            visited_in_layout.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
        }
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_str += c;
        }
    }

    if (layout_str.length() != 26) {
        // This should not happen if the logic is correct, but as a safeguard.
        // It implies some character was missed or duplicated, or cycle detection failed.
        std::cout << "NO\n";
    } else {
        std::cout << "YES\n";
        std::cout << layout_str << "\n";
    }
}

