    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    std::vector<std::vector<int>> next_occurrence(L, std::vector<int>(26, -1));
    for (int c_idx = 0; c_idx < 26; ++c_idx) {
        if (char_indices[c_idx].empty()) continue;
        int last_idx = char_indices[c_idx].back();
        for (int i = L - 1; i >= 0; --i) {
            if (s[i] - 'a' == c_idx) {
                last_idx = i;
            }
            next_occurrence[i][c_idx] = last_idx;
        }
    }

    std::vector<std::vector<int>> prev_occurrence(L, std::vector<int>(26, -1));
    for (int c_idx = 0; c_idx < 26; ++c_idx) {
        if (char_indices[c_idx].empty()) continue;
        int first_idx = char_indices[c_idx].front();
        for (int i = 0; i < L; ++i) {
            if (s[i] - 'a' == c_idx) {
                first_idx = i;
            }
            prev_occurrence[i][c_idx] = first_idx;
        }
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char c0_val = s[k_actual];

        std::vector<int> possible_k_for_c0;
        for (int i = 0; i < L; ++i) {
            if (s[i] == c0_val) {
                possible_k_for_c0.push_back(i);
            }
        }

        if (possible_k_for_c0.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        double max_win_prob_for_k_actual = 0.0;

        for (int p = 1; p < L; ++p) {
            char cp_val = s[(k_actual + p) % L];
            int count_unique_k = 0;
            for (int k_cand : possible_k_for_c0) {
                if (s[(k_cand + p) % L] == cp_val) {
                    count_unique_k++;
                }
            }
            if (count_unique_k == 1) {
                max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, 1.0);
            } else {
                // Check for unique (k_cand, (k_cand+p)%L) pairs
                // This is equivalent to checking if (c0_val, cp_val) uniquely determines k_cand
                // among those k_cand that produce c0_val at index 0.
                // If count_unique_k > 1, Vasya loses for this (c0_val, cp_val) pair.
                // So, max_win_prob_for_k_actual remains 0.0 if it was 0.0, or 1.0 if it was 1.0.
            }
        }
        total_win_prob += max_win_prob_for_k_actual;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

