long long solve() {
    long long n;
    std::cin >> n;

    if (n % 2 != 0) {
        // If N is odd, Chanek must take 1 coin.
        // The remaining N-1 coins are even.
        // The opponent will then face an even number of coins.
        // Chanek's score will be 1 + (N-1)/2.
        // This is because after Chanek takes 1, N-1 coins remain.
        // The opponent will take (N-1)/2 coins (optimal for opponent).
        // Then (N-1)/2 coins remain.
        // Chanek will take (N-1)/4 coins (optimal for Chanek).
        // This pattern continues.
        // Effectively, Chanek gets 1 coin, and then the game continues with N-1 coins,
        // where Chanek is the second player.
        // The total coins Chanek gets from the N-1 part is (N-1)/2.
        // So total for Chanek is 1 + (N-1)/2 = (N+1)/2.
        return (n + 1) / 2;
    } else {
