#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> bal_left(n + 1, 0); // bal_left[k] is balance for jars 1 to k
    for (int i = 0; i < n; ++i) {
        bal_left[i + 1] = bal_left[i] + (a[i] == 1 ? 1 : -1);
    }

    std::vector<int> bal_right(n + 1, 0); // bal_right[k] is balance for jars 2n-k+1 to 2n
    for (int i = 0; i < n; ++i) {
        bal_right[i + 1] = bal_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars eaten from the left (k)
    // to achieve a certain balance (bal_left[k]).
    // Key: balance, Value: k (number of jars eaten from left)
    std::map<int, int> left_balance_to_k;
    for (int k = 0; k <= n; ++k) {
        // We want to find the minimum k for a given balance.
        // Since we iterate k from 0 upwards, the first time we see a balance,
        // it corresponds to the minimum k.
        if (left_balance_to_k.find(bal_left[k]) == left_balance_to_k.end()) {
            left_balance_to_k[bal_left[k]] = k;
        }
    }

    int min_jars_eaten = 2 * n; // Initialize with max possible jars eaten

    // Iterate through possible number of jars eaten from the right (k_right)
    for (int k_right = 0; k_right <= n; ++k_right) {
        int current_right_balance = bal_right[k_right];
        int target_left_balance = -current_right_balance;

        // Check if this target_left_balance can be achieved by eating some jars from the left
        if (left_balance_to_k.count(target_left_balance)) {
            int k_left = left_balance_to_k[target_left_balance];
            min_jars_eaten = std::min(min_jars_eaten, k_left + k_right);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
