int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_ones(n, 0);
    std::vector<int> right_ones(n, 0);

    // Calculate left_ones[i]: distance to the nearest 1 to the left (inclusive)
    // If a[i] is 1, left_ones[i] = 0. If a[i] is 0, left_ones[i] = left_ones[i-1] + 1.
    // If no 1 to the left, it's effectively infinity.
    if (a[0] == 1) {
        left_ones[0] = 0;
    } else {
        left_ones[0] = n + 1; // Represents infinity
    }
    for (int i = 1; i < n; ++i) {
        if (a[i] == 1) {
            left_ones[i] = 0;
        } else {
            left_ones[i] = left_ones[i - 1] + 1;
        }
    }

    // Calculate right_ones[i]: distance to the nearest 1 to the right (inclusive)
    // If a[i] is 1, right_ones[i] = 0. If a[i] is 0, right_ones[i] = right_ones[i+1] + 1.
    // If no 1 to the right, it's effectively infinity.
    if (a[n - 1] == 1) {
        right_ones[n - 1] = 0;
    } else {
        right_ones[n - 1] = n + 1; // Represents infinity
    }
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 1) {
            right_ones[i] = 0;
        } else {
            right_ones[i] = right_ones[i + 1] + 1;
        }
    }

    std::vector<int> left_zeros(n, 0);
    std::vector<int> right_zeros(n, 0);

    // Calculate left_zeros[i]: distance to the nearest 0 to the left (inclusive)
    if (a[0] == 0) {
        left_zeros[0] = 0;
    } else {
        left_zeros[0] = n + 1;
    }
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zeros[i] = 0;
        } else {
            left_zeros[i] = left_zeros[i - 1] + 1;
        }
    }

    // Calculate right_zeros[i]: distance to the nearest 0 to the right (inclusive)
    if (a[n - 1] == 0) {
        right_zeros[n - 1] = 0;
    } else {
        right_zeros[n - 1] = n + 1;
    }
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zeros[i] = 0;
        } else {
            right_zeros[i] = right_zeros[i + 1] + 1;
        }
    }

    int max_steps = 0;
    std::vector<int> final_a = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // Current element is 0
            // If it's a 0 that will become 1, it must be surrounded by 1s
            // i.e., 1 0 1. This 0 will become 1.
            // The number of steps for this 0 to become 1 is ceil(min(left_ones[i], right_ones[i]) / 2.0)
            // This is equivalent to (min(left_ones[i], right_ones[i]) + 1) / 2
            if (left_ones[i] % 2 == 0 && right_ones[i] % 2 == 0) { // 1...1 0 1...1 (even length blocks of 0s)
                // This 0 is part of a block of 0s that will eventually become 1s.
                // The number of steps is min(left_ones[i], right_ones[i]) / 2
                int steps_to_become_one = std::min(left_ones[i], right_ones[i]) / 2;
                max_steps = std::max(max_steps, steps_to_become_one);
                if (steps_to_become_one > 0) {
                    final_a[i] = 1;
                }
            } else { // 0 will remain 0 or become 0
                // If it's 0 and surrounded by 0s, it remains 0.
                // If it's 0 and surrounded by 1s, but one side is odd distance, it remains 0.
                // Example: 1 1 0 0 0 -> 1 1 0 0 0
                // Example: 1 0 0 0 1 -> 1 0 0 0 1
                // Example: 1 1 1 0 0 -> 1 1 1 1 0
                // The 0 at index i will become 1 if it's part of a 1-block expansion.
                // This happens if left_ones[i] and right_ones[i] are both even.
                // Otherwise, it will eventually become 0.
                // So, if it's not the even-even case, final_a[i] remains 0.
            }
        } else { // Current element is 1
            // If it's a 1 that will become 0, it must be surrounded by 0s
            // i.e., 0 1 0. This 1 will become 0.
            // The number of steps for this 1 to become 0 is ceil(min(left_zeros[i], right_zeros[i]) / 2.0)
            // This is equivalent to (min(left_zeros[i], right_zeros[i]) + 1) / 2
            if (left_zeros[i] % 2 == 0 && right_zeros[i] % 2 == 0) { // 0...0 1 0...0 (even length blocks of 1s)
                // This 1 is part of a block of 1s that will eventually become 0s.
                // The number of steps is min(left_zeros[i], right_zeros[i]) / 2
                int steps_to_become_zero = std::min(left_zeros[i], right_zeros[i]) / 2;
                max_steps = std::max(max_steps, steps_to_become_zero);
                if (steps_to_become_zero > 0) {
                    final_a[i] = 0;
                }
            } else { // 1 will remain 1 or become 1
                // If it's 1 and surrounded by 1s, it remains 1.
                // If it's 1 and surrounded by 0s, but one side is odd distance, it remains 1.
                // So, if it's not the even-even case, final_a[i] remains 1.
            }
        }
    }

    std::cout << max_steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

