int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a_input(n); // a_input[0] is unused, a_input[1]...a_input[n-1] are a_2...a_n
    for (int i = 1; i < n; ++i) {
        std::cin >> a_input[i];
    }

    std::vector<long long> dp_y(n + 1, 0);
    std::vector<int> dp_x_next(n + 1, 0);
    std::vector<bool> visited(n + 1, false);
    std::vector<bool> in_stack(n + 1, false);

    for (int i = n; i >= 1; --i) {
        long long current_a_val;
        if (i == 1) {
            // This case is handled by the outer loop for each starting a_1
            // We only precompute for a_x where x >= 2
            continue; 
        } else {
            current_a_val = a_input[i - 1]; // a_input[idx] stores a_{idx+1}
        }

        long long x_after_step2 = (long long)i + current_a_val;
        long long y_after_step2 = current_a_val;

        long long x_after_step3 = x_after_step2 - current_a_val;
        long long y_after_step3 = y_after_step2 + current_a_val;

        if (x_after_step3 <= 0 || x_after_step3 > n) {
            dp_y[i] = y_after_step3;
            dp_x_next[i] = 0; // Sentinel for termination
        } else {
            // This is a jump to a state (x_after_step3, y_after_step3)
            // We need to add the y from the next state
            // The next state is (x_after_step3, 0) effectively, and we add y_after_step3 to its result
            dp_y[i] = y_after_step3 + dp_y[x_after_step3];
            dp_x_next[i] = dp_x_next[x_after_step3];
        }
    }

    for (int i = 1; i < n; ++i) {
        long long a1_val = i; // a_1 is set to i for this run

        long long current_x = 1;
        long long current_y = 0;

        // First step: x=1, y=0. a_x is a_1 = a1_val
        long long x_after_step2 = current_x + a1_val;
        long long y_after_step2 = current_y + a1_val;

        long long x_after_step3 = x_after_step2 - a1_val;
        long long y_after_step3 = y_after_step2 + a1_val;

        if (x_after_step3 <= 0 || x_after_step3 > n) {
            std::cout << y_after_step3 << "\n";
        } else {
            // Now we are at state (x_after_step3, y_after_step3)
            // The remaining path is determined by dp_y[x_after_step3] and dp_x_next[x_after_step3]
            if (dp_x_next[x_after_step3] == 0) { // Terminates
                std::cout << y_after_step3 + dp_y[x_after_step3] << "\n";
            } else { // Loops
                std::cout << -1 << "\n";
            }
        }
    }

