#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;
    std::vector<int> current_line_indices(n);
    std::iota(current_line_indices.begin(), current_line_indices.end(), 0); // 0-indexed original indices

    int head = 0; // Pointer to the first child in the current_line_indices that is still in line

    while (head < current_line_indices.size()) {
        int current_child_original_idx = current_line_indices[head];
        if (!children[current_child_original_idx].in_line) {
            head++;
            continue;
        }

        cured_children_indices.push_back(children[current_child_original_idx].original_idx);
        children[current_child_original_idx].in_line = false;

        long long v_cry = children[current_child_original_idx].v;
        long long d_chain_cry_sum = 0; // Sum of d_j from children leaving due to chain reaction

        // Apply v_cry and d_chain_cry_sum to children after the current one
        for (int i = head + 1; i < current_line_indices.size(); ++i) {
            int child_idx_in_original_array = current_line_indices[i];
            if (!children[child_idx_in_original_array].in_line) {
                continue;
            }

            // Apply v_cry reduction
            if (v_cry > 0) {
                children[child_idx_in_original_array].p -= v_cry;
                v_cry--;
            }

            // Apply d_chain_cry_sum reduction
            children[child_idx_in_original_array].p -= d_chain_cry_sum;

            // Check for chain reaction
            if (children[child_idx_in_original_array].p < 0) {
                children[child_idx_in_original_array].in_line = false;
                d_chain_cry_sum += children[child_idx_in_original_array].d;
            }
        }
        head++;
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

