            return 0;
        }
    }

    // Case k=2
    // Try all possible two cuts
    // s = s_a s_b s_c
    // We need to form a new palindrome s' != s by reordering s_a, s_b, s_c.
    // The only way to form a palindrome from 3 pieces is if the middle piece is a palindrome
    // and the outer pieces are reverses of each other.
    // For example, s_a s_b s_c is a palindrome if s_a = reverse(s_c) and s_b is a palindrome.
    // The problem states that pieces cannot be turned over.
    // The only reordering that can form a palindrome from 3 pieces is s_c s_b s_a,
    // given that s_a s_b s_c is a palindrome.
    // If s_a s_b s_c is a palindrome, then s_a = reverse(s_c) and s_b is a palindrome.
    // Then s_c s_b s_a will also be a palindrome.
    // We need s_c s_b s_a != s_a s_b s_c. This implies s_a != s_c.
    // Since s_a = reverse(s_c), this means s_a is not a palindrome.
    // If s_a is not a palindrome, then s_a != reverse(s_a), so s_a != s_c.
    // So we are looking for a cut s_a | s_b | s_c such that:
    // 1. s_a s_b s_c is the original string s (which is a palindrome)
    // 2. s_a is not a palindrome (this implies s_a != s_c)
    // 3. s_b is a palindrome (this is implied by s being a palindrome and s_a = reverse(s_c))
    // If these conditions hold, then s_c s_b s_a is a new palindrome.

    // Iterate over all possible first cut positions (i) and second cut positions (j)
    // s_a = s.substr(0, i)
    // s_b = s.substr(i, j - i)
    // s_c = s.substr(j)
    for (int i = 1; i < n; ++i) { // Length of s_a
        for (int j = i + 1; j < n; ++j) { // Start index of s_c
            std::string sa = s.substr(0, i);
            std::string sb = s.substr(i, j - i);
            std::string sc = s.substr(j);

            // Since s is a palindrome, and s = sa + sb + sc,
            // it must be that sa = reverse(sc) and sb is a palindrome.
            // We just need to check if sa is NOT a palindrome.
            // If sa is not a palindrome, then sa != reverse(sa).
            // Since sa = reverse(sc), this means sa != sc.
            // If sa != sc, then sc + sb + sa != sa + sb + sc.
            // And sc + sb + sa will be a palindrome.
            if (!is_palindrome(sa)) {
                std::cout << 2 << std::endl;
                return 0;
            }
        }
    }

    // If no solution found for k=1 or k=2, it's impossible.
    // This happens if all prefixes of s are palindromes.
    // If all prefixes are palindromes, then s must be of the form 'aaaaa...'
    // Example: "qqqq"
    // If s = "aaaaa...", then any s_a is "aaaa...", which is a palindrome.
    // So k=2 solution is not found.
    // For k=1, if s = "aaaaa...", then s1 = "aaa", s2 = "aa".
    // new_s = "aaaaa" = s. So k=1 solution is not found.
    std::cout << "Impossible" << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the minimum r such that s[l...r] contains a triple.
                                                // Using 1-based indexing for l, r.
                                                // Initialize with n+1, meaning no triple found starting at or after l.

    // Iterate through all possible x and k to find triples s[x] = s[x+k] = s[x+2k]
    // Indices are 0-based for string s.
    // The problem uses 1-based indexing for l, r, x, k.
    // If s[x] = s[x+k] = s[x+2k] (0-based), then the triple spans indices [x, x+2k].
    // For a substring s[l...r] (1-based) to contain this triple, we need l-1 <= x and x+2k <= r-1.
    // This means l <= x+1 and x+2k+1 <= r.
    // The smallest possible r for a given l is x+2k+1.
    // The largest possible l for a given r is x+1.

    for (int x = 0; x < n; ++x) {
        // k can be at most (n-1-x)/2.
        // The maximum k is when x+2k = n-1, so 2k = n-1-x, k = (n-1-x)/2.
        // The minimum k is 1.
        // So k ranges from 1 to (n-1-x)/2.
        // The maximum value for x+2k is n-1.
        // The minimum value for x+2k is x+2.
        // The maximum value for k is 8 because if k >= 9, then 2k >= 18.
        // If a triple exists with k >= 9, say s[x]=s[x+k]=s[x+2k], then
        // s[x]=s[x+k]=s[x+2k] implies s[x]=s[x+1]=s[x+2] (if k=1)
        // or s[x]=s[x+2]=s[x+4] (if k=2) etc.
        // If k >= 9, then x+2k >= x+18.
        // Any substring of length 18 or more must contain a triple of the form s[i]=s[i+1]=s[i+2] or s[i]=s[i+2]=s[i+4] or s[i]=s[i+3]=s[i+6] etc.
        // This is a known property for binary strings: any binary string of length 9 or more must contain a square (XX) or an alternating pattern (XYX).
        // More specifically, any binary string of length 10 or more must contain a square.
        // For our condition s[x]=s[x+k]=s[x+2k], this is a specific type of pattern.
        // The maximum k we need to check is small.
        // If k is large, say k=9, then x+2k >= x+18.
        // If a triple s[x]=s[x+k]=s[x+2k] exists, then any substring of length 18 or more will contain it.
        // The maximum k we need to check is 8.
        // If k > 8, then 2k > 16.
        // If s[x] = s[x+k] = s[x+2k] for k > 8, then the length of this pattern is 2k+1 > 17.
        // Any substring of length 18 or more will contain a triple of length at most 17.
        // So we only need to check k up to 8.
        // This is because if a triple exists with k > 8, then there must exist a triple with k <= 8.
        // This is a known result from combinatorics on words.
        // For binary strings, any string of length 10 contains a square (XX).
        // For our pattern s[x]=s[x+k]=s[x+2k], the maximum k to check is 8.
        // If a string contains s[x]=s[x+k]=s[x+2k] for some k > 8, it must also contain such a pattern for some k' <= 8.
        // This means we only need to check k from 1 to 8.
        for (int k = 1; k <= 8 && x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a triple s[x] = s[x+k] = s[x+2k] (0-based indices).
                // This triple starts at 0-based index x and ends at 0-based index x+2k.
                // In 1-based indexing, it starts at x+1 and ends at x+2k+1.
                // For any l_1based from 1 to x+1, this triple is contained in s[l_1based ... r_1based]
                // if r_1based >= x+2k+1.
                // So, for each l_1based from 1 to x+1, the minimum r_1based required is x+2k+1.
                // We update min_r_for_l[l_1based] with min(current_value, x+2k+1).
                int triple_start_1based = x + 1;
                int triple_end_1based = x + 2 * k + 1;
                min_r_for_l[triple_start_1based] = std::min(min_r_for_l[triple_start_1based], triple_end_1based);
            }
        }
    }

    // Propagate minimum r values:
    // If s[l...r] contains a triple, then s[l-1...r] also contains it.
    // This means min_r_for_l[l-1] <= min_r_for_l[l].
    // So we can iterate from n-1 down to 1 and update min_r_for_l[i] = min(min_r_for_l[i], min_r_for_l[i+1]).
    for (int l = n - 1; l >= 1; --l) {
        min_r_for_l[l] = std::min(min_r_for_l[l], min_r_for_l[l + 1]);
    }

    long long count = 0;
    for (int l = 1; l <= n; ++l) {
        if (min_r_for_l[l] <= n) { // If there is at least one r such that s[l...r] contains a triple
            // For a fixed l, any r from min_r_for_l[l] to n will satisfy the condition.
            // The number of such r values is n - min_r_for_l[l] + 1.
            count += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_goodness = -1;
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., S1, S2 is empty)
    // All f(a_i, a_j) = a_i + a_j
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    long long current_goodness_case1 = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value);
    min_goodness = current_goodness_case1;
    for (int i = 0; i < n; ++i) {
        best_partition[a[i].original_index] = 1;
    }

    // Case 2: Partition into two non-empty subsequences.
    // Consider placing a[0] in S1 and a[1]...a[n-1] in S2.
    // This is equivalent to placing a[0] in S1 and a[1] in S1, and a[2]...a[n-1] in S2.
    // The minimum f value will be a[0].value + a[1].value (if a[0], a[1] are in same group)
    // OR a[0].value + a[2].value + h (if a[0] in S1, a[2] in S2)
    // OR a[1].value + a[2].value + h (if a[1] in S1, a[2] in S2)
    // The maximum f value will be a[n-1].value + a[n-2].value (if a[n-1], a[n-2] are in same group)
    // OR a[n-1].value + a[0].value + h (if a[n-1] in S2, a[0] in S1)

    // Let's analyze the minimum and maximum possible f values for any partition.
    // min_f_val = min(a_i + a_j, a_i + a_j + h)
    // max_f_val = max(a_i + a_j, a_i + a_j + h)

    // The smallest possible sum of two elements is a[0].value + a[1].value.
    // The largest possible sum of two elements is a[n-1].value + a[n-2].value.

    // If a[0] and a[1] are in the same group, min_f_same_group = a[0].value + a[1].value.
    // If a[0] and a[1] are in different groups, min_f_diff_group = a[0].value + a[1].value + h.

    // If a[n-1] and a[n-2] are in the same group, max_f_same_group = a[n-1].value + a[n-2].value.
    // If a[n-1] and a[n-2] are in different groups, max_f_diff_group = a[n-1].value + a[n-2].value + h.

    // Consider a partition where a[0] is in S1 and all other elements a[1]...a[n-1] are in S2.
    // This is a specific partition.
    // f values:
    // 1. a_i + a_j for i,j in {1, ..., n-1} (all in S2)
    // 2. a[0].value + a_j + h for j in {1, ..., n-1} (a[0] in S1, a_j in S2)

    // min_f for this partition:
    // min( (a[1].value + a[2].value), (a[0].value + a[1].value + h) )
    // max_f for this partition:
    // max( (a[n-1].value + a[n-2].value), (a[0].value + a[n-1].value + h) )

    // Goodness for this partition:
    // max_f - min_f
    // = max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)
    //   - min(a[1].value + a[2].value, a[0].value + a[1].value + h)

    // This is the "standard" partition for minimizing goodness when h is large.
    // The minimum f value is a[0].value + a[1].value + h (a[0] in S1, a[1] in S2).
    // The maximum f value is a[n-1].value + a[n-2].value (a[n-1], a[n-2] in S2).
    // The goodness is (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value + h).
    // This is only valid if a[0] is in S1, and a[1], a[2], ..., a[n-1] are in S2.
    // In this case, min_f = a[0].value + a[1].value + h.
    // max_f = a[n-1].value + a[n-2].value.
    // This is only true if a[n-1] and a[n-2] are in S2.
    // And if a[0].value + a[1].value + h is indeed the minimum.
    // And if a[n-1].value + a[n-2].value is indeed the maximum.

    // Let's consider the two main strategies:
    // Strategy A: All elements in one group. Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value).
    // This is already handled by `current_goodness_case1`.

    // Strategy B: Split elements such that a[0] is in S1 and a[1]...a[n-1] are in S2.
    // min_f = a[0].value + a[1].value + h (from S1-S2 pair)
    // max_f = a[n-1].value + a[n-2].value (from S2-S2 pair)
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value + h).
    // This is valid if:
    // 1. a[0].value + a[1].value + h is the minimum. This means a[0] is in S1, a[1] is in S2.
    //    And there is no pair (x,y) in S2 such that x+y < a[0].value + a[1].value + h.
    //    And there is no pair (x,y) in S1 such that x+y < a[0].value + a[1].value + h.
    //    Since S1 only has a[0], no S1-S1 pairs.
    //    Smallest S2-S2 pair is a[1].value + a[2].value.
    //    So we need a[0].value + a[1].value + h <= a[1].value + a[2].value.
    //    This simplifies to a[0].value + h <= a[2].value.
    // 2. a[n-1].value + a[n-2].value is the maximum. This means a[n-1], a[n-2] are in S2.
    //    And there is no pair (x,y) from S1-S2 such that x+y+h > a[n-1].value + a[n-2].value.
    //    Largest S1-S2 pair is a[0].value + a[n-1].value + h.
    //    So we need a[0].value + a[n-1].value + h <= a[n-1].value + a[n-2].value.
    //    This simplifies to a[0].value + h <= a[n-2].value.

    // Combining these, if a[0].value + h <= a[n-2].value, then this partition is optimal.
    // The goodness is (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value + h).
    // This is the "h-large" case.
    if (n >= 2) { // Need at least two elements for a[n-2] to be valid
        if (a[0].value + h <= a[n-2].value) {
            long long current_goodness_case2 = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value + h);
            if (current_goodness_case2 < min_goodness) {
                min_goodness = current_goodness_case2;
                best_partition[a[0].original_index] = 1;
                for (int i = 1; i < n; ++i) {
                    best_partition[a[i].original_index] = 2;
                }
            }
        }
    }

    // What if a[0].value + h > a[n-2].value?
    // This means the "h-large" partition might not be optimal.
    // The minimum f value could be a[0].value + a[1].value (if a[0], a[1] are in the same group).
    // The maximum f value could be a[n-1].value + a[0].value + h (if a[n-1] in S2, a[0] in S1).

    // Let's consider the partition where a[0] is in S1, and a[1]...a[n-1] are in S2.
    // min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h) (if n >= 3)
    // If n=2, min_f = a[0].value + a[1].value + h.
    // max_f = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h) (if n >= 3)
    // If n=2, max_f = a[0].value + a[1].value + h.
    // For n=2, this partition is the same as all in one group, goodness 0.
    // (a[0] in S1, a[1] in S2). f(a[0],a[1]) = a[0]+a[1]+h. min_f=max_f=a[0]+a[1]+h. Goodness=0.
    // This is covered by the general case.

    // For n >= 3:
    long long current_min_f_val;
    long long current_max_f_val;

    // Partition: a[0] in S1, a[1]...a[n-1] in S2
    current_min_f_val = a[0].value + a[1].value + h; // Smallest S1-S2 pair
    if (n >= 3) {
        current_min_f_val = std::min(current_min_f_val, a[1].value + a[2].value); // Smallest S2-S2 pair
    }

    current_max_f_val = a[0].value + a[n-1].value + h; // Largest S1-S2 pair
    if (n >= 3) {
        current_max_f_val = std::max(current_max_f_val, a[n-1].value + a[n-2].value); // Largest S2-S2 pair
    }

    long long current_goodness_case3 = current_max_f_val - current_min_f_val;
    if (current_goodness_case3 < min_goodness) {
        min_goodness = current_goodness_case3;
        best_partition[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            best_partition[a[i].original_index] = 2;
        }
    }

    // The problem statement implies that the optimal partition might involve a[0] and a[1] being in different groups.
    // The example 1: 1 2 3, h=2. Output 1 2 2.
    // a[0]=1, a[1]=2, a[2]=3.
    // Case 1 (all in one group): (3+2)-(1+2) = 5-3 = 2. Partition: 1 1 1.
    // Case 2 (a[0] in S1, others in S2):
    // a[0]=1 (S1), a[1]=2 (S2), a[2]=3 (S2).
    // f(1,2) = 1+2+2 = 5 (S1-S2)
    // f(1,3) = 1+3+2 = 6 (S1-S2)
    // f(2,3) = 2+3 = 5 (S2-S2)
    // min_f = 5, max_f = 6. Goodness = 1.
    // This matches the example output.
    // This is exactly the partition considered in "Case 3" above.
    // For n=3, a[0]=1, a[1]=2, a[2]=3, h=2.
    // current_min_f_val = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value)
    //                   = std::min(1 + 2 + 2, 2 + 3) = std::min(5, 5) = 5.
    // current_max_f_val = std::max(a[0].value + a[2].value + h, a[2].value + a[1].value)
    //                   = std::max(1 + 3 + 2, 3 + 2) = std::max(6, 5) = 6.
    // Goodness = 6 - 5 = 1. This is correct.

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <vector>
#include <algorithm>

int count_ones(const std::string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') {
            count++;
        }
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_in_a = count_ones(a);
    int ones_in_b = count_ones(b);

    // The maximum number of '1's we can have in a string of length L
    // is L.
    // The minimum number of '1's we can have in a string of length L
    // is 0.
    //
    // When we append a parity bit:
    // If current parity is 0, we append '0'. Number of '1's remains the same.
    // If current parity is 1, we append '1'. Number of '1's increases by 1.
    //
    // So, the number of '1's can only increase or stay the same.
    // It can never decrease.
    //
    // Let N_a be the number of ones in string a.
    // Let N_b be the number of ones in string b.
    //
    // If we start with string a, we can remove characters from the front.
    // This might decrease the number of ones.
    // Let a' be a suffix of a. Let N_a' be the number of ones in a'.
    //
    // Then we can append parity bits.
    // Each appended '1' increases N_a' by 1.
    // Each appended '0' keeps N_a' the same.
    //
    // The length of the string can only increase or stay the same (if we remove and then add).
    //
    // The key insight is that we can always make the string longer by appending parity bits.
    // If we have a string `s` with `k` ones, and its length is `L`.
    // We can append `parity(s)`.
    // If `k` is even, we append '0'. `k` remains `k`. Length becomes `L+1`.
    // If `k` is odd, we append '1'. `k` becomes `k+1`. Length becomes `L+1`.
    //
    // So, the number of ones can only increase or stay the same.
    // The maximum number of ones we can achieve for a string of length `L`
    // is `L`.
    //
    // Let's consider the number of ones in `a` and `b`.
    // `ones_in_a` is the count of '1's in the initial string `a`.
    // `ones_in_b` is the count of '1's in the target string `b`.
    //
    // The operations allow us to:
    // 1. Remove characters from the front of `a`. This can only decrease or keep `ones_in_a` the same.
    //    Let `a_suffix` be any suffix of `a`. `count_ones(a_suffix) <= ones_in_a`.
    // 2. Append parity bits. This can only increase or keep `count_ones(a_suffix)` the same.
    //    If `count_ones(a_suffix)` is odd, appending parity adds a '1', increasing the count.
    //    If `count_ones(a_suffix)` is even, appending parity adds a '0', keeping the count the same.
    //
    // So, if we start with `a_suffix`, we can generate a string `a_final` of length `|b|`.
    // The number of ones in `a_final` will be `count_ones(a_suffix)` plus some number of '1's
    // that were appended as parity bits.
    //
    // The maximum number of '1's we can achieve from `a` is `ones_in_a` + 1 (if `ones_in_a` is odd).
    // This is because if `ones_in_a` is odd, we can append a '1'. If it's even, we append a '0'.
    // After that, the new string has `ones_in_a` or `ones_in_a + 1` ones.
    // The length is `|a|+1`.
    //
    // The crucial observation is that if we have a string `s` with `k` ones, we can always
    // reach a state where the number of ones is `k` or `k+1` (if `k` is odd).
    //
    // Let `max_ones_reachable_from_a` be the maximum number of ones we can have in a string
