void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
    } else {
        // For n >= 2, we can construct a number.
        // A number consisting of (n-1) '2's followed by a '3'
        // e.g., n=2 -> 23
        // n=3 -> 223
        // n=4 -> 2223
        // This number is not divisible by 2 (ends in 3).
        // This number is not divisible by 3 (sum of digits is 2*(n-1)+3 = 2n+1.
        // If 2n+1 is divisible by 3, then 2n+1 = 3k.
        // For n=2, sum=5. Not div by 3.
        // For n=3, sum=7. Not div by 3.
        // For n=4, sum=9. Div by 3.
        // So 2223 is divisible by 3. This construction fails for n=4.

        // Let's try a different construction:
        // For n >= 2, print '2' for the first digit, and '3' for the remaining (n-1) digits.
        // Example: n=2 -> 23
        // n=3 -> 233
        // n=4 -> 2333
        // Digits are 2 and 3.
        // Not divisible by 2 (ends in 3).
        // Not divisible by 3:
        // Sum of digits = 2 + 3*(n-1) = 2 + 3n - 3 = 3n - 1.
        // 3n - 1 is never divisible by 3, because 3n is divisible by 3, so 3n-1 leaves a remainder of 2 when divided by 3.
        // This construction works for all n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << "\n";
    }
}

