void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    bool color_for_half_T = false; // false for 0, true for 1

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T / 2.0) { // Use 2.0 to ensure floating point division
            p[i] = 0; // Assign to white (c)
        } else if (a[i] > T / 2.0) {
            p[i] = 1; // Assign to black (d)
        } else { // a[i] == T / 2.0
            p[i] = color_for_half_T ? 1 : 0;
            color_for_half_T = !color_for_half_T; // Alternate color for T/2 elements
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

