#include <numeric>
#include <algorithm>

void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<std::vector<int>> a(n, std::vector<int>(m));
    std::vector<bool> row_has_one(n, false);
    std::vector<bool> col_has_one(m, false);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            std::cin >> a[i][j];
            if (a[i][j] == 1) {
                row_has_one[i] = true;
                col_has_one[j] = true;
            }
        }
    }

    int available_rows = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_has_one[i]) {
            available_rows++;
        }
    }

    int available_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_has_one[j]) {
            available_cols++;
        }
    }

    int moves = std::min(available_rows, available_cols);

    if (moves % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

