#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_for_i) {
                max_val_for_i = a[i][j];
            }
        }
        // If max_val_for_i is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_for_i.
        // This logic is based on the observation that if p[i] is not n,
        // then max_{j!=i} min(p[i], p[j]) = p[i].
        // If p[i] is n, then max_{j!=i} min(n, p[j]) = max_{j!=i} p[j] = n-1.
        // So, if max_val_for_i is n-1, p[i] must be n.
        // Otherwise, p[i] must be max_val_for_i.
        if (max_val_for_i == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_for_i;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for competitive programming.
    // This unties cin/cout from C stdio and disables synchronization,
    // which can significantly speed up I/O operations.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) { // Loop through each test case
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Declare a vector to store prices.
        // Using a vector is flexible and efficient enough for N up to 150000.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices into the vector
        }

        if (n <= 1) {
            // If there's only one day or no days, no price can be "bad"
            // because there are no later days.
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix_price with the price of the last day.
        // The last day's price is the minimum in the suffix starting from itself.
        int min_suffix_price = a[n - 1];

        // Iterate from the second to last day backwards to the first day.
        // For each day i, we compare its price a[i] with the minimum price
        // found in the suffix a[i+1...n-1].
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix_price) {
                // If the current day's price is greater than the minimum
                // price found later, it's a "bad" price.
                bad_prices_count++;
            } else {
                // If the current day's price is not greater than the minimum
                // price found later, it means a[i] is a new minimum for
                // the suffix a[i...n-1]. Update min_suffix_price.
                min_suffix_price = a[i];
            }
        }

        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0; // Indicate successful execution
}

#include <iostream>
