int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = -1; // Represents cell 0

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                max_gap = std::max(max_gap, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After the loop, consider the jump from the last 'R' cell to n+1
        // or from cell 0 to n+1 if no 'R' cells exist.
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

