int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is A_total = (1/2) * base * height = (1/2) * 1 * h = h/2.
    // We want to divide this into n equal pieces.
    // Each piece has area A_piece = A_total / n = (h/2) / n = h / (2n).

    // Consider a cut at distance x from the apex.
    // This cut forms a smaller triangle similar to the original one.
    // If the height of this smaller triangle is x, its base will be (x/h) * 1 = x/h.
    // The area of this smaller triangle is A_x = (1/2) * (x/h) * x = x^2 / (2h).

    // We want the area from the apex up to the k-th cut (x_k) to be k times A_piece.
    // So, A_{x_k} = k * A_piece
    // x_k^2 / (2h) = k * (h / (2n))
    // x_k^2 = k * (h^2 / n)
    // x_k = sqrt(k * h^2 / n)
    // x_k = h * sqrt(k / n)

    for (int k = 1; k < n; ++k) {
        double x_k = h * std::sqrt(static_cast<double>(k) / n);
        std::cout << std::fixed << std::setprecision(12) << x_k << (k == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long ans = 0;

        // The maximum number of teams is limited by the minimum of coders and mathematicians.
        // Each team needs at least one coder and at least one mathematician.
        // So, we can form at most min(c, m) teams.
        // Let's try to form 'k' teams.
        // We need 'k' coders, 'k' mathematicians, and 'k' other students.
        // The 'k' other students can be additional coders, additional mathematicians, or students without specialization.
        // Total students available: c + m + x
        // Total students needed for 'k' teams: 3 * k
        // So, 3 * k <= c + m + x
        // Also, k <= c and k <= m.
        // Combining these, k <= min(c, m, (c + m + x) / 3).
        // This suggests a binary search approach for 'k'.

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // Initial upper bound

        // A tighter upper bound for high can be min(c, m) because we need at least one of each.
        // However, (c+m+x)/3 might be even smaller.
        // So, high = std::min({c, m, (c + m + x) / 3}) is a good starting point.
        // The maximum possible value for c, m, x is 10^8.
        // So, c+m+x can be up to 3*10^8. (c+m+x)/3 can be 10^8.
        // min(c,m) can be 10^8. So high can be 10^8.
        // Binary search range is [0, 10^8]. This is efficient enough.

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // This uses 'mid' coders and 'mid' mathematicians.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining students without specialization: x
            // Total remaining students: (c - mid) + (m - mid) + x

            // Each of the 'mid' teams needs 3 members.
            // We've already accounted for 1 coder and 1 mathematician per team.
            // So, we need 'mid' more students to fill the third slot in each team.
            // These 'mid' students can come from the remaining coders, mathematicians, or x.
            // If (c - mid) + (m - mid) + x >= mid, then we have enough students for the third slot.

            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The numbers from 1 to k+1 will be used to generate k distinct differences.

    // Generate the first k+1 elements to produce k distinct differences.
    // We alternate between the smallest available and largest available numbers
    // from the range [1, k+1].
    // This sequence will be: 1, k+1, 2, k, 3, k-1, ...
    // The differences will be: k, k-1, k-2, ..., 1.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left (smallest)
            p[i] = left;
            left++;
        } else { // Odd index, take from right (largest)
            p[i] = right;
            right--;
        }
    }

    // For the remaining n - (k+1) elements, we need to ensure no new distinct differences are introduced.
    // The simplest way to do this is to continue the sequence in increasing order.
    // The last number used was either `left-1` or `right+1`.
    // The next available number is `k+2`.
    // By appending `k+2, k+3, ..., n` to the sequence, the differences will be `|p_k - (k+2)|`, `| (k+2) - (k+3) | = 1`, etc.
    // Since `1` is already one of the `k` distinct differences generated, this strategy works.
    // The numbers used so far are `1, ..., k+1`. The next available number is `k+2`.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This will be k+2, k+3, ..., n
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

