    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_count < k / 2) {
                result += c;
                open_count++;
                balance++;
            }
        } else { // c == ')'
            if (close_count < k / 2 && balance > 0) {
                result += c;
                close_count++;
                balance--;
            }
        }
        if (open_count == k / 2 && close_count == k / 2) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of a non-decreasing suffix
    // This is the first element from the right that breaks the non-decreasing order
    // i.e., a[i] > a[i+1]
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i=0, the whole array is non-decreasing.

    // Find the rightmost peak of a non-increasing suffix
    // This is the first element from the right that breaks the non-increasing order
    // i.e., a[j] < a[j+1]
    int j = i; // Start search from 'i'
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // Now a[j...i] is non-increasing.
    // The segment a[j...n-1] is of the form non-increasing then non-decreasing.
    // This means a[j...i] is non-increasing and a[i...n-1] is non-decreasing.
    // The element a[i] is the minimum in a[j...n-1].

    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

