    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        // The quadratic equation for 'a' is a^2 - d*a + d = 0
        // Using the quadratic formula: a = (d +/- sqrt(d^2 - 4d)) / 2
        // For real solutions, the discriminant (d^2 - 4d) must be non-negative.
        // d^2 - 4d >= 0
        // d * (d - 4) >= 0
        // Since d >= 0, this implies d - 4 >= 0, so d >= 4.
        // Also, if d = 0, then 0 * (-4) = 0, which is >= 0.
        // So, real solutions exist if d = 0 or d >= 4.

        if (d == 0) {
            // If d = 0, then a + b = 0 and a * b = 0.
            // Since a, b must be non-negative, the only solution is a = 0, b = 0.
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4) {
            // For 0 < d < 4, d^2 - 4d is negative, so no real solutions.
            std::cout << "N\n";
        } else { // d >= 4
            double discriminant = d * d - 4 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            // We need a and b to be non-negative.
            // Let's choose the '+' sign for 'a' to get a larger value,
            // and then 'b' will be d - a.
            // a = (d + sqrt_discriminant) / 2
            // b = (d - sqrt_discriminant) / 2
            // Both a and b will be non-negative because:
            // d >= 0 and sqrt_discriminant >= 0, so a is clearly >= 0.
            // For b: d - sqrt_discriminant >= 0
            // d >= sqrt_discriminant
            // d^2 >= discriminant (since both sides are non-negative)
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0, which is true for this case.

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

