        // We need to check if a_i >= i for all i in the increasing part.
        // The first element a_0 must be 0.
        // The second element a_1 must be at least 1.
        // The third element a_2 must be at least 2.
        // ...
        // The i-th element a_{i-1} must be at least i-1.
        // So, a_i must be at least i.
        // We need to find the maximum k such that a_i >= i for 0 <= i < k.
        // If a_i < i for some i, then it's impossible to make a_i >= i.
        // So, we need to check if a_i >= i for all i from 0 to n-1.
        // If this holds, then we can form a sequence 0, 1, 2, ..., n-1.
        // This is a sharpened array with k=n.
        // If a_i < i for some i, then it's impossible to make a_i >= i.
        // In this case, we can't form the increasing part 0, 1, ..., i.
        // So, if a_0 is 0, we must have a_i >= i for all i.
        // If this is true, we can make it 0, 1, ..., n-1, which is sharpened.
        // If not, it's impossible.
        bool possible = true;
        for (int i = 0; i < n; ++i) {
            if (a[i] < i) {
                possible = false;
                break;
            }
        }
        if (possible) {
            std::cout << "Yes\n";
        } else {
            std::cout << "No\n";
        }
        return;
    }

    // If a_0 > 0, then we can always make a_0 = 0.
    // The problem reduces to the case where a_0 is 0.
    // We need to check if a_i >= i for all i from 0 to n-1.
    // If this is true, we can make it 0, 1, ..., n-1, which is sharpened.
    // If not, it's impossible.
    bool possible = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            possible = false;
            break;
        }
    }
    if (possible) {
