int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2; // For 0-indexed array of odd length n, median is at n/2

    // First, ensure the median element itself is s.
    operations += std::abs(a[mid_idx] - s);

    // If a[mid_idx] is less than s, all elements to its right (including itself)
    // that are currently less than s must be increased to at least s.
    // Since we already handled a[mid_idx], we iterate from mid_idx + 1.
    if (a[mid_idx] < s) {
        for (int i = mid_idx + 1; i < n; ++i) {
            if (a[i] < s) {
                operations += (s - a[i]);
            } else {
                // Since the array is sorted, if a[i] >= s, all subsequent elements are also >= s.
                // No further operations needed for elements to the right.
                break;
            }
        }
    }
    // If a[mid_idx] is greater than s, all elements to its left (including itself)
    // that are currently greater than s must be decreased to at most s.
    // Since we already handled a[mid_idx], we iterate from mid_idx - 1.
    else if (a[mid_idx] > s) {
        for (int i = mid_idx - 1; i >= 0; --i) {
            if (a[i] > s) {
                operations += (a[i] - s);
            } else {
                // Since the array is sorted, if a[i] <= s, all previous elements are also <= s.
                // No further operations needed for elements to the left.
                break;
            }
        }
    }
    // If a[mid_idx] == s, no additional operations for elements to its left/right
    // based on the median value itself. The loops above correctly handle this
    // by not adding anything if a[i] already satisfies the condition.

    std::cout << operations << std::endl;

    return 0;
}

