// Function to determine if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // Box 1: x <= -1
    // Requires a negative product with magnitude >= 1.
    // This means an odd number of negative factors, and product of magnitudes >= 1.

    // Case 1: Final product is negative.
    // This requires an odd number of negative toys.
    // The number of negative toys is A + B.
    // If (A + B) is even, we need to make it odd.
    // If (A + B) is odd, we need to keep it odd.

    // Case 2: Final product has magnitude >= 1.
    // This requires at least one toy with magnitude >= 1 (from A or D)
    // OR multiple toys with magnitude < 1 that multiply to >= 1 (e.g., 0.5 * 3 = 1.5, 0.5 * 0.5 * 5 = 1.25).
    // The problem states "fun values are real numbers". We can pick values like 0.5 and 3.
    // If we have at least one toy from Box 1 or Box 4, we can potentially achieve magnitude >= 1.
    // If we only have toys from Box 2 and Box 3, the product of magnitudes will always be < 1.
    // So, if A + D == 0, Box 1 cannot be the special box.

    if (A + D == 0) { // No toys with magnitude >= 1 initially
        return false;
    }

    // If A + B is odd, we can potentially end up with a negative number.
    // If A + B is even, we need to make it odd.
    // This can be done by pairing up negative numbers to make positive, or positive numbers to make positive.
    // The parity of negative numbers can only change if we have at least one positive number to pair with a negative number.
    // If we have only negative numbers (C+D=0), the parity of A+B is fixed.
    // If we have at least one positive number (C+D > 0), we can always change the parity of negative numbers.
    // Example: N1, N2, P1. (A+B=2, even). N1*P1 = N3. Now N3, N2. (A+B=2, even). N3*N2 = P4.
    // This logic is tricky. Let's simplify.
    // The final product's sign depends on the parity of negative numbers used in the final multiplication.
    // If we have at least one positive number (C+D > 0), we can always choose to pair a negative number with a positive number
    // to produce a negative number, or pair two negative numbers to produce a positive number.
    // This means if C+D > 0, we can control the final sign.
    // If C+D == 0, then all toys are negative. The final product will be negative if (A+B) is odd, positive if (A+B) is even.

    // If A+D > 0 (magnitude >= 1 is possible)
    // If C+D > 0 (at least one positive toy exists)
    // We can always achieve a negative final product.
    // We can always achieve magnitude >= 1.
    // So if A+D > 0 and C+D > 0, Box 1 is possible.

    // What if C+D == 0? All toys are negative.
    // The final product will be negative if (A+B) is odd.
    // The final product will be positive if (A+B) is even.
    // If C+D == 0, then D must be 0. So A > 0.
    // If C+D == 0 and A+B is odd, then the final product is negative.
    // Since A > 0, magnitude >= 1 is possible.
    // So if C+D == 0 and (A+B) % 2 == 1, Box 1 is possible.

    // Combining:
    // Box 1 is possible if:
    // (A + D > 0) AND ( (C + D > 0) OR ((A + B) % 2 == 1) )
    // This covers all cases where magnitude >= 1 is possible AND a negative sign is possible.

    return (A + D > 0) && ((C + D > 0) || ((A + B) % 2 == 1));
}

// Function to determine if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Box 2: -1 < x < 0
    // Requires a negative product with magnitude < 1.
    // This means an odd number of negative factors, and product of magnitudes < 1.

    // Case 1: Final product is negative.
    // Same logic as Box 1: (C+D > 0) OR ((A+B) % 2 == 1)

    // Case 2: Final product has magnitude < 1.
    // This requires that all toys with magnitude >= 1 (from A or D) are "cancelled out"
    // by toys with magnitude < 1 (from B or C), such that the final product is < 1.
    // This is always possible if we have at least one toy from B or C.
    // If B + C == 0, then all toys have magnitude >= 1. The product will always be >= 1.
    // So if B + C == 0, Box 2 cannot be the special box.

    if (B + C == 0) { // No toys with magnitude < 1 initially
        return false;
    }

    // If B+C > 0 (magnitude < 1 is possible)
    // If C+D > 0 (at least one positive toy exists)
    // We can always achieve a negative final product.
    // We can always achieve magnitude < 1.
    // So if B+C > 0 and C+D > 0, Box 2 is possible.

    // What if C+D == 0? All toys are negative.
    // The final product will be negative if (A+B) is odd.
    // The final product will be positive if (A+B) is even.
    // If C+D == 0 and (A+B) is odd, then the final product is negative.
    // Since B > 0 (because B+C > 0 and C=0), magnitude < 1 is possible.
    // So if C+D == 0 and (A+B) % 2 == 1, Box 2 is possible.

    // Combining:
    // Box 2 is possible if:
    // (B + C > 0) AND ( (C + D > 0) OR ((A + B) % 2 == 1) )
    // This covers all cases where magnitude < 1 is possible AND a negative sign is possible.

    return (B + C > 0) && ((C + D > 0) || ((A + B) % 2 == 1));
}

// Function to determine if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Box 3: 0 < x < 1
    // Requires a positive product with magnitude < 1.
    // This means an even number of negative factors, and product of magnitudes < 1.

    // Case 1: Final product is positive.
    // This requires an even number of negative toys.
    // If (A + B) is even, we need to keep it even.
    // If (A + B) is odd, we need to make it even.
    // This is possible if we have at least one positive toy (C+D > 0).
    // If C+D == 0, then all toys are negative. The final product will be positive if (A+B) is even.
    // So, (C+D > 0) OR ((A+B) % 2 == 0)

    // Case 2: Final product has magnitude < 1.
    // Same logic as Box 2: B + C > 0.

    if (B + C == 0) { // No toys with magnitude < 1 initially
        return false;
    }

    // If B+C > 0 (magnitude < 1 is possible)
    // If C+D > 0 (at least one positive toy exists)
    // We can always achieve a positive final product.
    // We can always achieve magnitude < 1.
    // So if B+C > 0 and C+D > 0, Box 3 is possible.

    // What if C+D == 0? All toys are negative.
    // The final product will be positive if (A+B) is even.
    // If C+D == 0 and (A+B) is even, then the final product is positive.
    // Since B > 0 (because B+C > 0 and C=0), magnitude < 1 is possible.
    // So if C+D == 0 and (A+B) % 2 == 0, Box 3 is possible.

    // Combining:
    // Box 3 is possible if:
    // (B + C > 0) AND ( (C + D > 0) OR ((A + B) % 2 == 0) )
    // This covers all cases where magnitude < 1 is possible AND a positive sign is possible.

    return (B + C > 0) && ((C + D > 0) || ((A + B) % 2 == 0));
}

// Function to determine if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Box 4: x >= 1
    // Requires a positive product with magnitude >= 1.
    // This means an even number of negative factors, and product of magnitudes >= 1.

    // Case 1: Final product is positive.
    // Same logic as Box 3: (C+D > 0) OR ((A+B) % 2 == 0)

    // Case 2: Final product has magnitude >= 1.
    // Same logic as Box 1: A + D > 0.

    if (A + D == 0) { // No toys with magnitude >= 1 initially
        return false;
    }

    // If A+D > 0 (magnitude >= 1 is possible)
    // If C+D > 0 (at least one positive toy exists)
    // We can always achieve a positive final product.
    // We can always achieve magnitude >= 1.
    // So if A+D > 0 and C+D > 0, Box 4 is possible.

    // What if C+D == 0? All toys are negative.
    // The final product will be positive if (A+B) is even.
    // If C+D == 0 and (A+B) is even, then the final product is positive.
    // Since A > 0 (because A+D > 0 and D=0), magnitude >= 1 is possible.
    // So if C+D == 0 and (A+B) % 2 == 0, Box 4 is possible.

    // Combining:
    // Box 4 is possible if:
    // (A + D > 0) AND ( (C + D > 0) OR ((A + B) % 2 == 0) )
    // This covers all cases where magnitude >= 1 is possible AND a positive sign is possible.

    return (A + D > 0) && ((C + D > 0) || ((A + B) % 2 == 0));
}

