            // While i < n and j < n:
            //   If a[i] > a[j]:
            //     We found a pair. Increment count. Move to next element to place (i++) and next position (j++).
            //   Else (a[i] <= a[j]):
            //     a[i] is too small for a[j]. We must try a larger element to place. So, i++.
            //     We keep j as is, hoping a later a[i] will be greater than a[j].
            // This greedy strategy works because by using the smallest possible a[i] that works for a[j],
            // we leave larger elements available for subsequent positions, maximizing future matches.

            // My current code's 'left_ptr' is 'i' and 'right_ptr' is 'j'.
            // So, if a[left_ptr] < a[right_ptr], it means a[left_ptr] is too small for a[right_ptr].
            // We should advance left_ptr to find a larger element.
            // If a[left_ptr] > a[right_ptr], we found a match. Increment count, advance both.
            // This is the correct logic.

            // Let's trace with example: [1, 1, 1, 3, 5, 5, 10] (sorted A)
            // left_ptr (i) = 0, right_ptr (j) = 0, count = 0
            // a[0]=1, a[0]=1. a[i] <= a[j]. Advance i.
            // i=1, j=0. a[1]=1, a[0]=1. a[i] <= a[j]. Advance i.
            // i=2, j=0. a[2]=1, a[0]=1. a[i] <= a[j]. Advance i.
            // i=3, j=0. a[3]=3, a[0]=1. a[i] > a[j]. Match! count=1. Advance i, j.
            // i=4, j=1. a[4]=5, a[1]=1. a[i] > a[j]. Match! count=2. Advance i, j.
            // i=5, j=2. a[5]=5, a[2]=1. a[i] > a[j]. Match! count=3. Advance i, j.
            // i=6, j=3. a[6]=10, a[3]=3. a[i] > a[j]. Match! count=4. Advance i, j.
            // i=7 (end), j=4. Loop terminates. Result 4. This is correct.

            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // a[left_ptr] is not greater than a[right_ptr] (i.e., a[left_ptr] <= a[right_ptr]).
            // This means a[left_ptr] is too small to be placed at position a[right_ptr]
            // and satisfy the condition. Since 'a' is sorted, a[left_ptr] will also be too small
            // for any subsequent a[right_ptr'] where right_ptr' > right_ptr.
            // So, we must try a larger element from the 'elements to place' pool.
            left_ptr++;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

