// Function to check if a prefix of length `len` is a permutation
// `a` is the original array, `n` is its total length
// `max_val_prefix[len-1]` stores the maximum value in a[0...len-1]
// `is_distinct_prefix[len-1]` is true if a[0...len-1] contains distinct elements
bool is_prefix_permutation(int len, int n, const std::vector<int>& a,
                           const std::vector<int>& max_val_prefix,
                           const std::vector<bool>& is_distinct_prefix) {
    if (len <= 0 || len > n) return false;
    return is_distinct_prefix[len - 1] && max_val_prefix[len - 1] == len;
}

// Function to check if a suffix of length `len` is a permutation
// `a` is the original array, `n` is its total length
// `max_val_suffix[n-len]` stores the maximum value in a[n-len...n-1]
// `is_distinct_suffix[n-len]` is true if a[n-len...n-1] contains distinct elements
bool is_suffix_permutation(int len, int n, const std::vector<int>& a,
                           const std::vector<int>& max_val_suffix,
                           const std::vector<bool>& is_distinct_suffix) {
    if (len <= 0 || len > n) return false;
    return is_distinct_suffix[n - len] && max_val_suffix[n - len] == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute for prefixes
    std::vector<int> max_val_prefix(n);
    std::vector<bool> is_distinct_prefix(n);
    std::vector<bool> seen_prefix(n + 1, false); // Using n+1 for 1-based indexing
    int current_max_prefix = 0;
    bool current_distinct_prefix = true;

    for (int i = 0; i < n; ++i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization, max value in permutation of length k is k
            current_distinct_prefix = false;
        }
        seen_prefix[a[i]] = true;
        current_max_prefix = std::max(current_max_prefix, a[i]);
        max_val_prefix[i] = current_max_prefix;
        is_distinct_prefix[i] = current_distinct_prefix;
    }

    // Precompute for suffixes
    std::vector<int> max_val_suffix(n);
    std::vector<bool> is_distinct_suffix(n);
    std::fill(seen_prefix.begin(), seen_prefix.end(), false); // Reset seen array
    int current_max_suffix = 0;
    bool current_distinct_suffix = true;

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || seen_prefix[a[i]]) {
            current_distinct_suffix = false;
        }
        seen_prefix[a[i]] = true;
        current_max_suffix = std::max(current_max_suffix, a[i]);
        max_val_suffix[i] = current_max_suffix;
        is_distinct_suffix[i] = current_distinct_suffix;
    }

    std::vector<std::pair<int, int>> results;

    for (int l1 = 1; l1 < n; ++l1) { // l1 can range from 1 to n-1
        int l2 = n - l1;
        if (is_prefix_permutation(l1, n, a, max_val_prefix, is_distinct_prefix) &&
            is_suffix_permutation(l2, n, a, max_val_suffix, is_distinct_suffix)) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

