void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // If current_sum == 2 * current_xor_sum, the array is already good.
    // We can append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
        return;
    }

    // We need to append elements.
    // Let S be current_sum and X be current_xor_sum.
    // We want to find b1, b2, ... such that (S + sum(b_i)) = 2 * (X ^ xor(b_i)).

    // Strategy: Append two elements.
    // Let the two elements be X and S + X.
    // New XOR sum: X' = X ^ X ^ (S + X) = S + X.
    // New sum: S' = S + X + (S + X) = 2S + 2X.
    // Check condition: S' == 2 * X'
    // (2S + 2X) == 2 * (S + X)
    // This is always true.
    // So, appending X and S+X always makes the array good.
    // The problem states we can append at most 3 elements. This uses 2.

    // The values can be large, up to 10^18.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 (approx 10^9).
    // So S + X can be up to 10^14 + 10^9, which fits in long long.

    std::cout << 2 << "\n";
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
}

