int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will contribute to the total steps.
            // The number of 'a's currently accumulated (count_a)
            // represents the 'a's that are to the left of this 'b'.
            // When an 'a' interacts with this 'b', it effectively
            // "jumps" over it, and this 'b' becomes part of the 'b's
            // that the 'a' will eventually jump over.
            // The number of steps added by this 'b' is equal to the
            // number of 'a's that are currently to its left.
            total_steps = (total_steps + count_a) % MOD;

            // After this 'b' has been processed (i.e., all 'a's to its left
            // have "jumped" over it), this 'b' effectively doubles the
            // number of 'a's that will be "available" to jump over
            // subsequent 'b's to its left.
            // This is because each 'a' that jumps over this 'b' creates
            // a new 'b'. So, if there were `count_a` 'a's, they will
            // create `count_a` new 'b's. These new 'b's, along with the
            // original 'b', will be to the right of any 'a's further left.
            // The 'a's themselves remain.
            // The crucial insight is that each 'a' that passes this 'b'
            // effectively doubles the "potential" for future steps
            // for 'a's further to the left.
            // So, the count of 'a's that are "active" for future 'b's
            // effectively doubles for each 'b' encountered.
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of
            // 'a's that are currently to the left of any 'b's we might
            // encounter later (when iterating right-to-left).
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

