// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    std::reverse(pattern.begin(), pattern.end());
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            counts[pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // The problem states that if the pattern is shorter than the integer,
            // it's supplemented with 0-s from the left.
            // Similarly, if the integer is shorter than the pattern,
            // its decimal notation is supplemented with 0-s from the left.
            // This means we effectively compare patterns of length 18 (max possible length for 10^18-1).
            // A '0' in the pattern means an even digit.
            // A '1' in the pattern means an odd digit.
            // When padding with '0's, it means padding with even digits.
            // So, we can normalize all patterns to length 18 by padding with '0's from the left.
            // Example: 92 (092) matches 010.
            // 92 -> 010 (parity pattern)
            // 010 (query pattern)
            // Both are length 3.
            // If query is "1", and number is 241.
            // 241 -> 001 (parity pattern)
            // "1" -> 000000000000000001 (padded query pattern)
            // This is not how it works. The example 92, 2212, 50, 414 match 010.
            // 92 -> 010
            // 2212 -> 0010
            // 50 -> 00
            // 414 -> 000
            // The rule is: "If the pattern is shorter than this integer, it's supplemented with 0-s from the left.
            // Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // This means we should normalize the query pattern to a fixed length (e.g., 18) by padding with '0's from the left.
            // And the stored patterns for numbers should also be normalized to length 18 by padding with '0's from the left.
            // The `get_parity_pattern` function already produces the minimal length pattern.
            // So, we need to pad the query pattern `s` to length 18.
            // And when storing, we should also pad the number's pattern to length 18.

            // Let's re-evaluate the `get_parity_pattern` function and storage.
            // The maximum value for a_i is < 10^18, which means it can have up to 18 digits.
            // The pattern length is no more than 18.
            // So, we can normalize all patterns to a fixed length, say 18, by padding with '0's from the left.
            // This way, a number like 92 (parity 010) becomes "000...0010" (18 chars).
            // A query pattern like "010" becomes "000...0010" (18 chars).
            // A query pattern like "1" becomes "000...0001" (18 chars).
            // This simplifies matching to direct string comparison.

            std::string normalized_s = std::string(18 - s.length(), '0') + s;
            std::cout << counts[normalized_s] << "\n";
        }
    }

    return 0;
}

