int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_total_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let i be the number of items taken from the left (0 <= i <= n)
    // Then n - i items are taken from the right.
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        // These are w[0]...w[i-1]
        current_energy += (prefix_sum[i] - prefix_sum[0]) * l;

        // Energy for items taken from the right
        // These are w[i]...w[n-1] (if i < n)
        // The number of items taken from the right is n - i.
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for imbalance
        int num_left = i;
        int num_right = n - i;

        if (num_left > num_right) {
            // More items taken from left.
            // The last item taken from the right was at index n-1.
            // The last item taken from the left was at index i-1.
            // If num_left > num_right + 1, then the (num_right + 1)-th item from left
            // was taken after the last right item, and it was a consecutive left.
            // The number of extra left items is num_left - num_right - 1.
            // Each such extra item incurs Ql penalty.
            current_energy += std::max(0, num_left - num_right - 1) * Ql;
        } else if (num_right > num_left) {
            // More items taken from right.
            // The number of extra right items is num_right - num_left - 1.
            // Each such extra item incurs Qr penalty.
            current_energy += std::max(0, num_right - num_left - 1) * Qr;
        }
        // If num_left == num_right, no penalty.

        if (min_total_energy == -1 || current_energy < min_total_energy) {
            min_total_energy = current_energy;
        }
    }

    std::cout << min_total_energy << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    if (n == 1) {
        return 1;
    }
    if (n == 2) {
        return 1;
    }
    if (n == 3) {
        return 2;
    }

    // Case 1: N is odd
    // Chanek must take 1. N becomes N-1 (even).
    // Opponent faces N-1.
    // If N-1 is a power of 2, opponent takes (N-1)/2.
    // If N-1 is not a power of 2, opponent takes 1.
    // This strategy is not simple. Let's analyze the optimal moves.

    // The game is impartial, but players want to maximize their own score, not just win.
    // This is a minimax problem.
    // Let f(N) be the maximum coins Chanek can get if it's his turn and N coins are left.
    // Let g(N) be the maximum coins Opponent can get if it's Opponent's turn and N coins are left.
    // Chanek's turn:
    //   Option 1: Take 1. Chanek gets 1 + (N - 1 - g(N-1)).
    //   Option 2: Take N/2 (if N is even). Chanek gets N/2 + (N - N/2 - g(N/2)).
    // Chanek chooses max(Option 1, Option 2).
    // Opponent's turn:
    //   Option 1: Take 1. Opponent gets 1 + (N - 1 - f(N-1)).
    //   Option 2: Take N/2 (if N is even). Opponent gets N/2 + (N - N/2 - f(N/2)).
    // Opponent chooses max(Option 1, Option 2).

    // This is too complex for N up to 10^18.
    // Let's look for a pattern or a greedy strategy.

    // If N is odd: Chanek must take 1. N becomes N-1 (even).
    // Chanek gets 1. Remaining N-1. Opponent's turn.
    // If N is even: Chanek can take 1 or N/2.
    //   If Chanek takes 1: N becomes N-1 (odd). Chanek gets 1. Remaining N-1. Opponent's turn.
    //   If Chanek takes N/2: N becomes N/2. Chanek gets N/2. Remaining N/2. Opponent's turn.

    // Consider the "take N/2" move. This is very powerful.
    // If N is even, and Chanek takes N/2, he gets a large chunk.
    // The opponent then faces N/2.
    // If N is even, and Chanek takes 1, he gets 1. The opponent faces N-1 (odd).
    // The opponent must take 1, leaving N-2 (even).

    // Let's analyze the game for N.
    // If N is odd: Chanek must take 1.
    //   Chanek gets 1. Remaining N-1. Opponent's turn.
    //   Now N-1 is even. Opponent can take 1 or (N-1)/2.
