            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // If x is divisible by q, then x must have at least a_i factors of f_i for all i.
        // To make x not divisible by q, we must remove enough factors of some f_i from p
        // such that x has fewer than a_i factors of f_i.
        // To maximize x, we should remove the minimum necessary factors.
        // This means for each prime factor f_i of q, we try to make x not divisible by f_i^a_i
        // by dividing p by f_i until it's no longer divisible by f_i^a_i.
        // Specifically, if p has b_i factors of f_i, and q has a_i factors of f_i,
        // then p is divisible by f_i^b_i.
        // If b_i >= a_i, then p is divisible by f_i^a_i.
        // To make x not divisible by q, we must ensure that for at least one f_j,
        // x has fewer than a_j factors of f_j.
        // The strategy is to iterate through each prime factor f_i of q.
        // For each f_i, we calculate p' = p / (f_i^k) such that p' is not divisible by q.
        // The largest such p' will be our answer.

        std::vector<std::pair<long long, int>> q_factors = prime_factorize(q);
        long long max_x = 1;

        for (const auto& factor_pair : q_factors) {
            long long f = factor_pair.first;
            // int a = factor_pair.second; // This 'a' is the exponent of f in q.

            // Calculate the current p_candidate by removing factors of f from p
            // until p_candidate is no longer divisible by q.
            // More precisely, we want to find the largest divisor of p, say x_candidate,
            // such that x_candidate is not divisible by q.
            // If p is divisible by q, then p has enough factors of f to be divisible by q.
            // We need to remove factors of f from p until it's no longer divisible by q.
            // The smallest number of factors of f we can remove from p to make it not divisible by q
            // is to remove all factors of f that are present in q.
            // Example: p=12, q=6. q_factors: (2,1), (3,1).
            // For f=2: p=12. p has 2^2. q has 2^1.
            // We need to make x not divisible by 2^1.
            // If we divide p by 2, we get 6. 6 is divisible by 6.
            // If we divide p by 2^2, we get 3. 3 is not divisible by 6.
            // For f=3: p=12. p has 3^1. q has 3^1.
            // If we divide p by 3, we get 4. 4 is not divisible by 6.
            // The maximum of 3 and 4 is 4.

            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= f;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

