int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 1: can move left (x-1). If cannot move left (f1=0),
            // then target X must be >= current x.
            // So, X >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // f3 = 1: can move right (x+1). If cannot move right (f3=0),
            // then target X must be <= current x.
            // So, X <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // f4 = 1: can move down (y-1). If cannot move down (f4=0),
            // then target Y must be >= current y.
            // So, Y >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // f2 = 1: can move up (y+1). If cannot move up (f2=0),
            // then target Y must be <= current y.
            // So, Y <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // A valid point exists. The problem guarantees that if a point exists,
            // one exists with coordinates not exceeding 10^5 by absolute value.
            // So, we can just pick (min_x, min_y) or any point in the valid range.
            // The problem statement implies that the coordinates of the output point
            // should not exceed 10^5 by absolute value.
            // The initial coordinates are up to 10^5.
            // If min_x or max_x are outside [-10^5, 10^5], it means the constraints
            // from robots pushed them there.
            // However, the problem guarantees that if a point exists, one exists
            // within [-10^5, 10^5]. So, we can just output min_x, min_y.
            // The problem statement says "Both X and Y should not exceed 10^5 by absolute value;
            // it is guaranteed that if there exists at least one point reachable by all robots,
            // then at least one of such points has both coordinates not exceeding 10^5 by absolute value."
            // This means we don't need to clamp min_x, min_y to [-10^5, 10^5] if they are outside.
            // The problem implies that if min_x > 10^5, then there must be some other valid X' <= 10^5.
            // But our min_x is the tightest lower bound.
            // The simplest interpretation is that any valid point is fine, and if our calculated min_x, min_y
            // are outside [-10^5, 10^5], it's still a valid point, and the problem guarantees
            // that *some* valid point exists within the bounds.
            // Let's just output min_x, min_y.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];
    long long days_left = d;

    for (int i = 1; i < n; ++i) {
        long long distance = i; // distance from pile i+1 to pile 1 (0-indexed)

        if (days_left <= 0) {
            break;
        }

        // Calculate how many haybales can be moved from pile i to pile 1
        // Each haybale costs 'distance' days.
        // We have 'a[i]' haybales in pile i.
        // We have 'days_left' days remaining.

        long long haybales_to_move = a[i];
        long long max_haybales_possible_by_days = days_left / distance;

        long long actual_haybales_moved = std::min(haybales_to_move, max_haybales_possible_by_days);

        current_a1 += actual_haybales_moved;
        days_left -= actual_haybales_moved * distance;
    }

    std::cout << current_a1 << std::endl;
}

