#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long abs_n = n;
        long long abs_m = m;

        if (k < std::max(abs_n, abs_m)) {
            std::cout << -1 << "\n";
            continue;
        }

        long long parity_n = abs_n % 2;
        long long parity_m = abs_m % 2;
        long long parity_k = k % 2;

        if (parity_n == parity_m) { // (0,0) or (1,1)
            if (parity_k == parity_n) { // k has same parity as n and m
                std::cout << k << "\n";
            } else { // k has different parity
                // Need to make 2 non-diagonal moves to change parity of k without changing final position
                // e.g., (x,y) -> (x+1,y) -> (x,y)
                // or (x,y) -> (x+1,y) -> (x+1,y+1) -> (x,y+1) -> (x,y)
                // This costs 2 moves and changes parity of k by 2 (effectively 0)
                // But we need to change parity of k by 1.
                // This means we need to use 2 non-diagonal moves to "waste" parity.
                // For example, if n,m are even, k is odd.
                // We can reach (n,m) in max(n,m) moves.
                // If max(n,m) is even, k is odd. We need to make k-max(n,m) additional moves.
                // k-max(n,m) must be even. But here it's odd.
                // So we need to adjust.
                // We can make one non-diagonal move and one diagonal move.
                // (x,y) -> (x+1,y) -> (x+2,y+1)
                // This changes parity of x by 0, y by 1.
                // This is not what we want.
                // The simplest way to change parity of k without changing target parity is to use 2 non-diagonal moves.
                // (x,y) -> (x+1,y) -> (x,y)
                // This uses 2 moves, changes k by 2, and doesn't change (x,y) parity.
                // So if k has different parity than n and m, we must use at least 2 non-diagonal moves.
                // This means we lose 2 diagonal moves.
                std::cout << k - 2 << "\n";
            }
        } else { // (0,1) or (1,0)
            // n and m have different parities.
            // k must also have different parity from n (and m).
            // If n is even, m is odd, then k must be odd.
            // If n is odd, m is even, then k must be odd.
            // In general, k must be odd.
            if (parity_k == 1) { // k is odd
                std::cout << k << "\n";
            } else { // k is even
                // This case is impossible.
                // If n and m have different parities, then after any number of moves,
                // the current point (x,y) will have x and y with different parities if k is odd,
                // and same parities if k is even.
                // Since n and m have different parities, we need k to be odd.
                // If k is even, it's impossible.
                std::cout << -1 << "\n";
            }
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of k from 1 to a: a * (a + 1) / 2
    long long sum_k = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k = (sum_k * ((MOD + 1) / 2)) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // Sum of r from 1 to b-1: (b-1) * b / 2
    long long sum_r = ((b - 1) % MOD * (b % MOD)) % MOD;
    sum_r = (sum_r * ((MOD + 1) / 2)) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // The total sum is sum_{k=1 to a} sum_{r=1 to b-1} (krb + r)
    // = sum_{k=1 to a} sum_{r=1 to b-1} (r * (kb + 1))
    // = sum_{k=1 to a} (kb + 1) * sum_{r=1 to b-1} r
    // = (sum_{r=1 to b-1} r) * sum_{k=1 to a} (kb + 1)
    // = sum_r * (sum_{k=1 to a} (kb) + sum_{k=1 to a} 1)
    // = sum_r * (b * sum_{k=1 to a} k + a)
    // = sum_r * (b * sum_k + a)

    long long term_b_sum_k = (b % MOD * sum_k) % MOD;
    long long inner_sum = (term_b_sum_k + (a % MOD)) % MOD;

    long long total_sum = (sum_r * inner_sum) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

