#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

// Function to compute Z-array for a string
std::vector<int> compute_z_array(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    z[0] = n; // Conventionally, z[0] is n
    int l = 0, r = 0;
    for (int i = 1; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute Z-arrays for all cyclic shifts of s
    // z_arrays[i] stores the Z-array for s[i...L-1] + s[0...i-1]
    // This is not exactly what we need. We need Z-array for s + s.
    // Let's compute Z-array for s + s (length 2L)
    std::string s_double = s + s;
    std::vector<int> z_s_double = compute_z_array(s_double);

    // For each possible first character t_0 (which is s_k for some k)
    // we need to find the optimal p and calculate the probability.
    // We group k's by their s_k value.
    std::vector<std::vector<int>> k_indices_by_char(26);
    for (int k = 0; k < L; ++k) {
        k_indices_by_char[s[k] - 'a'].push_back(k);
    }

    double total_win_prob = 0.0;

    for (int char_code = 0; char_code < 26; ++char_code) {
        const std::vector<int>& current_k_group = k_indices_by_char[char_code];
        if (current_k_group.empty()) {
            continue;
        }

        int num_k_in_group = current_k_group.size();

        // If only one k produces this t_0, Vasya wins for sure for this k.
        if (num_k_in_group == 1) {
            total_win_prob += 1.0;
            continue;
        }

        // If multiple k's produce this t_0, Vasya needs to choose p.
        // Vasya wants to maximize the number of k's in this group that become unique.
        // For a fixed p, and fixed t_0=s_k, t_p=s_{(k+p)%L},
        // a k' from current_k_group is uniquely determined if it's the only one
        // such that s_{k'} = s_k AND s_{(k'+p)%L} = s_{(k+p)%L}.
        // The first condition s_{k'} = s_k is already satisfied for all k' in current_k_group.
        // So we need to count how many k' in current_k_group satisfy s_{(k'+p)%L} = s_{(k+p)%L}.
        // If this count is 1, then k is uniquely determined.

        int max_unique_k_for_group = 0;

        // Iterate over all possible positions p (1 to L-1)
        for (int p = 1; p < L; ++p) {
            int current_p_unique_count = 0;

            // For each k in the current group (i.e., s_k == char_code)
            for (int k_idx = 0; k_idx < num_k_in_group; ++k_idx) {
                int k = current_k_group[k_idx];
                char char_B = s[(k + p) % L]; // This is t_p for this specific k

                int count_matches_for_char_B = 0;
                for (int k_prime_idx = 0; k_prime_idx < num_k_in_group; ++k_prime_idx) {
                    int k_prime = current_k_group[k_prime_idx];
                    if (s[(k_prime + p) % L] == char_B) {
                        count_matches_for_char_B++;
                    }
                }

                if (count_matches_for_char_B == 1) {
                    current_p_unique_count++;
                }
            }
            max_unique_k_for_group = std::max(max_unique_k_for_group, current_p_unique_count);
        }
        total_win_prob += static_cast<double>(max_unique_k_for_group);
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
