#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (char c = 'a'; c <= 'z'; ++c) {
        adj[c] = {};
    }

    bool possible = true;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1].insert(c2);
        adj[c2].insert(c1);
    }

    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout_str = "";
    std::set<char> visited;
    char start_char = '\0';

    // Find a starting character (one with 1 neighbor or the first char of s if all have 2)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If no char has 1 neighbor, it means all chars in s have 2 neighbors (forming a cycle or a path where endpoints are not in s)
    // Or s is empty/single char, or all chars in s form a single path/cycle.
    // If s is not empty, we can pick the first character of s as a starting point.
    // If s is empty, this logic won't be hit. s has length >= 1.
    if (start_char == '\0' && !s.empty()) {
        // All characters in s must have 2 neighbors. This implies a cycle or a path where endpoints are not in s.
        // If it's a cycle, it's impossible to form a linear layout.
        // If it's a path, we can start from any character in s.
        // We need to check for cycles.
        // A simple way to check for cycles is to try to build the path.
        // If we pick s[0] and it has two neighbors, say n1 and n2.
        // If n1 and n2 are connected, it's a cycle.
        // If we pick s[0] and it has two neighbors, and we follow one path, say s[0] -> n1 -> ... -> n_k.
        // If n_k's other neighbor is s[0], it's a cycle.
        // The current graph construction (adj) already handles this.
        // If start_char is still '\0', it means all characters that appear in 's' have exactly two neighbors.
        // This implies that the characters in 's' form one or more disjoint cycles.
        // A single cycle is impossible for a linear layout. Multiple cycles are also impossible.
        // Example: abca. a-b, b-c, c-a. All have 2 neighbors.
        // The only case where start_char is '\0' and it's possible is if s is empty or single char,
        // but s has length >= 1.
        // So if start_char is '\0', it means all characters in s have degree 2.
        // This implies that the graph formed by characters in s is a collection of disjoint cycles.
        // A linear keyboard cannot contain a cycle.
        // So, if start_char is '\0' and s is not empty, it's impossible.
        // Wait, this is not entirely correct. If s = "abacaba", adj[a]={b,c}, adj[b]={a}, adj[c]={a}.
        // Here, b and c have 1 neighbor, a has 2. So start_char would be b or c.
        // If s = "abcde", adj[a]={b}, adj[b]={a,c}, adj[c]={b,d}, adj[d]={c,e}, adj[e]={d}.
        // Here, a and e have 1 neighbor. start_char would be a.
        // The only way start_char remains '\0' is if all characters that appear in 's' have degree 2.
        // This means the graph components formed by characters in 's' are all cycles.
        // For example, s = "abac". adj[a]={b,c}, adj[b]={a}, adj[c]={a}.
        // This is not a cycle. b and c have degree 1.
        // Example: s = "abcb". adj[a]={b}, adj[b]={a,c}, adj[c]={b}.
        // a and c have degree 1.
        // Example: s = "abacaba". adj[a]={b,c}, adj[b]={a}, adj[c]={a}.
        // b and c have degree 1.
        // The only way start_char is '\0' is if all characters in 's' have degree 2.
        // This means the graph formed by characters in 's' is a collection of disjoint cycles.
        // A linear keyboard cannot contain a cycle.
        // So, if start_char is '\0' and s is not empty, it's impossible.
        // This logic is sound.
        std::cout << "NO\n";
        return;
    }

    // If s is a single character, e.g., "a", then adj['a'] is empty.
    // start_char will be '\0'. This case needs to be handled.
    // If s is "a", then 'a' has 0 neighbors. It's a valid start.
    if (s.length() == 1) {
        start_char = s[0];
    }

    // If start_char is still '\0', it means no character in 's' has 1 neighbor.
    // This implies all characters in 's' have 2 neighbors.
    // This means the graph formed by characters in 's' is a collection of disjoint cycles.
    // A linear keyboard cannot contain a cycle.
    // So, if start_char is '\0' and s is not empty, it's impossible.
    // This is already handled by the previous block.
    // The only remaining case for start_char == '\0' is if s is empty, but s.length() >= 1.
    // So, if we reach here and start_char is '\0', it means s.length() == 1 and s[0] has 0 neighbors.
    // Or, it means s.length() > 1 and all chars in s have 2 neighbors.
    // The previous block correctly sets start_char for s.length() == 1.
    // So, if start_char is still '\0', it means all chars in s have 2 neighbors.
    // This is an impossible case.
    // Let's re-evaluate.
    // If s = "abacaba", adj[a]={b,c}, adj[b]={a}, adj[c]={a}.
    // b and c have degree 1. start_char will be 'b' or 'c'.
    // If s = "abcde", adj[a]={b}, adj[b]={a,c}, adj[c]={b,d}, adj[d]={c,e}, adj[e]={d}.
    // a and e have degree 1. start_char will be 'a' or 'e'.
    // If s = "abac", adj[a]={b,c}, adj[b]={a}, adj[c]={a}.
    // b and c have degree 1. start_char will be 'b' or 'c'.
    // The only way start_char is '\0' is if all characters that appear in 's' have degree 2.
    // This means the graph formed by characters in 's' is a collection of disjoint cycles.
    // A linear keyboard cannot contain a cycle.
    // So, if start_char is '\0' and s is not empty, it's impossible.
    // This is correct.

    // If s is "a", start_char will be 'a'.
    // If s is "ab", start_char will be 'a' or 'b'.
    // If s is "aba", start_char will be 'b'.
    // If s is "abacaba", start_char will be 'b' or 'c'.
    // So, start_char will always be set to a valid character if a path exists.
    // If start_char is '\0' here, it means all characters in 's' have degree 2.
    // This implies a cycle, which is impossible.
    // So, if start_char is '\0', it's "NO".
    // This is already handled by the previous block.
    // The only case where start_char is '\0' after the loop is if s is empty, but s.length() >= 1.
    // So, start_char will always be set to a valid character if a path exists.
    // If start_char is '\0' here, it means all characters in 's' have degree 2.
    // This implies a cycle, which is impossible.
    // So, if start_char is '\0', it's "NO".
    // This is correct.

    // Build the layout string
    char current_char = start_char;
    char prev_char = '\0'; // Sentinel for the first character

    while (current_char != '\0' && visited.find(current_char) == visited.end()) {
        layout_str += current_char;
        visited.insert(current_char);

        char next_char = '\0';
        for (char neighbor : adj[current_char]) {
            if (neighbor != prev_char) {
                next_char = neighbor;
                break;
            }
        }
        prev_char = current_char;
        current_char = next_char;
    }

    // Check if all characters from 's' were included in the layout_str
    std::set<char> s_chars;
    for (char c : s) {
        s_chars.insert(c);
    }
    for (char c : s_chars) {
        if (visited.find(c) == visited.end()) {
            // This means there's a disconnected component in the graph of 's' characters
            // that wasn't reached from start_char. This implies multiple paths/cycles.
            // If start_char was chosen from a degree-1 node, and there's another degree-1 node
            // in a different component, this would be caught.
            // If all nodes in 's' have degree 2, and start_char was '\0', it's already "NO".
            // If start_char was set, and we didn't visit all s_chars, it means there are multiple components.
            // This is impossible for a single linear layout.
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Add remaining characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

