#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Precompute positions of '1's
    std::vector<int> ones_pos;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            ones_pos.push_back(i);
        }
    }

    // Iterate through all possible starting positions l
    for (int l = 0; l < n; ++l) {
        // Case 1: Substrings starting with '0'
        // These substrings must have a '1' somewhere to have a non-zero value.
        // If s[l] is '0', we need to find the first '1' at or after l.
        // Let this be at index k.
        // The value of s[l...r] is f(s[k...r]).
        // The length is r - l + 1.
        // We need r - l + 1 = f(s[k...r]).
        // This implies r - k + 1 + (k - l) = f(s[k...r]).
        // Let current_val = f(s[k...r]) and current_len = r - k + 1.
        // We need current_len + (k - l) = current_val.
        // This means current_val - current_len = k - l.
        // The term k - l is the number of leading zeros before the first '1' in s[l...r].

        // Find the first '1' at or after index l
        auto it = std::lower_bound(ones_pos.begin(), ones_pos.end(), l);
        if (it == ones_pos.end()) {
            // No '1' found from index l onwards.
            // All substrings s[l...r] will be all '0's.
            // f(s[l...r]) = 0.
            // Condition: r - l + 1 = 0. This is impossible as length >= 1.
            // So, no good substrings if all are '0's.
            continue;
        }
        int first_one_idx = *it;

        // Iterate through possible ending positions r, starting from first_one_idx
        // We only need to check a limited range of lengths because value grows exponentially.
        // Max length to check is around 20 (since 2^20 > 2e5).
        // Let's say max_len_check = 20.
        // So r can go up to l + max_len_check - 1.
        // But we also need to consider the actual first_one_idx.
        // The length of the binary part (from first_one_idx to r) is r - first_one_idx + 1.
        // If this length exceeds 20, the value will be too large.
        // So, r should not be too far from first_one_idx.
        // r - first_one_idx + 1 <= 20 => r <= first_one_idx + 19.
        // Also, r must be within string bounds: r < n.

        long long current_val = 0;
        for (int r = first_one_idx; r < n; ++r) {
            int len_from_first_one = r - first_one_idx + 1;
            if (len_from_first_one > 20) { // Value will be too large to match length
                break;
            }

            current_val = (current_val << 1) | (s[r] - '0');

            // Check if current_val exceeds max possible length (n)
            // This optimization is crucial. If current_val > n, it can't be equal to r-l+1.
            // However, current_val can be up to 2^20, while n is 2e5.
            // So, if current_val > n, it's definitely too large.
            // But we need to be careful: r-l+1 can be up to n.
            // If current_val is already > n, then it cannot be equal to r-l+1.
            // This check is implicitly handled by the `len_from_first_one > 20` break,
            // because 2^20 is already larger than 2e5.
            // So, current_val will not exceed 2^20.
            // The actual check is `current_val == r - l + 1`.

            // The number of leading zeros for the substring s[l...r] is first_one_idx - l.
            // The length of the substring s[l...r] is r - l + 1.
            // We need: current_val == r - l + 1.
            // Rearranging: current_val - (r - first_one_idx + 1) == first_one_idx - l.
            // Let `val_minus_binary_len = current_val - len_from_first_one`.
            // We need `val_minus_binary_len == first_one_idx - l`.

            long long val_minus_binary_len = current_val - len_from_first_one;

            if (val_minus_binary_len >= 0 && val_minus_binary_len <= first_one_idx - l) {
                // This means there exists a starting position `l_prime` such that
                // `first_one_idx - l_prime = val_minus_binary_len`.
                // And `l_prime` must be >= l.
                // The actual `l_prime` would be `first_one_idx - val_minus_binary_len`.
                // We need to count how many `l_prime` values satisfy this.
                // The valid `l_prime` values are `l, l+1, ..., first_one_idx - val_minus_binary_len`.
                // The number of such `l_prime` values is `(first_one_idx - val_minus_binary_len) - l + 1`.
                // This is exactly `(first_one_idx - l) - val_minus_binary_len + 1`.
                good_substrings_count += (first_one_idx - l) - val_minus_binary_len + 1;
            }
        }
    }

    std::cout << good_substrings_count << "\n";
}

