#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // and suffix sums for the right half (jars n+1 to 2n)
    // where 1 contributes +1 and 2 contributes -1.

    // Left half: jars 1 to n
    // P_left[k] = sum of (a_i == 1 ? 1 : -1) for i from 1 to k
    // P_left[0] = 0
    std::vector<int> p_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        p_left[i + 1] = p_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Right half: jars n+1 to 2n
    // P_right[k] = sum of (a_i == 1 ? 1 : -1) for i from 2n-k+1 to 2n
    // P_right[0] = 0
    std::vector<int> p_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        p_right[i + 1] = p_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Calculate the initial balance of all 2n jars
    int initial_balance = p_left[n] + p_right[n];

    // Store the minimum number of jars removed from the left to achieve a certain balance
    // for the remaining jars in the left half.
    // map: balance_value -> jars_removed_from_left
    std::map<int, int> left_balance_to_removed_count;
    for (int k = 0; k <= n; ++k) { // k jars removed from left (0 to k-1)
        // The balance of remaining jars in the left half is p_left[n] - p_left[k]
        // This is equivalent to the sum of (a_i == 1 ? 1 : -1) for i from k to n-1
        // Or, if we consider the original indices, jars from k+1 to n.
        // The balance of jars from index k to n-1 (0-indexed) is p_left[n] - p_left[k].
        // The number of jars removed is k.
        left_balance_to_removed_count[p_left[n] - p_left[k]] = k;
    }

    int min_removed = 2 * n; // Initialize with maximum possible removals

    // Iterate through possible removals from the right side
    for (int k = 0; k <= n; ++k) { // k jars removed from right (2n-k to 2n-1)
        // The balance of remaining jars in the right half is p_right[n] - p_right[k]
        // This is equivalent to the sum of (a_i == 1 ? 1 : -1) for i from 2n-k to 2n-1
        // Or, if we consider the original indices, jars from n+1 to 2n-k.
        // The balance of jars from index 2n-k to 2n-1 (0-indexed) is p_right[n] - p_right[k].
        // The number of jars removed is k.

        // We want the total balance of remaining jars to be 0.
        // (balance of remaining left jars) + (balance of remaining right jars) = 0
        // (p_left[n] - p_left[L]) + (p_right[n] - p_right[R]) = 0
        // where L is jars removed from left, R is jars removed from right.
        // We are iterating R (which is k here).
        // So we need (p_left[n] - p_left[L]) = -(p_right[n] - p_right[k])
        // Let target_left_balance = -(p_right[n] - p_right[k])
        // We need to find if target_left_balance exists in left_balance_to_removed_count.

        int current_right_remaining_balance = p_right[n] - p_right[k];
        int target_left_remaining_balance = -current_right_remaining_balance;

        if (left_balance_to_removed_count.count(target_left_remaining_balance)) {
            int removed_from_left = left_balance_to_removed_count[target_left_remaining_balance];
            min_removed = std::min(min_removed, removed_from_left + k);
        }
    }

    std::cout << min_removed << std::endl;
}

