int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two values:
    // val0: what happens to an input bit 0 after all operations
    // val1: what happens to an input bit 1 after all operations
    // We track these for each of the 10 bits (0-9).
    // So, val0[j] is the j-th bit of the result if input bit j was 0.
    // And val1[j] is the j-th bit of the result if input bit j was 1.
    // Initially, if input bit j is 0, it's 0. If input bit j is 1, it's 1.
    // So, val0 = 0, val1 = 1023 (all bits set).
    int val0 = 0;
    int val1 = 1023; // All 10 bits set

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1 ^= x;
        }
    }

