    b[0] = a[0];
    b[n - 1] = a[n - 1];

    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        int median_val = (sum >= 2) ? 1 : 0;
        b[i] = median_val;
        if (b[i] != a[i]) {
            changed = true;
        }
    }
    return changed;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> current_a = a;
    std::vector<int> next_a(n);

    // Find all 010 patterns (peaks) and 101 patterns (valleys)
    // These are the only places where a[i] can change from 0 to 1 or 1 to 0
    // 010 -> 000 (0 changes to 0, 1 changes to 0, 0 changes to 0)
    // 101 -> 111 (1 changes to 1, 0 changes to 1, 1 changes to 1)
    // The middle element changes: 1 -> 0 for 010, 0 -> 1 for 101

    std::vector<int> peaks; // indices i where a[i-1]=0, a[i]=1, a[i+1]=0
    std::vector<int> valleys; // indices i where a[i-1]=1, a[i]=0, a[i+1]=1

    for (int i = 1; i < n - 1; ++i) {
        if (current_a[i - 1] == 0 && current_a[i] == 1 && current_a[i + 1] == 0) {
            peaks.push_back(i);
        } else if (current_a[i - 1] == 1 && current_a[i] == 0 && current_a[i + 1] == 1) {
            valleys.push_back(i);
        }
    }

    if (peaks.empty() && valleys.empty()) { // Already stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    int max_steps = 0;

    // Process peaks (1s turning to 0s)
    // A 1 at index `p` (010 pattern) will turn to 0.
    // This change propagates outwards.
    // A 1 at `p` will turn to 0 in 1 step.
    // A 1 at `p-1` or `p+1` will turn to 0 if it's part of a 010 pattern.
    // The number of steps for a 1 to turn to 0 is related to its distance from a 0.
    // Specifically, for a block of 1s like 011...110, the 1s in the middle will turn to 0s.
    // The 1s at the ends of the block (adjacent to 0s) will turn to 0 last.
    // The number of steps for a 1 at index `i` to turn to 0 is `min(i - last_zero_idx, first_zero_idx - i)`.
    // We need to find the maximum of these steps over all 1s that will eventually turn to 0.

    // For each peak `p` (010 pattern), the `1` at `p` will become `0`.
    // This change can propagate to its neighbors.
    // Consider a block of 1s: `0 1 1 ... 1 0`.
    // The 1s at `i` and `j` are the first and last 1s in this block.
    // The 1 at `i` will become 0 if `a[i-1]` is 0.
    // The 1 at `j` will become 0 if `a[j+1]` is 0.
    // The number of steps for a 1 at index `k` within this block to become 0 is `min(k-i+1, j-k+1)`.
    // The maximum steps for this block is `ceil((j-i+1)/2.0)`.

    // We can find contiguous blocks of 1s that are surrounded by 0s.
    // Example: 0 1 1 1 1 0
    // Indices:   1 2 3 4
    // Steps:     1 2 2 1 (for 011110 -> 001100 -> 000000)
    // Max steps = 2. Length of block = 4. ceil(4/2) = 2.
    // Example: 0 1 1 1 0
    // Indices:   1 2 3
    // Steps:     1 2 1 (for 01110 -> 00100 -> 00000)
    // Max steps = 2. Length of block = 3. ceil(3/2) = 2.

    // Iterate through the sequence to find blocks of 1s surrounded by 0s.
    int i = 0;
    while (i < n) {
        if (current_a[i] == 0) {
            i++;
            continue;
        }
        // Found a 1. This is the start of a potential block of 1s.
        int start_block = i;
        while (i < n && current_a[i] == 1) {
            i++;
        }
        int end_block = i - 1; // end_block is the last index of 1 in this block

        // Check if this block of 1s is surrounded by 0s (or boundaries)
        bool left_zero = (start_block == 0 || current_a[start_block - 1] == 0);
        bool right_zero = (end_block == n - 1 || current_a[end_block + 1] == 0);

        if (left_zero && right_zero) {
            // This block of 1s will eventually turn to 0s.
            int block_len = end_block - start_block + 1;
            max_steps = std::max(max_steps, (block_len + 1) / 2); // ceil(block_len / 2.0)
        }
    }

    // Process valleys (0s turning to 1s)
    // A 0 at index `v` (101 pattern) will turn to 1.
    // This change propagates outwards.
    // The number of steps for a 0 at index `i` to turn to 1 is related to its distance from a 1.
    // Specifically, for a block of 0s like 100...001, the 0s in the middle will turn to 1s.
    // The 0s at the ends of the block (adjacent to 1s) will turn to 1 last.
    // The number of steps for a 0 at index `k` within this block to become 1 is `min(k-i+1, j-k+1)`.
    // We need to find the maximum of these steps over all 0s that will eventually turn to 1.

    // Iterate through the sequence to find blocks of 0s surrounded by 1s.
    i = 0;
    while (i < n) {
        if (current_a[i] == 1) {
            i++;
            continue;
        }
        // Found a 0. This is the start of a potential block of 0s.
        int start_block = i;
        while (i < n && current_a[i] == 0) {
            i++;
        }
        int end_block = i - 1; // end_block is the last index of 0 in this block

        // Check if this block of 0s is surrounded by 1s (or boundaries)
        bool left_one = (start_block == 0 || current_a[start_block - 1] == 1);
        bool right_one = (end_block == n - 1 || current_a[end_block + 1] == 1);

        if (left_one && right_one) {
            // This block of 0s will eventually turn to 1s.
            int block_len = end_block - start_block + 1;
            max_steps = std::max(max_steps, (block_len + 1) / 2); // ceil(block_len / 2.0)
        }
    }

    // After max_steps, the sequence will be stable.
    // Now, apply the smoothing max_steps times to get the final sequence.
    for (int step = 0; step < max_steps; ++step) {
        apply_median_smoothing(current_a, next_a);
        current_a = next_a;
    }

    std::cout << max_steps << std::endl;
    for (int j = 0; j < n; ++j) {
        std::cout << current_a[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize b_i to a very large value, representing no upper bound yet.
    // b_i = min(m_k - sum(d_j for j in ops[0..k-1] affecting i))
    std::vector<long long> b(n, std::numeric_limits<long long>::max());

    // Calculate b_i values
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long current_delta_sum = 0;
            for (int j = 0; j < i; ++j) { // Sum d_j for previous type 1 ops
                if (ops[j].type == 1 && ops[j].l <= ops[i].r && ops[j].r >= ops[i].l) {
                    // If op j affects any element in [ops[i].l, ops[i].r],
                    // it affects all elements in that range equally for the purpose of max.
                    // So we just sum up all d_j that affect the range [ops[i].l, ops[i].r].
                    current_delta_sum += ops[j].val;
                }
            }
            // For each k in [ops[i].l, ops[i].r], a_0[k] + current_delta_sum <= ops[i].val
            // So a_0[k] <= ops[i].val - current_delta_sum
            // We update b[k] = min(b[k], ops[i].val - current_delta_sum)
            long long upper_bound_for_initial_a = ops[i].val - current_delta_sum;
            for (int k = ops[i].l; k <= ops[i].r; ++k) {
                b[k] = std::min(b[k], upper_bound_for_initial_a);
            }
        }
    }

    // Initialize a_0 with b_i values. If b_i is still max, set to 0.
    // This is a valid choice because we need *any* suitable array.
    // If b_i is max, it means no type 2 operation constrained this element,
    // so we can pick 0 (within [-10^9, 10^9]).
    std::vector<long long> a0(n);
    for (int i = 0; i < n; ++i) {
        if (b[i] == std::numeric_limits<long long>::max()) {
            a0[i] = 0;
        } else {
            a0[i] = b[i];
        }
    }

    // Check if this a0 works
    std::vector<long long> current_a = a0;
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int k = ops[i].l; k <= ops[i].r; ++k) {
                current_a[k] += ops[i].val;
            }
        } else { // type 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int k = ops[i].l; k <= ops[i].r; ++k) {
                max_val = std::max(max_val, current_a[k]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraints for a0
    for (int i = 0; i < n; ++i) {
        if (a0[i] < -1000000000LL || a0[i] > 1000000000LL) {
            // This case should ideally not be reached if the problem guarantees a solution
            // within these bounds, but it's a safety check.
            // The problem statement says "Levko clearly remembers that all numbers in his array didn't exceed 10^9 in their absolute value, so he asks you to find such an array."
            // This implies that if a solution exists, one exists within these bounds.
            // Our construction of a0 uses b_i, which are derived from m_i values (up to 5*10^7)
            // and sums of d_i (up to 5000 * 10^4 = 5*10^7). So b_i can be around 10^8,
            // which is well within 10^9.
            std::cout << "NO\n"; // Should not happen with valid problem constraints
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a0[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i goes to doctor

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply effect from child i's crying in office
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect--;
            }

            // Apply cumulative effect from children crying in hall
            children[j].p -= total_d_effect;

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

