// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could be n * 2 * max(a_i) which is 2*10^5 * 2 * 10^9 = 4*10^14.
// This fits in a long long.

// The problem statement uses 1-based indexing for a_x.
// We will use 0-based indexing for the vector `a` in C++.
// So, a[x] in problem becomes a_vec[x-1] in code.
// The input `a_2, ..., a_n` means `a_vec[1], ..., a_vec[n-1]`.
// For each run, `a_1` is set to `i`. This means `a_vec[0]` is set to `i`.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_vec will store a_1, a_2, ..., a_n.
    // a_vec[0] will be set for each query.
    // a_vec[1] to a_vec[n-1] are read from input.
    std::vector<long long> a_vec(n); 
    for (int k = 1; k < n; ++k) {
        std::cin >> a_vec[k];
    }

    // dp[k] will store the result (final y value) if the program starts at x=k+1
    // and the next step is step 2 (x increases).
    // dp[k] = -1 means it loops or terminates out of bounds.
    // dp[k] = 0 means it's not computed yet.
    // dp[k] > 0 means it's the final y value.
    std::vector<long long> dp(n + 1, 0); // dp[0] unused, dp[1] to dp[n] for x=1 to x=n

    // For each possible starting value for a_1 (from 1 to n-1)
    for (int i = 1; i < n; ++i) {
        a_vec[0] = i; // Set a_1 = i

        // Reset dp for this run. Only values that depend on a_1 need to be recomputed.
        // However, since a_1 only affects the first step, and subsequent steps depend
        // on a_k for k > 1, we can optimize.
        // The problem asks for the result when a_1 = i.
        // The state is (current_x, current_y).
        // The sequence of operations is:
        // (x, y) -> (x + a[x], y + a[x]) -> (x, y + 2*a[x]) -> (x + a[x], y + a[x] + 2*a[x]) -> ...
        // Let's denote the state after a full cycle (step 2 then step 3) as (x_next, y_next).
        // If current state is (x_curr, y_curr), and a_val = a[x_curr-1]:
        // After step 2: (x_curr + a_val, y_curr + a_val)
        // After step 3: (x_curr, y_curr + 2 * a_val)
        // So, the x value returns to its original value after a full cycle.
        // The y value increases by 2 * a_val.
        // The program terminates if x_curr + a_val <= 0 or x_curr + a_val > n.

        // We need to simulate the path.
        // x_curr is 1-indexed, a_vec is 0-indexed.
        long long current_x = 1;
        long long current_y = 0;

        // To detect cycles, we can store visited states (x values) and their y contributions.
        // However, since x always returns to its original value after a full cycle,
        // a cycle means x keeps returning to the same value.
        // The only way to loop infinitely is if x never goes out of bounds.
        // This means x + a[x] is always within [1, n].
        // If x + a[x] is always within [1, n], then x will always be within [1, n].
        // The problem states x increases by a_x, then decreases by a_x.
        // So, x becomes x + a_x, then x becomes (x + a_x) - a_x = x.
        // The x value for the *next* iteration of the loop (step 2) is the same x.
        // This means the program will always terminate unless a_x is 0, which is not allowed (a_i >= 1).
        // The problem description is a bit tricky. Let's re-read carefully:
        // "The program increases both x and y by a value equal to a_x simultaneously." (Step 2)
        // "The program now increases y by a_x while decreasing x by a_x." (Step 3)
        // "The program executes steps 2 and 3 (first step 2, then step 3) repeatedly until it terminates."

        // Let's trace the state (x, y)
        // Initial: (1, 0)
        // Loop:
        //   Let current_a_val = a_vec[x-1]
        //   Step 2: x_temp = x + current_a_val, y_temp = y + current_a_val
        //   Check termination: if x_temp <= 0 or x_temp > n, terminate. Final y is y_temp.
        //   Step 3: x = x_temp - current_a_val, y = y_temp + current_a_val
        //   Check termination: if x <= 0 or x > n, terminate. Final y is y.
        //   (Note: x here is the x after step 3, which is the x for the *next* iteration of step 2)

        // This means the x value for the *next* iteration of step 2 is the same as the x value
        // for the *current* iteration of step 2.
        // Example:
        // Start: (x_0, y_0)
        // Step 2: (x_0 + a[x_0], y_0 + a[x_0]) -> let this be (x_1, y_1)
        //   Check termination for x_1. If terminates, y_1 is final.
        // Step 3: (x_1 - a[x_0], y_1 + a[x_0]) -> let this be (x_2, y_2)
        //   Note that x_2 = x_0 + a[x_0] - a[x_0] = x_0.
        //   Check termination for x_2. If terminates, y_2 is final.
        // Next iteration starts with (x_2, y_2) which is (x_0, y_0 + 2*a[x_0]).

        // This implies that the x value for the *start* of step 2 never changes.
        // If x_0 + a[x_0] is always within [1, n], then the program will never terminate.
        // This is because x_0 will always be x_0, and y will keep increasing by 2*a[x_0].
        // This is an infinite loop.

        // So, the program terminates if and only if x_0 + a[x_0] goes out of bounds.
        // Let's re-read the example:
        // For i = 1, a_1 = 1. Sequence: 1, 2, 4, 1. n=4.
        // Initial: x=1, y=0.
        // a_x = a_1 = 1.
        // Step 2: x becomes 1+1=2, y becomes 0+1=1. State (2, 1).
        //   x=2 is within [1,4]. No termination.
        // Step 3: x becomes 2-1=1, y becomes 1+1=2. State (1, 2).
        //   x=1 is within [1,4]. No termination.
        // Next iteration: x=1, y=2.
        // a_x = a_1 = 1.
        // Step 2: x becomes 1+1=2, y becomes 2+1=3. State (2, 3).
        //   x=2 is within [1,4]. No termination.
        // Step 3: x becomes 2-1=1, y becomes 3+1=4. State (1, 4).
        //   x=1 is within [1,4]. No termination.
        // This example implies my interpretation of "x" in "a_x" is wrong.
        // "a_x" must refer to the value of `a` at the *current* `x` at the moment of the operation.

        // Let's re-trace the example with the new interpretation:
        // For i = 1, a_1 = 1. Sequence: 1, 2, 4, 1. n=4.
        // Initial: x=1, y=0.
        // Iteration 1:
        //   Current x=1. a_x = a_1 = 1.
        //   Step 2: x_new = x + a_x = 1 + 1 = 2. y_new = y + a_x = 0 + 1 = 1.
        //     State becomes (2, 1).
        //     Check termination: x_new=2 is in [1,4]. No termination.
        //   Current x=2. a_x = a_2 = 2.
        //   Step 3: x_new = x - a_x = 2 - 2 = 0. y_new = y + a_x = 1 + 2 = 3.
        //     State becomes (0, 3).
        //     Check termination: x_new=0 is <= 0. Terminate. Final y = 3.
        // This matches the example output!

        // So, the `a_x` value used in Step 3 is based on the `x` value *after* Step 2.
        // Let's formalize the state transitions:
        // Current state: (x_curr, y_curr)
        // 1. Get a_val_1 = a_vec[x_curr - 1]
        // 2. Step 2: x_next_2 = x_curr + a_val_1, y_next_2 = y_curr + a_val_1
        // 3. Check termination: If x_next_2 <= 0 or x_next_2 > n, program terminates. Result is y_next_2.
        // 4. Get a_val_2 = a_vec[x_next_2 - 1] (This is the crucial part!)
        // 5. Step 3: x_next_3 = x_next_2 - a_val_2, y_next_3 = y_next_2 + a_val_2
        // 6. Check termination: If x_next_3 <= 0 or x_next_3 > n, program terminates. Result is y_next_3.
        // 7. If not terminated, the next iteration starts with (x_next_3, y_next_3).

        // This is a standard path-finding problem on a graph.
        // The nodes are (x, y) states.
        // Since y always increases, we only need to worry about cycles in x.
        // The x values can range from 1 to n.
        // We can use dynamic programming or memoization.
        // Let `solve(x_start)` be the final y value if the program starts with `x = x_start` and `y = 0`.
        // The problem asks for `solve(1)` for each `a_1`.
        // The `a_vec[0]` changes for each query, so `solve(1)` needs to be recomputed.
        // However, `solve(k)` for `k > 1` might be reusable if `a_vec[k-1]` doesn't change.
        // But `a_vec[k-1]` is fixed for `k > 1`.
        // So, we can precompute `solve(k)` for `k = 2, ..., n`.
        // Then for each `i`, we compute `solve(1)` using `a_vec[0] = i`.

        // Let `memo[x]` store the pair `(final_x, final_y_contribution)` if starting at `x` with `y=0`.
        // `final_x` is the `x` value that the program would transition to for the *next* step 2.
        // `final_y_contribution` is the `y` value accumulated *from* this `x` until termination or reaching a known state.
        // We need to be careful about the "next step 2" vs "final termination".
        // Let `memo[x]` store the final `y` value if starting at `x` with `y=0`.
        // If `memo[x]` is -1, it's an infinite loop.
        // If `memo[x]` is 0, it's uncomputed.
        // If `memo[x]` > 0, it's the result.

        // The state is `(x, y)`. The `y` value is cumulative.
        // The `x` value can be `1..n`.
        // Let `dp_results[x]` store the final `y` value if the program starts at `x` with `y=0`.
        // We need to compute `dp_results[x]` for `x` from `1` to `n`.
        // For a given `x_curr`:
        //   a_val_1 = a_vec[x_curr - 1]
        //   x_next_2 = x_curr + a_val_1
        //   y_next_2 = a_val_1
        //   If x_next_2 <= 0 or x_next_2 > n: return y_next_2
        //   a_val_2 = a_vec[x_next_2 - 1]
        //   x_next_3 = x_next_2 - a_val_2
        //   y_next_3 = y_next_2 + a_val_2
        //   If x_next_3 <= 0 or x_next_3 > n: return y_next_3
        //   Else: return y_next_3 + dp_results[x_next_3] (if dp_results[x_next_3] is not -1)
        //   If dp_results[x_next_3] is -1, then this path is also -1.

        // This looks like a recursive function with memoization.
        // `dp_results` needs to be reset for each query `i` because `a_vec[0]` changes.
        // However, `a_vec[k]` for `k > 0` is fixed.
        // This means `dp_results[x]` for `x > 1` can be precomputed.
        // `dp_results[1]` depends on `a_vec[0]`, so it must be computed for each `i`.

        // Let's define `memo[x]` as the final `y` value if the program starts at `x` with `y=0`.
        // `memo` will be a vector of size `n+1`.
        // `memo[0]` is unused.
        // `memo[x]` can be:
        //   0: uncomputed
        //   -1: infinite loop
        //   >0: final y value

        // We need to handle cycles. If we encounter an `x` that is currently being computed, it's a cycle.
        // We can use a `visited` array or mark `memo[x]` as -2 (currently computing).

        std::vector<long long> memo(n + 1); // Stores results for x=1 to n
        std::vector<bool> visiting(n + 1); // To detect cycles

        // Function to compute the final y value starting from x_start with current_y_accumulated
        // This function will be called recursively.
        // It returns the final y value, or -1 for infinite loop.
        // `x_start` is 1-indexed.
        auto calculate_y = [&](int x_start, auto& self) -> long long {
            if (x_start <= 0 || x_start > n) {
                return 0; // Base case for termination: no further y accumulated
            }
            if (memo[x_start] != 0) {
                return memo[x_start]; // Already computed or detected cycle
            }
            if (visiting[x_start]) {
                return -1; // Cycle detected
            }

            visiting[x_start] = true; // Mark as currently visiting

            long long a_val_1 = a_vec[x_start - 1];

            // Step 2
            long long x_next_2 = x_start + a_val_1;
            long long y_accum_2 = a_val_1;

            if (x_next_2 <= 0 || x_next_2 > n) {
                visiting[x_start] = false;
                memo[x_start] = y_accum_2;
                return y_accum_2;
            }

            long long a_val_2 = a_vec[x_next_2 - 1];

            // Step 3
            long long x_next_3 = x_next_2 - a_val_2;
            long long y_accum_3 = y_accum_2 + a_val_2;

            if (x_next_3 <= 0 || x_next_3 > n) {
                visiting[x_start] = false;
                memo[x_start] = y_accum_3;
                return y_accum_3;
            }

            // Recursive call for the next state
            long long res_from_next_state = self(x_next_3, self);

            visiting[x_start] = false; // Unmark after computation

            if (res_from_next_state == -1) {
                memo[x_start] = -1; // Propagate infinite loop
                return -1;
            } else {
                memo[x_start] = y_accum_3 + res_from_next_state;
                return memo[x_start];
            }
        };

        // Reset memo and visiting for the current query.
        // Only memo[1] needs to be reset for each query.
        // However, since the recursive calls might go to any x, it's safer to reset all.
        // But we can optimize: only reset memo[1] and any x that was visited during the previous calculation of memo[1].
        // A simpler approach for competitive programming is to just reset all for each query if N is small enough.
        // N = 2*10^5. Resetting N elements N times is N^2, too slow.
        // N * log N or N * constant is fine.
        // The key is that `a_vec[k]` for `k > 0` is fixed.
        // So, `memo[x]` for `x > 1` can be computed once.
        // `memo[1]` depends on `a_vec[0]`, which changes.

        // Let's compute memo[x] for x = 2 to n once.
        // This requires a separate memoization table for fixed a_vec values.
        // Or, we can compute it on demand.
        // The `calculate_y` function will fill `memo` as it goes.
        // For each query `i`, we call `calculate_y(1, calculate_y)`.
        // This will compute `memo[1]`. If it needs `memo[k]` for `k > 1`, it will compute it.
        // The `memo[k]` for `k > 1` will remain computed for subsequent queries.
        // Only `memo[1]` needs to be explicitly reset to 0 before each query.
        // And `visiting` array needs to be cleared for each query.

        // Reset only the relevant parts for the current query.
        // The `visiting` array must be cleared for each query.
        std::fill(visiting.begin(), visiting.end(), false);
        memo[1] = 0; // Reset memo[1] for the new a_vec[0]

        long long result = calculate_y(1, calculate_y);
        std::cout << result << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., S1 is empty, S2 contains all elements)
    // All f values are a_i + a_j.
    // Min f = a[0].value + a[1].value
    // Max f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    long long goodness_all_one_subsequence = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);

    long long min_goodness = goodness_all_one_subsequence;
    std::vector<int> best_partition(n, 2); // Default to all in subsequence 2

    // Case 2: Partition into two non-empty subsequences
    // Let S1 contain a[0] and S2 contain a[n-1].
    // The minimum possible sum a_i + a_j is a[0].value + a[1].value.
    // The maximum possible sum a_i + a_j is a[n-1].value + a[n-2].value.
    //
    // The values of f are:
    //   - a_i + a_j (same subsequence)
    //   - a_i + a_j + h (different subsequences)
    //
    // The minimum f value will be min(a[0].value + a[1].value, a[0].value + a[n-1].value + h).
    // The maximum f value will be max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h).
    //
    // Consider the partition where a[0] is in S1 and all other elements are in S2.
    // Min f:
    //   - a[1].value + a[2].value (if n >= 3, both in S2)
    //   - a[0].value + a[1].value + h (a[0] in S1, a[1] in S2)
    //   So, min_f = min(a[1].value + a[2].value, a[0].value + a[1].value + h) if n >= 3.
    //   If n=2, min_f = a[0].value + a[1].value + h.
    // Max f:
    //   - a[n-1].value + a[n-2].value (both in S2)
    //   - a[0].value + a[n-1].value + h (a[0] in S1, a[n-1] in S2)
    //   So, max_f = max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h).
    //
    // Goodness = max_f - min_f.

    // This specific partition strategy is:
    // a[0] in S1, a[1]...a[n-1] in S2.
    //
    // Possible f values:
    // 1. a[i] + a[j] for i,j in {1, ..., n-1} (both in S2)
    //    Min: a[1].value + a[2].value (if n >= 3)
    //    Max: a[n-1].value + a[n-2].value
    // 2. a[0].value + a[j].value + h for j in {1, ..., n-1} (a[0] in S1, a[j] in S2)
    //    Min: a[0].value + a[1].value + h
    //    Max: a[0].value + a[n-1].value + h

    // Overall min_f and max_f for this partition:
    long long current_min_f;
    long long current_max_f;

    if (n == 2) {
        current_min_f = a[0].value + a[1].value + h;
        current_max_f = a[0].value + a[1].value + h;
    } else {
        current_min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
        current_max_f = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h);
    }

    long long goodness_one_in_S1 = current_max_f - current_min_f;

    if (goodness_one_in_S1 < min_goodness) {
        min_goodness = goodness_one_in_S1;
        best_partition.assign(n, 2);
        best_partition[a[0].original_index] = 1;
    }

    // Consider a special case where h is very large.
    // If h is large enough, it's always better to have all elements in one subsequence.
    // The threshold for "large enough" is when a[0].value + a[n-1].value + h
    // becomes larger than a[n-1].value + a[n-2].value AND
    // a[0].value + a[1].value + h becomes smaller than a[1].value + a[2].value.
    //
    // More precisely, if a[0].value + a[n-1].value + h is the maximum, and
    // a[0].value + a[1].value + h is the minimum, then the goodness is
    // (a[0].value + a[n-1].value + h) - (a[0].value + a[1].value + h) = a[n-1].value - a[1].value.
    // This is the goodness for the partition (a[0] in S1, rest in S2) if h is large.
    //
    // The condition for this to be the case is:
    // a[0].value + a[n-1].value + h >= a[n-1].value + a[n-2].value
    // h >= a[n-2].value - a[0].value
    // AND
    // a[0].value + a[1].value + h <= a[1].value + a[2].value (if n >= 3)
    // h <= a[2].value - a[0].value
    //
    // If h is such that h > a[n-2].value - a[0].value, then a[0].value + a[n-1].value + h will be the max.
    // If h is such that h < a[2].value - a[0].value, then a[0].value + a[1].value + h will be the min.
    //
    // Let's check the partition where a[0] and a[1] are in S1, and the rest are in S2.
    // This is only possible if n >= 3.
    if (n >= 3) {
        // S1: {a[0], a[1]}, S2: {a[2], ..., a[n-1]}
        //
        // Possible f values:
        // 1. a[0].value + a[1].value (both in S1)
        // 2. a[i].value + a[j].value for i,j in {2, ..., n-1} (both in S2)
        //    Min: a[2].value + a[3].value (if n >= 4)
        //    Max: a[n-1].value + a[n-2].value
        // 3. a[k].value + a[j].value + h for k in {0,1}, j in {2, ..., n-1} (different subsequences)
        //    Min: a[0].value + a[2].value + h
        //    Max: a[1].value + a[n-1].value + h

        long long current_min_f_2inS1;
        long long current_max_f_2inS1;

        current_min_f_2inS1 = a[0].value + a[1].value; // From S1
        if (n >= 4) {
            current_min_f_2inS1 = std::min(current_min_f_2inS1, a[2].value + a[3].value); // From S2
        }
        current_min_f_2inS1 = std::min(current_min_f_2inS1, a[0].value + a[2].value + h); // From S1-S2

        current_max_f_2inS1 = a[0].value + a[1].value; // From S1
        if (n >= 4) {
            current_max_f_2inS1 = std::max(current_max_f_2inS1, a[n-1].value + a[n-2].value); // From S2
        }
        current_max_f_2inS1 = std::max(current_max_f_2inS1, a[1].value + a[n-1].value + h); // From S1-S2

        long long goodness_two_in_S1 = current_max_f_2inS1 - current_min_f_2inS1;

        if (goodness_two_in_S1 < min_goodness) {
            min_goodness = goodness_two_in_S1;
            best_partition.assign(n, 2);
            best_partition[a[0].original_index] = 1;
            best_partition[a[1].original_index] = 1;
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

