bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current target track index
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long current_h = h[h_idx];
        long long first_p_to_cover = p[p_idx];

        // If the current head cannot reach the first uncovered track,
        // or if it's too far to the right to be useful for this track,
        // it might be better to skip this head for now or it's impossible.
        // However, since heads can move freely and we want to cover tracks
        // from left to right, we should try to use the current head for
        // the leftmost possible track.

        // If current_h is too far to the right to cover first_p_to_cover,
        // even with max left movement, this head cannot cover it.
        // This implies that previous heads should have covered it.
        // If first_p_to_cover is not covered, it's impossible.
        if (current_h + T < first_p_to_cover) {
            continue; // This head cannot reach first_p_to_cover, try next head
        }

        // The current head can reach first_p_to_cover.
        // Now, determine the rightmost track this head can cover.
        // This depends on whether first_p_to_cover is to the left or right of current_h.

        long long rightmost_reachable_by_current_head;

        if (first_p_to_cover <= current_h) {
            // Case 1: first_p_to_cover is to the left or at current_h.
            // The head moves right from current_h to cover tracks.
            // It can move left to first_p_to_cover, taking current_h - first_p_to_cover time.
            // Remaining time: T - (current_h - first_p_to_cover).
            // It can then move right by this remaining time.
            rightmost_reachable_by_current_head = current_h + (T - (current_h - first_p_to_cover));
        } else { // first_p_to_cover > current_h
            // Case 2: first_p_to_cover is to the right of current_h.
            // The head moves right to first_p_to_cover, taking first_p_to_cover - current_h time.
            // Remaining time: T - (first_p_to_cover - current_h).
            // It can then move further right by this remaining time.
            rightmost_reachable_by_current_head = first_p_to_cover + (T - (first_p_to_cover - current_h));
        }

        // Now, advance p_idx as far as possible using this head.
        while (p_idx < m && p[p_idx] <= rightmost_reachable_by_current_head) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance: 10^10 (max p_i) - 1 (min h_i) + 10^10 (max p_i) - 1 (min p_i)
                                    // A safer upper bound is max(p_m - h_1, h_n - p_1) + max(p_i) - min(p_i)
                                    // Max p_i is 10^10, min h_i is 1. So 10^10 is a reasonable upper bound for a single move.
                                    // If a head needs to cover a range, say from 1 to 10^10, and it starts at 1, it takes 10^10 time.
                                    // If it starts at 5*10^9, and needs to cover 1 and 10^10, it takes 5*10^9 to reach 1, then 10^10-1 time to reach 10^10.
                                    // The total time is roughly 2 * 10^10. So 2 * 10^10 is a safe upper bound.

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

