    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // last_valid_r[i] stores the maximum r such that the substring s[i...r]
    // does NOT contain the pattern.
    // Initialize last_valid_r[i] to n for all i, meaning s[i...n] is initially
    // considered "good" (no pattern found yet).
    // This is equivalent to saying that for any l, the maximum r such that
    // s[l...r] is bad (does not contain pattern) is n.
    // We are looking for the maximum r such that s[l...r] is bad.
    // Let's rephrase: last_valid_r[i] stores the largest index j such that
    // the substring s[i...j] does NOT contain the pattern.
    // If s[i...j] contains a pattern, then any s[i...k] for k >= j also contains it.
    // If s[i...j] does not contain a pattern, then any s[i...k] for k < j also does not contain it.
    // So, for a fixed l, we want to find the maximum r such that s[l...r] is "bad".
    // Let's call this max_bad_r[l].
    // The number of bad pairs starting at l is max_bad_r[l] - l + 1.
    // If max_bad_r[l] < l, it means no bad pairs start at l.

    // Initialize max_bad_r[l] to n for all l.
    // This means initially, we assume s[l...n] is "bad" (does not contain pattern).
    // When we find a pattern s_x = s_{x+k} = s_{x+2k}, it means any substring
    // s[l...r] where l <= x and r >= x+2k is "good" (contains pattern).
    // For such l, the maximum r for which s[l...r] is "bad" must be less than x+2k.
    // So, for each l from 1 to x, we update max_bad_r[l] = min(max_bad_r[l], x+2k-1).
    // This is equivalent to saying that for any l in [1, x], the first occurrence
    // of a pattern ends at x+2k. So, any r >= x+2k makes s[l...r] "good".
    // Thus, the maximum r for which s[l...r] is "bad" cannot exceed x+2k-1.

    // We need to find the minimum x+2k for each l.
    // Let min_pattern_end[l] be the minimum value of x+2k such that
    // s_x = s_{x+k} = s_{x+2k} and l <= x.
    // If no such pattern exists for a given l, min_pattern_end[l] can be n+1.
    // Then, for each l, the number of bad pairs is (min_pattern_end[l] - 1) - l + 1.
    // This simplifies to min_pattern_end[l] - l.
    // We sum this over all l from 1 to n.
    // If min_pattern_end[l] - l < 0, it means min_pattern_end[l] < l, so no bad pairs.
    // This happens if min_pattern_end[l] is n+1, and l is also n+1, or if l is greater than n+1.
    // More precisely, if min_pattern_end[l] <= l, then there are no bad pairs starting at l.
    // The number of bad pairs is max(0, min_pattern_end[l] - l).

    std::vector<int> min_pattern_end(n + 1, n + 1); // 1-indexed

    // Iterate through all possible x and k to find patterns
    // x is 0-indexed in string, so s[x], s[x+k], s[x+2k]
    // l is 1-indexed, so l = x+1
    // x+2k is 0-indexed, so x+2k+1 is 1-indexed end position
    for (int x = 0; x < n; ++x) {
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Pattern found: s[x], s[x+k], s[x+2k]
                // This pattern starts at 0-indexed x, ends at 0-indexed x+2k.
                // In 1-indexed terms, it starts at x+1, ends at x+2k+1.
                int pattern_start_1_idx = x + 1;
                int pattern_end_1_idx = x + 2 * k + 1;

                // This pattern makes any substring s[l...r] "good" if l <= pattern_start_1_idx
                // and r >= pattern_end_1_idx.
                // So, for any l' from 1 to pattern_start_1_idx, the minimum end position
                // for a pattern starting at or after l' is at most pattern_end_1_idx.
                // We want to update min_pattern_end[l'] for l' from 1 to pattern_start_1_idx.
                // However, we only need to update min_pattern_end[l'] for l' from
                // max(1, pattern_start_1_idx - 6) to pattern_start_1_idx.
                // This is because k can be at most 6 for the pattern to be relevant.
                // If k >= 7, then x+2k >= x+14.
                // The maximum length of a "bad" substring is 13.
                // If a pattern s_x = s_{x+k} = s_{x+2k} exists, and k >= 7,
                // then x+2k - x = 2k >= 14.
                // This means the length of the pattern is at least 14.
                // Any substring of length 14 or more is guaranteed to contain a pattern
                // if it contains this one.
                // The problem states that any substring of length 13 or more must contain a pattern.
                // This implies that we only need to check k up to 6.
                // If k > 6, then 2k > 12. The distance between x and x+2k is 2k.
                // If 2k >= 13, then the substring s[x...x+2k] has length at least 14.
                // Any substring of length 13 or more is guaranteed to contain a pattern.
                // This means that if we find a pattern with k >= 7, it's already covered
                // by the "length 13" rule.
                // So, we only need to consider k from 1 to 6.
                // This optimization is crucial for performance.

                if (k > 6) { // Optimization: only consider k up to 6
                    break; // No need to check larger k for this x
                }

                // Update min_pattern_end for all l' such that l' <= pattern_start_1_idx
                // and l' is relevant to this pattern.
                // The relevant l' values are those for which the pattern starts at or after l'.
                // So, l' from 1 to pattern_start_1_idx.
                // We want to find the minimum pattern_end_1_idx for each l'.
                // This means we iterate l' from pattern_start_1_idx down to 1.
                for (int l_prime = pattern_start_1_idx; l_prime >= 1; --l_prime) {
                    min_pattern_end[l_prime] = std::min(min_pattern_end[l_prime], pattern_end_1_idx);
                }
            }
        }
    }

    // Calculate bad_pairs
    for (int l = 1; l <= n; ++l) {
        // The number of bad pairs (l, r) is max(0, (min_pattern_end[l] - 1) - l + 1)
        // which simplifies to max(0, min_pattern_end[l] - l).
        // If min_pattern_end[l] is n+1, then (n+1) - l is the count.
        // This is correct because if no pattern starts at or after l, then all
        // pairs (l, r) for r from l to n are bad.
        bad_pairs += std::max(0, min_pattern_end[l] - l);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

