    // We need s' to be a palindrome and s' != s.
    // Since s is a palindrome, s[i] == s[n-1-i].
    // If s' = s2s1 is a palindrome, then s2s1 == reverse(s2s1).
    //
    // Consider cuts that split s into s[0...i-1] and s[i...n-1].
    // The new string is s[i...n-1] + s[0...i-1].
    //
    // Example: s = "otto", n=4
    // i=1: s1="o", s2="tto". s'="ttoo". Not palindrome.
    // i=2: s1="ot", s2="to". s'="toot". Palindrome. "toot" != "otto". So k=1 is possible.
    // i=3: s1="ott", s2="o". s'="oott". Not palindrome.
    //
    // Example: s = "nolon", n=5
    // i=1: s1="n", s2="olon". s'="olonn". Not palindrome.
    // i=2: s1="no", s2="lon". s'="lonno". Not palindrome.
    // i=3: s1="nol", s2="on". s'="onnol". Not palindrome.
    // i=4: s1="nolo", s2="n". s'="nnolo". Not palindrome.
    // For "nolon", k=1 is not possible.

    // Iterate through all possible cut positions for k=1
    // A cut at index `i` means s1 = s.substr(0, i) and s2 = s.substr(i).
    // `i` can range from 1 to n-1.
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 is not possible, check for k=2.
    // With k=2, we can make two cuts, resulting in three substrings: s1, s2, s3.
    // s = s1s2s3.
    // We can rearrange them. For example, s2s1s3, s3s1s2, etc.
    //
    // A special case for k=2 is when all characters in s are the same.
    // E.g., "aaaa", "qqqq".
    // If all characters are the same, any rearrangement of substrings will result in the same string.
    // For example, if s = "aaaa", s1="a", s2="a", s3="aa".
    // s1s2s3 = "aaaa". s1s3s2 = "aaaa". s2s1s3 = "aaaa". etc.
    // In this case, it's impossible to form a new string s' != s.
    // We can check this by counting unique characters.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }
    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Why?
    // Consider the string s. Since it's a palindrome and not all characters are the same,
    // there must be at least two distinct characters.
    // Also, since it's a palindrome, s[0] == s[n-1].
    // If s is not all same characters, then there exists some `i` such that s[i] != s[0].
    //
    // Consider cutting s into s[0...i-1], s[i], s[i+1...n-1].
    // This is 2 cuts.
    //
    // A simpler argument for k=2:
    // If s is a palindrome and not all characters are the same, then s is not of the form "aaaa...a".
    // This means there is at least one character s[i] such that s[i] != s[0].
    // Since s is a palindrome, s[i] == s[n-1-i].
    //
    // Consider the string s. If we remove the first character s[0] and the last character s[n-1],
    // we get s.substr(1, n-2). This substring is also a palindrome.
    //
    // If s is a palindrome and not all characters are the same, then s.substr(0, n/2) is not a palindrome.
    // (Unless n=1, but n>=1. If n=1, s="a", all same, impossible. If n=2, s="aa", all same, impossible.
    // If n=3, s="aba", s.substr(0,1)="a", palindrome. But s.substr(0, n/2) is not the whole string.)
    //
    // Let's consider the first half of the string: s_half = s.substr(0, n/2).
    // If s_half is a palindrome, then s looks like "abccba" where "abc" is a palindrome.
    // E.g., "abccba", s_half="abc". Not a palindrome.
    // E.g., "racecar", s_half="rac". Not a palindrome.
    // E.g., "level", s_half="le". Not a palindrome.
    //
    // The only way s_half could be a palindrome is if s itself is composed of repeating identical characters.
    // For example, if s = "aaaaa", s_half = "aa". This is a palindrome.
    // If s = "ababa", s_half = "ab". Not a palindrome.
    //
    // If s is a palindrome and not all characters are the same, then s.substr(0, n/2) is NOT a palindrome.
    // (Proof: Assume s.substr(0, n/2) IS a palindrome.
    // Let s = P + M + reverse(P), where P = s.substr(0, n/2) and M is the middle character if n is odd.
    // If P is a palindrome, then P = reverse(P).
    // So s = P + M + P.
    // Example: s="abccba", P="abc". P is not a palindrome.
    // Example: s="aaaaa", P="aa". P is a palindrome.
    // If P is a palindrome, then P must be of the form "xyzyx".
    // Then s = "xyzyx" + M + "xyzyx".
    // This implies that s[0] == s[1] == ... == s[n/2-1] == s[n/2] (if n is even)
    // This would mean all characters are the same.
    // For example, if P="aa", s="aa" + M + "aa". If M="a", s="aaaaa". All same.
    // If P="aba", s="aba" + M + "aba". If M="b", s="abababa". Not all same.
    // But if P="aba", then s.substr(0, n/2) is "aba", which is a palindrome.
    // In this case, s="abababa".
    //
    // Let's re-evaluate the condition "s.substr(0, n/2) is NOT a palindrome".
    // If s.substr(0, n/2) is a palindrome, then s must be of the form X + M + X, where X is a palindrome.
    // Example: s="abacaba", n=7. s.substr(0,3)="aba". This is a palindrome.
    // In this case, s="abacaba".
    //
    // The problem states that if all characters are the same, it's impossible.
    // If not all characters are the same, then k=2 is always possible.
    //
    // Consider s = "abacaba". n=7.
    // k=1 check:
    // i=1: s'="bacabaa". No.
    // i=2: s'="acabaab". No.
    // i=3: s'="cabaaba". No.
    // i=4: s'="abacaba". No (s'==s).
    // i=5: s'="bacabaa". No.
    // i=6: s'="acabaab". No.
    // So for "abacaba", k=1 is not possible.
    //
    // For "abacaba", all chars are not same. So output should be 2.
    //
    // The argument for k=2 being always possible (if not all chars are same):
    // Take the string s. Since it's a palindrome and not all characters are the same,
    // there must be at least one character s[i] such that s[i] != s[0].
    //
    // Consider the string s. If we cut it into s[0], s.substr(1, n-2), s[n-1].
    // These are three pieces.
    // s1 = s[0]
    // s2 = s.substr(1, n-2)
    // s3 = s[n-1]
    // Since s is a palindrome, s[0] == s[n-1]. So s1 == s3.
    // s2 is also a palindrome.
    // We can rearrange them as s3 + s2 + s1.
    // This forms s[n-1] + s.substr(1, n-2) + s[0].
    // Since s[n-1] == s[0], this is effectively s[0] + s.substr(1, n-2) + s[0], which is just s.
    // This rearrangement doesn't work.
    //
    // What if we take s[0...n/2-1], s[n/2], s[n/2+1...n-1]? (for odd n)
    // s = P + M + reverse(P).
    // P = s.substr(0, n/2)
    // M = s.substr(n/2, 1)
    // reverse(P) = s.substr(n/2+1)
    //
    // If P is not a palindrome, then we can form a new palindrome.
    // Example: s="nolon", n=5. P="no". Not a palindrome. M="l". reverse(P)="on".
    // Pieces: "no", "l", "on".
    // Rearrange to "on", "l", "no". This is "onlno".
    // "onlno" is a palindrome. "onlno" != "nolon".
    // This uses 2 cuts.
    //
    // This strategy works if s.substr(0, n/2) is NOT a palindrome.
    // When is s.substr(0, n/2) a palindrome?
    // If s.substr(0, n/2) is a palindrome, then s must be of the form X + M + X, where X is a palindrome.
    // Example: s="abacaba", n=7. s.substr(0,3)="aba". This is a palindrome.
    // In this case, the strategy "on|l|no" -> "onlno" doesn't work.
    // "aba" | "c" | "aba" -> "aba" + "c" + "aba" = "abacaba" (original)
    //
    // So, if s.substr(0, n/2) is a palindrome, and s is not all same characters,
    // then we need to find another way for k=2.
    //
    // If s.substr(0, n/2) is a palindrome, and s is not all same characters,
    // then s must be of the form "abacaba" or "abcdeffedcba" where "abc" is a palindrome.
    // This means s[0] == s[2] == s[4] ... and s[1] == s[3] == s[5] ...
    //
    // Example: s="abacaba". s.substr(0,3)="aba" is a palindrome.
    // s[0]='a', s[1]='b', s[2]='a', s[3]='c', s[4]='a', s[5]='b', s[6]='a'.
    //
    // If s.substr(0, n/2) is a palindrome, and s is not all same characters,
    // then it means s has at least two distinct characters, and the first half is a palindrome.
    // This implies that s must be of the form P M P, where P is a palindrome.
    // Example: s="abacaba", P="aba", M="c".
    // Example: s="racecar", P="rac", M="e". P is not a palindrome.
    // Example: s="kinnikkinnik", n=12. s.substr(0,6)="kinnik". Not a palindrome.
    // So for "kinnikkinnik", k=1 is possible.
    // s="kinnikkinnik". i=9. s1="kinnikkin", s2="nik". s'="nikkinnikkin". Palindrome. s'!=s. So k=1.
    //
    // The only case where k=2 is needed is when k=1 fails AND not all characters are the same.
    // The argument for k=2 always being possible in this scenario:
    // If s is a palindrome and not all characters are the same, then s.substr(0, n/2) is not a palindrome.
    // (This is the key insight from competitive programming problems like this).
    // Proof by contradiction: Assume s.substr(0, n/2) IS a palindrome.
    // Let P = s.substr(0, n/2).
    // If n is even, s = P + reverse(P). Since P is a palindrome, P = reverse(P). So s = P + P.
    // If P = "aba", then s = "abaaba". This is not a palindrome. Contradiction.
    // So if n is even, P cannot be a palindrome unless P consists of all same characters.
    // If P consists of all same characters, e.g., P="aaa", then s="aaaaaa". All characters are same.
    // If n is odd, s = P + M + reverse(P). Since P is a palindrome, P = reverse(P). So s = P + M + P.
    // If P = "aba", M = 'c', then s = "abacaba". Here P="aba" is a palindrome.
    // In this case, s.substr(0, n/2) is a palindrome.
    //
    // So the statement "s.substr(0, n/2) is NOT a palindrome" is false for cases like "abacaba".
    //
    // Let's re-evaluate the condition for k=2.
    // If k=1 fails, and not all characters are the same, then the answer is 2.
    // This is a common pattern in such problems.
    // The only case where it's impossible is when all characters are the same.
    //
    // So the logic is:
    // 1. Check if k=1 is possible. If yes, print 1.
    // 2. If k=1 is not possible, check if all characters in s are the same. If yes, print "Impossible".
    // 3. Otherwise (k=1 not possible, but not all characters are the same), print 2.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

// Function to calculate the parity of a 01-string
// Returns 1 if odd number of '1's, 0 if even.
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of string a
    int parity_a = calculate_parity(a);

    // Calculate parity of string b
    int parity_b = calculate_parity(b);

    // The minimum number of '1's required in 'a' to be able to generate 'b'
    // is parity_b. If parity_b is 0, we need at least 0 '1's.
    // If parity_b is 1, we need at least 1 '1'.
    // This is because if we have X '1's, we can append '0's until we have
    // enough length, or append '1's to change parity and then append '0's.
    // The crucial observation is that if we have X '1's, we can always
    // reach a state with X '1's (by appending '0's) or X+1 '1's (by appending '1' then '0's).
    // So, if we have X '1's, we can effectively generate any string of length >= X
    // that has X '1's (if X is even) or X+1 '1's (if X is odd).
    // More simply, if we have X '1's, we can generate any string of length >= X
    // that has X '1's or X+1 '1's.
    // The number of '1's in the final string 'b' must be achievable.
    // If parity_b is 0, it means 'b' has an even number of '1's.
    // If parity_b is 1, it means 'b' has an odd number of '1's.
    //
    // Let N_a be the count of '1's in the initial string 'a'.
    // Let N_b be the count of '1's in string 'b'.
    //
    // If N_a is even, we can append '0's to 'a' to maintain even parity,
    // or append '1' to make it odd, then append '0's.
    // So, if N_a is even, we can achieve N_a '1's or N_a+1 '1's.
    // If N_a is odd, we can append '0's to 'a' to maintain odd parity,
    // or append '1' to make it even, then append '0's.
    // So, if N_a is odd, we can achieve N_a '1's or N_a+1 '1's.
    //
    // In general, if we start with N_a ones, we can eventually create a string
    // with N_a ones (by appending 0s) or N_a+1 ones (by appending 1 then 0s).
    // This means the maximum number of '1's we can effectively "carry" is N_a + parity_a.
    // For example, if a="00", N_a=0, parity_a=0. We can make "000" (0 ones) or "001" (1 one).
    // Max effective ones = 0+0 = 0. But we can get 1 one.
    //
    // A better way to think:
    // If we have `k` ones in a string, we can append `parity(string)` to it.
    // If `k` is even, `parity` is 0. We get `k` ones.
    // If `k` is odd, `parity` is 1. We get `k+1` ones.
    // So, if we start with `k` ones, we can always reach `k` ones (if `k` is even)
    // or `k+1` ones (if `k` is odd) by appending a single character.
    // After that, we can append '0's indefinitely to increase length without changing parity.
    //
    // So, the maximum number of '1's we can achieve in a string of sufficient length
    // is `ones_count_a + parity_a`.
    // For example, if a="01011", ones_count_a=3, parity_a=1. Max_ones = 3+1=4.
    // We can get "01011" (3 ones), "010111" (4 ones).
    // If a="0011", ones_count_a=2, parity_a=0. Max_ones = 2+0=2.
    // We can get "0011" (2 ones), "00110" (2 ones).
    //
    // The condition is that the number of '1's in 'b' (parity_b) must be less than or equal to
    // the maximum number of '1's we can achieve from 'a' (parity_a_effective).
    // And the length of 'b' must be less than or equal to the length of 'a' after
    // potentially adding enough characters to reach parity_a_effective.
    //
    // Let `ones_a` be the count of '1's in `a`.
    // Let `ones_b` be the count of '1's in `b`.
    //
    // The maximum number of '1's we can achieve from `a` is `ones_a + (ones_a % 2)`.
    // This is because if `ones_a` is even, we can append '0's, keeping `ones_a` ones.
    // If `ones_a` is odd, we can append '1', making `ones_a+1` ones, then append '0's.
    //
    // So, we need `ones_b <= ones_a + (ones_a % 2)`.
    // And we also need `|b| <= |a| + (ones_a % 2)`.
    // The second condition is implicitly handled by the first one if we consider
    // that we can always remove characters from the front of `a`.
    //
    // The logic is:
    // 1. Calculate `ones_a` (count of '1's in `a`).
    // 2. Calculate `ones_b` (count of '1's in `b`).
    // 3. The maximum number of '1's we can achieve from `a` is `ones_a_max = ones_a + (ones_a % 2)`.
    //    This is because if `ones_a` is even, we can only ever have an even number of '1's
    //    if we only append '0's. If we append '1', we get `ones_a+1` '1's.
    //    If `ones_a` is odd, we can only ever have an odd number of '1's
    //    if we only append '0's. If we append '1', we get `ones_a+1` '1's.
    //    So, we can always achieve `ones_a` or `ones_a+1` '1's.
    //    The maximum is `ones_a + (ones_a % 2)`.
    //
    // 4. If `ones_b <= ones_a_max`, then it's possible. Otherwise, it's not.
    //    This is because we can always remove characters from the front of `a`
    //    until its length is `|b|` (or less, then append).
    //    The key is that removing characters from the front can only decrease the number of '1's.
    //    But we can always append characters to increase length and potentially '1's.
    //    The only constraint is the maximum number of '1's we can generate.
    //
    // Example 1: a="01011", b="0110"
    // ones_a = 3. ones_a % 2 = 1. ones_a_max = 3 + 1 = 4.
    // ones_b = 3.
    // Is 3 <= 4? Yes. So YES.
    //
    // Example 2: a="0011", b="1110"
    // ones_a = 2. ones_a % 2 = 0. ones_a_max = 2 + 0 = 2.
    // ones_b = 3.
    // Is 3 <= 2? No. So NO.

    int ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_a++;
        }
    }

    int ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    int ones_a_max_achievable = ones_a + (ones_a % 2);

    if (ones_b <= ones_a_max_achievable) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Item {
    int value;
    int original_index;
};

bool compareItems(const Item& a, const Item& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a(n);
        std::vector<Item> b(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i].value;
            a[i].original_index = i;
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b[i].value;
            b[i].original_index = i;
        }

        std::sort(a.begin(), a.end(), compareItems);
        std::sort(b.begin(), b.end(), compareItems);

        std::vector<int> x(n);
        std::vector<int> y(n);

        for (int i = 0; i < n; ++i) {
            x[a[i].original_index] = a[i].value;
            y[a[i].original_index] = b[n - 1 - i].value;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << x[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << y[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long min_val = a[0];
    long long total_spells = 0;

    for (int i = 1; i < n; ++i) {
        // For each pile a[i] (where i > 0), we can add min_val to it
        // as many times as possible without exceeding k.
        // The number of times is (k - a[i]) / min_val.
        // We use integer division, which correctly truncates.
        // Since a[i] >= 1 and min_val >= 1, k - a[i] will be non-negative
        // if a[i] <= k, which is guaranteed by problem constraints (a_i <= k).
        // If a[i] > k, this would be negative, but problem guarantees a_i <= k.
        // If a[i] == k, then (k - k) / min_val = 0, which is correct.
        total_spells += (k - a[i]) / min_val;
    }

    std::cout << total_spells << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

