    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);
        long long ans = 0;

        // Use 5s as much as possible
        ans += diff / 5;
        diff %= 5;

        // Now diff is 0, 1, 2, 3, or 4
        if (diff == 0) {
            // No remaining difference
        } else if (diff == 1) {
            // 1 can be achieved by +1 or -1.
            // If we have a 5-press, we could potentially replace it with two 2-presses and one 1-press (5 -> 2+2+1),
            // which is 3 presses instead of 1. This is worse.
            // Or replace a 5-press with three 2-presses (5 -> 2+2+2), which is 3 presses instead of 1. Worse.
            // So, just add 1 press for the remaining 1.
            ans += 1;
        } else if (diff == 2) {
            // 2 can be achieved by +2 or -2.
            // Just add 1 press for the remaining 2.
            ans += 1;
        } else if (diff == 3) {
            // 3 can be achieved by +1+2 (2 presses) or +1+1+1 (3 presses).
            // Optimal is 2 presses.
            ans += 2;
        } else if (diff == 4) {
            // 4 can be achieved by +2+2 (2 presses) or +1+1+2 (3 presses) or +1+1+1+1 (4 presses).
            // Optimal is 2 presses.
            ans += 2;
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation always produces a different permutation
    // (unless n=1, which is not allowed, or p is a palindrome, which is rare but possible).
    // The sums of adjacent elements for p = [p_1, p_2, ..., p_n] are:
    // p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n
    // The sums of adjacent elements for p' = [p_n, p_{n-1}, ..., p_1] are:
    // p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1
    // This set of sums is identical to the original set, just in reverse order.
    // Therefore, their sorted versions (fingerprints) will be identical.
    // The only case where p' might be equal to p is if p is a palindrome.
    // However, the problem statement guarantees a solution exists, and for n >= 2,
    // reversing the permutation is a simple and effective strategy.
    // If p is a palindrome, e.g., [1,2,1] (not a permutation), or [1,2,3,2,1] (not a permutation),
    // or [1,2,3,4,5,4,3,2,1] (not a permutation).
    // A permutation cannot be a palindrome unless n=1 (not allowed) or n=0.
    // For example, if n=4, p=[1,2,3,4]. Reversed p'=[4,3,2,1]. These are different.
    // If n=2, p=[1,2]. Reversed p'=[2,1]. These are different.
    // So reversing always works for n >= 2.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

