void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) { // Only numbers up to 2048 are useful for forming 2048
            counts[s_val]++;
        }
    }

    // Simulate the merging process
    // We iterate through powers of two from smallest to largest
    // and merge them to form larger powers of two.
    // The maximum power of two we care about is 2048.
    // The smallest possible power of two is 1.
    // So we iterate from 1 up to 1024.
    for (int val = 1; val < 2048; val *= 2) {
        if (counts[val] >= 2) {
            // If we have two or more of 'val', we can merge two of them
            // to form one '2 * val'.
            // The number of 'val's that can be merged is counts[val] / 2.
            // Add this quantity to the count of '2 * val'.
            counts[val * 2] += counts[val] / 2;
        }
    }

    // After all possible merges, check if 2048 exists in the multiset.
    if (counts[2048] > 0) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

