#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n, it means p[i] must be n.
        // Otherwise, p[i] could be max_val_in_row or n.
        // Since we need to reconstruct *any* permutation,
        // we can try to assign p[i] = max_val_in_row if it's not n,
        // and p[i] = n if max_val_in_row is n.
        // This logic is simplified: if max_val_in_row is less than n,
        // it means p[i] could be max_val_in_row or n.
        // If p[i] is max_val_in_row, then for all j, min(p[i], p[j]) <= p[i].
        // If p[i] is n, then for all j, min(p[i], p[j]) <= p[j].
        // The crucial observation is that if max_val_in_row < n, then p[i] must be n.
        // Why? If p[i] = max_val_in_row, then max_val_in_row would be the largest value
        // in the permutation that is not n. But if max_val_in_row < n, it means
        // there is some p[k] = n. Then a[i][k] = min(p[i], p[k]) = min(p[i], n) = p[i].
        // So max_val_in_row would be p[i].
        // However, if p[i] is not n, then there must be some p[k] = n.
        // Then a[i][k] = min(p[i], n) = p[i].
        // So max_val_in_row would be p[i].
        // If max_val_in_row is n, then p[i] must be n.
        // If max_val_in_row is less than n, then p[i] must be n.
        // This is because if p[i] was max_val_in_row, then max_val_in_row would be
        // the largest value in the permutation that is not n.
        // But if max_val_in_row < n, it means there is some p[k] = n.
        // Then a[i][k] = min(p[i], p[k]) = min(p[i], n) = p[i].
        // So max_val_in_row would be p[i].
        // This implies that if max_val_in_row < n, then p[i] must be n.
        // This is incorrect. The correct logic is:
        // p[i] must be at least max_val_in_row.
        // If max_val_in_row is n, then p[i] must be n.
        // If max_val_in_row < n, then p[i] could be max_val_in_row or n.
        // To satisfy the permutation property, exactly one element must be n.
        // The problem states that a solution is guaranteed.
        // The simplest way to assign values is to assign p[i] = max_val_in_row.
        // If this results in a permutation where one value is missing and n is missing,
        // then the missing value must be n, and the element that was assigned max_val_in_row
        // should have been n.
        // A simpler approach:
        // For each i, p[i] >= max_{j!=i} a[i][j].
        // Let M_i = max_{j!=i} a[i][j].
        // If M_i = n, then p[i] must be n.
        // If M_i < n, then p[i] could be M_i or n.
        // There must be exactly one index k such that p[k] = n.
        // For this k, M_k = max_{j!=k} min(p[k], p[j]) = max_{j!=k} min(n, p[j]) = max_{j!=k} p[j].
        // Since p is a permutation of 1..n, max_{j!=k} p[j] must be n-1.
        // So, if p[k] = n, then M_k = n-1.
        // For any i such that p[i] < n, M_i = max_{j!=i} min(p[i], p[j]).
        // If there is some p[j] = n, then a[i][j] = min(p[i], n) = p[i].
        // So M_i must be p[i].
        // Therefore, for all i, if p[i] < n, then p[i] = M_i.
        // And for the unique k such that p[k] = n, M_k = n-1.
        // So we can find the index k where M_k = n-1. For this k, p[k] = n.
        // For all other i, p[i] = M_i.

        p[i] = max_val_in_row;
    }

    // Check if any value in p is n. If not, it means n was not assigned.
    // This happens if for all i, max_val_in_row < n.
    // In this case, the element that should be n is the one whose max_val_in_row is n-1.
    // And all other elements should be their max_val_in_row.
    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not found, it means for all i, max_val_in_row < n.
        // This implies that the actual value of p[i] for some i must be n.
        // The problem guarantees a solution.
        // The only way for max_val_in_row to be less than n for all i,
        // and for a solution to exist, is if one of the p[i] values is n,
        // and for that i, max_{j!=i} min(p[i], p[j]) = max_{j!=i} p[j] = n-1.
        // So, we find the index i where p[i] (which is max_val_in_row) is n-1,
        // and we change p[i] to n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

