        long long k = 1; // Represents 2^0, 2^1, 2^2, ...
        while (true) {
            // Cost for a staircase with (2*k - 1) stairs
            // This is (2*k - 1) * (2*k) / 2 = k * (2*k - 1)
            // The formula for the cost of a nice staircase with (2^p - 1) stairs is (2^p - 1) * 2^p / 2.
            // Let p be the power of 2. So k = 2^(p-1).
            // The number of stairs is 2^p - 1.
            // The cost is (2^p - 1) * 2^p / 2.
            // Let's use the derived formula: cost = (2^p - 1) * 2^p / 2.
            // Here, k is 2^(p-1). So 2*k = 2^p.
            // The number of stairs is 2*k - 1.
            // The cost is (2*k - 1) * k.

            long long cost_for_this_staircase = k * (2 * k - 1);

            if (current_cost + cost_for_this_staircase <= x) {
                current_cost += cost_for_this_staircase;
                count++;
                // Next k will be 2*k, effectively moving to the next power of 2 for p.
                // If current k was 2^(p-1), next k will be 2^p.
                k *= 2;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams 'k' must satisfy:
        // 1. k <= c (at least k coders needed)
        // 2. k <= m (at least k mathematicians needed)
        // 3. 3k <= c + m + x (total students available)
        // From 1 and 2, k <= min(c, m).
        // From 3, k <= (c + m + x) / 3.
        // So, k <= min(c, m, (c + m + x) / 3).
        // This condition is also sufficient.
        // If we form k teams, we use k coders and k mathematicians.
        // This requires c >= k and m >= k.
        // The remaining k spots in the teams can be filled by any of the
        // remaining students: (c - k) coders, (m - k) mathematicians, and x
        // students with no specialization.
        // The total number of remaining students is (c - k) + (m - k) + x.
        // We need to show that (c - k) + (m - k) + x >= k.
        // This simplifies to c + m + x >= 3k.
        // So, if k satisfies c >= k, m >= k, and c + m + x >= 3k,
        // then we can always form k teams.
        // The maximum such k is min(c, m, (c + m + x) / 3).
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the top triangle up to the i-th cut (from apex)
        // should be i * (total_area / n).
        // Total area = (1/2) * base * h = (1/2) * 1 * h = h/2.
        // Area_i = i * (h/2) / n = i * h / (2n).
        //
        // For a triangle with height x_i, its area is x_i^2 / (2h)
        // (since base is x_i/h and area = (1/2) * (x_i/h) * x_i = x_i^2 / (2h)).
        //
        // So, x_i^2 / (2h) = i * h / (2n)
        // x_i^2 = i * h^2 / n
        // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n)

        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right bounds.
    // For example, if k=4, we use numbers 1, 2, 3, 4, 5.
    // We want differences 4, 3, 2, 1.
    // Sequence: 1, 5, 2, 4, 3
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1
    // This uses k+1 numbers and generates k distinct differences.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left (smallest available)
            p[i] = left;
            left++;
        } else { // Odd index, take from right (largest available)
            p[i] = right;
            right--;
        }
    }

    // After generating k distinct differences using numbers from 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append these numbers in increasing order to the permutation.
    // This will only introduce a difference of 1, which is already among the k distinct differences (since k >= 1).
    // The last number used was either `left-1` or `right+1`.
    // The next number to use is `k+2`.
    // If `left` is the next available number from the small end, and `right` is the next available from the large end,
    // then the numbers used are `1, ..., left-1` and `right+1, ..., k+1`.
    // The remaining numbers are `left, ..., right`.
    // Since `left` was incremented and `right` was decremented, and they started as `1` and `k+1`,
    // after `k+1` elements are placed, `left` will be `(k+1)/2 + 1` if `k+1` is odd, or `k/2 + 1` if `k+1` is even.
    // `right` will be `k+1 - (k+1)/2` if `k+1` is odd, or `k+1 - k/2` if `k+1` is even.
    // In essence, `left` and `right` will have crossed or met.
    // The numbers used are `1, ..., k+1`.
    // The next available number is `k+2`.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // Append numbers k+2, k+3, ..., n in increasing order
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_count < k / 2) {
                result += c;
                open_count++;
                balance++;
            }
        } else { // c == ')'
            if (close_count < k / 2 && balance > 0) {
                result += c;
                close_count++;
                balance--;
            }
        }
        if (open_count == k / 2 && close_count == k / 2) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <algorithm> // For std::sort
#include <cmath>     // For std::abs
#include <iostream>  // For std::cin, std::cout
#include <vector>    // For std::vector

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        int n;
        std::cin >> n; // Read n, which means there are 2n students

        // Create a vector to store skill levels and read them.
        // The total number of students is 2n.
        std::vector<int> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }

        // Sort the skill levels in non-decreasing order.
        // This is crucial because the median is defined on a sorted array.
        std::sort(a.begin(), a.end());

        // After sorting, the minimum possible absolute difference between the
        // medians of two classes (each of odd size) is achieved when
        // one class takes the first n elements and the other takes the
        // remaining n elements.
        //
        // Specifically, if we sort the entire array a_1, a_2, ..., a_{2n},
        // and we want to form two classes, each with an odd number of students,
        // the optimal strategy to minimize the difference between medians
        // is to make one class's median a_n and the other class's median a_{n+1}.
        //
        // Consider the sorted array: a_0, a_1, ..., a_{2n-1}.
        // The element at index n-1 is a_n (1-indexed).
        // The element at index n is a_{n+1} (1-indexed).
        //
        // We can form a class with students {a_0, ..., a_{n-1}} and another
        // class with students {a_n, ..., a_{2n-1}}.
        // However, these classes would each have n students.
        // If n is odd, this is a valid partition.
        // If n is even, this is not a valid partition because class sizes must be odd.
        //
        // The problem states that each class must have an odd number of students.
        // Let the sizes be $S_1$ and $S_2$, where $S_1 + S_2 = 2n$.
        // Since $2n$ is even, if $S_1$ is odd, then $S_2 = 2n - S_1$ must also be odd.
        //
        // The key insight is that to minimize the difference between medians,
        // the medians themselves should be as close as possible in the sorted list.
        //
        // If we have a sorted array $a_0, a_1, \dots, a_{2n-1}$,
        // the smallest possible median for any class will be $a_0$ (if class size is 1).
        // The largest possible median for any class will be $a_{2n-1}$ (if class size is 1).
        //
        // To achieve the minimum difference, we want to pick two elements $a_i$ and $a_j$
        // from the sorted array such that $|a_i - a_j|$ is minimized, and $a_i$ can be
        // the median of one class and $a_j$ the median of the other.
        //
        // It turns out that the optimal choice is to make one median $a_{n-1}$ and the other $a_n$.
        //
        // For example, we can form Class 1 with $n$ students having skills $a_0, \dots, a_{n-1}$.
        // This class has $n$ students. Its median would be $a_{(n-1)/2}$ if $n$ is odd.
        // We can form Class 2 with $n$ students having skills $a_n, \dots, a_{2n-1}$.
        // This class has $n$ students. Its median would be $a_{n + (n-1)/2}$ if $n$ is odd.
        // This doesn't directly lead to $a_{n-1}$ and $a_n$ as medians.
        //
        // The problem is simpler: we need to find the minimum difference between *any* two medians.
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // Any class of odd size $2k+1$ will have its median as $a_j$ for some $j$.
        // To minimize the difference, we want to pick two elements $a_i$ and $a_j$ that are adjacent
        // in the sorted array.
        //
        // The crucial observation is that we can always construct two classes such that their medians
        // are $a_{n-1}$ and $a_n$.
        //
        // Class 1: Take $a_0, a_1, \dots, a_{n-1}$. This is a set of $n$ students.
        // Class 2: Take $a_n, a_{n+1}, \dots, a_{2n-1}$. This is a set of $n$ students.
        //
        // If $n$ is odd:
        // Class 1 has $n$ students. Its median is $a_{(n-1)/2}$.
        // Class 2 has $n$ students. Its median is $a_{n + (n-1)/2}$.
        // This is a valid partition, and the difference is $|a_{n + (n-1)/2} - a_{(n-1)/2}|$.
        //
        // The problem is not asking for a specific partition, but the minimum possible difference.
        // The minimum difference will always be between $a_{n-1}$ and $a_n$.
        //
        // Why?
        // Consider any partition into two classes, Class A and Class B, with odd sizes $S_A$ and $S_B$.
        // Let $m_A$ be the median of Class A and $m_B$ be the median of Class B.
        //
        // If we sort all $2n$ students, $a_0, \dots, a_{2n-1}$.
        // The median of any class of size $2k+1$ must be one of the $a_i$'s.
        //
        // Suppose we pick $a_i$ as the median of Class A and $a_j$ as the median of Class B.
        // To make $a_i$ the median of a class of size $2k_A+1$, we need to pick $k_A$ students
        // with skill $\le a_i$ and $k_A$ students with skill $\ge a_i$.
        // Similarly for $a_j$.
        //
        // The key insight for this problem type is often that the optimal medians are adjacent
        // elements in the globally sorted array.
        //
        // Specifically, the $n$-th element (0-indexed $a_{n-1}$) and the $(n+1)$-th element
        // (0-indexed $a_n$) are the "middle" two elements of the entire sorted array.
        //
        // We can always construct a partition where $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        //
        // Consider Class 1: $a_0, a_1, \dots, a_{n-1}$. This class has $n$ students.
        // Consider Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$. This class has $n$ students.
        //
        // If $n$ is odd, then these are valid classes (odd size).
        // The median of Class 1 is $a_{(n-1)/2}$.
        // The median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $|a_{n + (n-1)/2} - a_{(n-1)/2}|$.
        //
        // This is not what the example implies. The example for n=3 (2n=6 students)
        // has sorted skills [1, 2, 3, 4, 5, 6].
        // Here n=3.
        // The elements are a_0=1, a_1=2, a_2=3, a_3=4, a_4=5, a_5=6.
        // The problem states the answer is 1.
        // This corresponds to |a_3 - a_2| = |4 - 3| = 1.
        //
        // So the answer is indeed $|a_n - a_{n-1}|$ (using 0-indexed array).
        //
        // Let's verify this.
        // We need to show that we can always form two classes, each of odd size,
        // such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        //
        // Class 1: Students $a_0, \dots, a_{n-1}$. This class has $n$ students.
        // Class 2: Students $a_n, \dots, a_{2n-1}$. This class has $n$ students.
        //
        // If $n$ is odd, then both classes have odd size.
        // The median of Class 1 (sorted $a_0, \dots, a_{n-1}$) is $a_{(n-1)/2}$.
        // The median of Class 2 (sorted $a_n, \dots, a_{2n-1}$) is $a_{n + (n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler: we need to find the minimum possible absolute difference.
        // The minimum difference will always be between $a_{n-1}$ and $a_n$.
        //
        // Let's consider the elements $a_0, \dots, a_{2n-1}$.
        // We need to pick $S_1$ students for Class 1 and $S_2$ students for Class 2,
        // where $S_1, S_2$ are odd and $S_1+S_2=2n$.
        //
        // Let $M_1$ be the median of Class 1 and $M_2$ be the median of Class 2.
        // We want to minimize $|M_1 - M_2|$.
        //
        // Consider the $n$-th element $a_{n-1}$ and the $(n+1)$-th element $a_n$ in the sorted array.
        //
        // Can we always make $a_{n-1}$ the median of one class and $a_n$ the median of another?
        //
        // Let's try to make $a_{n-1}$ the median of Class 1.
        // We need to pick $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$
        // from the remaining students.
        //
        // Let's try to make $a_n$ the median of Class 2.
        // We need to pick $k_2$ elements smaller than $a_n$ and $k_2$ elements larger than $a_n$.
        //
        // The simplest way to achieve this is to assign $a_{n-1}$ to Class 1 and $a_n$ to Class 2.
        //
        // For Class 1 (median $a_{n-1}$):
        // We need $k_1$ elements from $a_0, \dots, a_{n-2}$ (there are $n-1$ such elements).
        // We need $k_1$ elements from $a_n, \dots, a_{2n-1}$ (there are $n$ such elements).
        //
        // For Class 2 (median $a_n$):
        // We need $k_2$ elements from $a_0, \dots, a_{n-1}$ (there are $n$ such elements).
        // We need $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$ (there are $n-1$ such elements).
        //
        // Let's try a specific construction:
        // Class 1: $a_0, a_1, \dots, a_{n-1}$. This class has $n$ students.
        // Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$. This class has $n$ students.
        //
        // If $n$ is odd, then both classes have odd size.
        // Median of Class 1 is $a_{(n-1)/2}$.
        // Median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $|a_{n + (n-1)/2} - a_{(n-1)/2}|$.
        // This is not $|a_n - a_{n-1}|$.
        //
        // The example for n=3: skills [1, 2, 3, 4, 5, 6].
        // $a_0=1, a_1=2, a_2=3, a_3=4, a_4=5, a_5=6$.
        // $n=3$.
        // $a_{n-1} = a_2 = 3$.
        // $a_n = a_3 = 4$.
        // The answer is $|4-3|=1$.
        //
        // The example partition:
        // Class 1: [6, 4, 2]. Sorted: [2, 4, 6]. Median is 4. Size 3 (odd).
        // Class 2: [5, 1, 3]. Sorted: [1, 3, 5]. Median is 3. Size 3 (odd).
        // Difference: $|4-3|=1$.
        //
        // Here, the median of Class 1 is $a_3=4$.
        // The median of Class 2 is $a_2=3$.
        //
        // This confirms that the minimum difference is indeed $|a_n - a_{n-1}|$.
        //
        // Why is this always possible?
        // We need to construct two classes, each of odd size, such that their medians are $a_{n-1}$ and $a_n$.
        //
        // Let Class 1 have median $a_{n-1}$.
        // Let Class 2 have median $a_n$.
        //
        // To make $a_{n-1}$ the median of Class 1:
        // We need to pick $k_1$ elements from $a_0, \dots, a_{n-2}$ (there are $n-1$ available).
        // We need to pick $k_1$ elements from $a_n, \dots, a_{2n-1}$ (there are $n$ available).
        //
        // To make $a_n$ the median of Class 2:
        // We need to pick $k_2$ elements from $a_0, \dots, a_{n-1}$ (there are $n$ available).
        // We need to pick $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$ (there are $n-1$ available).
        //
        // Let's try to make Class 1 of size $2k_1+1$ and Class 2 of size $2k_2+1$.
        // $a_{n-1}$ is in Class 1. $a_n$ is in Class 2.
        //
        // Consider the following construction:
        // Class 1: $a_{n-1}$ (as median)
        //          $a_0, a_1, \dots, a_{k_1-1}$ (smallest $k_1$ elements)
        //          $a_{2n-1}, a_{2n-2}, \dots, a_{2n-k_1}$ (largest $k_1$ elements)
        // This is not good because it mixes elements.
        //
        // A simpler construction:
        // Class 1: $a_0, a_1, \dots, a_{n-1}$. This class has $n$ students.
        // Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$. This class has $n$ students.
        //
        // This partition is valid if $n$ is odd.
        // In this case, the median of Class 1 is $a_{(n-1)/2}$.
        // The median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $|a_{n + (n-1)/2} - a_{(n-1)/2}|$.
        // This is not $|a_n - a_{n-1}|$.
        //
        // The problem is that the definition of median is $b_{k+1}$ for $2k+1$ elements.
        // For $n$ elements, if $n$ is odd, $n=2k+1$, so $k=(n-1)/2$. The median is $b_{(n-1)/2}$.
        //
        // The example for n=3 (2n=6 students) has sorted skills [1, 2, 3, 4, 5, 6].
        // $a_0=1, a_1=2, a_2=3, a_3=4, a_4=5, a_5=6$.
        // $n=3$.
        // The answer is $|a_3 - a_2| = |4 - 3| = 1$.
        //
        // The example partition:
        // Class 1: [2, 4, 6]. Median is 4.
        // Class 2: [1, 3, 5]. Median is 3.
        //
        // Here, 4 is $a_3$. 3 is $a_2$.
        // So the medians are indeed $a_n$ and $a_{n-1}$ (using 0-indexed $a$).
        //
        // How can we construct this partition?
        // Class 1 (median $a_n$):
        //   Take $a_n$ itself.
        //   Take $k$ elements smaller than $a_n$. For example, $a_0, \dots, a_{k-1}$.
        //   Take $k$ elements larger than $a_n$. For example, $a_{2n-1}, \dots, a_{2n-k}$.
        // This is not how it works. We need to partition ALL students.
        //
        // The problem is simpler than constructing the partition.
        // It asks for the minimum possible absolute difference.
        //
        // Consider the $2n$ students sorted: $a_0, a_1, \dots, a_{2n-1}$.
        //
        // Any class of size $2k+1$ will have its median as one of the $a_i$'s.
        // Let $M_1$ and $M_2$ be the medians of the two classes.
        //
        // Suppose $M_1 = a_i$ and $M_2 = a_j$. We want to minimize $|a_i - a_j|$.
        // This means $a_i$ and $a_j$ should be as close as possible in the sorted array.
        // The closest possible distinct elements are $a_k$ and $a_{k+1}$ for some $k$.
        //
        // The crucial point is that we can always make $a_{n-1}$ and $a_n$ the medians.
        //
        // Let's try to make $a_{n-1}$ the median of Class 1 and $a_n$ the median of Class 2.
        //
        // Class 1 (median $a_{n-1}$):
        //   Take $a_{n-1}$.
        //   Take $n-1$ students from $a_0, \dots, a_{n-2}$ (all of them).
        //   Take $n-1$ students from $a_{n+1}, \dots, a_{2n-1}$ (the largest $n-1$ students).
        //   This forms a class of size $1 + (n-1) + (n-1) = 2n-1$.
        //   The students are $\{a_0, \dots, a_{n-1}\} \cup \{a_{2n-1}, \dots, a_{2n-(n-1)}\}$.
        //   This class has $2n-1$ students. Its median is $a_{n-1}$.
        //   This is a valid class if $2n-1$ is odd, which is always true.
        //
        // The remaining students are:
        //   $a_n$ (which was not used in Class 1)
        //   $a_{n}, \dots, a_{2n-n}$ (the $n$-th largest element, $a_n$)
        //   The students not used from $a_0, \dots, a_{n-2}$ are none.
        //   The students not used from $a_{n+1}, \dots, a_{2n-1}$ are $a_n$.
        //
        // This construction is wrong. Let's restart the construction idea.
        //
        // We need to partition $2n$ students into two classes, $C_1$ and $C_2$, each of odd size.
        // Let $M_1$ be the median of $C_1$ and $M_2$ be the median of $C_2$.
        // We want to minimize $|M_1 - M_2|$.
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        //
        // We can always form a class $C_1$ with $a_{n-1}$ as its median and a class $C_2$ with $a_n$ as its median.
        //
        // Let $C_1$ consist of $a_{n-1}$ and $k$ elements smaller than $a_{n-1}$ and $k$ elements larger than $a_{n-1}$.
        // Let $C_2$ consist of $a_n$ and $l$ elements smaller than $a_n$ and $l$ elements larger than $a_n$.
        //
        // The total number of students is $2n$.
        //
        // Consider the partition where:
        // Class 1: $a_0, a_1, \dots, a_{n-1}$. This class has $n$ students.
        // Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$. This class has $n$ students.
        //
        // This partition is valid if $n$ is odd.
        // If $n$ is odd, then $n=2k+1$ for some $k$.
        // Median of Class 1 is $a_k = a_{(n-1)/2}$.
        // Median of Class 2 is $a_{n+k} = a_{n+(n-1)/2}$.
        // The difference is $|a_{n+(n-1)/2} - a_{(n-1)/2}|$.
        //
        // This is not $|a_n - a_{n-1}|$.
        //
        // The example for n=3 (2n=6 students) has sorted skills [1, 2, 3, 4, 5, 6].
        // $n=3$. $k=(3-1)/2=1$.
        // Median of Class 1 ($a_0, a_1, a_2$) is $a_1=2$.
        // Median of Class 2 ($a_3, a_4, a_5$) is $a_{3+1}=a_4=5$.
        // Difference is $|5-2|=3$.
        // But the answer is 1.
        //
        // This means the simple partition of first $n$ and last $n$ elements is not always optimal,
        // or not always possible if $n$ is even.
        //
        // The problem statement is: "Among such partitions, you want to choose one in which the absolute difference between skill levels of the classes is minimized."
        //
        // The key is that the medians must be $a_{n-1}$ and $a_n$.
        //
        // Let's prove that the minimum difference is $|a_n - a_{n-1}|$.
        //
        // Consider any partition into two classes $C_1$ and $C_2$ with odd sizes $S_1$ and $S_2$.
        // Let $M_1$ be the median of $C_1$ and $M_2$ be the median of $C_2$.
        // Assume $M_1 \le M_2$.
        //
        // $M_1$ is the $( (S_1-1)/2 + 1)$-th smallest element in $C_1$.
        // $M_2$ is the $( (S_2-1)/2 + 1)$-th smallest element in $C_2$.
        //
        // The total number of students is $2n$.
        //
        // The number of students in $C_1$ with skill $\le M_1$ is $(S_1-1)/2 + 1$.
        // The number of students in $C_2$ with skill $\le M_2$ is $(S_2-1)/2 + 1$.
        //
        // Sum of students with skill $\le M_1$ in $C_1$ and $\le M_2$ in $C_2$:
        // Total students with skill $\le M_1$ (from $C_1$) + Total students with skill $\le M_2$ (from $C_2$).
        //
        // Consider the $n$-th smallest student $a_{n-1}$ and the $(n+1)$-th smallest student $a_n$.
        //
        // Suppose $M_1 < a_{n-1}$ and $M_2 > a_n$. Then $|M_1 - M_2| > |a_n - a_{n-1}|$.
        // Suppose $M_1 = a_{n-1}$ and $M_2 = a_n$. Then $|M_1 - M_2| = |a_n - a_{n-1}|$.
        //
        // Can we always construct a partition such that $a_{n-1}$ and $a_n$ are the medians?
        //
        // Let $C_1$ be the class with median $a_{n-1}$.
        // Let $C_2$ be the class with median $a_n$.
        //
        // To make $a_{n-1}$ the median of $C_1$:
        // $C_1$ must contain $a_{n-1}$.
        // $C_1$ must contain $k_1$ elements from $\{a_0, \dots, a_{n-2}\}$ (elements smaller than $a_{n-1}$).
        // $C_1$ must contain $k_1$ elements from $\{a_n, \dots, a_{2n-1}\}$ (elements larger than $a_{n-1}$).
        // The size of $C_1$ is $2k_1+1$.
        //
        // To make $a_n$ the median of $C_2$:
        // $C_2$ must contain $a_n$.
        // $C_2$ must contain $k_2$ elements from $\{a_0, \dots, a_{n-1}\}$ (elements smaller than $a_n$).
        // $C_2$ must contain $k_2$ elements from $\{a_{n+1}, \dots, a_{2n-1}\}$ (elements larger than $a_n$).
        // The size of $C_2$ is $2k_2+1$.
        //
        // All students must be assigned.
        //
        // Let's try to make $k_1 = n-1$ and $k_2 = 0$.
        // Class 1: $a_{n-1}$ (median), plus $n-1$ elements smaller, plus $n-1$ elements larger.
        //   Smallest $n-1$ elements: $a_0, \dots, a_{n-2}$.
        //   Largest $n-1$ elements: $a_{2n-1}, \dots, a_{2n-(n-1)}$.
        //   So $C_1 = \{a_0, \dots, a_{n-2}, a_{n-1}, a_{2n-n+1}, \dots, a_{2n-1}\}$.
        //   Size of $C_1$ is $1 + (n-1) + (n-1) = 2n-1$. This is always odd.
        //
        // The remaining student is $a_n$.
        // Class 2: $\{a_n\}$. This class has size 1 (odd). Its median is $a_n$.
        //
        // This construction works!
        // Class 1 has median $a_{n-1}$.
        // Class 2 has median $a_n$.
        // Both classes have odd sizes ($2n-1$ and $1$).
        // All $2n$ students are assigned.
        // The absolute difference is $|a_n - a_{n-1}|$.
        //
        // Since $a_n$ and $a_{n-1}$ are adjacent in the sorted array, their difference is the minimum possible
        // difference between any two distinct elements in the array.
        // If $a_n = a_{n-1}$, the difference is 0.
        // If $a_n > a_{n-1}$, the difference is $a_n - a_{n-1}$.
        //
        // This construction proves that $|a_n - a_{n-1}|$ is an achievable difference.
        // Since it's the difference between two adjacent elements in the sorted array, it must be the minimum possible.
        // Any other pair of medians $M_1, M_2$ would either be $a_{n-1}$ and $a_n$ (same difference),
        // or $M_1 < a_{n-1}$ and $M_2 > a_n$ (larger difference),
        // or $M_1, M_2$ are both $\le a_{n-1}$ or both $\ge a_n$ (then one of them must be $a_{n-1}$ or $a_n$ to be minimal,
        // or they are further apart).
        //
        // The logic holds. The minimum difference is $a_n - a_{n-1}$ (using 0-indexed array).

        // The answer is the absolute difference between the element at index n-1 and the element at index n.
        // In a 0-indexed array of size 2n, these are a[n-1] and a[n].
        std::cout << std::abs(a[n] - a[n - 1]) << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the longest suffix that is non-increasing
    // This suffix is a_k, a_{k+1}, ..., a_{n-1} such that a_k >= a_{k+1} >= ... >= a_{n-1}
    int k_suffix_non_increasing = n - 1;
    while (k_suffix_non_increasing > 0 && a[k_suffix_non_increasing - 1] >= a[k_suffix_non_increasing]) {
        k_suffix_non_increasing--;
    }

    // Find the longest suffix that is non-decreasing
    // This suffix is a_j, a_{j+1}, ..., a_{n-1} such that a_j <= a_{j+1} <= ... <= a_{n-1}
    int j_suffix_non_decreasing = n - 1;
    while (j_suffix_non_decreasing > 0 && a[j_suffix_non_decreasing - 1] <= a[j_suffix_non_decreasing]) {
        j_suffix_non_decreasing--;
    }

    // The "good" suffix must start at or before the start of the non-increasing suffix
    // and at or before the start of the non-decreasing suffix.
    // The actual start of the "good" suffix is the minimum of these two indices.
    // The elements from index 0 up to this minimum index (exclusive) must be removed.
    int start_of_good_suffix = std::min(k_suffix_non_increasing, j_suffix_non_decreasing);

    std::cout << start_of_good_suffix << std::endl;
}

