#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] = index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length is 1, min is 1, max is 1. So m=1 is always beautiful.

        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from the minimum index seen so far (containing 1 to m-1)
        // to the maximum index seen so far (containing 1 to m-1), AND also include 'm'.
        // So, we update current_min_idx and current_max_idx to include pos[m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if there exists a subsegment [p_l, ..., p_r]
        // that is a permutation of 1, ..., m.
        // This implies:
        // 1. The length of the subsegment (r - l + 1) must be m.
        // 2. The minimum value in the subsegment must be 1.
        // 3. The maximum value in the subsegment must be m.
        //
        // If we consider the segment defined by [current_min_idx, current_max_idx],
        // this segment contains all numbers from 1 to m (because we've updated
        // current_min_idx and current_max_idx to span all positions of 1, 2, ..., m).
        // The minimum value in this segment is 1, and the maximum value is m.
        //
        // For this segment to be a permutation of 1, ..., m, its length must be exactly m.
        // The length of the segment [current_min_idx, ..., current_max_idx] is
        // (current_max_idx - current_min_idx + 1).
        // If this length equals m, then all numbers from 1 to m are present exactly once
        // in this segment, and no other numbers are present.
        // Thus, it forms a permutation of 1, ..., m.

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

