#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        // The quadratic equation for 'a' is a^2 - d*a + d = 0
        // Using the quadratic formula: a = (d +/- sqrt(d^2 - 4d)) / 2
        // For real solutions, the discriminant (d^2 - 4d) must be non-negative.
        // d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d is non-negative, this implies d - 4 >= 0, so d >= 4.
        // Also, if d = 0, then 0(0-4) = 0 >= 0, so d=0 is a valid case.
        // If d = 1, 2, 3, then d^2 - 4d < 0, so no real solutions.

        if (d == 0.0) {
            // Special case: a+b=0, a*b=0. Only solution is a=0, b=0.
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            // Discriminant d^2 - 4d would be negative for d in (0, 4).
            // No real solutions.
            std::cout << "N\n";
        } else {
            // d >= 4.0, so d^2 - 4d >= 0. Real solutions exist.
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            // We need a and b to be non-negative.
            // a = (d + sqrt_discriminant) / 2
            // b = (d - sqrt_discriminant) / 2
            // Since d >= 4, d^2 >= 4d, so d >= sqrt(4d).
            // Also, d >= sqrt(d^2 - 4d) because d^2 >= d^2 - 4d (since 4d >= 0).
            // So, d - sqrt_discriminant will be non-negative.
            // Both a and b will be non-negative.

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

