void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    if (total_toys == 1) {
        if (A == 1) std::cout << "Ya Tidak Tidak Tidak\n";
        else if (B == 1) std::cout << "Tidak Ya Tidak Tidak\n";
        else if (C == 1) std::cout << "Tidak Tidak Ya Tidak\n";
        else if (D == 1) std::cout << "Tidak Tidak Tidak Ya\n";
        return;
    }

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    // Box 1: x <= -1
    // Final product must be negative and magnitude >= 1
    // Number of negative factors must be odd.
    // Number of factors with magnitude >= 1 must be odd if all other factors have magnitude < 1.
    // Or, if there are factors with magnitude >= 1 and factors with magnitude < 1,
    // the product of magnitudes must be >= 1.

    // Case 1: Final toy in Box 1 (x <= -1)
    // Requires odd number of negative factors.
    // Requires product magnitude >= 1.
    bool possible1 = false;
    if ((A + B) % 2 == 1) { // Odd number of negative factors
        // To get magnitude >= 1:
        // 1. At least one toy from Box 1 or Box 4 (magnitude >= 1)
        // 2. Or, if only toys from Box 2 and Box 3, then it's impossible to get magnitude >= 1.
        //    (This is covered by the condition below: if A+D == 0, then magnitude will be < 1)
        if (A + D > 0) { // At least one toy with magnitude >= 1
            possible1 = true;
        } else { // All initial toys have magnitude < 1 (B+C > 0)
            // If A+D == 0, then all initial toys are from B or C.
            // Product of any number of B/C toys will have magnitude < 1.
            // So, if A+D == 0, it's impossible to get magnitude >= 1.
            possible1 = false;
        }
    }
    ans1 = possible1 ? "Ya" : "Tidak";

    // Case 2: Final toy in Box 2 (-1 < x < 0)
    // Requires odd number of negative factors.
    // Requires product magnitude < 1.
    bool possible2 = false;
    if ((A + B) % 2 == 1) { // Odd number of negative factors
        // To get magnitude < 1:
        // 1. At least one toy from Box 2 or Box 3 (magnitude < 1)
        // 2. If all initial toys are from Box 1 or Box 4 (A+D > 0, B+C == 0),
        //    then it's impossible to get magnitude < 1 unless A+D=1.
        //    If A+D=1, then the single toy is either in Box 1 or Box 4.
        //    If A+D > 1 and B+C == 0, then product magnitude will be >= 1.
        //    So, if B+C > 0, it's possible to get magnitude < 1.
        //    If B+C == 0, then all toys are from A or D.
        //    If A+D > 1, product magnitude >= 1.
        //    If A+D == 1, then it's the single toy case, handled above.
        if (B + C > 0) { // At least one toy with magnitude < 1
            possible2 = true;
        } else { // All initial toys have magnitude >= 1 (A+D > 0)
            // If B+C == 0, then all initial toys are from A or D.
            // Product of any number of A/D toys will have magnitude >= 1.
            // So, if B+C == 0, it's impossible to get magnitude < 1 (unless total_toys=1, handled).
            possible2 = false;
        }
    }
    ans2 = possible2 ? "Ya" : "Tidak";

    // Case 3: Final toy in Box 3 (0 < x < 1)
    // Requires even number of negative factors.
    // Requires product magnitude < 1.
    bool possible3 = false;
    if ((A + B) % 2 == 0) { // Even number of negative factors
        // To get magnitude < 1:
        // 1. At least one toy from Box 2 or Box 3 (magnitude < 1)
        // 2. If all initial toys are from Box 1 or Box 4 (A+D > 0, B+C == 0),
        //    then it's impossible to get magnitude < 1 unless A+D=1.
        //    If A+D > 1 and B+C == 0, then product magnitude will be >= 1.
        //    So, if B+C > 0, it's possible to get magnitude < 1.
        //    If B+C == 0, then all toys are from A or D.
        //    If A+D > 1, product magnitude >= 1.
        //    If A+D == 1, then it's the single toy case, handled above.
        if (B + C > 0) { // At least one toy with magnitude < 1
            possible3 = true;
        } else { // All initial toys have magnitude >= 1 (A+D > 0)
            // If B+C == 0, then all initial toys are from A or D.
            // Product of any number of A/D toys will have magnitude >= 1.
            // So, if B+C == 0, it's impossible to get magnitude < 1 (unless total_toys=1, handled).
            possible3 = false;
        }
    }
    ans3 = possible3 ? "Ya" : "Tidak";

    // Case 4: Final toy in Box 4 (x >= 1)
    // Requires even number of negative factors.
    // Requires product magnitude >= 1.
    bool possible4 = false;
    if ((A + B) % 2 == 0) { // Even number of negative factors
        // To get magnitude >= 1:
        // 1. At least one toy from Box 1 or Box 4 (magnitude >= 1)
        // 2. Or, if only toys from Box 2 and Box 3, then it's impossible to get magnitude >= 1.
        //    (This is covered by the condition below: if A+D == 0, then magnitude will be < 1)
        if (A + D > 0) { // At least one toy with magnitude >= 1
            possible4 = true;
        } else { // All initial toys have magnitude < 1 (B+C > 0)
            // If A+D == 0, then all initial toys are from B or C.
            // Product of any number of B/C toys will have magnitude < 1.
            // So, if A+D == 0, it's impossible to get magnitude >= 1.
            possible4 = false;
        }
    }
    ans4 = possible4 ? "Ya" : "Tidak";

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

