#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate max_left_val[i]: the maximum possible value for a_i
    // such that a_1 < a_2 < ... < a_i, given a_1 >= 0.
    // This means a_j >= j-1 for j=1..i.
    // So, a_i must be at least i-1.
    // We can decrease a_i to any value from 0 to original a_i.
    // So, a_i must be at least i-1. If original a_i < i-1, it's impossible.
    // Otherwise, it's possible.
    // We are looking for a peak k.
    // For the left side (1 to k): a_i >= i-1.
    // For the right side (k to n): a_i >= n-i.

    // Check if there exists a k such that a_k can be a peak.
    // For a_k to be a peak, it must satisfy:
    // 1. a_k >= k-1 (to allow 0, 1, ..., k-1 for a_1, ..., a_k)
    // 2. a_k >= n-k (to allow 0, 1, ..., n-k for a_n, ..., a_{k+1})
    // Note: a_k is the peak, so it's a_k > a_{k+1} > ... > a_n.
    // The values a_{k+1}, ..., a_n must be at least n-(k+1), ..., 0 respectively.
    // So a_k must be at least (n-k).
    // Example: n=3, k=1. a_1 > a_2 > a_3. a_1 >= 2. (n-k = 3-1 = 2)
    // Example: n=3, k=2. a_1 < a_2 > a_3. a_1 >= 0, a_2 >= 1. a_2 >= 1. (n-k = 3-2 = 1)
    // Example: n=3, k=3. a_1 < a_2 < a_3. a_1 >= 0, a_2 >= 1, a_3 >= 2. (n-k = 3-3 = 0)

    // So, for a given k (1-indexed):
    // We need a[i-1] >= i-1 for i from 1 to k.
    // We need a[i-1] >= n-i for i from k to n.

    // Let's find the leftmost index `left_idx` such that for all `i < left_idx`, `a[i] < i`.
    // If `a[i] < i`, then `a[i]` cannot be made `i`.
    // For example, if `a[0] < 0`, impossible. (a[0] is always >= 0, so this is fine)
    // If `a[1] < 1`, then `a[0] < a[1]` is impossible if `a[0]` is 0.
    // More precisely, `a[i]` must be at least `i` to allow `0, 1, ..., i` for `a[0], ..., a[i]`.
    // No, `a[i]` must be at least `i` to allow `0, 1, ..., i-1` for `a[0], ..., a[i-1]` and `a[i]` to be `i`.
    // So, `a[i]` must be at least `i`.
    // Let's find the first `i` (0-indexed) such that `a[i] < i`.
    // All indices `j < i` can potentially be part of an increasing sequence `0, 1, ..., j`.
    int left_bound = n; // All elements up to left_bound-1 can satisfy a[j] >= j
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            left_bound = i;
            break;
        }
    }

    // Let's find the rightmost index `right_idx` such that for all `i > right_idx`, `a[i] < n-1-i`.
    // For the decreasing sequence `a_k > a_{k+1} > ... > a_n`.
    // `a_n` must be at least 0. `a_{n-1}` must be at least 1. `a_{n-j}` must be at least `j`.
    // So `a[i]` must be at least `n-1-i`.
    // Let's find the first `i` (0-indexed, from right) such that `a[i] < n-1-i`.
    // All indices `j > i` can potentially be part of a decreasing sequence `..., j, j-1, ..., 0`.
    int right_bound = -1; // All elements from right_bound+1 to n-1 can satisfy a[j] >= n-1-j
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            right_bound = i;
            break;
        }
    }

    // A peak `k` (0-indexed) can exist if `k` is within the range `[left_bound, right_bound]`.
    // More precisely, `k` must be an index `i` such that `a[i] >= i` AND `a[i] >= n-1-i`.
    // The `left_bound` is the first index `i` where `a[i] < i`. So any `j < left_bound` satisfies `a[j] >= j`.
    // The `right_bound` is the first index `i` (from right) where `a[i] < n-1-i`. So any `j > right_bound` satisfies `a[j] >= n-1-j`.
    // We need to find an index `k` (0-indexed) such that `a[k] >= k` AND `a[k] >= n-1-k`.
    // This means `k` must be less than `left_bound` AND `k` must be greater than `right_bound`.
    // So, we need to check if `left_bound > right_bound`.
    // If `left_bound > right_bound`, it means there is at least one index `k` such that `a[k] >= k` and `a[k] >= n-1-k`.
    // For example, if `left_bound = 3` and `right_bound = 1`, then `k=2` is a candidate.
    // `a[2] >= 2` (because `2 < left_bound=3`) and `a[2] >= n-1-2` (because `2 > right_bound=1`).
    // So, if `left_bound > right_bound`, then there exists such a `k`.

    if (left_bound > right_bound) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
