struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    std::vector<long long> result_a_prime(m);

    // The strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // This means a_elements[i] (which is the i-th smallest A value)
    // should be paired with b_elements[i] (which is the i-th smallest B value).
    // However, the problem asks for A' to be a permutation of A,
    // and the output should be A'_1, A'_2, ..., A'_m, where A'_i is paired with B_i
    // from the original input.
    // So, if original B_k is the i-th smallest B value, it should be paired
    // with the i-th smallest A value.

    // Map original index of B to its sorted position.
    // b_elements[i].original_index is the original index of the i-th smallest B value.
    // We want to assign a_elements[i].value to result_a_prime[b_elements[i].original_index].
    for (int i = 0; i < m; ++i) {
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
