#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will cause 'count_a' steps
            // and double the 'count_a' for future 'b's.
            // So, when we see a 'b', we add the current 'count_a' to total_steps.
            total_steps = (total_steps + count_a) % MOD;
            // After this 'b' interacts with all 'a's to its left,
            // each 'a' effectively becomes 'bba'.
            // The 'a' moves past the 'b', and a new 'b' is created.
            // This new 'b' will then interact with 'a's further left.
            // The 'a's that were to the left of the current 'b'
            // effectively double their "potential" to cause steps for 'b's further left.
            // This is because each 'a' that passes this 'b'
            // will eventually pass the new 'b' created by this 'b'.
            // So, we double count_a.
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are waiting to interact with a 'b' to their right.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

