// Function to convert a number to its 18-digit parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern_str(18, '0'); // Initialize with 18 '0's
    int i = 17; // Start from the rightmost digit position
    if (n == 0) {
        // For 0, all digits are 0, which is even. So pattern is all '0's.
        // The default initialized pattern_str is already all '0's.
        return pattern_str;
    }
    while (n > 0 && i >= 0) {
        if ((n % 10) % 2 != 0) { // If digit is odd
            pattern_str[i] = '1';
        }
        n /= 10;
        i--;
    }
    return pattern_str;
}

int main() {
