    for (int k = 0; k < t; ++k) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the pattern s with leading zeros to 18 digits
            std::string padded_s(18 - s.length(), '0');
            padded_s += s;
            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

