// Function to find prime factors of a number
// Returns a vector of unique prime factors
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            // If p is not divisible by q, then p itself is the answer.
            // It's the largest divisor of p, and it satisfies p % q != 0.
            std::cout << p << "\n";
        } else {
            // If p is divisible by q, we need to find a smaller x.
            // x must be a divisor of p, and x must not be divisible by q.
            // We want to maximize x.

            // Find prime factors of q.
            // We only care about unique prime factors of q.
            std::vector<long long> q_prime_factors = get_prime_factors(q);

            long long max_x = 0;

            // For each prime factor f of q:
            // We want to remove enough factors of f from p such that
            // the resulting number (p / f^k) is no longer divisible by q.
            // To maximize x, we should remove the minimum necessary factors.
            for (long long f : q_prime_factors) {
                long long current_p = p;
                // Divide current_p by f until it's no longer divisible by q.
                // This means current_p / f^k is not divisible by q.
                // We want to find the largest such current_p / f^k.
                // So we divide p by f until (p / f^k) % q != 0.
                // The largest such (p / f^k) will be p / f^(k_min).
                // k_min is the smallest power of f such that p / f^k_min is not divisible by q.
                // This is equivalent to finding the smallest k such that (p / f^k) % q != 0.
                // We can achieve this by repeatedly dividing p by f until the condition is met.
                while (current_p % q == 0) {
                    current_p /= f;
                }
                max_x = std::max(max_x, current_p);
            }
            std::cout << max_x << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>

void solve() {
    int n;
    std::cin >> n;

    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1: can move left (x-1)
        // f2: can move up (y+1)
        // f3: can move right (x+1)
        // f4: can move down (y-1)

        // If robot cannot move left (f1=0), it must end up at X >= its current x.
        // So, the target X must be greater than or equal to x.
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }
        // If robot cannot move down (f4=0), it must end up at Y >= its current y.
        // So, the target Y must be greater than or equal to y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
        // If robot cannot move right (f3=0), it must end up at X <= its current x.
        // So, the target X must be less than or equal to x.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }
        // If robot cannot move up (f2=0), it must end up at Y <= its current y.
        // So, the target Y must be less than or equal to y.
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // A valid point exists. We can pick any point in the intersection.
        // The problem guarantees that if a point exists, one with coordinates
        // not exceeding 10^5 by absolute value exists.
        // So, we can just pick (min_x, min_y) as a valid point.
        // We need to clamp it to the guaranteed range if min_x/min_y are still
        // at their initial "negative infinity" values, but the problem constraints
        // on x_i, y_i (-10^5 to 10^5) mean that min_x/min_y will be at most 10^5
        // and max_x/max_y will be at least -10^5 if they are constrained.
        // If they are not constrained, they will remain at their initial large values.
        // The problem statement guarantees that if a solution exists, one with
        // coordinates within [-10^5, 10^5] exists. So we can just output min_x, min_y.
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

