    while (q--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool possible = false;

    for (int p = 0; p <= 9; ++p) { // p is the split digit
        // p represents the largest digit that can be in S1.
        // All digits < p must be in S1.
        // All digits > p must be in S2.
        // Digits == p can be in S1 or S2.
        // We try to put as many 'p's as possible into S1, then switch to S2.

        std::string current_result(n, ' ');
        char last_s1_digit = '0' - 1; // Smaller than any digit
        char first_s2_digit = '9' + 1; // Larger than any digit
        bool s1_has_p = false;
        bool s2_has_p = false;

        bool current_possible = true;

        for (int i = 0; i < n; ++i) {
            char digit_char = s[i];
            int digit_val = digit_char - '0';

            if (digit_val < p) {
                current_result[i] = '1';
                if (digit_char < last_s1_digit) {
                    current_possible = false;
                    break;
                }
                last_s1_digit = digit_char;
            } else if (digit_val > p) {
                current_result[i] = '2';
                if (digit_char < first_s2_digit) {
                    current_possible = false;
                    break;
                }
                first_s2_digit = digit_char;
            } else { // digit_val == p
                // Try to put 'p's into S1 first, then switch to S2.
                // The switch point for 'p's is determined by the first 'p' that is smaller than the last 'p' in S1.
                // Or, more simply, find the first 'p' that is greater than or equal to the last 'p' in S1.
                // All 'p's before this point go to S1, all 'p's after this point go to S2.
                // This is not quite right. We need to find a split point for 'p's.
                // All 'p's before some index `k` go to S1, all 'p's at or after `k` go to S2.
                // This is equivalent to finding the rightmost 'p' that can be in S1.
                // Let's iterate through the digits and assign 'p's greedily.
                // If a 'p' can go to S1 (i.e., it's >= last_s1_digit), put it in S1.
                // If it can't go to S1, it must go to S2.
                // Once a 'p' goes to S2, all subsequent 'p's must also go to S2.
                // This is the key: we want to find the *last* possible 'p' that can be in S1.
                // All 'p's before it that are >= last_s1_digit go to S1.
                // All 'p's after it go to S2.
                // This is what the `p_split_idx` logic does.

                // Let's re-evaluate the strategy for 'p's.
                // All digits < p must be 1.
                // All digits > p must be 2.
                // For digits == p:
                // We want to find an index `k` such that all `d_i = p` with `i < k` are colored 1,
                // and all `d_i = p` with `i >= k` are colored 2.
                // This `k` can be `n` (all `p`s are 1) or `0` (all `p`s are 2).
                // The `p` in the loop is this `k`.
                // So, `p` is the value of the digit.
                // We need to find a `split_idx_for_p` for the digits equal to `p`.

                // Let's try a different approach:
                // Iterate through `p` from 0 to 9.
                // For a given `p`:
                //   Initialize `last_s1_val = -1`, `last_s2_val = -1`.
                //   `ans_colors` array.
                //   `s1_finished = false` (meaning we are still assigning 'p's to S1 if possible)
                //   For `i` from 0 to `n-1`:
                //     `digit = s[i] - '0'`
                //     If `digit < p`:
                //       If `s1_finished` is true (meaning we already started assigning 'p's to S2), then impossible.
                //       If `digit < last_s1_val`, then impossible.
                //       `ans_colors[i] = '1'`. `last_s1_val = digit`.
                //     Else if `digit > p`:
                //       `s1_finished = true`.
                //       If `digit < last_s2_val`, then impossible.
                //       `ans_colors[i] = '2'`. `last_s2_val = digit`.
                //     Else (`digit == p`):
                //       If `s1_finished` is false:
                //         If `digit >= last_s1_val`:
                //           `ans_colors[i] = '1'`. `last_s1_val = digit`.
                //         Else (`digit < last_s1_val`):
                //           `s1_finished = true`. // Cannot put this 'p' in S1, so all subsequent 'p's must go to S2.
                //           If `digit < last_s2_val`, then impossible.
                //           `ans_colors[i] = '2'`. `last_s2_val = digit`.
                //       Else (`s1_finished` is true):
                //         If `digit < last_s2_val`, then impossible.
                //         `ans_colors[i] = '2'`. `last_s2_val = digit`.
                //   If not impossible, then we found a solution. Print it and return.

        int last_s1_val = -1;
        int last_s2_val = -1;
        std::string current_ans(n, ' ');
        bool s1_p_assigned = false; // True if we've started assigning 'p's to S2

        bool current_p_possible = true;
        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < p) {
                if (s1_p_assigned) { // A digit < p appears after we started assigning 'p's to S2
                    current_p_possible = false;
                    break;
                }
                if (digit < last_s1_val) { // S1 not sorted
                    current_p_possible = false;
                    break;
                }
                current_ans[i] = '1';
                last_s1_val = digit;
            } else if (digit > p) {
                s1_p_assigned = true; // We must assign 'p's to S2 from now on
                if (digit < last_s2_val) { // S2 not sorted
                    current_p_possible = false;
                    break;
                }
                current_ans[i] = '2';
                last_s2_val = digit;
            } else { // digit == p
                if (!s1_p_assigned) { // Still trying to assign 'p's to S1
                    if (digit >= last_s1_val) { // Can put this 'p' in S1
                        current_ans[i] = '1';
                        last_s1_val = digit;
                    } else { // Cannot put this 'p' in S1, must put in S2
                        s1_p_assigned = true;
                        if (digit < last_s2_val) { // S2 not sorted
                            current_p_possible = false;
                            break;
                        }
                        current_ans[i] = '2';
                        last_s2_val = digit;
                    }
                } else { // Already assigning 'p's to S2
                    if (digit < last_s2_val) { // S2 not sorted
                        current_p_possible = false;
                        break;
                    }
                    current_ans[i] = '2';
                    last_s2_val = digit;
                }
            }
        }

        if (current_p_possible) {
            possible = true;
            result = current_ans;
            break;
        }
    }

    if (possible) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

