#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> partition(n);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // This is always a valid partition.
    // All f(a_i, a_j) values are a_i + a_j.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> best_partition(n, 1);
    long long min_goodness = goodness1;

    // Case 2: Partition into two non-empty subsequences.
    // Consider the partition where elements[0] is in S1 and elements[1] is in S2.
    // The remaining elements can be assigned to S1 or S2.
    // To minimize max_f - min_f, we want to make the range of f values as small as possible.
    // The critical values are:
    // min_same = elements[0].value + elements[1].value (if elements[0] and elements[1] are in the same group)
    // min_diff = elements[0].value + elements[1].value + h (if elements[0] and elements[1] are in different groups)
    // max_same = elements[n-1].value + elements[n-2].value
    // max_diff = elements[n-1].value + elements[n-2].value + h

    // Let's try a specific partition strategy:
    // elements[0] is in S1.
    // elements[1] is in S2.
    // elements[2] to elements[n-1] are all in S1.
    // S1 = {elements[0], elements[2], ..., elements[n-1]}
    // S2 = {elements[1]}
    // This ensures S1 and S2 are non-empty.

    // Values within S1:
    // min_S1_same = elements[0].value + elements[2].value (if n >= 3)
    // max_S1_same = elements[n-1].value + elements[n-2].value (if n >= 3)
    // Values within S2: (only one element, so no pairs)

    // Values between S1 and S2:
    // min_diff = elements[0].value + elements[1].value + h
    // max_diff = elements[n-1].value + elements[1].value + h

    // If n=2, this strategy is: S1={elements[0]}, S2={elements[1]}.
    // Only f(elements[0], elements[1]) = elements[0].value + elements[1].value + h.
    // min_f = max_f = elements[0].value + elements[1].value + h. Goodness = 0.
    // This is covered by the general logic below.

    // For n >= 2:
    // min_f_candidate = std::min(elements[0].value + elements[2].value, elements[0].value + elements[1].value + h)
    // max_f_candidate = std::max(elements[n-1].value + elements[n-2].value, elements[n-1].value + elements[1].value + h)
    // This is not quite right. The min/max f values depend on which pairs exist.

    // Let's consider the partition:
    // S1 = {elements[0], elements[2], ..., elements[n-1]}
    // S2 = {elements[1]}
    // This partition is valid if n >= 2.
    // If n=2: S1={elements[0]}, S2={elements[1]}.
    //   min_f = max_f = elements[0].value + elements[1].value + h. Goodness = 0.
    // If n > 2:
    //   Pairs within S1: (elements[0], elements[2]), ..., (elements[n-1], elements[n-2])
    //     min_same = elements[0].value + elements[2].value
    //     max_same = elements[n-1].value + elements[n-2].value
    //   Pairs between S1 and S2: (elements[0], elements[1]), (elements[2], elements[1]), ..., (elements[n-1], elements[1])
    //     min_diff = elements[0].value + elements[1].value + h
    //     max_diff = elements[n-1].value + elements[1].value + h

    // The overall min_f for this partition:
    long long current_min_f;
    if (n == 2) {
        current_min_f = elements[0].value + elements[1].value + h;
    } else { // n > 2
        current_min_f = std::min(elements[0].value + elements[2].value, elements[0].value + elements[1].value + h);
    }

    // The overall max_f for this partition:
    long long current_max_f;
    if (n == 2) {
        current_max_f = elements[0].value + elements[1].value + h;
    } else { // n > 2
        current_max_f = std::max(elements[n - 1].value + elements[n - 2].value, elements[n - 1].value + elements[1].value + h);
    }

    long long goodness2 = current_max_f - current_min_f;

    if (goodness2 < min_goodness) {
        min_goodness = goodness2;
        partition[elements[0].original_index] = 1;
        partition[elements[1].original_index] = 2;
        for (int i = 2; i < n; ++i) {
            partition[elements[i].original_index] = 1;
        }
        best_partition = partition;
    }

    // Case 3: Consider the partition where elements[0] is in S1, and all other elements are in S2.
    // S1 = {elements[0]}
    // S2 = {elements[1], ..., elements[n-1]}
    // This is valid if n >= 2.
    // If n=2: S1={elements[0]}, S2={elements[1]}. Same as above, goodness 0.
    // If n > 2:
    //   Pairs within S1: (none)
    //   Pairs within S2: (elements[1], elements[2]), ..., (elements[n-1], elements[n-2])
    //     min_same = elements[1].value + elements[2].value
    //     max_same = elements[n-1].value + elements[n-2].value
    //   Pairs between S1 and S2: (elements[0], elements[1]), ..., (elements[0], elements[n-1])
    //     min_diff = elements[0].value + elements[1].value + h
    //     max_diff = elements[0].value + elements[n-1].value + h

    // The overall min_f for this partition:
    if (n == 2) {
        current_min_f = elements[0].value + elements[1].value + h;
    } else { // n > 2
        current_min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    }

    // The overall max_f for this partition:
    if (n == 2) {
        current_max_f = elements[0].value + elements[1].value + h;
    } else { // n > 2
        current_max_f = std::max(elements[n - 1].value + elements[n - 2].value, elements[0].value + elements[n - 1].value + h);
    }

    long long goodness3 = current_max_f - current_min_f;

    if (goodness3 < min_goodness) {
        min_goodness = goodness3;
        partition[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            partition[elements[i].original_index] = 2;
        }
        best_partition = partition;
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

