#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All tracks covered
            break;
        }

        long long current_h = h[h_idx];
        long long head_reach_left = current_h - T;
        long long head_reach_right = current_h + T;

        // If the current head cannot reach the current target track p[p_idx],
        // it means this head is too far to the right.
        // We need to find a head that can reach p[p_idx].
        // If p[p_idx] is to the right of head_reach_right, this head cannot cover it.
        // This head can only cover tracks up to head_reach_right.
        // So, if p[p_idx] > head_reach_right, this head is useless for p[p_idx] and subsequent tracks.
        // This logic is flawed. A head can cover tracks to its left or right.
        // We need to cover p[p_idx] using the current head or a future head.
        // The current head can cover p[p_idx] if p[p_idx] is within [current_h - T, current_h + T].

        // Find the first track p[p_idx] that this head can potentially cover.
        // This head can cover tracks starting from max(p[p_idx], head_reach_left).
        // But we want to cover p[p_idx] first.
        // If p[p_idx] is too far to the left for this head, this head cannot cover it.
        // This means p[p_idx] < head_reach_left.
        // In this case, this head cannot cover p[p_idx] and we must use a previous head (which is not possible here)
        // or p[p_idx] is simply not coverable by this head.
        // This implies that p[p_idx] must be covered by a head h_k where k < h_idx.
        // Since we iterate h_idx from left to right, we assume previous heads covered previous tracks.
        // So, if p[p_idx] < head_reach_left, it means p[p_idx] was not covered by previous heads
        // and cannot be covered by current head. This implies `check` should return false.
        // However, this is not true. A head can cover tracks to its left.
        // The greedy strategy should be:
        // For the current head h[h_idx], what is the rightmost track it can cover,
        // given that it must cover p[p_idx] (if p[p_idx] is not yet covered)?

        // If p[p_idx] is already to the right of what this head can reach (current_h + T),
        // then this head cannot cover p[p_idx]. We move to the next head.
        // This is incorrect. A head can move left.
        // The crucial observation is that if a head h_i covers a track p_j, it can cover any track in [p_j - (T - |h_i - p_j|), p_j + (T - |h_i - p_j|)].
        // This is equivalent to saying it can cover any track in [h_i - T, h_i + T].

        // We want to cover p[p_idx] using the current head h[h_idx].
        // If h[h_idx] cannot reach p[p_idx] (i.e., p[p_idx] < h[h_idx] - T or p[p_idx] > h[h_idx] + T),
        // then this head cannot cover p[p_idx].
        // Since p is sorted, if h[h_idx] cannot cover p[p_idx], it also cannot cover p[p_idx+1], etc.,
        // if p[p_idx] is too far to the left of h[h_idx].
        // If p[p_idx] < h[h_idx] - T, then h[h_idx] cannot cover p[p_idx].
        // This means p[p_idx] must have been covered by a previous head.
        // But we are processing p_idx sequentially. So if p[p_idx] is not covered, it must be covered by current or future head.
        // If p[p_idx] < h[h_idx] - T, then h[h_idx] cannot cover p[p_idx].
        // This implies that p[p_idx] cannot be covered by any head h_k where k >= h_idx, because h_k >= h_idx implies h_k >= h[h_idx],
        // so h_k - T >= h[h_idx] - T. Thus, p[p_idx] < h_k - T for all k >= h_idx.
        // So, if p[p_idx] < h[h_idx] - T, it's impossible to cover p[p_idx].
        // This is the key condition for failure.

        if (p[p_idx] < head_reach_left) {
            return false; // Current track p[p_idx] is too far left for current head and any subsequent heads.
        }

        // If we reach here, p[p_idx] >= head_reach_left.
        // This means the current head h[h_idx] CAN cover p[p_idx].
        // Now, we want to cover as many subsequent tracks as possible with this head.
        // The current head can cover tracks up to head_reach_right.
        // So, we advance p_idx as long as p[p_idx] <= head_reach_right.
        while (p_idx < m && p[p_idx] <= head_reach_right) {
            p_idx++;
        }
    }
    return p_idx == m; // All tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance is 10^10 - 1 + 10^10 - 1 = ~2*10^10.
                                    // A safe upper bound for T.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

